/* characters q12 (100 mục) — R2.6 bồi tiểu sử Diệp Mịch */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q12"]=window.__LIBQ["tien-nghich"]["q12"]||{};window.__LIBQ["tien-nghich"]["q12"]["characters"]={"updatedAt":"2026-07-14","count":100,"chars":[{"id":"vuong-lam","name":"Vương Lâm","canhGioiCaoNhat":"Đài mộ cấp chín (9000 trượng)","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1324","importance":"major","mucCt":"ky","tieuDe":"Hóa hư hỏa, vào Thiên phương giới","text":"Hoàn thành thức tỉnh Chu Tước lần thứ tư, nghiệp chướng luân hồi hóa cửu sắc, thực hỏa thăng cấp thành hư hỏa bộc phát kinh thiên động địa. Phát hiện năng lực mới: nhìn bất kỳ ai cũng thấy tia tâm tình lưu chuyển, muốn thì biến thành hư hỏa. Trên người Vân Lạc đại ti, tâm tình nồng đậm hơn người khác vô số lần. Ôm quyền cung kính lão Chu Tước rồi đi tới cây Thiên phương hương cuối cùng, nhắm mắt bước vào Thiên phương giới — nơi do Điên Lạc đại đế trấn giữ, khảo nghiệm tiềm lực. Xuất hiện trên bàn tay pho tượng khổng lồ khắc hình Điên Lạc đại đế trong thế giới tràn ngập mây trắng. Suy tư về viễn cổ tiên tôn và viễn cổ tiên hoàng có phải một người không, ba tộc Thanh Long, Bạch Hổ, Huyền Vũ ở đâu, vì sao Chu Tước tộc và hỏa tước tộc cùng tồn tại.","anchor":"Mái tóc Vương Lâm không gió mà tung bay, quần áo phấp phới."},{"importance":"normal","mucCt":"ky","chuong":"@c1325","tieuDe":"Thí luyện Sâm La Viêm trong Thiên Phương giới","text":"Vương Lâm vào Thiên Phương giới, đối diện pho tượng khổng lồ của Lão Tổ Chu Tước đời đầu tiên, ôm quyền hành lễ tự xưng Chu Tước đời thứ sáu. Lão tổ bừng tỉnh, khen huyết mạch ít mà tỉnh giấc bốn lần, đề ra thí luyện: mỗi năm nhịp thở kiên trì được hỏi một câu. Bị Chu Tước Sâm La Viêm thiêu đốt, nhận ra đây là luyện hồn chứ không phải thí luyện thường, nhờ hư hỏa từ thức tỉnh Chu Tước lần thứ tư mà không chết. Vượt năm nhịp thở thì thân thể bên ngoài Đại Đế tinh vỡ tan, hỏi về nguồn gốc Hỏa Tước tộc. Tới sáu nhịp thở đạt cực hạn chịu đựng, dữ tợn nhìn pho tượng rồi triệu lôi đồ từ mắt phải, lấy lôi kháng hỏa, cuối cùng vượt được mười nhịp thở.","anchor":"Lôi đồ này quay cuồng khiến lôi đình ầm vang, những tia sét lóe lên, khiến Vương Lâm có thể vượt qua thời gian chín, rồi mười nhịp thở"},{"mucCt":"ky","text":"Tiếp tục chịu thí luyện trong Thiên phương giới, dùng lôi đồ và lửa Chu Tước chống lại Chu Tước già nua do pho tượng biến hóa ra, hồn phách nổ tung một nửa, thân thể ngoài Đại đế tinh phun máu huyết bốc hơi. Triệu huyết kiếm và lần đầu mở Cổ Lôi Giới — thần thông đại trưởng lão Thiểm Lôi tộc — xé khe không gian ngàn trượng, thái cổ Lôi Long xuất hiện, nhưng bị Chu Tước đời đầu dùng Chu Tước ấn phong bế hoàn toàn. Chuyển huyết kiếm tấn công thẳng pho tượng, bị lực vô hình chặn trước mi tâm, khiến Chu Tước đời đầu lần đầu lộ vẻ khiếp sợ khi nhận ra thanh kiếm. Từ nhịp thở 15 đến 19 bị bàn tay pho tượng nắm lại, nửa thân dưới tan nát, hồn phách cuối cùng hóa Chu Tước trong nắm tay. Được Chu Tước đời đầu dùng hư hỏa chín màu thẩm tra toàn bộ quá khứ, xác nhận thân phận rồi buông tay. Được chỉ ra con đường tu luyện sai lầm: lôi đình bổn nguyên đại thành mà không môn không mở, định bỏ qua thiên nhân ngũ suy là không thể — phải hiểu tu hành như chưởng, năm ngón tay đầy đủ mới phá không.","anchor":"thần sắc Vương Lâm dữ tợn, cất tiếng gầm nhẹ, nửa người dưới bị lực lượng quá mạnh mẽ khiến cho ầm ầm tan nát","bridge":true,"khoang":"@c1326"},{"importance":"normal","mucCt":"ky","chuong":"@c1327","tieuDe":"Từ chối đề xuất, tự ngộ đạo riêng","text":"Nghe Chu Tước đời đầu tiên giảng giải con đường Niết Không bước thứ ba, nhận ra thân thể Cổ Thần kết hợp năm đạo bổn nguyên khiến việc tiến vào Niết Không cực kỳ khó khăn. Bị hấp dẫn mạnh bởi đề xuất từ bỏ Cổ Thần và bốn bổn nguyên, chỉ giữ hỏa bổn nguyên, ở lại Thiên Phương giới trăm năm bước vào bước thứ ba rồi nhận Sâm La Viêm. Dao động kịch liệt, hơi thở dồn dập. Lấy quan tài Lý Mộ Uyển ra hỏi cách cứu sống, được biết tại quê nhà Chu Tước đời đầu có ba người có thể dung hợp hồn phách cứu nàng nhưng đều hạng cao quý khó nhờ. Nhớ tới Lý Mộ Uyển, Tư Đồ Nam, Thanh Thủy, Chu Như, Lý Thiến Mai — không thể bỏ rơi ai. Cuối cùng kiên quyết từ chối: không từ bỏ thân thể Cổ Thần, không từ bỏ bốn bổn nguyên, tuyên bố hành chỉ thuộc về mình. Tự ngộ con đường riêng — năm đạo bổn nguyên tương đương thiên nhân ngũ suy, khi đại thành sẽ tự phá không môn thành đạo. Ba chữ “Cũng có thể” vang động thiên địa, khiến Chu Tước đời đầu tiên sững sờ. Vái Chu Tước đời đầu tiên một cái rồi rời đi.","anchor":"bọn họ có thể tu tới trình độ như thế thì Vương Lâm ta cũng có thể"},{"importance":"normal","mucCt":"ky","chuong":"@c1328","tieuDe":"Tuyên thệ tự lực, nhận bảo vật, lập uy thách đấu","text":"Vương Lâm vái pho tượng Chu Tước đời đầu, thu Huyết kiếm trở lại, tuyên thệ trước thiên địa rằng sẽ không trông cậy ai để cứu Uyển Nhi, chỉ dựa sức bản thân, tự đánh tan thiên không rồi mang tất cả bằng hữu thăng tiên. Chu Tước đời đầu trầm mặc nửa ngày rồi thừa nhận hắn có thể đúng, xác nhận hắn đã vượt qua thí luyện Thiên phương giới, tiết lộ Nghiệt tước đời thứ ba gian trá có đường lui và có thể đang bế quan thánh địa Hỏa Tước tộc. Chu Tước đời đầu tặng lông chim chín màu ngưng tụ Sâm La Hỏa để phòng thân trước Nghiệt tước đời thứ ba, truyền khẩu quyết điều khiển chí bảo Chu Tước tộc đang trong tay Nghiệt tước, dặn lưu lại tộc nhân Hỏa Tước tộc vì còn tác dụng lớn, hứa giúp máu Chu Tước trên tinh cầu hoang dã thật hơn, sau đó pho tượng mất sinh cơ. Hồn phách Vương Lâm trở về thân thể đúng khoảnh khắc Thiên phương hương cháy hết, thương thế toàn thân khôi phục, hồn phách ngưng tụ hơn trước. Mắt trái có ngọn lửa chín màu, mắt phải có lôi đồ chín luồng lôi điện, ánh mắt quét qua khiến mấy vạn tu sĩ cảm giác thân thể bị thiêu đốt và hồn phách bị đặt vào lôi đồ. Vung tay hút hư hỏa từ cơ thể mấy vạn tu sĩ bốn phía, hóa thành cơn lốc hư hỏa khổng lồ cuộn quanh thân — đây là ngưng tụ hư hỏa bên ngoài. Từ trong cơn lốc hư hỏa, thân thể bay lên, cúi đầu nhìn xuống, thách đấu Tư Mặc Tử.","anchor":"Tư Mặc Tử, ngươi không phải muốn giết ta sao. ta cho ngươi một cơ hội, tới đây!"},{"chuong":"@c1329","importance":"normal","mucCt":"ky","tieuDe":"Khiêu chiến Ti Mặc Tử — đối kháng Phá Không Cửu Diệt","text":"Khí thế đạt đỉnh sau thí luyện, công khai khiêu chiến Ti Mặc Tử (bước thứ ba, Không Niết Sơ kỳ) trước mấy vạn tu sĩ trên Đại Đế tinh. Kích phát cửu sắc hư hỏa, niệm chú hóa cơn lốc thành chín con viêm long chín màu vờn quanh thân. Dùng song chỉ hóa kiếm, tập hợp chín viêm long cuộn quanh đối kháng chưởng Phá Thiên của Ti Mặc Tử. Bị đẩy lùi trăm trượng, sắc mặt hồng hào khác thường, thừa nhận bước thứ ba kinh người. Tuy nhiên hư hỏa không bị dập tắt, nắm khoảnh khắc Ti Mặc Tử lộ sợ hãi, lập tức phản công hô Hư hỏa bốc lên.","anchor":"Chín con viêm long ở bên ngoài thân thể hắn trong tiếng gầm nhẹ nhanh chóng vờn quanh song chỉ của hắn, lao thẳng đến Tư Mặc Tử"},{"mucCt":"ky","text":"Nén thương thế từ Phá Không Cửu Diệt, phóng hư hỏa chín màu từ đồng tử, đồng thời vung tay áo tạo cuồng phong kích phát tâm tình mấy vạn tu sĩ quan chiến, rút hư hỏa từ cơ thể họ ngưng tụ thành 36.793 con viêm long hư hỏa — vượt cực hạn Chu Tước đời thứ tư và đời thứ hai nhờ lực Thiên Nghịch. Lần lượt rút ngọc bội Phá Thiên Tông, khối thú cốt và nhắc chuyện sư đệ bị đuổi khỏi động phủ để công tâm Tư Mặc Tử, hỏi thẳng tên thật khiến hắn phun máu. Bị Tư Mặc Tử thi triển Hương hỏa nhất bái — cuồng phong tím kèm quy tắc bước thứ ba áp bức đau đớn gần xé thân, không chỗ trốn. Nhìn thấy linh hồn gốc Tư Mã Mặc ở mi tâm đối phương kêu cứu, quyết tự mình đối mặt, hô ngăn lão Chu Tước ra tay.","anchor":"Lão tổ, vãn bối làm được!","bridge":true,"khoang":"@c1330"},{"importance":"normal","mucCt":"ky","chuong":"@c1331","tieuDe":"Phong ấn hương hỏa giới bằng Cổ Tức Diệp","text":"Bị hồn phách hương hỏa vô tận của Tư Mặc Tử ép lùi, khóe miệng rỉ máu sắc mặt tái nhợt. Bùng chiến ý, lấy Cổ Tức Diệp kích hoạt tinh điểm Cổ Thần trên mi tâm, phun máu Cổ Thần lên lá, lá phát hồng quang vạn trượng xuyên qua thân Tư Mặc Tử dán lên khe hương hỏa giới, phong ấn thành công nguồn hồn phách vô tận. Uy lực Cổ Tức Diệp trong tay Vương Lâm (thân Cổ Thần) cao hơn vô số lần so với khi ở tay Tham Lang. Sau đó triệu Cổ Ma Hồn từ ngực ra, Cổ Ma Hồn hóa hình người nhỏ bé giống hệt Vương Lâm, triệu trường thương hư thực tấn công Tư Mặc Tử. Cổ Ma Hồn đối mặt Tử Đạo sương tím không sợ mà hưng phấn, chủ động nuốt sương tím, ma tính càng dày, xuyên qua màn sương lao thẳng tới Tư Mặc Tử.","anchor":"Cổ Tức Diệp này là một trong những bảo vật mà Tham Lang năm đó đã lấy được từ vùng đất cổ mộ, lai lịch thần bí khó lường"},{"chuong":"@c1332","importance":"normal","mucCt":"ky","tieuDe":"Dùng Thiên Hoàng Lô luyện hóa Tư Mặc Tử, thi triển Mộng Đạo","text":"Xoay tinh điểm Cổ Thần triệu xuất Thiên Hoàng Lô — pháp khí vương tộc Cổ Thần, bao vây Tư Mặc Tử vào bên trong lò. Phun ba ngụm máu tươi dùng ba chữ Định khống chế Tư Mặc Tử, ngồi lên đỉnh lò dùng lôi hỏa giao hòa luyện hóa cao thủ bước thứ ba, chấn động tu sĩ bốn phía. Khi 29 Thất Thải Thần Không Đinh đâm xuyên vách lò, rút Ma Hồn Bình phun máu Cổ Thần triệu ba vạn Cổ Ma trợ giúp luyện hóa. Cuối cùng hít sâu thở ra một hơi vô hình rơi lên Thiên Hoàng Lô, thi triển đệ nhất đạo thuật cả đời — Mộng Đạo, thuật thứ tư sau Tàn Dạ và Lưu Nguyệt, sáng chế bên trong Đạo Cảnh ở Thiên Nghịch.","anchor":"Cả đơif Vương Lâm nghĩ ra ba thuật, Tàn Dạ, Lưu nguyệt. sau này, ở trong Thiên nghịch, bên trong Đạo Cảnh, lại sáng chế đệ nhất đạo thuật cả đời, Mộng Đạo!"},{"importance":"normal","mucCt":"ky","chuong":"@c1333","tieuDe":"Sáng chế Mộng Đạo thuật, gieo tâm ma Tư Mặc Tử","text":"Hồi tưởng ba thức thần thông tự sáng tạo trong hai ngàn năm tu đạo: Tàn Dạ, Nguyệt Lưu và Mộng Đạo. Nhớ lại quá trình bước vào Đạo Cảnh sau trận chiến với Thủy Đạo Tử, trong mười năm ở Đạo Cảnh đã dung hợp Mộng Về Viễn Cổ và Tán Đạo để sáng chế Mộng Đạo thuật. Thi triển Mộng Đạo, thổi đạo tức vào Thiên Hoàng Lô gieo tâm ma vào Tư Mặc Tử, tạo đoạn ký ức hư ảo vĩnh hằng không thể loại bỏ, khiến Tư Mặc Tử quên mất thú cốt trên tay và chưởng ấn, đạo tâm dao động mạnh.","anchor":"Miệng Vương Lâm thổi một hơi - đó lại đạo tức của Vương Lâm, rơi vào trong Thiên Hoàng Lô, nhanh chóng dung nhập thẩm thấu vào bên trong"},{"chuong":"@c1334","importance":"normal","mucCt":"ky","tieuDe":"Thả Tư Mặc Tử, liên hệ Uyển Nhi","text":"Ngồi trên đỉnh Thiên Hoàng Lô, xem trọn ký ức bi thương của Tư Mặc Tử từ thảm kịch thôn trang đến con đường phục thù và bị Chưởng Tôn dụ dỗ. Nhận định tiếp tục luyện hóa sẽ không thành công vì Tư Mặc Tử còn nhiều thủ đoạn chưa dùng. Chủ động phá tan Thiên Hoàng Lô thả Tư Mặc Tử, chỉ lưu lại một số suy nghĩ cho đối phương. Đối thoại với Tư Mặc Tử, tự hỏi nếu bản thân ở vị trí Tư Mã Mặc và muội muội là Uyển Nhi thì sẽ lựa chọn ra sao, không dám nghĩ đáp án hoặc đã có đáp án từ Tư Mặc Tử.","anchor":"nếu như ngày đó ta là Tư Mã Mặc, muội muội kia là uyển Nhi thì ta. sẽ lựa chọn ra sao"},{"chuong":"@c1335","importance":"major","mucCt":"ky","tieuDe":"Chia tay Lão Chu Tước, nhận Cổ Hồn Cấm và nhiệm vụ mới","text":"Uy danh quật khởi sau trận chiến, được mấy vạn tu sĩ công nhận có thể giao chiến cao thủ bước thứ ba. Ngồi bên hồ cùng Lão Chu Tước, nhận định đạo thuật Lưu Kim Bưu cao minh đã lừa được lão tổ Hỏa Tước tộc. Bấm quyết tạo Truyền Tống trận quanh thân thể, chuẩn bị xâm nhập thánh địa Hỏa Tước tộc khi Lưu Kim Bưu được đưa vào. Nhờ Lão Chu Tước chiếu cố thuộc hạ Chung Đại Hồng ở vùng đất Điên Lạc. Nhận mai rùa chứa Cổ Hồn Cấm do lão tổ đời đầu Chu Tước tộc để lại để phòng thân tự nghiên cứu. Nhận nhiệm vụ tuyển chọn Chu Tước đời thứ bảy, yêu cầu phải bảo tồn nguyên dương hoàn hảo. Được Lão Chu Tước hứa truyền một trong ba thuật mạnh nhất Chu Tước tộc — thần thông bảo mệnh do Viễn Cổ tiên tôn truyền lại, uy lực lớn nhưng thiêu đốt tuổi thọ.","anchor":"Thuật này uy lực rất lớn, sẽ thiêu đốt tuổi thọ, không thể tùy tiện sử dụng, là một thuật bảo mệnh!"},{"importance":"normal","mucCt":"ky","chuong":"@c1336","tieuDe":"Nhận truyền thừa Phần Giới Cổ Tán, lập chí vượt giới hạn","text":"Chứng kiến Lão Chu Tước biểu diễn Phần Giới Cổ Tán, da đầu tê dại trước uy lực hủy diệt cấp giới. Nhận ra cửa ải đánh gần hai trăm vạn ấn quyết trong chín nhịp thở tuy khó nhưng không tuyệt đối với hắn nhờ kinh nghiệm đại sư cấm chế từ thời Kết Đan. Chấn động khi biết thuật do Viễn Cổ Tiên Hoàng học trộm mà không hoàn chỉnh đã đủ diệt thế, suy tư về giới hạn tu vi và bầu trời bên ngoài. Kích phát bất cam trong tính cách, hạ quyết tâm: hôm nay học thuật của người, ngày sau sẽ khiến người phải học thuật của Vương Lâm. Nhận ngọc giản từ Lão Chu Tước, dung nhập tâm thần khắc sâu toàn bộ ấn quyết vào tâm trí rồi hủy ngọc giản thành tro bụi.","anchor":"Hôm nay ta sẽ học Phần Giới thần thông do người khác sáng chế được Tiên Hoàng học trộm để lại, ngày khác. ta sẽ phải khiến cho người kia học thuật của Vương Lâm ta"},{"chuong":"@c1337","importance":"normal","mucCt":"ky","tieuDe":"Ý tưởng điên cuồng tấn công tam đại nghiệt tước","text":"Trên Đại đế tinh, Vương Lâm đang ngồi trong Truyền tống trận, tâm thần dung nhập Hô Phong Hoán Vũ giới tìm hồn phách Thiên Vận Tử. Đột nhiên mở mắt, hồi tưởng thông tin từ Chu Tước đời đầu tiên về tam đại nghiệt tước đang bế quan trị thương trong thánh địa Hỏa Tước tộc. Suy luận chín phần chính xác rằng tam đại nghiệt tước còn có thân phận khác trong Thái Cổ Tinh Thần, đã âm thầm thao túng mọi thứ suốt vài ngàn năm: con gái hắn dụ dỗ Thanh Lâm, hủy diệt hương hỏa Tứ Đại Tiên giới, bức bách chủ nhân Phong Giới suýt tử vong, dụ dỗ Tư Mã Mặc, nghi ngờ liên quan việc Thanh Thủy điên khùng. Nảy ra ý tưởng điên cuồng — tấn công đối phương lúc đang trị thương. Kích hoạt trận pháp biến mất khỏi Đại đế tinh.","anchor":"trong mắt Vương Lâm lộ ra vẻ điên cuồng. Việc mà hắn muốn làm vốn là một việc điên cuồng"},{"chuong":"@c1338","importance":"normal","mucCt":"ky","tieuDe":"Đột nhập thánh địa, lừa Chưởng Tôn bằng Cổ Ma Hồn, triệu nguyên linh Chu Tước","text":"Xé cơn lốc kiếm xâm nhập thánh địa Hỏa Tước tộc, đối mặt trực diện Chưởng Tôn đang trọng thương. Cứu Hứa Lập Quốc và Lưu Kim Bưu bằng lôi đình kết hợp lửa chín màu, đưa cả hai vào không gian trữ vật. Tổng lực tấn công Chưởng Tôn bằng toàn bộ thần thông: lửa chín màu, chín con Thái Cổ Lôi Long, Vạn Cổ Mộc Linh, huyết kiếm. Bị Chưởng Tôn dùng đại thần thông Mò Trăng Đáy Giếng mò hồn, nhưng thứ bị mò là Cổ Ma Hồn đã xóa thần trí thế chỗ hồn phách bản thân từ trước — chỉ Cổ Thần mới làm được vì Cổ Thần và Cổ Ma đồng nguyên. Tổn thương khi Cổ Ma Hồn bị hủy nhưng vẫn đứng vững. Rút lông Chu Tước hóa biển lửa bao trùm bầu trời, tự xưng Chu Tước đời thứ sáu, đọc khẩu quyết Trạch Lưu Tước Vũ triệu nguyên linh Chu Tước tộc từ Thái Cổ Giới giáng lâm. Trước khi tới đã dung hợp hồn Thiên Vân Tử, triển khai kế hoạch điên cuồng, chuẩn bị đường lui chu toàn.","anchor":"Lấy Cổ ma Hồn thay cho hồn của bản thân, cũng chỉ có Vương Lâm là Cổ Thần mới có thể làm được"},{"importance":"normal","mucCt":"ky","chuong":"@c1339","tieuDe":"Thi triển Phần Giới Cổ Tán diệt thế","text":"Dùng chiếc lông chí bảo Chu Tước đời thứ nhất triệu hồi nguyên linh Chu Tước chân chính từ quê hương Chu Tước đời đầu, con Chu Tước khổng lồ chiếm hơn nửa bầu trời giáng xuống tấn công Chưởng Tôn. Quyết tâm không rút về giới nội, chọn ở lại giới ngoại để giết Chưởng Tôn dù lực xung kích diệt thế có thể hủy diệt bản thân. Nhận ra lão tổ đời thứ hai đã truyền thuật Phần Giới Cổ Tán chính là để trợ giúp giờ phút này. Trong chín nhịp thở đánh ra gần hai trăm vạn ấn ký hình thành Phần Giới Cổ Tán — thuật mạnh nhất Chu Tước tộc. Bị sức tấn công nhập thể, miệng tràn máu, sức sống bị Cổ Tán hấp thụ. Phóng vạn cổ mộc linh cản đường Chưởng Tôn nhưng bị chưởng ấn xuyên thấu. Gầm lên Mở ô diệt thế vung tay thi triển.","anchor":"Hắn muốn ở tại giới ngoại này, sau khi hủy diệt Thiểm Lôi tộc, làm một việc kinh thiên động địa khiến cho cả Thái Cổ chấn kinh"},{"chuong":"@c1340","importance":"major","mucCt":"ky","tieuDe":"Cổ Tán tự hủy — Cổ Thần bảo mệnh đánh bại Chưởng Tôn","text":"Nhỏ máu kích hoạt Phần Giới Cổ Tán, hỏa khí vô hình phá vỡ chưởng ấn Chưởng Tôn nhưng tu vi chưa đủ chỉ mở được hai phần. Quát \"Bạo\" cho Cổ Tán nổ tung, sức mạnh hủy diệt phá sập toàn bộ thánh địa Hỏa Tước tộc. Xuyên qua cửa vỡ thoát ra ngoài, liên tiếp dùng Hô Phong Hoán Vũ giới, Quang Ảnh thuẫn, Thiên Hoàng Lô, Cổ Thần hộ tí chống đỡ chưởng ấn truy kích, đều lần lượt bị phá, bị đánh xuyên qua tu chân tinh sụp đổ rơi vào tinh không Thái Cổ Tinh Thần. Kích hoạt Thuật bảo mệnh bát tinh Cổ Thần — cổ chi tí hữu, triệu hoán Cổ Thần hư ảo khổng lồ ôm mình bảo vệ, Cổ Thần tung quyền đánh Chưởng Tôn hoàn toàn trọng thương. Vung huyết kiếm tấn công bất thành, cầm kiếm bỏ chạy chuẩn bị Súc Địa thành thốn thì nghe Chưởng Tôn hứa hồi sinh vợ con, toàn thân như sét đánh dừng bước, đối mặt lựa chọn bước ngoặt giữa tự do và quy phục.","anchor":"Nếu ngươi trở thành người của lão phu, chỉ cần ngươi đồng ý, ta sẽ có thể làm cho vợ con ngưoi sống lại"},{"chuong":"@c1341","importance":"major","mucCt":"ky","tieuDe":"Từ chối Chưởng Tôn — chọn Ân hơn Tình","text":"Chưởng Tôn dụ dỗ bằng lời hứa cầu sư tôn hồi sinh Lý Mộ Uyển và Vương Bình qua Trường sinh ấn, ban ngoại hiệu Lâm Thương Tử, địa vị vượt Tư Mặc Tử, Thanh Thủy, Thanh Lâm. Vương Lâm rơi vào đấu tranh nội tâm kịch liệt nhất đời, hồi tưởng ân nghĩa Tư Đồ Nam, Thanh Thủy, Chu Dật, lão Thánh Hoàng, Chu Tước đời hai, lão tổ Luyện Hồn Tông. Nhớ ký ức Tư Mặc Tử — kẻ vì muội muội mà từ bỏ tất cả trở thành nô bộc — làm tấm gương cảnh tỉnh. Kiên định từ chối, tuyên bố đời không chỉ có tình mà còn có ân, khẳng định sẽ tự mình tái sinh thê tử. Xoay người hóa cầu vồng bay vào tinh không, hai hàng nước mắt rơi, thốt lời xin Uyển Nhi và Bình Nhi đừng trách.","anchor":"Thê tử của Vương Lâm ta, ta muốn tự mình tái sinh!"},{"chuong":"@c1342","importance":"normal","mucCt":"ky","tieuDe":"Trọng thương thổ nạp, nghi ngờ Chưởng Tôn, bị bàn tay bắt","text":"Vương Lâm rời Hỏa Tước tộc trong trạng thái trọng thương nặng, trái tim như nứt ra, tới tu chân tinh bỏ hoang ngồi bên bờ sông thổ nạp. Hắn thì thào nhớ Uyển Nhi và Bình Nhi, hứa cứu sống vợ rồi cả nhà ẩn cư sơn thôn, dạy Bình Nhi khắc tượng gỗ kế thừa kỹ thuật phụ thân. Hắn nhớ tới ngọc giản mà nữ tử thần bí đưa ở cái khe tầng chín Vân Hải Tinh vực — mở ở giới ngoại có thể tránh Phong Giới Đại Trận mà về, nhưng chưa dám mở vì trọng thương và chưa rõ bạn thù. Sau khi bình tĩnh, hắn phân tích nghi ngờ danh tính Chưởng Tôn: nam tử trung niên thi triển Mò Trăng Đáy Giếng, Tứ Đại Giai Không, biết Ti Mặc Tử, là tam đại nghiệt tước — nhưng Thanh Lâm từng nói Chưởng Tôn tu bổn nguyên Thái Sơ Lực mà người này không hề xuất thần thông liên quan, khí chất cũng không giống kiêu hùng vạn năm. Ba ngày thổ nạp, nhờ thân lục tinh Cổ Thần hồi phục năm phần, nhận ra Điên Lạc bên ngoài đã bị phong ấn. Đột nhiên dự cảm nguy hiểm, hắn thi triển Súc Địa Thành Thốn nhưng bầu trời nứt ra, một bàn tay to vươn từ khe nứt chộp lấy hắn.","anchor":"Ở bên trong cái khe còn có một bàn tay to, mạnh mẽ vươn ra, chộp lấy Vương Lâm đang sắp sửa dung nhập vào trong trời đất"},{"chuong":"@c1343","importance":"normal","mucCt":"ky","tieuDe":"Bị Phụng Thiên lang tộc truy sát, dùng móng tay phản kích","text":"Đang dung nhập thiên địa bằng Súc Địa Thành Thốn thì bị tiếng sói tru bức ra, tu sĩ Không Niết sơ kỳ Phụng Thiên lang tộc phục kích. Rút móng tay đen của Đại Hoang thượng nhân phản kích, xuyên thấu cánh tay đối thủ khiến tan thành bụi nhưng bản thân cũng phun máu vì phản lực. Dùng Cổ Tức Diệp phong ấn khe nứt rồi triệu hồi lại bằng Lạc Diệp Quy Căn. Tính kế lợi dụng cuộc truy sát của Chưởng Tôn để dẫn dụ cao thủ ra cắn nuốt khôi phục tu vi. Phát hiện nữ tử trên vai đại hán mang ấn ký Phong Diệt tộc, là thị nữ Diệu Âm đạo tôn, tay cầm la bàn định vị chính xác vị trí hắn. Dùng Cổ Tức Diệp phong ấn hố đen ngăn đại hán xuyên không truy đuổi, tiếp tục chạy trốn qua Thái Cổ tinh thần.","anchor":"ta sẽ có thể lợi dụng cắn nuốt, khôi phục tu vi"},{"mucCt":"ky","text":"Tính toán trước lộ tuyến truy đuổi của đại hán Phụng Thiên Lang tộc, lưu lại phục kích sau khi thôn phệ khôi phục nguyên thần. Cách không vỗ một cái khiến sáu tu chân tinh đồng thời nổ tung, hình thành cơn lốc nuốt trọn đại hán. Triệu mai rùa Cổ Hồn cấm hóa cự quy khổng lồ chống đỡ Thanh Lang vạn trượng lao ra từ cơn lốc. Nhận ra ấn ký Phong Diệt tộc trên mi tâm thiếu nữ ngồi trên vai đại hán, đánh giá mối uy hiếp của nàng ngang đại hán bước ba Không Niết. Dùng hư hỏa làm mồi nhử buộc đại hán toàn lực áp chế, huyết kiếm giấu sẵn trong tu chân tinh bất ngờ lao ra xuyên thẳng mi tâm thiếu nữ rồi bay về. Toàn bộ bố cục phục kích nhắm vào thiếu nữ chứ không phải đại hán. Dùng Súc địa thành thốn bỏ chạy hướng Đông Bắc — hướng cổ mộ.","anchor":"Hắn đã sớm tính rằng đối phương sẽ đuổi theo, sau khi thôn phệ để khôi phục nguyên thần thì lại lưu lại nơi này phục kích","bridge":true,"khoang":"@c1344"},{"importance":"normal","mucCt":"ky","chuong":"@c1345","tieuDe":"Phân thần thức vào Thiên Vận Tử, đụng độ đại hán Phụng Thiên Lang tộc","text":"Trước khi bỏ chạy, Vương Lâm đã phân thần thức dung nhập vào Thiên Vận Tử, mơ hồ tính ra hướng chạy hiện tại có ích lợi vô cùng. Hắn phóng về phía trước trong tinh không thì bất ngờ đại hán Phụng Thiên Lang tộc xé không bước ra, tấn công bằng Bát phương cực lang đạo — tám hư ảnh sói khổng lồ lao tới. Vương Lâm hóa lưu tinh vọt đi né tránh, cơn lốc sương mù cổ mộ ập tới đánh tan tám con sói rồi cuốn tới đại hán.","anchor":"hắn trước khi bỏ chạy đã phân thần thức ra dung nhập vào Thiên Vận Tử, mơ hồ tính ra là nên chạy theo hướng này"},{"chuong":"@c1346","importance":"major","mucCt":"ky","tieuDe":"Phát hiện bị thao túng, tiến vào cổ mộ","text":"Chứng kiến thiếu nữ Phong Diệt tộc chết lần hai rồi tái sinh, nhận ra chủng tộc này có ba mạng. Sương mù nhập thể hắn hóa sức mạnh Cổ Thần bị tinh điểm mi tâm hấp thụ, chứa tử khí và oán khí gây bạo ngược, sau khi xua tan lại cảm thấy sáng tỏ chưa từng có. Nhận ra ký hiệu con số trên mi tâm người khác là chữ cổ văn liên quan lời Tham Lang về phương hướng rời cổ mộ. Quyết đoán tiến vào vùng đất cổ mộ với tâm niệm tìm phú quý từ hung hiểm, tự tin thân Cổ Thần có lợi thế. Trong lúc tiến sâu bỗng hoài nghi kế hoạch đối phó Chưởng Tôn (nảy sinh sau khi nói chuyện nhất đại Chu Tước, dung nhập hồn phách Thiên Vận Tử) không hoàn toàn do ý chí mình — cảm giác bị sức mạnh hư vô thao túng từ khi tới Thái Cổ Tinh Thần. Khi vào sương mù, luồng sức mạnh bí ẩn trên người bị ngăn trở khiến nghi ngờ dâng lên mãnh liệt. Trấn định lại rồi tiếp tục, tới khe vào cổ mộ gặp văn sĩ trung niên bí ẩn xin giúp nhưng không đáp, bước thẳng vào khe. Thân ảnh hắn trong giếng cung điện bí mật tiêu tan — cho thấy đang bị kẻ hắc bào dùng thuật Tĩnh trung lao nguyệt khống chế, cổ mộ mở ra đã phá vỡ kế hoạch kẻ đó.","anchor":"Vương Lâm có một cảm giác như có một sức mạnh ở trong hư vô thao túng bản thân mình"},{"chuong":"@c1347","importance":"normal","mucCt":"ky","tieuDe":"Nhận ra bị thao túng tâm trí, vào khe cổ mộ","text":"Thần trí tỉnh táo, nhận ra trong Thái Cổ Tinh Thần có sức mạnh mờ ám yên lặng thao túng suy nghĩ ở chỗ rất nhỏ trong cơ thể mình, vô cùng hãi hùng. Phớt lờ lời nhờ giúp đỡ của văn sĩ trung niên (tam tỷ), hóa cầu vồng tiến vào khe cổ mộ. Bị truyền tống tới không gian lạ, lập tức thi triển Quang Ảnh thuẫn, phản kích nam tử đạo bào đánh lén bằng khúc xạ khiến hắn bị thương. Quan sát nội cảnh: bầu trời u ám, đài cao đầu lâu trôi nổi, mấy trăm tu sĩ rải rác.","anchor":"Càng nhớ lại những hành động của mình bên trong Thái Cổ Tinh Thần, Vương Lâm lại càng cảm thấy không phải là chính mình, mà có một sức mạnh mờ ám tiến vào bên trong cơ thể mình"},{"importance":"normal","mucCt":"ky","chuong":"@c1348","tieuDe":"Giết tu sĩ đánh lén, gặp nữ tử áo trắng gây kinh biến cổ mộ","text":"Vương Lâm bước vào vùng đất cổ mộ không hề mê man vì tự đi đến chứ không bị cuốn vào. Bị nam tử trung niên tu vi thiên nhân đệ tam suy đánh lén nhưng thần thông phản xạ ngược trúng kẻ tấn công. Thi triển Dịch Thiên Ấn một chiêu nghiền nát tu sĩ trung niên, lập uy trước mấy trăm tu sĩ. Quan sát đài cao trôi nổi có đầu lâu Cổ Thần, ấn ký mi tâm đã bị lấy đi. Gặp nữ tử áo trắng hình dáng cực kỳ giống văn sĩ trung niên bên ngoài khe, ánh mắt hai người chạm nhau gây kinh biến toàn cổ mộ. Khi sương mù tấn công và lực phòng hộ đài cao tiêu tan, nhanh trí bước lên đài cao tránh nạn, phóng khí ngăn người khác bước vào. Đối mặt hơn mười tu sĩ mắt đỏ lao tới liều chết tranh đoạt đài cao.","anchor":"Trong mắt hắn tràn ngập hàn quang, nhìn về phía nam tử trung niên đang vội vàng lui về phía sau kia"},{"mucCt":"ky","text":"Hơn mười tu sĩ xông vào đài cao của Vương Lâm, hắn dùng chưởng ấn hóa lốc xoáy đánh lui quá nửa. Liên tục giết ba người bằng chỉ lực xuyên mi tâm, chưởng đánh hậu tâm, gầm nhẹ hóa cuồng phong. Tiếp tục tung ba chỉ kiếm khí giết thêm ba người nữa, hút sương máu tử thi vào cơ thể. Quát một tiếng “Cút” tha ba người sống sót, áo trắng không dính một vết máu. Quan sát thiếu nữ Phong Diệt tộc dùng hào quang mi tâm bảo vệ đài cao vững chắc. Chú ý năm cao thủ đáng gờm: nữ tử áo trắng giết người bằng hắc khí, kiếm khách bầu rượu kiếm pháp hoa mai, nam tử áo tím triệu hồi cá dữ ngàn trượng, nam tử gầy áo đen tốc độ siêu phàm kéo nguyên thần — người cuối cùng có tốc độ mà kể cả Vương Lâm cũng không nhìn rõ.","anchor":"Vương Lâm mặc áo trắng như tuyết, một vết máu cũng không có","bridge":true,"khoang":"@c1349"},{"chuong":"@c1350","importance":"normal","mucCt":"ky","tieuDe":"Ẩn giấu thực lực, thu quạt Cổ Thần, đài cao chìm vào cổ mộ","text":"Khoanh chân thổ nạp chữa thương, cố tình không lộ thân phận hư hỏa, thần thông và pháp bảo. Thu pháp bảo cây quạt ba trượng từ trước đầu lâu Cổ Thần, nhận xét không phải tuyệt hảo. Hai mươi tám đài cao chìm xuống vạn trượng vào biển sương mù, bị mãnh thú hình người toàn thân mụn mủ đánh lén, vung tay đẩy lùi. Nhận ra mãnh thú giống vật kỳ dị tạo từ đầu lâu Cổ Thần ở vùng đất Yêu Linh. Bị nhiều tu sĩ xung quanh ngầm đánh giá nhưng không ai nhận ra hắn là tu sĩ hư hỏa.","anchor":"Hắn không đổi sắc mặt, thu lại pháp bảo, sau đó đứng lên"},{"chuong":"@c1351","importance":"normal","mucCt":"ky","tieuDe":"Phát hiện cơ chế trị thương, độc chiếm sức sống mãnh thú","text":"Dùng kiếm khí chém giết mãnh thú hình người, phát hiện bạch khí (sức sống) từ mãnh thú chết trước khi tự bạo có thể trị thương nhanh hơn cắn nuốt tu sĩ và tăng tu vi. Chủ động xông vào đàn mãnh thú, giết gần một ngàn con, cứu nhiều tu sĩ bị bao vây tuyệt vọng. Khi còn khoảng ngàn con cuối và hơn hai mươi tu sĩ tranh đoạt, triệu Thiên Hoàng Lô từ tinh điểm Cổ Thần trên mi tâm luyện hóa toàn bộ, độc chiếm sức sống. Phát tu vi cường hãn chấn át hơn hai mươi tu sĩ, không ai dám ra tay. Thiên Hoàng Lô bên trong mi tâm bộc phát sức sống vô biên, thương thế hồi phục cực nhanh. Quyết định đã đến lúc lập uy, ngọn lửa hư ảo trong mắt trái bùng lên bốc cháy.","anchor":"Ngọn lửa hư ảo trong mắt trái bỗng nhiên bùng lên, dần dần bốc cháy"},{"importance":"normal","mucCt":"ky","chuong":"@c1352","tieuDe":"Hư hỏa thiêu mãnh thú, lộ thân phận Tu sĩ hư hỏa","text":"Nhóm 25 người trên đài cao bị đưa vào vùng đất bị phong ấn trong cổ mộ, nơi có Cổ Thần quỳ cõng đài cao vỡ cùng Cổ Yêu và Cổ Ma quỳ bái hai bên. Mấy vạn mãnh thú hình người mắt đỏ tấn công, hai tu sĩ tu vi thấp bị xé xác. Hơn mười đại tu sĩ liên thủ đe dọa không cho Vương Lâm cướp mãnh thú vì lần trước hắn đã nuốt hơn phân nửa. Vương Lâm không lui, tăng tốc như lưu tinh, chỉ vung tay phải khiến hư hỏa sinh bên trong cơ thể mãnh thú thiêu cháy hơn phân nửa mấy vạn con thành biển lửa. Sức sống màu trắng tràn vào khiến thương thế khôi phục hoàn toàn. Hắn xoay người hỏi ai muốn giết, mắt trái bùng lên hư hỏa chín màu. Các tu sĩ kinh hoàng nhận ra hắn là tu sĩ hư hỏa hiếm gặp mấy vạn năm một lần, toàn trường khiếp sợ lui hơn mười trượng.","anchor":"gần một ngàn con mãnh thú trong tiếng ầm ầm đã bị hư hỏa sinh ra trong cơ thể đốt cháy toàn thân"},{"text":"Lần lượt uy hiếp tu sĩ béo, tu sĩ hắc y, nam tử áo tím, buộc dâng pháp bảo đoạt được trong cổ mộ. Giao chiến trực tiếp với bà lão áo lục, va chạm nguyên lực mấy mươi lần giữa không trung. Thi triển Tuế Nguyệt nhất chỉ — trong tâm thần hiện cánh cửa đá thê lương Phong Tiên Giới, dung nhập khí tức tang thương vào đòn đánh, phá tan Phong Huyễn Thuật của bà lão. Phát hiện bà lão là người Phong Huyễn Tộc (tam đại kỳ tộc), tha mạng, biến hư hỏa thành mồi lửa cấm chế trên người bà. Nhận lời nữ tử tóc dài rồi hướng mắt nhìn đài cao phong ấn. Đối mặt với kẻ địch mới — chín đài cao khổng lồ ầm ầm lao tới từ chân trời.","mucCt":"ky","anchor":"Hư hỏa trên thân thể của bà lão áo lục theo ý niệm của Vương Lâm liền nhanh chóng tiêu tan, hóa thành một mồi lửa, trở thành một thứ như cấm chế vậy","bridge":true,"khoang":"@c1353"},{"mucCt":"ky","text":"Vương Lâm lặng lẽ quan sát chín tu sĩ cường giả do Linh Động Thượng Nhân dẫn đầu đứng trên chín đài cao trong chỗ phong ấn. Các tu sĩ xung quanh tự nguyện coi hắn là người cầm đầu. Hắn nhận ra cấm chế trên sương mù đỏ là Cổ Hồn cấm, bên trong còn ẩn chứa cấm chế khác. Hứa Phúc phản bội, bước ra xưng danh với Linh Động Thượng Nhân và toan tố cáo bí mật về Vương Lâm nhưng bị cắt lời. Vương Lâm đánh giá cao tâm cơ thâm trầm của văn sĩ trung niên Tiêu Tĩnh.","anchor":"Người này dù có tu vi thiên nhân đệ tam suy nhưng lại có thể ở nơi này, tâm cơ thâm trầm, bình tĩnh, đa mưu túc trí","bridge":true,"khoang":"@c1354"},{"mucCt":"ky","text":"Quan sát tu sĩ họ Hứa dùng bàn tính phá cấm chế sương đỏ thất bại tử vong, phân tích ra cấm chế trên sương đỏ gồm Cổ Hồn cấm và Tuế Nguyệt cấm kết hợp, uy lực kinh thiên. Nhìn ra văn sĩ trung niên Tiêu Tĩnh giả vờ phá cấm chế nhưng thực chất giấu thủ đoạn. Âm thầm ngưng tụ cấm chế dưới chân trong lúc không ai phát hiện. Khi sương đỏ bùng nổ tạo cơn lốc hủy diệt, rời khỏi cấm chế đã bố trí, lao xuống dưới rồi bay lên trời, rút lui nhanh nhất — nhanh hơn cả Linh Động Thượng Nhân.","anchor":"Vương Lâm lui lại phía sau nhanh nhất, thậm chí so với Linh Động kia còn nhanh hơn một chút","bridge":true,"khoang":"@c1355"},{"mucCt":"ky","text":"Vương Lâm ẩn mình quan sát Tiêu Tĩnh, nhìn thấu kế hoạch kích động cấm chế của đối phương rồi hiện thân hóa thi thể hắn thành tro. Hắn tìm ra đường sống ẩn trong Sinh Tử cấm, rút đường màu đen khỏi sương đỏ để phá cấm và mở thông đạo. Khi bị Linh Động Thượng Nhân nhốt trong bọt khí, Vương Lâm giả vờ đau khổ, bối rối và khuất phục, dẫn dụ đối phương tiến vào thông đạo rồi mới lộ sát khí.","anchor":"Vương Lâm ngẩng mạnh đầu, hai mắt lóe lên sát khí","bridge":true,"khoang":"@c1356"},{"importance":"normal","mucCt":"ky","chuong":"@c1357","tieuDe":"Tấn công liên hoàn nhốt Linh Động Thượng Nhân","text":"Khai chiến với Linh Động Thượng Nhân trong thông đạo sương mù, lần lượt dùng huyết kiếm xuyên tay phải đối phương, lôi đình bổn nguyên phá pho tượng phòng thủ, hư hỏa chín màu đối kháng Sơn Hải Đồ khiến biển bốc hơi. Lần đầu thi triển Lôi hỏa giao hòa — dung hợp lôi đình và hỏa diễm tại mi tâm phá nát ngọn núi từ Sơn Hải Đồ. Kích hoạt hư hỏa bên trong cơ thể Linh Động Thượng Nhân bằng một chỉ khiến đối phương đau đớn cực độ. Dùng Cổ Tức Diệp định phong ấn khe nứt Linh Động Đại Ma Giới nhưng bị Cổ Tức Diệp thứ hai của đối phương triệt tiêu. Triệu Cổ Thần hư ảnh từ cánh tay phải, Cổ Thần lấy lưng che chở rồi một quyền phá nát Thủy Động Ma Thần, đánh văng Linh Động Thượng Nhân trở lại sương mù. Lần thứ hai cảm nhận sự ấm áp từ Cổ Thần. Thu ba ngọc giản của Tiêu Tĩnh ra khỏi sương mù khiến sương đỏ khôi phục, lỗ hổng khép lại nhốt Linh Động Thượng Nhân cùng tứ phẩm đạo linh bên trong. Vung một chỉ Định khống chế Linh Động Thượng Nhân đang cố thoát ra.","anchor":"Tuyệt đối không thể để cho đối phương lao ra! Hắn muốn giết cao thủ vừa mới đạt tới bước thứ ba này."},{"chuong":"@c1358","importance":"normal","mucCt":"ky","tieuDe":"Diệt Linh Động, thu Cổ Tức Diệp, đài cao nâng bậc truyền ký ức bí ẩn","text":"Thi triển Định Thân Thuật vào lúc Linh Động Thượng Nhân trọng thương cực điểm, sương đỏ nuốt đối phương vào bên trong, đánh cấm chế để đạo linh bị phong ấn tấn công, tiếng gào của Linh Động dần tiêu tan. Dùng lôi đình từ mắt phải tạo lưới sét, lửa từ mắt trái tạo biển lửa bao phủ đám sương đỏ, kích hoạt tinh điểm Cổ Thần trên mi tâm triệu Thiên Hoàng Lô ra luyện hóa Linh Động. Tách hai Cổ Tức Diệp đang phong ấn lẫn nhau, dùng thần thức kết hợp sức mạnh Cổ Thần tản mát dấu ấn thần thức của Linh Động, lưu khí tức Cổ Thần của mình lên cả hai rồi thu hồi, đánh giá bảo vật này có lúc sánh được với Định Thân Thuật. Bước lên đài cao bậc hai cao hai ngàn trượng, phát hiện bề mặt chứa 589 ký hiệu chính là dấu ấn con số từ mi tâm tu sĩ tử vong. Thu hơn mười ký hiệu nạp vào đài cao, đến ký hiệu thứ 11 thì đài cao chấn động, hút bụi đất từ thiên địa mở rộng lên ba ngàn trượng, đổi sắc từ đỏ sẫm sang tím, trông như đại lục nhỏ. Một khí tức dạng thần thức từ đài cao tràn ra qua hai chân vào cơ thể, cưỡng chế hóa thành hình ảnh dung hợp với ký ức mà hoàn toàn không thể phản kháng.","anchor":"Những hình ảnh này rất nhanh dung hợp với ký ức của Vương Lâm, hoàn toan không cho hắn bất cứ cơ hội nào phản kháng, trở thành một bộ phận của bản thân hắn"},{"mucCt":"ky","text":"Nhắm mắt trên đài cao, thấy bản đồ cổ mộ khổng lồ phần lớn bị sương đen che phủ, ba phần đã lộ, có con đường mơ hồ xâm nhập sâu vào bên trong. Xác định vị trí hiện tại là Hỏa Đạo Phong Địa, một trong ba phong địa cùng loại trên bản đồ. Phát hiện vùng đất phong ấn xuất hiện vô số khe nứt quỷ dị chỉ nhìn thấy khi đứng trên đài cao, nhận định đài cao là mấu chốt toàn bộ cổ mộ, hiện đạt bậc ba, lên cao hơn sẽ thấy toàn bộ bản đồ. Ngồi bên ngoài Thiên Hoàng Lô dùng cấm chế đánh vào sương mù bên trong, sương mù co rút từ ngàn trượng xuống còn trăm trượng. Dùng ba ngọc giản của văn sĩ trung niên ấn lên sương mù trăm trượng khiến nó đình chỉ, rồi dùng sức mạnh Cổ Thần tạo hai bàn tay hồn phách khổng lồ xé mở sương mù, lộ ra tứ phẩm đạo linh hình kỳ lân. Thu đạo linh vào nơi khác trong Thiên Hoàng Lô, tuyên bố muốn biến Linh Động Thượng Nhân thành Cô Nô bước thứ ba, dùng sáu tinh điểm Cổ Thần trên mi tâm phát động sức mạnh Cổ Thần nhập vào Thiên Hoàng Lô bắt đầu luyện nô tàn khốc.","anchor":"So với một Linh Động đã chết, ta muốn một Cô Nô bước thứ ba hơn","bridge":true,"khoang":"@c1359"},{"chuong":"@c1360","importance":"normal","mucCt":"ky","tieuDe":"Luyện nô Linh Động, Mộng Đạo xâm nhập ký ức","text":"Dùng sức mạnh Cổ Thần kích hoạt Thiên Hoàng Lô theo phương thức Thiên Hoàng Vương Lộ, thập phủ luyện nô, niệm ngôn ngữ Cổ Thần triệu hồi liên tiếp tám Cổ Thần cầm búa chém liên hoàn phá vỡ Ma Thần pho tượng của Linh Động Thượng Nhân. Nắm khoảnh khắc Linh Động mê man, thi triển đạo thuật Mộng Đạo xâm nhập ký ức đối phương. Qua mộng cảnh phát hiện sư phụ dẫn Linh Động vào tộc và lão già áo đen trao tộc ấn đều tự xưng tên Vương Lâm.","anchor":"Đạo thuật… … Mộng đạo!"},{"chuong":"@c1361","importance":"normal","mucCt":"ky","tieuDe":"Thu phục Linh Động và phát hiện bản chất đạo linh","text":"Dùng thuật Mộng Đạo kết hợp Thiên Hoàng Lô xâm nhập ký ức suốt đời Linh Động Thượng Nhân, gieo tên Vương Lâm qua nhiều mốc sinh tử, tuyên bố ban tên Cổ Nô Tử. Tám Cổ Thần dung hợp thành Cổ Thần thứ chín chém lưỡi búa thứ mười khắc ấn ký hình tròn trên mi tâm Linh Động, hoàn thành thu phục sơ bộ nhưng nhận định còn nhiều nhược điểm cần thêm tế luyện và cấm chế. Chuyển cảnh trong Thiên Hoàng Lô tới nơi phong ấn đạo linh giống kỳ lân, kinh ngạc trước tốc độ hồi phục thương thế của nó. Triệu Thông Thiên Môn thi triển Lưu Nguyệt nghịch chuyển thời gian bóc từng lớp màn thần bí trên đạo linh, nhìn thấy bản chất thì biến sắc kinh hãi lùi lại.","anchor":"thuật Mộng Đạo của hắn làm rối loạn tâm thần của Linh Động thành công, để lại dấu ấn của mình"},{"chuong":"@c1362","importance":"major","mucCt":"ky","tieuDe":"Lộ nguồn gốc đạo linh — luyện hóa đan dược tăng hỏa bổn nguyên","text":"Dùng Lưu Nguyệt thuật nghịch chuyển thời gian trên tứ phẩm đạo linh, thời gian nghịch chuyển vượt quá dự tính. Đạo linh tiêu tan lộ bản chất là đan dược to bằng đầu người màu vàng, tiếp tục nghịch chuyển lộ ra tinh không cổ xưa hơn cả giới nội và giới ngoại, bên trong có chín tinh cầu bốc cháy như chín mặt trời thời hỗn mang. Chứng kiến người mặc đạo bào bảy màu đeo nhẫn xanh biếc dung hợp chín mặt trời thành đan dược, nói câu nuôi dưỡng thiên đạo — nhận ra hình tượng trùng với pho tượng lấy từ Tham Lang nhưng pho tượng không có nhẫn. Suy tư bản chất thiên đạo, liên hệ máu thiên đạo Thiên Vận Tử mưu tính, Thanh Long Thánh Hoàng nuốt máu thiên đạo, suy đoán thiên đạo có thể giống pháp bảo hoặc mãnh thú. Ba ngày dùng Thiên Hoàng Lô luyện hóa đạo linh thành đan dược kim quang, không dám nuốt vì sợ nổ tung thân Cổ Thần, hút ngọn lửa từ đan dược khiến hỏa bổn nguyên tăng, lôi đồ trong mắt phải bắt đầu thiêu đốt tạp chất. Nhận ra lộ trình: hư hỏa → đạo hỏa đại thành → lôi hỏa bổn nguyên đại thành. Cuối cùng thả vô số Văn thú từ khe trữ vật để thăm dò những con sông đỏ như máu trên mặt đất.","anchor":"Lấy đạo đan dược nuôi dưỡng thiên đạo, quả thực không phải chuyện dễ"},{"mucCt":"ky","text":"Triệu mười vạn Văn Thú hấp thụ dòng sông máu trên mặt đất, thân thể to gấp đôi, sức chiến đấu tăng mạnh. Kiểm tra ba thi hài Cổ Ma, Cổ Thần đã hoàn toàn tử vong, hy vọng tìm thi thể Cổ Ma chưa chết hẳn để hoàn thành phân thân Cổ Ma. Thu đài cao ngàn trượng Cổ Thần vác trên lưng vào không gian trữ vật, để lại ba thi thể bộ tộc cổ đại. Rời vùng phong ấn xuyên sương mù cổ mộ, dùng bản đồ ba khối hợp lại tìm đường. Gặp hơn 30 tu sĩ đang tử chiến với mãnh thú hình người, dùng mười vạn Văn Thú diệt sạch vạn mãnh thú rồi uy hiếp đoạt đài cao bậc hai từ Chu Công, rút 312 ấn ký dung nhập vào đài bậc ba, tổng hơn 900 ấn ký, gần đột phá bậc bốn. Chứng kiến cánh tay vạn trượng khí tức Cổ Thần từ sương mù chộp mất toàn bộ hơn 30 tu sĩ trong nháy mắt, nhận ra sức mạnh không thể chống cự. Hướng tới vùng phong ấn thứ hai, đã âm thầm cài ấn ký trên cơ thể nữ tử Phong Diệt Tộc, muốn tìm bí ẩn hai lần bất tử của cô ta.","anchor":"có lẽ phân thân Cổ Ma của ta sẽ có thể thành công!","bridge":true,"khoang":"@c1363"},{"mucCt":"ky","text":"Cưỡi đài cao bậc ba tím sẫm mang mấy vạn Văn Thú đến vùng đất phong ấn, phái Văn Thú mang thần thức do thám, phát hiện Diệu Âm Đạo Tôn và Đại Hoang Thượng Nhân giao chiến, tu vi bị cổ mộ áp chế chỉ ở Không Niết Sơ Kỳ. Xông vào vùng phong ấn, dùng hư hỏa thiêu đốt hơn chục tu sĩ cản đường, dùng lôi đồ chín đạo kết hợp lôi hỏa bổn nguyên dung hợp chống đỡ kiếm quang hương hỏa của Diệu Âm, mượn lực xông lên điểm song chỉ lên mi tâm nữ tử Phong Diệt Tộc đặt cấm chế phong kín, thu vào không gian trữ vật. Giả vờ bị trọng thương dụ Diệu Âm đuổi theo, tạo cơ hội cho Đại Hoang tập kích từ phía sau. Phóng huyết kiếm xuyên thấu hư ảnh trăm trượng cùng tam xoa kích, đâm trúng lưng Diệu Âm xuyên qua trước ngực. Tuyên bố muốn toàn bộ hương hỏa của Diệu Âm, chuẩn bị đòn mạnh nhất khi chương kết.","anchor":"Sạch sẽ gọn gang như nước chảy mây trôi, Vương Lâm thu tay trái lại xoay người bay lên, ánh mắt lạnh lùng nhìn bầu trời","bridge":true,"khoang":"@c1364"},{"chuong":"@c1365","importance":"major","mucCt":"ky","tieuDe":"Đòn sát thủ phục kích Diệu Âm","text":"Chờ Diệu Âm và Đại Hoang lưỡng bại câu thương, thu Văn Thú vào tay áo khi biển gào thét bùng nổ. Khi Diệu Âm trọng thương lùi lại chưa đến mười trượng, dùng tinh điểm Cổ Thần trên mi tâm triệu Thiên Hoàng Lô thực chất hóa chắn cuồng phong. Linh Động ẩn sẵn bên trong Thiên Hoàng Lô lao ra cùng tượng Ma Thần, đẩy ba châm Tam Tiên sâu thêm một tấc vào mi tâm Diệu Âm khiến độc tố bộc phát toàn diện, Diệu Âm trọng thương gần chết.","anchor":"Đây chính là đòn sát thủ của Vương Lâm, vì đối phương mà chuẩn bị, là một đòn mạnh nhất cực kỳ bất ngờ."},{"chuong":"@c1366","importance":"normal","mucCt":"ky","tieuDe":"Cướp hương hỏa, bị kéo vào biển sương mù","text":"Bị thương sau đòn đánh Diệu Âm, màng nhĩ ầm vang, nguyên thần đau đớn, phun máu. Gắng gượng mở rộng Thiên Hoàng Lô mấy vạn trượng thu toàn bộ độc hải (hải dương đen chứa độc hồn) trước Đại Hoang Thượng Nhân, tính luyện thành giọt nước có sát thương chấn động bước thứ ba. Tiết lộ cố ý không ấn hết ba cây châm vào mi tâm Diệu Âm, lưu đường sinh để trì hoãn, tạo cơ hội cho Đại Hoang đoạt xá. Khi khe hương hỏa Hải Dân Giới sắp đóng, hiện chân thân Cổ Thần mấy trăm trượng, dùng hai Cổ Tức Diệp giữ khe, hút hương hỏa bằng miệng được một thành rồi dùng Thiên Hoàng Lô hút thêm hai phần, tổng cộng khoảng ba phần. Cuối cùng bị cánh tay khổng lồ mấy vạn trượng từ biển sương mù túm ngực kéo vào, biến mất.","anchor":"Hắn không cam lòng để bàn tay này bắt lấy, lại càng không cam lòng đối với cái khe hương hỏa giới cách hắn không tới trăm trượng"},{"importance":"normal","mucCt":"ky","chuong":"@c1367","tieuDe":"Nâng đài mộ cấp năm, thoát ly Đại Hoang","text":"Bị bàn tay khổng lồ nắm lấy từ ngực trở xuống cùng Đại Hoang Thượng Nhân trong biển sương mù cổ mộ. Nhận ra cánh tay hạ nghiêng chứ không thẳng, suy đoán bàn tay sẽ ném chứ không bắt giữ, ngăn Đại Hoang kích thích bàn tay. Thu nhỏ thân thể trăm trượng về bình thường, lùi ra cách Đại Hoang trăm trượng, thu lấy đài mộ của mình và đài mộ Diệu Âm Đạo Tôn. Khi bị ném, thi triển phương pháp lấy lực chứng đạo của bộ tộc Huyền Vũ dậm mạnh vào bàn tay tạo phản lực, vượt qua Đại Hoang mà thoát ly. Quang Ảnh Thuẫn và cấm chế phòng ngự tan rã tầng tầng rồi ngưng tụ lại. Nửa ngày sau dừng lại, phá hủy đài mộ Diệu Âm Đạo Tôn lấy ký hiệu dung nhập vào đài mộ của mình đạt cấp bốn (bốn ngàn trượng), thêm gần trăm ký hiệu thu từ tu sĩ tử vong nâng đài mộ lên cấp năm (năm ngàn trượng, màu đen hoàn toàn). Bản đồ trong đầu mở thêm hai mảnh (tổng năm mảnh), vén gần nửa tấm màn cổ mộ. Phát hiện vị trí ở cuối tấm bản đồ thứ năm, đã rời hẳn vùng đất cổ mộ bên ngoài, gần khu rừng Cổ Tức Diệp nơi Tham Lang từng lấy pho tượng.","anchor":"Không ngờ đã tới được nơi này."},{"importance":"normal","mucCt":"ky","chuong":"@c1368","tieuDe":"Nhận thông điệp Đạo Cổ Diệp Mịch, khám phá khu rừng đầu lâu","text":"Nhận thông điệp từ thần thức trong đài mộ cấp năm: mở cấp năm thì mở cánh cửa luân hồi, trở thành người thí luyện truyền thừa; không phải tộc Diệp Mịch mà đạt cấp chín thì lấy địa phủ rời đi. Nhớ lại lần đầu nghe tên Đạo Cổ Diệp Mịch từ Chu Tước đời đầu — Diệp Mịch tuy không nằm trong nhóm tiên tôn nhưng tu vi đủ khiến tiên tôn e dè. Cảm ứng được bốn đài mộ cấp năm khác trong cổ mộ, nhận ra họ cũng cảm ứng được mình. Phân tích rằng phải đoạt đài mộ người khác để đạt cấp chín. Điều khiển đài mộ hướng tới khu rừng quỷ dị mà Tham Lang từng phát hiện Cổ Tức Diệp và pho tượng. Trên đường đi giết mãnh thú hình người hấp thu sinh cơ chữa thương. Dùng Cổ Tức Diệp khớp vào vết lõm trên vùng đất vàng vặn vẹo, mở lỗ hổng tiến vào khu rừng khô héo. Bay lên không trung phát hiện toàn bộ khu rừng có hình đầu lâu. Dùng thần thức xâm nhập rễ cây, cảm nhận vật ẩn giấu dưới đất khiến kinh nghi, tung huyết kiếm chém xuống mặt đất.","anchor":"Huyết kiếm xuất hiện, hóa thành một đạo cầu vồng lao thẳng tới mặt đất"},{"mucCt":"ky","text":"Vương Lâm dùng huyết kiếm, lửa chín màu và lôi đồ diệt con mãnh thú giống Vọng Nguyệt (khối cầu thịt bốn xúc tu) ẩn trong hốc mắt đầu lâu khổng lồ dưới rừng. Cày tung nửa cánh rừng, lộ ra đầu lâu Cổ Thần cửu tinh có chín tinh điểm mờ — lần đầu tiên hắn thấy đầu lâu Cửu tinh Cổ Thần. Nhận ra pho tượng bảy màu tồn tại chính để phong ấn đầu lâu này, lòng bi thương vì ngay cả Cổ Thần cửu tinh cũng chết. Chui vào hốc mắt lấy ra một khúc xương lớn cỡ ba bàn tay, suy đoán Cổ Thần này bị giết trong thời Cổ Thần thất tổn thất kiếp. Giả thiết đạo nhân bảy màu chính là viễn cổ tiên hoàng, đã có được thiên đạo trước khi la bàn Thiên Nghịch bị cướp, vì nuôi đạo linh khó nên sắp đặt mọi chuyện. Liên hệ lời Cổ Yêu Tháp Giả về nghịch tu đời thứ nhất, sứ giả thiên đạo Thiểm Lôi tộc gọi hắn là bộ tộc diệt đạo, Thanh Lâm nói thiên đạo đã chết — mê mang về bản chất thiên đạo và ai là bộ tộc diệt đạo đời đầu.","anchor":"Đây là lần đầu tiên hắn thấy đầu lâu của Cửu tinh Cổ Thần","bridge":true,"khoang":"@c1369"},{"mucCt":"ky","text":"Suy luận toàn cục về Đạo Cổ, Tiên Hoàng, cổ mộ, đạo nhân bảy màu, cánh cửa bí ẩn và địa phủ — cuối cùng thừa nhận mọi suy đoán có thể sai. Thiết lập sát trận phòng hộ quanh đầu lâu Cổ Thần bằng cấm chế, lôi đồ, lửa chín màu và huyết kiếm đan xen. Ngồi trên mi tâm đầu lâu, vận chuyển sức mạnh Cổ Thần qua sáu tinh điểm nuôi dưỡng đầu lâu, tập trung toàn lực vào mười chín cái cây khiến rễ khôi phục màu sắc. Triệu Thiên Hoàng Lô luyện hóa biển độc đen (lưỡi Đại Hoàng Thượng Nhân + hồn phách Diệu Âm Đạo Tôn), ba ngày sau mặt biển giảm gần nửa, độc tố cô đặc đến thần thức không xuyên thấu, dự tính sẽ thu được bảo vật mang độc uy lực hung mạnh. Phân nguyên thần vào Thiên Hoàng Lô kiểm tra Linh Động đang luyện hồn phách hương hỏa, truyền đạo thuật Dung qua lạc ấn vào mi tâm Linh Động để hắn nhanh hấp thụ hương hỏa tiến bước thứ ba. Tính toán dùng Linh Động phối hợp đánh kẻ Không Niết Sơ Kỳ, nảy ý luyện thêm một Cổ Nô nữa.","anchor":"Nếu có thể gặp lại được một người đạt tới bước thứ ba Không Niết Sơ Kỳ, có Linh Động phối hợp thì đánh cũng không khó","bridge":true,"khoang":"@c1370"},{"chuong":"@c1371","importance":"normal","mucCt":"ky","tieuDe":"Soát hồn Phong Chỉ Mạn, thu tộc ấn và Cổ Tức Diệp","text":"Lôi thiếu nữ Phong Diệt tộc Phong Chỉ Mạn ra khỏi không gian trữ vật, cho xem ngọc giản cảnh phân thân Diệu Âm bị diệt để phá tan ảo tưởng được cứu. Ép nàng khai bí mật Phong Diệt tộc: tộc nhân không có huyết thống, cướp trẻ con về tế tổ, sống sót được tộc ấn và tam mệnh thuật (ba mạng). Soát hồn Phong Chỉ Mạn đọc toàn bộ ký ức, rút tộc ấn từ mi tâm nàng rồi thu giữ. Nuôi dưỡng mười chín cái cây bằng sức mạnh Cổ Thần, ngộ ra phải dùng hơi thở khí tức Cổ Thần thổi vào mới phân biệt được lá thật, thu được mười tám chiếc Cổ Tức Diệp tỏa hào quang vạn trượng. Biển độc trong Thiên Hoàng Lô tiêu tan hóa thành chín giọt độc dịch cực mạnh. Nhìn Phong Chỉ Mạn liên tưởng đến Diêu Tích Tuyết.","anchor":"duy chỉ có mười tám chiếc lá vẫn còn nguyên ở trên cây, bị khí tức của Vương Lâm thổi vào, giống như là đang hấp thu khí tức, tản mát ra hào quang vạn trượng"},{"mucCt":"ky","text":"Khai chiến với đại hán Phụng Thiên Lang tộc Chu Cẩn, lần lượt triệu hoán lôi đồ, lửa chín màu, huyết kiếm tấn công. Ném Thiên Hoàng Lô gây phản chấn khiến Chu Cẩn phun máu, Linh Động ẩn bên trong xông ra phối hợp. Dùng mười tám Cổ Tức Diệp phong ấn lần lượt sau lưng, trái, phải, trên, dưới chặn hết đường thoát. Triệu Thiên Hoàng Lô phóng to bao phủ thiên địa che khuất mặt trăng đỏ và bao vây sói. Cuối cùng dùng chín giọt nước màu đen khống chế hoàn toàn Chu Cẩn, tuyên bố cử động là chết. Đứng trên đầu lâu Cổ Thần, nửa bước không lùi, thái độ bình tĩnh trào phúng.","anchor":"Ngươi nhìn thấy ta đã vui mừng, nhưng ngươi không biết sau khi nhìn thấy ngươi, ta còn sung sướng hơn","bridge":true,"khoang":"@c1372"},{"importance":"normal","mucCt":"ky","chuong":"@c1373","tieuDe":"Luyện hóa Chu Cẩn, dung hợp tam tộc lực","text":"Dùng chín giọt độc dịch, Cổ Tức Diệp và Linh Động vây khốn Chu Cẩn, ra lệnh thu hắn vào Thiên Hoàng Lô luyện hóa thành Cổ Nô, Linh Động từ hương hỏa giới bước vào độc hải giới hỗ trợ trông coi. Thu Thiên Hoàng Lô vào mi tâm qua tinh điểm Cổ Thần. Phong ấn khu rừng cây khô cùng vòng xoáy Tham Lang bằng nhiều tầng cấm chế, triệu cánh cửa Lưu Nguyệt thêm tuế nguyệt cấm gia cố. Hấp thụ đài cao bậc năm của Chu Cẩn, đài cao tăng lên sáu ngàn trượng, bản đồ trong đầu hiện thêm một tấm, nhận thông điệp Đạo Cổ Diệp Mịch tiết lộ về tam phủ Thiên Địa Nhân và Nhân Hỏa Kiếm. Bay xuyên bản đồ thứ năm vào bản đồ thứ sáu, suy luận ra bản chất dấu ấn con số: chính là thứ cho phép tồn tại trong cổ mộ, Cổ Thần không cần dấu ấn. Lấy Cổ Hồn Bình giết hồn phách Cổ Ma lấy Cổ Ma lực, lấy hồ lô chứa Cổ Yêu lực, dung hợp Cổ Thần lực cùng Cổ Ma lực và Cổ Yêu lực thành sức mạnh tam tộc vượt xa cả ba, dùng xóa thành công dấu ấn con số trên mi tâm thiếu nữ Phong Diệt tộc. Thiếu nữ mất dấu ấn, bị sương mù cổ mộ sôi trào nuốt mất, biến mất trước mặt.","anchor":"ba khí tức trong phút chốc ngưng tụ, lập tức ở trên tay phải Vương Lâm hoàn toàn dung hợp lại với nhau, hình thành một sức mạnh đặc biệt"},{"chuong":"@c1374","importance":"major","mucCt":"ky","tieuDe":"Phá vỡ quy tắc cổ mộ, đài mộ đạt cấp tám đầu tiên","text":"Phát hiện thân là Cổ Thần nên không cần ấn ký để tồn tại trong cổ mộ, nghĩ ra phương pháp dung hợp Cổ Thần lực, Cổ Ma lực và Cổ Yêu lực thành lực lượng kỳ dị đánh vào mi tâm tạo ấn ký rồi lôi ra nhập vào đài mộ. Lặp lại liên tục, chỉ trong một canh giờ ngưng tụ mấy trăm ký hiệu, đài mộ từ cấp sáu thăng lên cấp bảy (bảy ngàn trượng), bản đồ mở ra khu vực thứ tám. Nghe được âm thanh lần thứ ba tiết lộ về địa phủ phong ấn tam tiên tôn bị giết cả đời, vốn muốn luyện thành phân thân, cảnh báo tam hồn cực kỳ cường đại. Tiếp tục ngưng tụ, tiêu hao hết Cổ Ma hồn trong Ma Hồn bình và hủy diệt hết bảo vật Cổ Yêu chiếm được để rút khí tức, đài mộ đạt tám ngàn trượng — đài mộ cấp tám đầu tiên trong toàn bộ vùng đất cổ mộ, biển sương mù chấn động dữ dội. Lý giải ngoại nhân chỉ là sản phẩm của thí luyện, ba tộc cổ mới là người thí luyện thật sự.","anchor":"Đài mộ cấp tám, trong mọi người ở vùng đất cổ mộ, đây là đài mộ cấp tám đầu tiên."},{"chuong":"@c1375","importance":"normal","mucCt":"ky","tieuDe":"Đài mộ cấp tám, tránh truy sát và phản công Phần Giới Cổ Tán","text":"Đài mộ đạt cấp tám (đầu tiên trong cổ mộ), tám ngàn trượng tỏa kim quang, mở bản đồ thứ tám lộ hơn phân nửa cổ mộ. Nghe thanh âm vạn cổ tang thương lần thứ tư tiết lộ bí mật Thiên Phủ trong tam phủ Thiên Địa Nhân. Nhận định pháp khí Cổ Yêu gần cạn, không đủ lên cấp chín. Cảm nhận bốn cao thủ truy sát, tận dụng ưu thế cấp tám (tốc độ ngang bước thứ ba, định vị chính xác, nắm toàn bộ đường đi) tránh né, chạy từ bản đồ thứ sáu vào bản đồ thứ bảy tìm vật Cổ Yêu. Khi Cửu Thiên Ma Tôn và nữ tử áo trắng tiến gần từ hai bên, vung mấy trăm vạn ấn ký thi triển Phần Giới Cổ Tán, phun máu tươi khiến ô mờ hai phần, giải phóng lửa diệt thế bốn phương.","anchor":"Phần Giới Cổ Tán!"},{"mucCt":"ky","text":"Thi triển Phần Giới Cổ Tán tạo biển lửa bức lui Cửu Thiên Ma Tôn và bạch y nữ tử, nương lực tấn công xuyên qua bản đồ thứ bảy tiến vào bản đồ thứ tám. Triệu Thiên Hoàng Lô phòng thân khi cảm ứng nguy cơ, sau đó bay thẳng tới phong ấn Cổ Yêu. Nhảy vào cơn lốc xoáy mấy vạn trượng, triệu Ma Hồn bình đánh nát ma hồn bên trong, thu khí tức Cổ Yêu, dung hợp ba khí tức (Cổ Yêu + Ma hồn + Cổ Thần lực) chế tạo ký hiệu vuốt lên mi tâm nâng cấp đài mộ. Nửa canh giờ tạo mấy ngàn ký hiệu nhưng khoảng cách đài mộ cấp chín còn rất xa. Bị đạo thuật mê hoặc trong tiếng cười của nữ tử áo hồng khiến huyễn hóa ra cảnh tượng Chu Tước và Liễu Mi năm xưa, nhưng nhanh chóng tỉnh táo nhờ đạo tâm kiên định hai ngàn năm tu đạo và hậu quả thống khổ với Liễu Mi, lạnh lùng phóng sâu hơn trăm trượng vào trung tâm cơn lốc tiếp tục chế phù.","anchor":"Dựa vào hai ngàn năm tu đạo khiến đạo tâm kiên định cộng với một loạt hậu quả thống khổ với Liễu Mi mà hắn có thể nén một tia tâm tình không hiểu nổi vừa trào dâng trong lòng xuống","bridge":true,"khoang":"@c1376"},{"chuong":"@c1377","importance":"major","mucCt":"ky","tieuDe":"Dung hợp ba tộc, đài mộ cấp chín rồi bị hủy","text":"Ngồi khoanh chân trong vòng xoáy Cổ Yêu, dung hợp khí tức Cổ Yêu, Cổ Ma hồn từ Ma Hồn Bình và Cổ Thần lực từ tinh điểm mi tâm, tự chế tạo ký hiệu kỳ dị bao phủ toàn thân. Triệu đài mộ tám ngàn trượng hấp thụ toàn bộ ký hiệu, đài mộ tăng trưởng lên chín ngàn trượng đạt cấp chín — đài mộ cấp chín đầu tiên trong cổ mộ. Hai cánh tay khổng lồ từ hai đầu cổ mộ xuất hiện, đồng thời đánh lên đài mộ cấp chín khiến từng tầng tan vỡ hóa đá vụn, đài mộ bị phá hủy hoàn toàn. Hai cánh tay vỗ vào nhau ngay bên ngoài thân Vương Lâm rồi tách ra xé hư vô mở ra khe nứt lớn chứa thế giới kỳ dị. Vương Lâm không hề bị tổn thương nhưng tâm thần chấn động không ngừng.","anchor":"Sắc mặt Vương Lâm tái nhợt, ở dưới bàn tay này hắn không hề bị tổn thương một chút nào"},{"importance":"normal","mucCt":"ky","chuong":"@c1378","tieuDe":"Bước vào Thiên Phủ đại điện","text":"Hai bàn tay khổng lồ phá tan mộ đài cấp chín, mở ra khe thông đến thế giới khác. Vương Lâm không do dự bước vào khe trong khi Cửu Thiên Ma Tôn và Cổ Yêu không dám tiến lên trước uy lực bàn tay. Nhận được tấm bản đồ thứ chín nhưng không còn tác dụng. Nghe di ngôn tang thương của Đạo Cổ Hoa Mịch: Thiên Phủ là nơi phong ấn kẻ địch, cần đủ tu vi và cơ duyên lớn lao. Hoa Mịch kể bị đạo môn bao vây, đạo sĩ Lý Quảng bắn rơi mắt trái chứa ký ức nửa đời và nỗi nhớ quê hương. Vào đại điện Thiên Phủ khổng lồ lộng lẫy nhưng âm u, phát hiện bốn đội ngũ hàng ngàn tu sĩ đã chết đứng thẳng tắp, thất khiếu chảy máu, trên đầu mỗi người có ngọn lửa xanh biếc. Quần áo tu sĩ kỳ dị, chất liệu giống loại từng thấy trên thân người ngoài giới khi lấy lôi đồ bất diệt ở Thiểm Lôi Tộc. Đài đá cao vút trên đỉnh có ghế trống với quầng sáng hình tròn, phía trước ghế có lỗ hổng lớn chứa khí kinh thiên — dấu tích kiếm hoặc tiễn năm xưa. Bay lên cao vung cuồng phong chiếu sáng hơn phân nửa cung điện, nhìn về phía xa thì đồng tử co rụt lại.","anchor":"Ngay khi nhìn về phía xa, đồng tử trong hai mắt Vương Lâm co rụt lại"},{"chuong":"@c1379","importance":"major","mucCt":"ky","tieuDe":"Ngồi lên ghế đài, kích hoạt mười tám tinh điểm Cổ Thần","text":"Dưới lực dẫn dắt lần thứ năm từ mộ đài thăng cấp, Vương Lâm bước lên đài trong đại điện cổ mộ và ngồi lên chiếc ghế khổng lồ. Thân thể lập tức hóa thành Cổ Thần cao mấy trăm trượng. Sáu tinh điểm Cổ Thần trên mi tâm xoay tròn, một luồng yêu khí từ ghế chảy vào mắt trái hình thành sáu tinh điểm hư ảo, một luồng ma khí chảy vào mắt phải cũng thành sáu tinh điểm hư ảo, tổng cộng mười tám tinh điểm quỹ đạo đồng nhất. Uy nghiêm bá đạo tản mát khiến thiên địa run rẩy, vượt xa bước thứ ba, thậm chí Thái Cổ Ngũ Tôn cũng không sánh được. Uy áp bức Linh Động Thượng Nhân quỳ phục, bức Chu Cẩn đạo tâm tan nát cũng phải quỳ xuống khuất phục. Sau khi uy áp đạt cực đại, ánh mắt Vương Lâm xuyên thấu, nghịch chuyển thời gian nhìn thấy ảo cảnh đại chiến cổ xưa — một văn sĩ trung niên cầm ô yên lặng xuyên qua vô số tu sĩ, giơ tay chỉ về người ngồi trên ghế.","anchor":"thân thể Vương Lâm ầm ầm chấn động, lập tức nhanh chóng lớn lên, trong nháy mắt đã trở thành thân thể cổ Thần cao mấy trăm trượng"},{"chuong":"@c1380","importance":"major","mucCt":"ky","tieuDe":"Mượn khí thế Đạo Cổ, đấu ý chí chiếc ghế","text":"Ngồi trên ghế đài cao trong cổ mộ, chứng kiến cảnh tượng hư ảo trận chiến năm xưa, hóa thân thành Đạo cổ Diệp Mịch tuần tự thi triển Thần chấn Binh Tu Liệt Vị, Yêu thuật Phong Hỏa Thành Sơn, Ma đạo Sinh Tử Nghịch Động và Đạo cổ thuật, giết sạch đại quân tấn công. Mắt trái bị mũi tên Lý Quảng trong cảnh tượng hư ảo bắn trúng, chín tinh điểm Cổ Yêu trong mắt trái vỡ tan, mắt chảy máu. Tỉnh lại phát hiện ý chí trong ghế muốn thu hồi khí tức, kiên trì chống cự lực bài xích 17 nhịp thở. Điểm ấn Cổ Nô lên mi tâm Chu Cẩn, sai Linh Động và Chu Cẩn hỗ trợ phong ấn ghế chia sẻ lực phản chấn. Phát hiện cổ mộ có ba tầng, tầng ba có trái tim khổng lồ là nguồn truyền thừa hoàn chỉnh đạo cổ. Phần dưới eo nổ tung, hai chân tan nát, cánh tay phải tan nát. Tinh điểm Cổ Thần thứ bảy hình thành một nửa, mắt trái xuất hiện ma tinh Cổ Ma đầu tiên mơ hồ. Cuối cùng ném thân thể Cổ Thần hóa đá đánh bật Thác Sâm ra khỏi cung điện.","anchor":"Đã vào trong cơ thể ta, thì là của Vương Lâm ta, sao có thể nói đến là đến, nói đi là đi"},{"chuong":"@c1381","importance":"normal","mucCt":"ky","tieuDe":"Thành Vương tộc Thất tinh Cổ Thần, tiếp nhận truyền thừa","text":"Thân thể tan vỡ hoàn toàn dưới lực phản chấn nhịp thở thứ mười tám của chiếc ghế, chỉ còn sáu tinh điểm xoay tròn. Tinh điểm thứ bảy bùng sáng thực chất hóa, Cổ Thần lực bộc phát, bảy tinh điểm xoay ba vòng tái tạo toàn bộ thân thể cao ngàn trượng — thành Vương tộc Thất tinh Cổ Thần. Trước khi tay trái tan nát, triệu hai mươi lá cổ Tức Diệp phong ấn lỗ hổng cung điện, lệnh Linh Động và Chu Cẩn ngăn Thác Sâm. Tiếp nhận cảm ngộ chiêu Huyền Vũ lực đạo do Chu Tước đời thứ hai truyền lại trên Đại Đế Tinh và thần thông truyền thừa từ chiếc ghế. Chiếc ghế hóa đài mộ, thần thức được phóng đại vô số vạn lần, dung hợp ý chí Đạo cổ Diệp Mịch lưu lại trong cổ mộ. Thần thức tràn ra ngoài chấn nhiếp Thác Sâm và nữ tử áo hồng.","anchor":"tinh điểm thứ bảy kia đột nhiên phát ra ánh sáng chói mắt, một luồng Cổ Thần lực như thủy triều điên cuồng từ trong tinh điểm thứ bảy này bộc phát ra"},{"chuong":"@c1382","importance":"major","mucCt":"ky","tieuDe":"Dung hợp ý chí cổ mộ, đối đầu Chưởng Tôn, phát tiếng rống tàn sát","text":"Thần thức dung hợp với ý chí cổ mộ khuếch tán quét qua toàn bộ tu sĩ bên trong cổ mộ, khiến tất cả kinh hoàng. Nhìn ra khe cổ mộ thông ra Thái Cổ Tinh Thần đã bị pháp lực bên ngoài làm đông cứng. Đối diện Chưởng Tôn Thái Cổ Tinh Thần qua khe, nhận ra thần thông Mò trăng dưới giếng của hắn. Dùng ý chí cổ mộ ép khe co lại, định phong ấn mấy vạn năm nhằm cắt đứt ba phần sức mạnh Thái Cổ Tinh Thần. Bị chưởng ấn thái sơ lực của Chưởng Tôn xuyên khe đánh vào thần thức, lảo đảo. Tiếng rống từ thần niệm Đạo Cổ Diệp Mịch tầng thứ ba truyền qua ý chí cổ mộ vào thân thể, phát ra từ miệng hắn, gây hủy diệt hàng loạt: Thác Sâm hơn nửa thân tan nát, phân thân Cửu Thiên Ma Tôn tan vỡ, tứ phi thân thể nổ tung, ba bổn tôn Không Huyền thân xác tan vỡ chỉ còn nguyên thần.","anchor":"thần thức của Vương Lâm dung hợp với ý chí của cổ mộ đảo qua trên người của Đại Hoang Thượng Nhân"},{"chuong":"@c1383","importance":"normal","mucCt":"ky","tieuDe":"Phong ấn cổ mộ, kích hoạt lại truyền thừa vượt thất tinh","text":"Dùng thần thức truyền âm giúp Nữ tử áo trắng thoát khỏi cổ mộ qua khe đang đóng, đáp lại ơn trước. Sau đó dùng ý chí cổ mộ triệt để phong ấn cổ mộ vạn vạn năm, thần thức dung hợp với ý chí cổ mộ khiến lực bài xích trên ghế hoàn toàn tiêu tan. Không ra tay với Thác Sâm đang trọng thương vì muốn đánh với Thác Sâm hoàn chỉnh, giữ tôn nghiêm Cổ Thần. Dùng pho tượng thi thể Cổ Ma cao ngàn trượng để bổ sung ma khí cho Cổ Ma tinh ở mắt phải, nhưng thi thể chỉ có chút khí tức Cổ Ma, chưa đủ hoàn chỉnh. Nhận ra truyền thừa chỉ giúp đạt thất tinh, chưa đủ, dứt khoát cắt đứt dung hợp thần thức với cổ mộ, kích hoạt lại lực bài xích kinh thiên động địa, trái tim tầng ba lại đập, khí tức truyền thừa tràn ra. Với sức mạnh thất tinh trụ vững trên ghế, chủ động hấp thụ khí tức truyền thừa.","anchor":"hắn dứt khoát cắt đứt sự dung hợp giữa thần thức của mình với cổ mộ này"},{"chuong":"@c1384","importance":"major","mucCt":"ky","tieuDe":"Đạt thất tinh Cổ Thần, manh nha bát tinh, trận chiến định mệnh Thác Sâm","text":"Sau hai ngàn năm tu đạo chính thức đạt thất tinh Cổ Thần, sức mạnh thân thể ngang Không Niết Sơ Kỳ bước ba, là tu sĩ đầu tiên từ cổ chí kim dung hợp thân thể Cổ Thần. Ngồi trên ghế truyền thừa điên cuồng hấp thu khí tức, tinh điểm thứ tám manh nha thành vòng xoáy ngưng tụ trên mi tâm. Tay phải đưa ma khí vào thi thể Cổ Ma khiến ma tinh thứ 2-3-4 hiện ra. Giao chiến Thác Sâm: dùng Huyền Vũ Thuật mượn lực phản chấn đối thủ cộng lực phản chấn ghế, đánh ngang bát tinh Thác Sâm, chiếm chút ưu thế. Hô Thần Chấn Binh Tu Liệt Vị vung quyền tạo sóng gợn, rồi Ma Đạo Sinh Tử Nghịch Động dùng ngón tay chạm Diệt Thần Mâu. Mắt trái chảy máu, thị lực mờ dần, ký ức nửa đời — nỗi nhớ Mộ Uyển, cố hương, Chu Tước Tinh — bị xé rách biến mất do khí tức truyền thừa khiếm khuyết. Cuối cùng thần thức bất chấp tuôn vào ghế, xuyên tới trái tim tầng thứ ba.","anchor":"từng tầng thần thức kia trong lúc tan vớ, theo chiếc ghế đi vào tầng thứ ba có trái tim đang đập, tiến thẳng tới trái tim kia"},{"chuong":"@c1385","importance":"normal","mucCt":"ky","tieuDe":"Cắt đứt truyền thừa Đồ Ti, xưng Đạo Cổ","text":"Bạo phát Thần Chấn quyền kết hợp một chỉ ma đạo đối kháng Diệt Thần Mâu của Thác Sâm. Cố ý dẫn lực phản chấn từ Diệt Thần Mâu đẩy thần thức chạm trái tim tầng thứ ba, khởi động truyền thừa thực sự — trái tim đồng bộ nhịp đập, ký ức hỗn độn ồ ạt nhập vào gây đau nhức kinh hoàng. Hư ảnh Đồ Ti phía sau lưng tan vỡ, thay bằng cái đầu khổng lồ lờ mờ, mắt trái trống rỗng có máu đen. Dùng huyết kiếm kết hợp luồng đại lực truyền thừa chẻ đôi Diệt Thần Mâu như chẻ tre, xuyên thấu ngực Thác Sâm. Vòng xoáy tinh điểm thứ tám trên mi tâm hoàn toàn ngưng tụ, tạo cơ sở đột phá bát tinh Cổ Thần tương lai. Thu được khối ma tinh thứ năm và thứ sáu từ thi thể Cổ Ma tan vỡ. Mắt trái lờ mờ hơn phân nửa, ký ức sắp bị xóa — không chấp nhận mất ký ức về cha mẹ, người yêu, cố hương, chủ động đứng lên rời ghế cắt đứt truyền thừa tầng thứ ba. Tuyên bố bản thân từ nay là Đạo Cổ, không còn là Cổ Thần truyền thừa của Đồ Ti. Chủ động rút ký ức truyền thừa Đồ Ti ra khỏi hồn phách.","anchor":"Từ nay về sau, ta không còn là Cổ Thần truyền thừa của Đồ Ti nữa…… mà là …. Đạo Cổ!"},{"chuong":"@c1386","importance":"normal","mucCt":"ky","tieuDe":"Rời cổ mộ — thu Địa Phù — trở về La Thiên","text":"Chủ động hoá truyền thừa Đồ Ti thành hào quang trao cho Thác Sâm, vì truyền thừa không còn tác dụng với hắn. Đã lấy được một phần ký ức Đạo Cổ truyền thừa duy nhất, tuyên bố nếu tu vi đủ sẽ quay lại tiếp tục. Thu Linh Động và Chu Cẩn vào Thiên Hoàng Lô, thu thi thể Cổ Ma vào không gian trữ vật, thu lại Cổ Tức Diệp và huyết kiếm. Xé tấm lưới cấm chế phía bắc cung điện, tạo cuồng phong khiến Vũ Đông Thiện cùng đồng bạn phun máu rồi thu vào không gian trữ vật, sau đó thu Vọng Nguyệt vào khe không gian, nhớ La Trần có ân vẫn ở trong cơ thể Vọng Nguyệt. Dùng ký ức Đạo Cổ mở Địa Phù của Diệp Mịch trong bản đồ thứ chín, thu toà lầu các hoàng kim vào không gian trữ vật trước khi Diệu Âm, Cửu Thiên, Đại Hoang kịp đến. Đánh ấn ký mở tầng cổ mộ thứ hai chứa vô số chiến hồn làm lễ vật cho tu sĩ sống sót, bước vào vòng xoáy rồi thu luôn toàn bộ vùng đất phong ấn Cổ Tức Diệp khiến nó vĩnh viễn biến mất. Xuất hiện tại giới nội ngoài biên giới La Thiên Tinh Vực, đúng chỗ Tham Lang bị cuốn năm xưa, phát khí thế kinh thiên tràn ngập La Thiên, mỉm cười nói về tới nhà rồi.","anchor":"Không ngờ không phải là Thái Cổ Tinh Thần ở giới ngoại, mà đã về tới bên trong La Thiên……, về tới nhà rồi"}],"tuViMoc":[{"chuong":"@c1324","canhGioi":"Hư Hỏa","text":"Hoàn thành thức tỉnh Chu Tước lần thứ tư, nghiệp chướng luân hồi cửu sắc đốt lên hư hỏa, hóa thực hỏa thành hư hỏa bộc phát kinh thiên động địa. Có thể cảm nhận tâm tình và biến chúng thành hư hỏa.","importance":"major"},{"chuong":"@c1362","canhGioi":"Hỏa bổn nguyên tăng (hư hỏa → đạo hỏa đại thành)","text":"Hút ngọn lửa từ đan dược tứ phẩm đạo linh, hỏa bổn nguyên tăng lên, lôi đồ trong mắt phải bắt đầu thiêu đốt tạp chất. Nhận ra lộ trình: sau hư hỏa là đạo hỏa đại thành, lôi hỏa bổn nguyên hoàn toàn đại thành.","importance":"minor"},{"chuong":"@c1362","canhGioi":"Hỏa bổn nguyên — hư hỏa (tiến gần đạo hỏa đại thành)","text":"Hút ngọn lửa từ đan dược tứ phẩm đạo linh khiến hỏa bổn nguyên tăng lên, lôi đồ trong mắt phải bị lửa thiêu đốt tạp chất. Nhận ra sau hư hỏa sẽ là đạo hỏa đại thành, khi đó lôi hỏa bổn nguyên hoàn toàn đại thành.","importance":"minor"},{"chuong":"@c1373","canhGioi":"Đài cao sáu ngàn trượng","text":"Hấp thụ ấn ký đài cao bậc năm của Chu Cẩn, đài cao tăng lên sáu ngàn trượng, bản đồ trong đầu hiện thêm một tấm.","importance":"minor"},{"chuong":"@c1377","canhGioi":"Đài mộ cấp chín (9000 trượng)","text":"Dung hợp ký hiệu ba bộ tộc Cổ Yêu + Cổ Ma + Cổ Thần nạp vào đài mộ, đài mộ từ tám ngàn trượng tăng lên chín ngàn trượng đạt cấp chín. Tuy nhiên đài mộ bị hai cánh tay khổng lồ phá hủy ngay sau đó.","importance":"major"},{"chuong":"@c1379","canhGioi":"Cổ Thần lục tinh (mười tám tinh điểm đồng bộ)","text":"Ngồi lên ghế trên đài trong đại điện cổ mộ, yêu khí và ma khí từ ghế kích hoạt thêm mười hai tinh điểm hư ảo ở hai mắt, cộng với sáu tinh điểm mi tâm tạo thành mười tám tinh điểm quỹ đạo đồng nhất, uy áp vượt xa bước thứ ba.","importance":"major"},{"chuong":"@c1380","canhGioi":"Cổ Thần Thất Tinh (hình thành một nửa)","text":"Tinh điểm Cổ Thần thứ bảy trên mi tâm mơ hồ sắp xuất hiện, hình thành được một nửa. Mắt trái xuất hiện ma tinh Cổ Ma đầu tiên mơ hồ. Chín tinh điểm Cổ Yêu mắt trái vỡ tan do ảnh hưởng cảnh hư ảo.","importance":"minor"},{"chuong":"@c1381","canhGioi":"Vương tộc Thất tinh Cổ Thần","text":"Tinh điểm thứ bảy thực chất hóa hoàn thành, bảy tinh điểm xoay ba vòng tái tạo thân thể cao ngàn trượng. Cổ Thần lực mạnh hơn lục tinh vô số lần, cảm giác một quyền có thể đánh tan một tu chân tinh.","importance":"major"},{"chuong":"@c1384","canhGioi":"Thất tinh Cổ Thần","text":"Sau hai ngàn năm tu đạo, thân thể Cổ Thần đạt thất tinh, có thể đối đầu tu sĩ bước thứ ba Không Niết Sơ Kỳ, thậm chí liều mạng với Không Niết Trung Kỳ. Mi tâm manh nha vòng xoáy tinh điểm thứ tám — mầm bát tinh.","importance":"major"},{"chuong":"@c1385","canhGioi":"Vòng xoáy tinh điểm thứ tám ngưng tụ (cơ sở bát tinh Cổ Thần)","text":"Vòng xoáy sắp hình thành tinh điểm thứ tám trên mi tâm hoàn toàn ngưng tụ trong quá trình truyền thừa tầng thứ ba, tạo cơ sở quan trọng nhất để tương lai đột phá thành bát tinh Cổ Thần.","importance":"minor"}],"nhanMach":[{"ten":"Vân Lạc","tag":"khac","quanHe":"Nữ tử tâm tình nồng đậm nhất","ghiChu":"Tâm tình trên người nàng nồng đậm hơn vô số lần so với người khác, nàng nhận ra ánh mắt cửu sắc trùng với bóng lưng mơ hồ trong khoảnh khắc tử vong"},{"ten":"Lão Tổ Chu Tước Đời Đầu Tiên","tag":"su-mon","quanHe":"Lão tổ đời đầu của Chu Tước tộc, đặt thí luyện Sâm La Viêm cho Vương Lâm","gap":"@c1325"},{"ten":"Đại hán Phụng Thiên lang tộc","tag":"doi-thu","quanHe":"Kẻ truy sát dưới trướng Chưởng Tôn","ghiChu":"Không Niết sơ kỳ, thuộc Phụng Thiên lang tộc, phục kích Vương Lâm tại tu chân tinh hoang phế."},{"ten":"Thiếu nữ Phong Diệt tộc","tag":"doi-thu","quanHe":"Thị nữ Diệu Âm đạo tôn, dùng la bàn định vị Vương Lâm","ghiChu":"Cầm la bàn truy tung, mục đích lấy hết đồ vật trên người Vương Lâm."},{"ten":"Nữ tử áo trắng","tag":"khac","quanHe":"Gặp trong cổ mộ, ánh mắt chạm nhau gây kinh biến toàn cổ mộ","ghiChu":"Hình dáng giống văn sĩ trung niên bên ngoài khe"},{"ten":"Vân Lạc đại ti","tag":"khac","quanHe":"Nữ tử có tâm tình nồng đậm nhất đối với Vương Lâm","ghiChu":"Tâm tình trên người nàng nồng đậm hơn mọi người vô số lần @c1324"},{"ten":"Chung Đại Hồng","tag":"khac","quanHe":"Thuộc hạ","ghiChu":"Nhờ Lão Chu Tước chiếu cố Chung Đại Hồng ở vùng đất Điên Lạc"},{"ten":"Nữ tử Phong Diệt tộc","tag":"doi-thu","quanHe":"Kẻ truy sát (dẫn đường)","ghiChu":"Thị nữ Diệu Âm đạo tôn, dùng la bàn định vị Vương Lâm, mục đích lấy tất cả đồ vật trên người hắn."},{"ten":"Tư Mặc Tử","tag":"doi-thu","quanHe":"Đối thủ trong Thiên Hoàng Lô","ghiChu":"Thâm nhập ký ức, xem trọn quá khứ bi thảm rồi bỏ qua luyện hóa, để lại một số suy nghĩ"},{"ten":"Người hắc bào bên giếng","tag":"doi-thu","quanHe":"Kẻ thao túng","ghiChu":"Dùng thuật Tĩnh trung lao nguyệt thao túng tâm trí Vương Lâm từ khi tới Thái Cổ Tinh Thần, phong ấn thân ảnh trong giếng nước bằng ba ngọn nến"},{"ten":"Linh Động Thượng Nhân","tag":"doi-thu","quanHe":"Đối thủ tranh đoạt đạo linh trong phong ấn trên lưng Cổ Thần","ghiChu":"@c1354"},{"ten":"Tiêu Tĩnh","tag":"khac","quanHe":"Đánh giá cao tâm cơ, cùng có mặt trong phong ấn","ghiChu":"@c1354"},{"ten":"Hứa Phúc","tag":"doi-thu","quanHe":"Trước cùng phe, sau phản bội xưng thần với Linh Động Thượng Nhân, toan tố cáo bí mật về Vương Lâm","ghiChu":"@c1354"},{"ten":"Tiêu Tĩnh","tag":"doi-thu","quanHe":"Đối thủ trong cuộc tranh đoạt cơ duyên tại vùng đất phong ấn.","ghiChu":"Vương Lâm nhìn thấu mưu kế của Tiêu Tĩnh và hóa thi thể hắn thành tro sau khi hắn chết."},{"ten":"Linh Động Thượng Nhân","tag":"khac","quanHe":"Nô bộc bị thu phục","ghiChu":"Dùng Mộng Đạo + Thiên Hoàng Lô gieo ám thị suốt đời, ban tên Cổ Nô Tử, khắc ấn ký thu phục sơ bộ"},{"ten":"Chu Công","tag":"khac","quanHe":"Bị Vương Lâm uy hiếp giao đài cao bậc hai","gap":"@c1363"},{"ten":"Phong Chỉ Mạn","tag":"khac","quanHe":"Tù nhân, bị Vương Lâm thẩm vấn soát hồn rút tộc ấn","ghiChu":"@c1371"},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Đối đầu qua khe cổ mộ","ghiChu":"Chưởng Tôn Thái Cổ Tinh Thần, hai bên cách khe nhìn nhau, Vương Lâm ép khe đóng, Chưởng Tôn vung chưởng thái sơ lực phản kích"},{"ten":"Đạo Cổ Diệp Mịch","tag":"an-nhan","quanHe":"Tiền bối Đạo Cổ, người từng ngồi trên ghế","ghiChu":"Vương Lâm mượn khí thế của Diệp Mịch thi triển đạo cổ thuật trong cảnh tượng hư ảo @c1380"},{"ten":"Lý Quảng","tag":"khac","quanHe":"Tu sĩ áo đen bắn cung trong cảnh tượng hư ảo","ghiChu":"Mũi tên của Lý Quảng bắn mắt trái Diệp Mịch, ảnh hưởng tới mắt trái Vương Lâm @c1380"},{"ten":"La Trần","tag":"an-nhan","quanHe":"Người có ân với Vương Lâm, đang ở trong cơ thể Vọng Nguyệt","ghiChu":"Vương Lâm nhớ ân La Trần, thu Vọng Nguyệt cũng vì muốn cứu La Trần"}],"tuiDo":{"linhThu":[{"ten":"Viêm Long","trangThai":"chua-cam-che","moTa":"Lão Chu Tước tuyên bố trả tự do cho Viêm Long nhưng thực chất truyền âm hứa dạy Vương Lâm phương pháp cấm chế nó","nguon":"@c1324"}]},"diem":[{"text":"Đoạt xá thân Mã Lương sau khi tự nổ thân thể xuyên Vực Ngoại, mở ra giai đoạn tu đạo mới","chuong":"@c0103"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, khai mở huyết mạch cổ tộc","chuong":"@c0176"},{"text":"Thức tỉnh Cổ Thần thất tinh vương tộc, hoàn thành đỉnh cao huyết mạch cổ tộc","chuong":"@c1381"},{"text":"Hoàn thành sáu đạo bổn nguyên đại thành, phá Không Môn thành tựu bước thứ ba Không Linh","chuong":"@c1526"},{"text":"Minh ngộ chân tướng thiên đạo — thiên địa chỉ là động phủ, siêu thoát vận mệnh thiên đạo","chuong":"@c1540"},{"text":"Phá hủy Phong Giới Đại Trận, lập Vô Danh Chuyển Luân trận, một mình trấn giữ giới nội tuyên chiến giới ngoại","chuong":"@c1570"}]},"nguon":["@c1324","@c1325","@c1326","@c1327","@c1328","@c1329","@c1330","@c1331","@c1332","@c1333","@c1334","@c1335","@c1336","@c1337","@c1338","@c1339","@c1340","@c1341","@c1342","@c1343","@c1344","@c1345","@c1346","@c1347","@c1348","@c1349","@c1350","@c1351","@c1352","@c1353","@c1354","@c1355","@c1356","@c1357","@c1358","@c1359","@c1360","@c1361","@c1362","@c1363","@c1364","@c1365","@c1366","@c1367","@c1368","@c1369","@c1370","@c1371","@c1372","@c1373","@c1374","@c1375","@c1376","@c1377","@c1378","@c1379","@c1380","@c1381","@c1382","@c1383","@c1384","@c1385","@c1386"],"gioiTinh":"nam","cn":"王林","tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh vươn lên nhờ ý chí khổ tu và quyết tâm sinh tử; Thâm trầm mưu trí, giỏi bố trí hậu thủ, nhìn thấu cạm bẫy và tính toán trước nước cờ của đối thủ; Quyết đoán tàn nhẫn với kẻ thù, không ngại đại khai sát giới khi cần thiết; Trọng ân oán nhân quả, gánh vác đ","vaiTro":"Nhân vật chính — tu sĩ Cổ Thần thất tinh vương tộc, chúa tể vận mệnh giới nội","blurb":"Vương Lâm là thiếu niên tư chất kém từ Thạch Thôn, nhờ Nghịch Thiên Châu, ý chí khổ tu và vô số lần sinh tử mà bước vào con đường tu tiên nhuốm ma đạo — trải qua diệt tộc, đoạt xá thân Mã Lương, ngộ Thần Thức Cực Cảnh, nhận truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, rồi liên tiếp đột phá qua Anh Biến, Vấn Đỉnh, Âm Hư, Dương Thực, Khuy Niết, Tịnh Niết và Toái Niết, thức tỉnh Cổ Thần thất tinh vương tộc, vượt Nhất Tổn Nhị Kiếp trở thành Cổ Thần chân chính, cảm ngộ sáu đạo bổn nguyên đại thành, đạt bước thứ ba Không Linh trung kỳ. Hắn minh ngộ chân tướng thiên địa chỉ là động phủ "},{"id":"van-lac","name":"Vân Lạc","cn":"云落","aliases":["Vân Lạc đại ti","Vân Lạc"],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Vân Lạc là Đại Tư của Trường Tôn Hội, sở hữu Thuật Thiên Đại Tinh Thần có thể thôi diễn hình ảnh, ký ức và tung tích mục tiêu. Nàng tính ra hình dáng cùng khí tức của Vương Lâm để hỗ trợ Tư Mặc Tử truy sát, đồng hành tới Đại Đế tinh bái kiến đại đế, và tại đó nhiều lần âm thầm thôi diễn bí ẩn liên quan tới hạo kiếp Thái Cổ Tinh Thần nhưng liên tục bị lực lượng bí ẩn cắt đứt phép tính và phản phệ trọng thương. Sau khi bế quan hồi phục, nàng tái xuất với vai trò chỉ huy đại quân giới ngoại tấn công Vương Lâm, bày bẫy liên hoàn nhưng phân thân bị Khai Thiên Phủ chém nát; về sau phân thân của nàng","vaiTro":"Đại Tư của Trường Tôn Hội — chuyên gia thôi diễn tinh thần, chỉ huy quân sự giới ngoại","tinhCach":"Tinh thông thuật toán thôi diễn, suy tính tung tích và bí ẩn với độ chính xác cao; hành sự âm trầm kín kẽ, thường giấu tay bắt ấn quyết ngay giữa đám đông; kiên trì truy xét và chỉ huy quyết đoán dù liên tục bị phản phệ trọng thương; dễ hoảng loạn khiếp sợ khi biến cố vượt ngoài dự liệu hoặc đối diệ","tabs":{"diem":[{"text":"Dùng Thuật Thiên Đại Tinh Thần thôi diễn quả cầu nước hiển hiện hình bóng Vương Lâm, suy tính ra khí tức và tung tích của hắn để hỗ trợ Tư Mặc Tử truy sát","chuong":"@c1281"},{"text":"Bị lực lượng bí ẩn phản phệ khi thôi diễn bí ẩn cây hương trên Đại Đế tinh, tay phải rách nát nôn máu, trong cảnh hư ảo thấy dự tượng hạo kiếp Thái Cổ Tinh Thần","chuong":"@c1322"},{"text":"Chỉ huy đại quân giới ngoại bày bẫy liên hoàn truy sát Vương Lâm, điều khiển toàn quân phân bốn hướng và tiên tri tiên cơ để phục kích Hồng Sam Tử","chuong":"@c1429"},{"text":"Phân thân trên chiến trường bị Khai Thiên Phủ chém nát huyết thuẫn bát giác rồi xuyên thấu, thân thể hóa tan, bổn tôn bị diệt nhưng hồn phách thoát đi","chuong":"@c1433"},{"text":"Nhận ra Vương Lâm chính là bóng hình đáng sợ từng thấy trong thôi diễn, thân thể run rẩy không thể khống chế","chuong":"@c1561"},{"text":"Bóp nát ngọc giản bảo mạng do sư tôn trước khi chết tế luyện để thoát khỏi bánh xe vận mệnh của Vương Lâm","chuong":"@c1566"}],"kinhLich":[{"chuong":"@c1324","importance":"normal","mucCt":"vua","tieuDe":"Khiếp sợ trước hư hỏa Vương Lâm","text":"Nhìn mắt trái Vương Lâm chín màu xoay chuyển, nhớ lại hình ảnh bóng lưng mơ hồ xoay người trong nháy mắt tử vong trước kia. Khiếp sợ run rẩy lùi lại. Vương Lâm phát hiện trên người nàng tâm tình nồng đậm hơn người khác vô số lần.","anchor":"bóng lưng mơ hồ xoay người, ánh mắt nhìn về phía mình"},{"importance":"bridge","mucCt":"vua","chuong":"@c1325","text":"Định cố tính toán nhưng nhớ lại ánh mắt Vương Lâm trước đó liền run lên, không dám tính toán nữa.","anchor":"nghĩ tới hai mắt Vương Lâm vừa rồi, tâm thần liền run lên, không ngờ không dám tính toán nữa"},{"mucCt":"vua","text":"Bấm quyết tính toán nhưng bị cắt ngang lần thứ hai, lần này do lực lượng hỏa diễm từ Thiên phương hương trào ra, tay phải tràn ngập tơ máu. Tái nhợt khi thấy Vương Lâm trong cơn lốc hư hỏa — hình ảnh giống hệt hư ảo nàng từng nhìn thấy trước đó.","anchor":"Sắc mặt Vân Lạc đại ti tái nhợt, tâm thần chấn động","bridge":true,"khoang":"@c1328"},{"chuong":"@c1329","importance":"bridge","mucCt":"gon","text":"Tâm thần chấn động trước dũng khí Vương Lâm khiêu chiến Ti Mặc Tử, hình ảnh Vương Lâm và thân ảnh đáng sợ trong bức họa xen lẫn khiến nàng hoảng hốt.","anchor":"Vương Lâm ở trước mắt cùng với thân ảnh đáng sợ trong bức họa kia đang nhanh chóng thay đổi cho nhau"},{"mucCt":"vua","text":"Sợ hãi lui mấy bước khi thấy Cổ Tức Diệp, nhớ lại bức họa từng thấy: tiền thân Vương Lâm phất tay có 99 chiếc lá tương tự xuất hiện, phong ấn trời đất, dùng tuyệt thế đạo thuật phong ấn hoàn toàn rất nhiều tu sĩ Thái Cổ tinh thần.","anchor":"trong đó có một cảnh tượng chính người ở trước mắt trong lúc phất tay, có chín mươi chín chiếc lá giống như vậy xuất hiện, phong ấn trời đất","bridge":true,"khoang":"@c1331"},{"chuong":"@c1335","importance":"minor","mucCt":"gon","text":"Rời khỏi Đại đế tinh cùng Tư Mặc Tử sau trận chiến.","anchor":"Tư Mặc Tử rời đi.\nVân Lạc đại t"},{"chuong":"@c1343","importance":"bridge","mucCt":"gon","text":"Được nữ tử Phong Diệt tộc nhắc là sau khi trở về liền lập tức bế quan.","anchor":"Còn có Vân Lạc đại ti kia, sau khi trở về liền lập tức bế quan"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người có tiền duyên bí ẩn","ghiChu":"Ánh mắt cửu sắc trùng với bóng lưng mơ hồ trong khoảnh khắc nàng tử vong"},{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"Đồng hành","ghiChu":"Cùng rời Đại đế tinh"}],"tuiDo":{}},"nguon":["@c1324","@c1325","@c1328","@c1329","@c1331","@c1335","@c1343"]},{"id":"tu-mac-tu","name":"Tư Mặc Tử","tabs":{"kinhLich":[{"chuong":"@c1324","importance":"bridge","mucCt":"gon","text":"Nhìn chằm chằm Vương Lâm hóa hư hỏa, trầm mặc không nói.","anchor":"hóa thực hỏa thành hư hỏa, hay, hay lắm"},{"importance":"bridge","mucCt":"gon","chuong":"@c1325","text":"Ngạc nhiên trước thí luyện Sâm La Viêm, trao đổi ánh mắt với Vân Lạc đại ti.","anchor":"Lão tổ đời đầu tiên chẳng lẽ đầu óc không tỉnh táo, không ngờ lại dùng tới Sâm La Viêm thí luyện"},{"importance":"bridge","mucCt":"vua","chuong":"@c1326","tieuDe":"Mong Vương Lâm chết trong thí luyện","text":"Nheo mắt quan sát bên ngoài thí luyện, nhận ra vẻ âm trầm của lão Chu Tước, lạnh lùng mong Vương Lâm chết trong thí luyện để không phải tốn công ra tay.","anchor":"Tiểu tạp chủng này lần này thí luyện có rất nhiều lắt léo, tốt nhất là chết trong thí luyện đi"},{"mucCt":"vua","text":"Lộ vẻ bất thiện khi Vương Lâm ở trong Thiên phương hương quá lâu. Vui mừng khi tưởng Vương Lâm thất bại nhưng lập tức đờ ra khi hắn xuất hiện trở lại. Bị Vương Lâm thách đấu trực diện trước mấy vạn tu sĩ.","anchor":"Nhưng đột nhiên vẻ mặt hắn đờ ra, sắc mặt vui mừng tan biến, chỉ còn lại là vẻ âm trầm vô tận","bridge":true,"khoang":"@c1328"},{"chuong":"@c1329","importance":"normal","mucCt":"ky","tieuDe":"Thi triển Phá Không Cửu Diệt đối đầu Vương Lâm","text":"Khí chất thay đổi hoàn toàn khi nghiêm túc ra tay, trời đất vặn vẹo, vô số hồn phách hư ảo xuất hiện. Tuần tự thi triển đại thần thông Phá Không Cửu Diệt — chín bước chín diệt: thiên, địa, sinh, táng vong, thì quang, hư vô, hồng hoang, luân hồi, phá thiên — hợp nhất thành chưởng cửu bộ diệt thiên. Chưởng Phá Thiên va chạm với song chỉ chín viêm long của Vương Lâm, dư chấn khiến gần một vạn tu sĩ phun máu. Phá Thiên ấn không dập tắt được hư hỏa của Vương Lâm, lộ ra vẻ khiếp sợ, bị Vương Lâm nắm cơ hội phản công.","anchor":"Vẻ bình tĩnh trong mắt hắn lập tức tiêu tan, trong mắt không khỏi lộ ra vẻ khiếp sợ"},{"importance":"normal","mucCt":"ky","chuong":"@c1330","tieuDe":"Thi triển Hương hỏa thần thông, bị công tâm lộ linh hồn gốc","text":"Bị hư hỏa do lão Chu Tước cài qua ba cái tát bùng phát từ bên trong khi tâm tình dao động. Bị Vương Lâm công tâm bằng ngọc bội Phá Thiên Tông, khối thú cốt và hỏi thẳng tên Tư Mã Mặc, phun máu điên cuồng phủ nhận danh tính cũ. Cơ thể lóe ánh sáng bảy màu với tím lấn át. Xé không gian mở hương hỏa giới — giới riêng chứa vô số tu chân tinh có sinh linh cúng bái — triệu vô tận hồn phách hương hỏa. Hồn phách vái một cái dập tắt toàn bộ hư hỏa trên người, rồi sai hồn phách vái Vương Lâm một cái, cuồng phong tím kèm quy tắc bước thứ ba áp bức đối thủ. Tuy nhiên ở mi tâm xuất hiện thân hình nhỏ bé — tàn dư linh hồn gốc Tư Mã Mặc — ngồi khoanh chân thống khổ, nước mắt chảy, kêu yếu ớt cầu cứu.","anchor":"Lão phu không phải là Tư Mã Mặc, lão phu tên là Tư Mặc Tử!"},{"mucCt":"ky","text":"Tuyên bố hồn phách hương hỏa vô tận, liên tục triệu hồn phách từ hương hỏa giới ép Vương Lâm lùi. Bị Cổ Tức Diệp phong ấn hương hỏa giới, kinh hãi vì chưa từng nghe có pháp bảo phong ấn được hương hỏa giới tu sĩ bước thứ ba. Dù hư hỏa tái sinh trong cơ thể gây đau đớn, vẫn tiến lên thi triển Tử Đạo — đạo bổn nguyên màu tím do Chưởng Tôn đại nhân ban thưởng vì lập nhiều công lao năm xưa. Tử Đạo lấy đau đớn làm khởi đầu khiến mọi linh hồn phát điên, nhưng Cổ Ma Hồn không bị ảnh hưởng mà ngược lại nuốt sương tím xông tới.","anchor":"Lão phu năm đó vì Chưởng Tôn đại nhân mà lập nhiều công lao, được Chưởng Tôn đại nhân ban cho đạo bổn nguyên màu tím trong bảy màu","bridge":true,"khoang":"@c1331"},{"mucCt":"ky","text":"Nhận định Vương Lâm chưa đạt bước thứ ba nhưng cường hãn, bị hư hỏa thiêu khi tâm tình khẽ động khiến phun máu lùi lại. Triệu hồi nữ tử lụa trắng từ dải lụa vết máu hoa mai, nữ tử phóng sức mạnh tuế nguyệt bao vây Cổ Ma Hồn. Bị Thiên Hoàng Lô bao vây, phản kháng dữ dội. Dùng 29 Thất Thải Thần Không Đinh đâm xuyên vách lò. Lấy bộ xương thú có chưởng ấn Chưởng Tôn định kích hoạt phá lò, nhưng nữ tử bên cạnh van xin khiến hắn dừng tay.","anchor":"Tiểu tạp chủng này có không ít pháp bảo, nhưng nếu ngươi tưởng có thể vây khốn ta đúng là không biết tự lượng sức mình!","bridge":true,"khoang":"@c1332"},{"importance":"normal","mucCt":"ky","chuong":"@c1333","tieuDe":"Bị Mộng Đạo gieo tâm ma, đạo tâm dao động","text":"Quay đầu nhìn hư ảnh muội muội phía sau (nữ tử tự vẫn mặc áo trắng vấy máu, đã bầu bạn mấy vạn năm), sững sờ run rẩy dữ dội. Quên mất thú cốt trên tay và việc đặt tay lên chưởng ấn, đốm lửa trên mi tâm lóe lên kịch liệt. Bị Mộng Đạo thuật của Vương Lâm gieo tâm ma, chìm vào ký ức hư ảo: trong mộng là thiếu niên phàm nhân tên Tư Mã Mặc, mồ côi cha mẹ, có muội muội tên Tiểu Lan. Mộng trở thành tiên nhân, hẹn sau đại hôn của muội sẽ lên tiên sơn bái sư cầu đạo. Ngày đại hôn, mười một đại hán cưỡi ngựa xông vào thôn trang, lửa thiêu ngập trời.","anchor":"Thân thể hắn run rẩy rất mạnh. Biến cố đột ngột này khiến cho hắn sững sờ ở đó, quên mất cả thú cốt trên tay, quên cả bàn tay đang muốn đặt lên chưởng ấn trên thú cốt"},{"chuong":"@c1334","importance":"major","mucCt":"ky","tieuDe":"Toàn bộ quá khứ bi thương hé lộ","text":"Ký ức bị Vương Lâm nhìn thấy trong quá trình luyện hóa tại Thiên Hoàng Lô. Thời niên thiếu là thiếu niên hái thuốc, có muội muội tên Tiểu Lan. Thôn trang bị mã phỉ thiêu rụi tàn sát, muội muội bị vũ nhục rồi tự vẫn bằng dải lụa trắng treo cổ để giữ trinh tiết. Giữ dải lụa trong ngực, cảm nhận hồn phách muội muội vẫn trong đó. Gia nhập Phá Thiên Tông, vài chục năm sau diệt hơn 1400 mã phỉ báo thù, hành hạ bảy tám kẻ chủ mưu hơn nửa tháng, rút hồn phách bọn chúng luyện hồn. Trăm năm sau đạt Nguyên Anh, được tông chủ Phá Thiên Tông thu làm đệ tử. Dùng thần thông truy tìm thủ phạm chuyển thế đầu thai để truy sát lần nữa. Tại Thất Thải Giới bị Chưởng Tôn dụ dỗ bằng lời hứa giữ muội muội bên cạnh vĩnh hằng và cơ hội phục sinh, ban đầu khẳng khái từ chối nhưng tâm thần bị lay chuyển, cuối cùng quy thuận đổi tên Tư Mặc Tử. Trong Thiên Hoàng Lô mơ hồ rơi lệ, lửa trên mi tâm khuếch tán. Được Vương Lâm phá lô thả ra, hỏi lời nói muội muội vừa rồi là pháp thuật hay thật.","anchor":"Tư Mã Mặc ta mặc dù bị đuổi khỏi Phá Thiên tông nhưng ta là người giới nội, cho dù có chết cũng không trở thành chó săn cho giới ngoại"},{"chuong":"@c1335","importance":"minor","mucCt":"gon","text":"Rời khỏi Đại đế tinh cùng Vân Lạc đại ti sau trận chiến.","anchor":"Tư Mặc Tử rời đi.\nVân Lạc đại t"},{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Ký ức của Tư Mặc Tử trở thành tấm gương cảnh tỉnh cho Vương Lâm: vì muốn muội muội sống lại mà từ bỏ Phá Thiên Tông, sư huynh đệ, linh hồn, trở thành nô bộc Chưởng Tôn, thậm chí rơi nước mắt giơ đao giết cả sư tôn.","anchor":"Tư Mặc Tử hôm nay chính là Vương Lâm sau này"},{"chuong":"@c1343","importance":"bridge","mucCt":"gon","text":"Được nữ tử Phong Diệt tộc nhắc đã giao chiến với Vương Lâm nhưng không báo lại pháp thuật của hắn.","anchor":"Tư Mặc Tử đã giao chiến với người này, sao lại không nói ra"}],"nhanMach":[{"ten":"Tiểu Lan","tag":"khac","quanHe":"Nữ tử lụa trắng trong dải lụa, gọi hắn là Tư Mã, xưng muội","ghiChu":"Van xin hắn đưa muội về nhà"},{"ten":"Tiểu Lan","tag":"ho-hang","quanHe":"Muội muội ruột","ghiChu":"Bị mã phỉ lăng nhục tự vẫn, hồn phách lưu trong dải lụa trắng, là động lực suốt đời Tư Mặc Tử"},{"ten":"Chưởng Tôn","tag":"cap-tren","quanHe":"Chủ nhân / kẻ chiêu mộ","ghiChu":"Dụ Tư Mã Mặc đi theo bằng lời hứa cho muội muội sống lại, ban tên Tư Mặc Tử"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát","ghiChu":"@c1324"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ trong Thiên Hoàng Lô","ghiChu":"Thâm nhập ký ức qua Dục Tiên Dục Tử, cuối cùng bỏ qua luyện hóa"}],"tuViMoc":[{"chuong":"@c1334","canhGioi":"Nguyên Anh","text":"Trăm năm sau khi nhập Phá Thiên Tông, đạt Nguyên Anh, trở thành nhân tài kiệt xuất hàng tiểu bối, được tông chủ thu làm đệ tử.","importance":"major"}],"diem":[{"text":"Nhận huyết chỉ truy bắt Vương Lâm sau khi hấp thu Lục Phẩm đạo linh trong khe nứt hư vô, với tư cách đại năng Đệ Tam Bộ từng đuổi giết Thác Sâm","chuong":"@c1281"},{"text":"Dùng phân thân thi triển Phá Thiên Đạo, lấy bức tranh thiên địa làm tù ngục để giết Vương Lâm nhưng thất lợi","chuong":"@c1291"},{"text":"Bị lão Chu Tước tát bay vạn trượng vì châm chọc thí luyện của thiếu đế thứ ba, để lại thương tích tím đen và hư hỏa cài sẵn trong người","chuong":"@c1316"},{"text":"Thi triển Phá Không Cửu Diệt và Hương hỏa thần thông đối đầu Vương Lâm, bị hư hỏa do lão Chu Tước cài bùng phát khi tâm tình dao động, lộ linh hồn gốc","chuong":"@c1330"},{"text":"Bị Mộng Đạo gieo tâm ma, đạo tâm dao động trước hư ảnh muội muội áo trắng vấy máu — người đã bầu bạn hắn mấy vạn năm","chuong":"@c1333"},{"text":"Toàn bộ quá khứ bi thương hé lộ khi bị luyện hóa tại Thiên Hoàng Lô: từ thiếu niên hái thuốc tới đạt Nguyên Anh rồi nhập Phá Thiên Tông, ký ức trở thành tấm gương cảnh tỉnh cho Vương Lâm","chuong":"@c1334"}]},"nguon":["@c1324","@c1325","@c1326","@c1328","@c1329","@c1330","@c1331","@c1332","@c1333","@c1334","@c1335","@c1341","@c1343"],"gioiTinh":"nam","trangThai":"song","aliases":["Tư Mã Mặc","Ti Mặc Tử","Thiên Mặc Tử"],"canhGioiCaoNhat":"Nguyên Anh (thời điểm được đề cập)","cn":"司默子","vaiTro":"Đại năng Đệ Tam Bộ nhận huyết chỉ truy bắt Vương Lâm, mang quá khứ bi thương","tinhCach":"Kiêu ngạo, hay châm chọc khinh thường đối thủ yếu hơn; nhẫn nhịn e dè trước bậc mạnh hơn như lão Chu Tước; quyết liệt khi truy sát mục tiêu; nội tâm ẩn chứa nỗi đau sâu kín vì muội muội đã mất","blurb":"Tư Mặc Tử là một trong ba đại năng Đệ Tam Bộ từng tham gia đuổi giết Thác Sâm, sau khi hấp thu Lục Phẩm đạo linh trong khe nứt hư vô thì nhận huyết chỉ truy bắt Vương Lâm. Hắn dùng phân thân lần theo dấu Vương Lâm từ Thập Vạn Đại Sơn tới Đại Đế tinh, nhiều lần giao chiến bằng Phá Thiên Đạo, Phá Không Cửu Diệt và Hương hỏa thần thông nhưng đều thất lợi, cuối cùng bị Mộng Đạo gieo tâm ma và bị luyện hóa tại Thiên Hoàng Lô, toàn bộ quá khứ bi thương — từ thiếu niên hái thuốc đến vạn năm bầu bạn hư ảnh muội muội — bị phơi bày trước Vương Lâm. Ký ức của hắn sau đó trở thành tấm gương cảnh tỉnh cho "},{"id":"dieu-am-dao-ton","name":"Diệu Âm đạo tôn","tabs":{"kinhLich":[{"chuong":"@c1324","importance":"bridge","mucCt":"gon","text":"Nhìn Vương Lâm hóa hư hỏa, mắt hiện tia sáng kỳ dị, khóe miệng nụ cười lạnh.","anchor":"Nhân phương hương diệt, Địa phương hương gãy, nhưng Thiên phương hương sẽ không tắt không gãy"},{"importance":"normal","mucCt":"vua","chuong":"@c1325","tieuDe":"Bản thể hé lộ, lệnh phân thân về tra xét cổ mộ","text":"Bản thể là lão già tóc bạc tu dưới đáy hải dương ở tu chân tinh trung tâm (tinh không phía bắc Thái Cổ Tinh Thần), được xác nhận là một trong Thái Cổ Ngũ Tôn. Khi cổ mộ mở ra tạo dòng xoáy, bừng mắt phát hiện bất thường, lệnh phân thân bước thứ ba (thiếu niên trên Đại Đế tinh) bỏ lễ mau trở về tra xét. Phân thân cáo từ lão Chu Tước rồi hóa luồng sáng biến mất.","anchor":"Lão già này chính là bản thể của Diệu âm đ*o tôn - Một trong thái cổ ngũ tôn"},{"importance":"normal","mucCt":"ky","chuong":"@c1345","tieuDe":"Liều phân thân xông vào cổ mộ","text":"Phân thân thiếu niên của Diệu Âm đạo tôn (tu vi Không Linh trung kỳ) biết rõ truyền thuyết cổ mộ chứa pháp bảo, đan dược, thần thông, thậm chí phương pháp tiến vào Không Kiếp đại cảnh. Hắn dùng hương hỏa lực triệu hơn trăm triệu hương hỏa hồn (toàn nam tử tuấn mỹ) bao quanh thân xông vào sương mù. Toàn bộ hương hỏa hồn bị hủy diệt, tu vi suy chín lần từ Không Linh trung kỳ xuống Không Niết sơ kỳ. Trên mi tâm xuất hiện tiêu ký và bị hút vào trung tâm cổ mộ. Hắn ngộ ra sương mù hạn chế tu vi tiến vào tối đa chỉ Không Niết sơ kỳ.","anchor":"Nhưng bên trong vùng đất cổ mộ này hạn chế cao nhất để tiến vào chính là Không Niết sơ kỳ"},{"mucCt":"ky","text":"Giao chiến với phân hồn Đại Hoang Lão Độc trong vùng phong ấn thứ hai, tranh đoạt tứ phẩm đạo linh. Chiếm ưu thế, khinh miệt phân hồn đối thủ, tuyên bố phân hồn không phải đối thủ. Chê Đại Hoang tính tình cổ quái, trong Thái Cổ Tinh Thần ngoài Lão Điểu không có đạo hữu nào, không ai giúp tranh đoạt. Tiết lộ bổn tôn mình ở Âm Hải.","anchor":"Đại Hoang lão độc, đây là phân hồn của ngươi, nhưng phân hồn của ngươi tới nơi này cũng không phải là đối thủ của ta","bridge":true,"khoang":"@c1363"},{"mucCt":"ky","text":"Đánh lén cướp tứ phẩm mộc đạo linh của Đại Hoang Thượng Nhân, giao chiến khốc liệt. Tiêu diệt thần thức do thám của Vương Lâm, cảnh cáo người ngoài. Dùng kế li gián đề nghị trả đạo linh cho Đại Hoang để chia rẽ liên minh, mục đích thật là đoạt Thiên Nghịch trên người Vương Lâm. Triệu hương hỏa lực hóa tiên nữ cầm ngọc kiếm chém vỡ lôi đồ Vương Lâm. Bị Đại Hoang phản bội quay lại tập kích, lưỡng diện thọ địch: thuẫn sương tím bị năm móng tay Đại Hoang đánh vỡ đâm trước ngực, huyết kiếm Vương Lâm xuyên thấu hư ảnh đâm trúng lưng xuyên qua ngực, phun máu trọng thương nặng. Kích hoạt Âm bổn nguyên và Thủy bổn nguyên thi triển âm lãng diệt đạo phản đòn.","anchor":"một đòn mạnh nhất của Vương Lâm đã chuẩn bị xong","bridge":true,"khoang":"@c1364"},{"chuong":"@c1365","importance":"major","mucCt":"ky","tieuDe":"Dung hợp âm-thủy đại chiến, trọng thương gần chết","text":"Hé lộ là một trong Thái Cổ Ngũ Tôn, lấy âm bổn nguyên đại thành phá cửa ải không niết thành bước thứ ba, lại luyện hóa Thái Cổ Thiên Tinh Hải khiến thủy bổn nguyên thành chính quả, dung hợp âm đạo và thủy đạo uy lực long trời lở đất. Phá thệ phù hương hỏa của Đại Hoang, thi triển tiếng biển gào thét hủy diệt gần trăm tu sĩ và phá hủy vùng đất phong ấn. Mở Hải Dân Giới triệu biển tím hàng triệu hương hỏa sinh linh tấn công, phá hủy thân thể phân hồn Đại Hoang. Tuy nhiên bị ba châm Đại Hoang Tam Tiên cắm vào mi tâm, ngũ độc nhập thể, biển hương hỏa bị biến thành biển độc. Chặt cánh tay phải tạo cuồng phong chống Vương Lâm nhưng bị Linh Động lao ra đẩy ba châm sâu thêm một tấc, độc tố bộc phát toàn diện, trọng thương gần chết.","anchor":"Cho tới bây giờ hắn cũng không thể ngờ, Vương Lâm giống như một con kiến, không ngờ còn có thủ đoạn khiến hắn hoảng sợi tâm thần kịch chấn."},{"chuong":"@c1366","importance":"normal","mucCt":"vua","tieuDe":"Bị đoạt xá, bắt vào biển sương mù","text":"Bị Linh Động đánh trọng thương rồi bị cuốn xa. Đại Hoang Thượng Nhân hóa hắc khí chui vào thất khiếu triển khai đoạt xá, hai bên giao chiến bằng thần thức trong cơ thể. Khi cánh tay khổng lồ đánh trúng, phun máu, nguyên thần bị Đại Hoang áp chế hoàn toàn, thân thể bị hút vào bàn tay khổng lồ. Hương hỏa Hải Dân Giới hắn sưu tầm mấy vạn năm bị Vương Lâm cướp đi khoảng ba phần.","anchor":"Đó chính là do Diệu âm đ*o tôn sưu tầm và cướp đoạt mấy vạn năm nay, là điểm căn bản để hắn trở thành Thái Cổ Ngũ Tôn"},{"mucCt":"vua","text":"Mấy vạn năm ẩn dưới đáy tử hải, mở mắt vì khe cổ mộ tái xuất. Oán hận Đại Hoang cướp phân thân và Vương Lâm phá chuyện. Thỏa thuận với Cửu Thiên Ma Tôn: Cửu Thiên ngăn Đại Hoang, đổi lại giao vật lấy được, nhưng Vương Lâm thuộc về Cửu Thiên. Tin tưởng người áo đen sẽ có biện pháp cứu, xoay người bước vào khe cổ mộ.","anchor":"Diệu Âm lão đạo mấy vạn năm không rời khỏi tử hải, không ngờ cũng đến tranh đoạt hồn thủy này","bridge":true,"khoang":"@c1378"},{"mucCt":"vua","text":"Cùng Cửu Thiên Ma Tôn ở bản đồ thứ tư, bị thần thức Vương Lâm lướt qua, tâm thần chấn động. Dưới tiếng rống, phun máu, thân thể tan vỡ, nguyên thần sống sót, rút lui.","anchor":"Đồng từ trong hai mắt Diệu âm đ*o tôn co rụt lại","bridge":true,"khoang":"@c1382"},{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Phóng nhanh tới khi Vương Lâm thu vùng đất phong ấn Cổ Tức Diệp nhưng chỉ thấy khoảng trống, bị nhốt lại trong cổ mộ.","anchor":"cổ mộ đã bị Vương Lâm hoàn toàn khoá kín, những người này sẽ bị nhốt ở đây trong một thời gian dài"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát, phản ứng đáng ngờ","ghiChu":"@c1324"},{"ten":"Nữ tử Phong Diệt tộc","tag":"khac","quanHe":"Thị nữ","ghiChu":"Phái nàng dẫn đường truy sát Vương Lâm."},{"ten":"Đại Hoang Thượng Nhân","tag":"doi-thu","quanHe":"Đối thủ tranh đoạt tứ phẩm đạo linh, khinh miệt phân hồn Đại Hoang","gap":"@c1363"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ, mục tiêu đoạt Thiên Nghịch","ghiChu":"Hợp kích cùng Đại Hoang khiến Diệu Âm trọng thương"}],"tuViMoc":[{"chuong":"@c1365","canhGioi":"Không Niết bước thứ ba","text":"Hé lộ đã lấy âm bổn nguyên đại thành phá vỡ cửa ải không niết, đạt cao thủ bước thứ ba.","importance":"major"}],"diem":[{"text":"Từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa","chuong":"@c1193"},{"text":"Bản thể là lão già tóc bạc tu dưới đáy hải dương ở tu chân tinh trung tâm, phái phân thân thiếu niên ra ngoài hành sự","chuong":"@c1325"},{"text":"Lấy âm bổn nguyên đại thành phá vỡ cửa ải Không Niết, đạt bước thứ ba; là một trong Thái Cổ Ngũ Tôn","chuong":"@c1365"},{"text":"Giao chiến khốc liệt với phân hồn Đại Hoang Lão Độc trong cổ mộ, đánh lén cướp tứ phẩm mộc đạo linh","chuong":"@c1364"},{"text":"Bị trọng thương gần chết trong đại chiến dung hợp âm-thủy, sau đó bị Đại Hoang Thượng Nhân đoạt xá","chuong":"@c1366"},{"text":"Mấy vạn năm ẩn dưới đáy tử hải, mở mắt trở lại vì khe cổ mộ tái xuất, ôm oán hận Đại Hoang và Vương Lâm","chuong":"@c1378"}]},"nguon":["@c1324","@c1325","@c1343","@c1345","@c1363","@c1364","@c1365","@c1366","@c1378","@c1382","@c1386"],"gioiTinh":"nam","aliases":["Thiếu niên trên Đại Đế tinh","Diệu Âm","Diệu Âm lão đạo"],"trangThai":"song","cn":"妙音道尊","vaiTro":"Cường giả cổ tu — một trong Thái Cổ Ngũ Tôn, từng hợp lực giết chủ nhân Thần Tông","tinhCach":"Nhàn nhã phóng túng, thường nằm mây ăn đào quan sát thế cục; tham lam dã tâm, lộ rõ tham niệm khi thấy bảo vật; âm trầm khó lường, bề ngoài thiếu niên xinh xắn nhưng bản thể là lão già tóc bạc tu luyện dưới đáy hải dương","blurb":"Diệu Âm Đạo Tôn là một trong Thái Cổ Ngũ Tôn, bản thể là lão già tóc bạc ẩn tu dưới đáy hải dương ở tu chân tinh trung tâm, từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa. Y lấy âm bổn nguyên đại thành phá vỡ cửa ải Không Niết lên bước thứ ba, phái phân thân thiếu niên tham gia tranh đoạt tại cổ mộ và giao chiến khốc liệt với phân hồn Đại Hoang Lão Độc để cướp tứ phẩm đạo linh. Sau đại chiến dung hợp âm-thủy, y bị trọng thương gần chết rồi bị Đại Hoang Thượng Nhân đoạt xá; mấy vạn năm sau vẫn ẩn dưới đáy tử hải ôm mối oán hận, mở mắt trở lại khi khe cổ mộ tái xuất.","canhGioiCaoNhat":"Không Niết bước thứ ba","theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}]},{"id":"lao-gia-tren-lung-than-lan","name":"Lão giả trên lưng thằn lằn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đối thủ cũ giao chiến nhiều lần với lão Chu Tước, hiểu rõ sự cường đại của hư hỏa. Cưỡi thằn lằn khổng lồ.","vaiTro":"Đối thủ cũ của lão Chu Tước","tinhCach":["Thận trọng, am hiểu thực lực đối phương"],"tabs":{"diem":[{"text":"Giao chiến nhiều lần với lão Chu Tước, hiểu rõ sự cường đại của hư hỏa","chuong":"@c1324"}],"kinhLich":[{"chuong":"@c1324","importance":"bridge","mucCt":"gon","text":"Từng giao chiến nhiều lần với lão Chu Tước nên hiểu rõ sự cường đại của hư hỏa, lưu ý khi thấy Vương Lâm bước vào cảnh giới này.","anchor":"Hắn cùng với lão Chu Tước giao chiến nhiều lần, hiểu rất rõ sự cường đại của hư hỏa"},{"importance":"bridge","mucCt":"vua","chuong":"@c1325","text":"Khi dị biến xảy ra, không nói gì, hướng về lão Chu Tước ôm quyền rồi vỗ thằn lằn bay đi lao về phía chân trời.","anchor":"cái miệng bị những cây châm xuyên qua dường như hơi chuyển động, hướng về phía lão Chu Tước ôm quyền"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão Tổ Cấm Địa Chu Tước","tag":"doi-thu","quanHe":"Đối thủ cũ","ghiChu":"Giao chiến nhiều lần"},{"ten":"Lão Chu Tước","tag":"doi-thu","quanHe":"Đối thủ cũ, giao chiến nhiều lần","ghiChu":"@c1324"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Kẻ đạt hư hỏa khiến hắn chấn động","ghiChu":"@c1324"}],"tuiDo":{}},"nguon":["@c1324","@c1325"]},{"id":"lam-mong-dao-ton","name":"Lam Mộng đạo tôn","cn":"蓝梦道尊","aliases":[],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Lam Mộng Đạo Tôn là một trong ngũ đại tôn giả của Thái Cổ Tinh Thần, tu vi từ Không Huyền đỉnh phong hai đạo bổn nguyên dung hợp tiến tới Không Huyền đại viên mãn rồi đạt Không Huyền hậu kỳ viên mãn đỉnh phong, từng đứng đầu Thái Cổ Ngũ Tôn. Ông chiêu mộ Vương Lâm kế thừa đạo thống không thành nhưng vẫn truyền thụ ba thức thần thông — Đạo thuật Dung, Quang Ảnh Thuẫn và Phiên Thiên — rồi nhiều lần dõi theo, can thiệp giúp đỡ Vương Lâm giữa các biến cố lớn trên Đại Đế tinh, cho đến khi vì ước định với Chưởng Tôn mà buộc phải xuất thủ chặn Vương Lâm, ân đoạn nghĩa tuyệt. Ông luôn giữ nữ nhi Lý Th","vaiTro":"Ngũ đại tôn giả Thái Cổ Tinh Thần — lãnh đạo Lam Ti Tộc, cư ngụ tại Lam Sơn","tinhCach":"U buồn thâm trầm, thường độc tọa gảy cổ cầm; trọng tình nghĩa với thê tử và nữ nhi, sẵn sàng che chở người thân; điềm tĩnh cân nhắc trước mỗi biến cố, hành sự thận trọng; nội tâm phức tạp, có thể vì ước định mà ân đoạn nghĩa tuyệt dù bất đắc dĩ","tabs":{"diem":[{"text":"Chiêu mộ Vương Lâm kế thừa đạo thống thất bại, truyền thụ ba thức thần thông: Đạo thuật Dung, Quang Ảnh Thuẫn và Phiên Thiên","chuong":"@c1243"},{"text":"Đưa thần thức vào Địa Phương hương cứu Vương Lâm nhưng bị sức mạnh Thiên Nghịch bức khỏi Địa Phương giới","chuong":"@c1320"},{"text":"Lần đầu hối hận vì năm đó đã xóa ký ức Nguyệt Nhi khi thấy nàng yên lặng nhìn Vương Lâm","chuong":"@c1324"},{"text":"Tu vi đạt Không Huyền đại viên mãn, đứng đầu Thái Cổ Ngũ Tôn, xuất hiện can thiệp trận chiến Phong Giới","chuong":"@c1435"},{"text":"Vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, ân đoạn nghĩa tuyệt","chuong":"@c1492"},{"text":"Tu vi được xác nhận đạt Không Huyền hậu kỳ viên mãn đỉnh phong, chưa vượt qua huyền kiếp","chuong":"@c1568"}],"kinhLich":[{"chuong":"@c1324","importance":"normal","mucCt":"vua","tieuDe":"Lần đầu hối hận về Nguyệt Nhi","text":"Thấy nữ tử phía sau (Nguyệt Nhi) yên lặng nhìn Vương Lâm, lần đầu tiên hối hận vì năm đó xóa ký ức Nguyệt Nhi và không giữ Vương Lâm lại toàn lực trợ giúp, chỉ truyền có ba thức thần thông.","anchor":"Nếu năm đó ta không xóa đi ký ức của Nguyệt Nhi mà lưu Vương Lâm này lại"},{"importance":"bridge","mucCt":"vua","chuong":"@c1325","text":"Khi cổ mộ mở ra gây dị biến, sững lại rồi nói việc quỷ bí phải tới xem, dùng lam quang bao phủ Lý Thiến Mai rồi tiêu tán rời Đại Đế tinh.","anchor":"Việc này rất quỷ bí, lão phu cũng phải nhanh chân tới xem"}],"tuViMoc":[],"nhanMach":[{"ten":"Nguyệt Nhi","tag":"su-mon","quanHe":"Đồ nhi / người được bảo hộ","ghiChu":"Đã xóa ký ức Nguyệt Nhi năm xưa"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người từng truyền ba thức thần thông","ghiChu":"Hối hận không giữ lại toàn lực trợ giúp"},{"ten":"Lý Thiến Mai","tag":"ho-hang","quanHe":"Phụ tử, đưa theo khi rời Đại Đế tinh","gap":"@c1325"}],"tuiDo":{}},"nguon":["@c1324","@c1325"]},{"id":"nguyet-nhi-lam-mong","name":"Nguyệt Nhi","tabs":{"kinhLich":[{"chuong":"@c1324","importance":"bridge","mucCt":"gon","text":"Yên lặng nhìn Vương Lâm từ phía sau Lam Mộng đạo tôn, ký ức đã bị xóa.","anchor":"trong lòng lần đầu tiên nổi lên sự hối hận với quyết định ngày đó"}],"nhanMach":[{"ten":"Lam Mộng đạo tôn","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Người xóa ký ức nàng năm xưa"}],"tuViMoc":[]},"nguon":["@c1324"]},{"id":"lao-to-cam-dia-chu-tuoc","name":"Lão Tổ Cấm Địa Chu Tước","aliases":["Lão Chu Tước","Chu Tước đời thứ hai","Lão Tổ Cấm Địa Chu Tước","Chu Tước Tử Đời Thứ 14","Lão tổ đời thứ hai","Nhất đại Chu Tước"],"tabs":{"kinhLich":[{"chuong":"@c1324","importance":"normal","mucCt":"vua","tieuDe":"Thả Viêm Long, truyền âm Thiên phương hương","text":"Vui mừng khen Vương Lâm hóa hư hỏa. Ném Viêm Long đi tuyên bố tự do, thực chất tặng cho Vương Lâm. Truyền âm riêng: Thiên phương hương do Điên Lạc đại đế trấn giữ, khảo nghiệm tiềm lực — lão năm đó đạt mười hai nhịp thở, Chu Tước đời thứ tư đạt mười bốn nhịp thở. Hứa nếu Vương Lâm làm lão vui sẽ dạy phương pháp cấm chế Viêm Long.","anchor":"lão phu năm đó là mười hai nhịp thở, Chu Tước đời thứ tư là mười bốn nhịp thở"},{"importance":"bridge","mucCt":"vua","chuong":"@c1325","text":"Chứng kiến các cường giả lần lượt rời Đại Đế tinh. Khi thân thể Vương Lâm vỡ tan, lộ vẻ ngưng trọng, thần sắc âm trầm, nghi lão tổ đời đầu dùng Sâm La Viêm thí luyện là đầu óc không tỉnh táo.","anchor":"Lão tổ đời đầu tiên chẳng lẽ đầu óc không tỉnh táo, không ngờ lại dùng tới Sâm La Viêm thí luyện"},{"mucCt":"ky","text":"Thấy Vương Lâm bị tổn thương nặng trong thí luyện, xông tới Thiên phương hương đưa thần thức vào chất vấn lão tổ đời đầu vì sao đối xử tàn nhẫn với tộc nhân. Bị Chu Tước đời đầu gầm đẩy thần thức văng ra, lùi lại mấy bước, ánh mắt phức tạp nhìn Vương Lâm, không đoán nổi ý đồ lão tổ.","anchor":"Chẳng lẽ hắn không phải là tộc nhân của Chu Tước tộc ta, chẳng lẽ hắn là do người khác tạo ra","bridge":true,"khoang":"@c1326"},{"importance":"bridge","mucCt":"gon","chuong":"@c1328","tieuDe":"","text":"Suốt quá trình thần sắc âm trầm, mơ hồ đoán được tâm tư lão tổ, trợn mắt kinh hãi khi Vương Lâm ngưng tụ hư hỏa bên ngoài.","anchor":"Đây là. ngưng tụ hư hỏa bên ngoài!"},{"chuong":"@c1329","importance":"bridge","mucCt":"vua","text":"Cười đắc ý khi Vương Lâm khiêu chiến Ti Mặc Tử, tiết lộ vài cái tát trước đó dành cho Ti Mặc Tử cũng không nhẹ, ám chỉ đã cố tình tạo điều kiện cho Vương Lâm.","anchor":"Bước thứ ba tuy mạnh, nhưng vài cái tát lúc trước của lão phu cũng không nhẹ đâu"},{"mucCt":"vua","text":"Tiết lộ ba cái tát trước đó đã lưu hư hỏa trên người Tư Mặc Tử, khiến hắn bị tâm tình dao động và hư hỏa bùng phát từ bên trong. Định ra tay khi hương hỏa nhất bái nhắm Vương Lâm nhưng bị Vương Lâm ngăn lại.","anchor":"Mấy cái tát kia của lão phu không chỉ muốn giáo huấn ngươi mà còn lưu lại hư hỏa trên người ngươi","bridge":true,"khoang":"@c1330"},{"importance":"bridge","mucCt":"gon","chuong":"@c1331","tieuDe":"Kinh ngạc trước Cổ Tức Diệp","text":"Đồng tử co rụt, lộ vẻ không thể tin khi thấy Cổ Tức Diệp phong ấn hương hỏa giới.","anchor":"ngay cả Lão Chu tước đồng tử trong hai mắt cũng co rụt lại, lộ ra vẻ không thể tin"},{"chuong":"@c1332","importance":"bridge","mucCt":"vua","tieuDe":"Khen Vương Lâm là nhân tài","text":"Tiết lộ ban đầu chỉ tính âm thầm trợ giúp để Vương Lâm đánh ngang sức Tư Mặc Tử lấy uy danh, đã dọa nạt khiến Tư Mặc Tử không dám xuất sát chiêu. Khi thấy Vương Lâm muốn luyện hóa Tư Mặc Tử, trợn mắt kinh ngạc rồi cười rộ khen là nhân tài.","anchor":"Giỏi! Không hổ là hậu bối của tộc ta, bất kể có luyện hóa được hay không, có thể có ý tưởng này, có thể táo bạo như vậy, người này đúng là một nhân tài!"},{"chuong":"@c1335","importance":"normal","mucCt":"ky","tieuDe":"Tiễn Vương Lâm, trao Cổ Hồn Cấm và giao nhiệm vụ","text":"Ngồi câu cá bên hồ trên Đại đế tinh tiễn biệt Vương Lâm. Triệu con rùa giữa không trung thu nhỏ thành mai rùa chứa Cổ Hồn Cấm do lão tổ đời đầu để lại, ném cho Vương Lâm phòng thân. Nhờ Vương Lâm dùng ấn ký Chu Tước tuyển chọn Chu Tước đời thứ bảy, yêu cầu chọn từ trẻ con, bảo tồn nguyên thần chi dương hoàn hảo, tuyệt đối không ham nữ sắc. Tự hào vô số vạn năm chưa song tu, nguyên thần chi dương chưa hề tiêu tan. Hứa truyền một trong ba thuật mạnh nhất Chu Tước tộc — thần thông bảo mệnh do Viễn Cổ tiên tôn truyền lại.","anchor":"Thần thông này là một trong ba thuật mạnh nhất của Chu Tước tộc ta, được Viễn Cổ tiên tôn truyền lại"},{"importance":"normal","mucCt":"ky","chuong":"@c1336","tieuDe":"Truyền thụ Phần Giới Cổ Tán cho Vương Lâm","text":"Biểu diễn thần thông Phần Giới Cổ Tán trước mặt Vương Lâm, đánh bốn lần ấn quyết tổng gần hai trăm vạn ấn ký trong chín nhịp thở, hình thành cơn lốc hỏa cốt dạng cái ô chưa mở, uy áp trùm Đại đế tinh và lan nửa vùng Điên Lạc. Giải thích nguồn gốc thuật do Viễn Cổ Tiên Hoàng học trộm mà thành, không hoàn chỉnh. Tiết lộ lão tổ đời thứ nhất Chu Tước tộc tu vi Không Kiếp sơ kỳ chỉ mở được năm lần ô, còn bản thân nhờ nguyên dương chưa từng bị phá nên với tu vi Huyền Không trung kỳ mở được hai lần. Cảnh báo sai một ấn quyết sẽ bị phản phệ kinh khủng, không phải hỏa tu sẽ bị tiêu tan. Phải cắn đầu lưỡi phun máu Huyền Không trung kỳ mới thu hồi được cơn lốc, sau đó khoanh chân thổ nạp hồi phục. Trao ngọc giản chứa toàn bộ ấn quyết và thuật mở ô cho Vương Lâm.","anchor":"nhờ nguyên dương qua vô số vạn năm chưa bao giờ bị phá, lấy nguyên dương dẫn dắt, với tu vi Huyền Không trung kỳ cũng có thể mở ô hai lần"},{"importance":"bridge","mucCt":"gon","chuong":"@c1339","tieuDe":"Được nhắc đã truyền Phần Giới Cổ Tán cho Vương Lâm","text":"Vương Lâm nhận ra lão tổ đời thứ hai đã truyền thuật mạnh nhất Chu Tước tộc cho hắn là vì đã nhìn thấu tình huống trận chiến này.","anchor":"Lão tổ đời thứ hai đột nhiên lại truyền cho ta thuật mạnh nhất của Chu Tước tộc, hiển nhiên là đã nhìn thấu chuyện này"}],"nhanMach":[{"ten":"Lão giả trên lưng thằn lằn","tag":"doi-thu","quanHe":"Đối thủ cũ, giao chiến nhiều lần","ghiChu":"@c1324"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Truyền nhân Chu Tước, giao khảo nghiệm và hứa dạy cấm chế Viêm Long","ghiChu":"@c1324"}],"tuViMoc":[],"diem":[{"text":"Ra lệnh Kiền Phong nuốt Hồng Điệp, sai Liễu Mi truy tìm Vương Lâm để đoạt Thiên Nghịch Châu và Tinh La Bàn","chuong":"@c0340"},{"text":"Triệu Tiên vệ và Tiên đế nghênh chiến Vương Lâm, nhưng Tiên vệ áo đen bị hắn một chỉ Tịch Diệt diệt sát","chuong":"@c0577"},{"text":"Giảng giải bản chất Phá Không Ngũ Chỉ và con đường Niết Không bước thứ ba cho Vương Lâm","chuong":"@c1327"},{"text":"Tiễn biệt Vương Lâm trên Đại Đế tinh, trao Cổ Hồn Cấm và giao phó nhiệm vụ","chuong":"@c1335"},{"text":"Đích thân biểu diễn và truyền thụ Phần Giới Cổ Tán — thần thông mạnh nhất của Chu Tước tộc — cho Vương Lâm","chuong":"@c1336"},{"text":"Ngầm bố cục lưu hư hỏa trên người Tư Mặc Tử qua ba cái tát, tạo thế cho Vương Lâm lập uy danh","chuong":"@c1330"}]},"nguon":["@c1324","@c1325","@c1326","@c1328","@c1329","@c1330","@c1331","@c1332","@c1335","@c1336","@c1339"],"gioiTinh":"nam","trangThai":"song","vaiTro":"Lão tổ đời thứ hai của Chu Tước tộc — thế lực bí ẩn trong cấm địa Chu Tước Sơn","tinhCach":"Thủ đoạn lạnh lùng, xem sinh linh làm mồi luyện; toan tính thâm sâu, bố cục nhiều tầng từ trong cấm địa; ẩn dật bí hiểm, hành sự khó lường; trọng nhân tài, sẵn lòng truyền thụ tuyệt học cho kẻ xứng đáng","blurb":"Lão tổ đời thứ hai của Chu Tước tộc, toàn thân phát hồng quang, ẩn cư trong cấm địa phía sau Chu Tước Sơn. Thuở đầu nuôi Hồng Điệp làm mồi cho Kiền Phong và ra lệnh truy tìm Vương Lâm để đoạt Thiên Nghịch Châu cùng Tinh La Bàn, nhưng về sau nhận ra tài năng của Vương Lâm, chuyển sang âm thầm trợ giúp — giảng giải con đường Niết Không, trao Cổ Hồn Cấm, đích thân truyền thụ thần thông Phần Giới Cổ Tán tuyệt học mạnh nhất của Chu Tước tộc, ngầm bố cục để Vương Lâm lập uy danh trước Tư Mặc Tử, và âm thầm quan sát bước đường tu luyện của hắn về sau."},{"id":"viem-long","name":"Viêm long","tabs":{"kinhLich":[{"chuong":"@c1324","importance":"normal","mucCt":"vua","tieuDe":"Được thả tự do, không biết bị tặng cho Vương Lâm","text":"Đã hấp hối máu gần hết nhưng nghe lão Chu Tước tuyên bố tự do liền bay vụt đi, gầm thét vui sướng. Thực tế năm xưa bị Chu Tước đời đầu lừa, nay lại bị lão Chu Tước tặng cho Vương Lâm mà không biết.","anchor":"Lão long ta cuối cùng đã được giải thoát của bàn tay ma quái kia"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1324"],"trangThai":"song"},{"id":"dien-lac-dai-de","name":"Điên Lạc đại đế","aliases":["Chu Tước lão tổ đời đầu","Lão Tổ Chu Tước Đời Đầu Tiên","Chu Tước đời đầu tiên"],"tabs":{"kinhLich":[{"chuong":"@c1324","importance":"minor","mucCt":"gon","tieuDe":"Được nhắc tới — trấn giữ Thiên phương hương","text":"Được lão Chu Tước nhắc: lão tổ đầu tiên Chu Tước tộc, một trong tứ đại chiến tướng viễn cổ tiên tôn, tự mình trấn giữ Thiên phương hương. Pho tượng khổng lồ trong Thiên phương giới mang tướng mạo Chu Tước với lửa chín màu ở mi tâm.","anchor":"Điên lạc đại đế - Lão tổ đầu tiên của bộ tộc ta"},{"mucCt":"ky","text":"Ngọn lửa chín màu trên mi tâm bùng lên, bừng mắt khen Vương Lâm huyết mạch ít mà tỉnh giấc bốn lần là không tồi. Nói bị thương chưa lành, thời gian tỉnh táo ít, đề ra thí luyện mỗi năm nhịp thở được hỏi một câu. Dùng tâm thần hỏa Chu Tước Sâm La Viêm thiêu đốt Vương Lâm. Tiết lộ Nghiệt Tước đời thứ ba trộm chí bảo rồi trốn đi lập thành Hỏa Tước tộc, bản thân bị phong ấn không thể thanh lý môn hộ.","anchor":"Nghiệt tước đời thứ ba trộm chí bảo của ta rồi trốn đi, lập thành Hỏa Tước tộc","bridge":true,"khoang":"@c1325"},{"importance":"normal","mucCt":"ky","chuong":"@c1326","tieuDe":"Thẩm tra thân phận Vương Lâm — giảng đạo tu hành như chưởng","text":"Xác nhận viễn cổ tiên tôn và viễn cổ tiên hoàng chỉ là cách gọi khác nhau giữa hai thời đại. Biến ảo Chu Tước già nua tấn công Vương Lâm, thi triển Chu Tước ấn phong bế hoàn toàn Cổ Lôi Giới ngàn trượng nhốt thái cổ Lôi Long. Dùng bàn tay nắm chặt bóp Vương Lâm từ nhịp thở 15 đến 19. Phóng hư hỏa chín màu thẩm tra toàn bộ quá khứ Vương Lâm với ấn ký Chu Tước, xem vạn lần rồi thở dài lộ vẻ hiền lành, buông tay. Thú nhận toàn bộ mưu tính: từ tu chân tinh Long Giáp tộc đã nhận ra dấu vết trên Vương Lâm, sắp xếp thân phận thiếu đế và đưa vào thí luyện chỉ để kéo hắn tới trước mặt xác minh, vì năm xưa bị Chu Tước đời thứ ba — kẻ do người khác tạo ra — lừa gạt khiến rơi vào kết cục bị nhốt trong Thiên phương giới. Lần đầu lộ vẻ khiếp sợ khi nhận ra huyết kiếm. Cuối cùng giảng đạo: chỉ ra Vương Lâm có năm bổn nguyên nhưng con đường sai, giải thích phá không ngũ chỉ chính là thiên nhân ngũ suy, tu hành như bàn tay — năm ngón tay phải đầy đủ mới phá không.","anchor":"Lão phu năm đó chính là bởi vì nhìn nhầm một người, cho hắn trở thành tộc nhân cho nên mới rơi vào kết cục như ngày nay"},{"importance":"normal","mucCt":"ky","chuong":"@c1327","tieuDe":"Giảng đạo Niết Không, đề xuất bị từ chối","text":"Giảng giải bản chất Phá Không Ngũ Chỉ và Niết Không bước thứ ba cho Vương Lâm: bổn nguyên càng nhiều thì tiến vào Niết Không càng khó. Nhận xét tu luyện Vương Lâm quá hỗn tạp — vừa thân Cổ Thần vừa năm đạo bổn nguyên. Nhắc Cổ Thần thời thái cổ mạnh kinh thiên động địa khiến tiên tôn e dè. Bị hỏi về đạo cổ thì nói bị ràng buộc lời thề không thể tiết lộ. Đề xuất Vương Lâm từ bỏ Cổ Thần và bốn bổn nguyên, chỉ giữ hỏa, ở lại Thiên Phương giới trăm năm sẽ trợ bước vào bước thứ ba rồi truyền Sâm La Viêm. Hứa sau khi phá phong ấn sẽ mang Vương Lâm cùng Chu Tước đời hai và đời bốn rời khỏi, trở lại thế giới của mình. Lộ tâm trạng mệt mỏi, muốn về nhà, không muốn tham gia tranh đấu nữa. Đồng ý thêm tối đa một vị trí nữa cho bằng hữu của Vương Lâm. Phân tích tình trạng Lý Mộ Uyển: thọ nguyên tuyệt, Nguyên Anh tử vong, hồn phách tan nát, quan tài giữ linh hồn tạm. Nói tại quê nhà có ba người có thể dung hợp hồn phách cứu sống nàng nhưng đều hạng cao quý khó nhờ. Vương Lâm từ chối đề xuất khiến lão sững sờ.","anchor":"bọn họ muốn tranh đấu, muốn đoạt, lão phu mệt rồi, không muốn tham gia nữa, muốn. về nhà"},{"importance":"normal","mucCt":"ky","chuong":"@c1328","tieuDe":"Truyền bảo vật, cảnh báo, pho tượng mất sinh cơ","text":"Trầm mặc trước lời thề của Vương Lâm rồi thừa nhận hắn có thể đúng. Xác nhận Vương Lâm đã vượt qua thí luyện Thiên phương giới. Tiết lộ Nghiệt tước đời thứ ba có thiên tư đệ nhất nhưng gian trá dị thường, bị lão đánh trọng thương nhưng vẫn lưu lại đường lui, nghi ngờ ở Thái Cổ Tinh Thần có thân phận khác, có thể đang bế quan tại thánh địa Hỏa Tước tộc, tay có chí bảo Chu Tước tộc nhưng không biết cách điều khiển. Tặng Vương Lâm lông chim chín màu ngưng tụ Sâm La Hỏa để phòng thân. Truyền khẩu quyết điều khiển chí bảo Chu Tước tộc. Dặn lưu lại tộc nhân Hỏa Tước tộc vì còn tác dụng lớn, hứa giúp máu Chu Tước trên tinh cầu hoang dã thật hơn. Sau đó pho tượng mất sinh cơ.","anchor":"trong tay nghiệt tước đời thứ ba có chí bảo của Chu Tước tộc ta"},{"importance":"bridge","mucCt":"gon","chuong":"@c1336","text":"Được Lão Chu Tước nhắc đến: tu vi Không Kiếp sơ kỳ, chỉ mở được năm lần Phần Giới Cổ Tán.","anchor":"Lão tổ đời thứ nhất tu vi thông thiên, đã đạt tới Không Kiếp sơ kỳ, cũng chỉ có thể mở ra năm lần"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chu Tước đời thứ sáu, hậu bối được thí luyện","gap":"@c1325"},{"ten":"Nghiệt Tước đời thứ ba","tag":"doi-thu","quanHe":"Trộm chí bảo rồi trốn đi lập Hỏa Tước tộc","gap":"@c1325"}],"tuViMoc":[],"diem":[{"text":"Được xác nhận là tồn tại bước thứ ba bảo hộ vùng Điên Lạc, khiến Trường Tôn hội không thể quản lý nơi này","chuong":"@c1286"},{"text":"Không lộ thân, chỉ dùng tiếng cười và giọng nói từ hư vô truyền tới tai mọi sinh linh trên tu chân tinh, can thiệp khiến Tư Mặc Tử phải kiêng kỵ","chuong":"@c1291"},{"text":"Truyền lệnh phong Vương Lâm làm thiếu đế, đồng thời xử tử tộc trưởng Long Giáp Tộc để lập uy","chuong":"@c1294"},{"text":"Được xác nhận là lão tổ đầu tiên Chu Tước thánh tộc, một trong tứ đại chiến tướng của viễn cổ tiên tôn, tự mình trấn giữ Thiên phương hương","chuong":"@c1324"},{"text":"Giảng đạo bản chất Phá Không Ngũ Chỉ và Niết Không bước thứ ba cho Vương Lâm, truyền bảo vật sau khi xác nhận hắn vượt qua thí luyện","chuong":"@c1327"},{"text":"Tu vi được xác định là Không Kiếp sơ kỳ, chỉ mở được năm lần Phần Giới Cổ Tán","chuong":"@c1336"}]},"nguon":["@c1324","@c1325","@c1326","@c1327","@c1328","@c1336"],"trangThai":"khong-ro","vaiTro":"Đại đế thần bí bảo hộ vùng Điên Lạc — lão tổ đầu tiên Chu Tước thánh tộc, viễn cổ chiến tướng","tinhCach":"Ẩn mình hành sự từ hư vô, không trực tiếp lộ thân; quyết đoán trong thưởng phạt, xử tử kẻ phản trắc không do dự; ban phát đan dược và pháp bảo cho thuộc hạ xứng đáng; thâm trầm trước đại sự, trầm mặc cân nhắc trước khi thừa nhận lý lẽ người khác","blurb":"Điên Lạc đại đế là lão tổ đầu tiên của Chu Tước thánh tộc, một trong tứ đại chiến tướng của viễn cổ tiên tôn, tự mình trấn giữ Thiên phương hương và che chở vùng Điên Lạc khiến nơi này nằm ngoài tầm quản lý của Trường Tôn hội. Tu vi đạt Không Kiếp sơ kỳ ở bước thứ ba, ông hành sự chủ yếu từ hư vô — giọng nói truyền tới tai sinh linh cả tu chân tinh mà không hiện thân, phong Vương Lâm làm thiếu đế và giảng đạo về bản chất Niết Không bước thứ ba cho hắn. Thân phận cùng mối liên hệ với Viêm hỏa dị tinh và Chu Tước thánh tộc từng bị Vương Lâm nghi vấn, cho đến khi Chu Tước đời thứ hai xác nhận Chu","gioiTinh":"nam","theLuc":[{"ten":"Chu Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Kiếp sơ kỳ"},{"id":"chu-tuoc","name":"Chu Tước Tử Đời Thứ 14","aliases":["Chu Tước đời thứ tư","Chu Tước Tử Đời Thứ 14","Lão tổ Cấm Địa Chu Tước","Nhất đại Chu Tước","Lão tổ đời thứ hai","Chu Tước đời thứ nhất"],"tabs":{"kinhLich":[{"mucCt":"vua","text":"Ngồi bên hồ nhìn Vương Lâm biến mất. Trái với ý lão tổ đời đầu (cho rằng Vương Lâm không phải người Chu Tước tộc), tự ý truyền thuật mạnh nhất Chu Tước tộc cho Vương Lâm vì tin hắn xứng đáng sau khi kết thúc thí luyện.","anchor":"Ta không nghe theo sự phân phó của người, tự tiện truyền thuật mạnh nhất của Chu Tước tộc ta cho hắn","bridge":true,"khoang":"@c1337"},{"importance":"bridge","mucCt":"gon","chuong":"@c1339","tieuDe":"Được nhắc về chiếc lông chí bảo và tâm tư thâm sâu","text":"Được Vương Lâm đánh giá là tâm tư cực kỳ thâm sâu, tàn nhẫn, đã sắp đặt toàn bộ kế hoạch chiếc lông chí bảo để giết tam đại nghiệt tước.","anchor":"Chu Tước đời thứ nhât tàn nhẫn lắm!"}]},"nguon":["@c1324","@c1337","@c1339"],"trangThai":"song"},{"id":"lao-gia-mat-am-duong","name":"Lão già mặt âm dương","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ bí ẩn khuôn mặt âm dương, cưỡi trên lưng cự thú Vọng Nguyệt ở bên ngoài vùng đất Điên Lạc.","vaiTro":"Cường giả bí ẩn cưỡi Vọng Nguyệt, liên quan tới cổ mộ","tinhCach":"Trầm ổn, do dự cân nhắc trước khi hành động","tabs":{"diem":[{"text":"Khuôn mặt âm dương, cưỡi trên lưng cự thú Vọng Nguyệt có thể so với một tu chân tinh","chuong":"@c1325"}],"kinhLich":[{"mucCt":"vua","text":"Ở bên ngoài vùng đất Điên Lạc, cảm nhận dị biến khi cổ mộ mở. Vọng Nguyệt run rẩy sợ hãi lẫn kích động, gầm thét kinh thiên. Do dự rồi điều khiển Vọng Nguyệt lao thẳng về hướng cổ mộ.","anchor":"Hắn còn chưa nói xong, Vọng nguyệt dưới thân hắn đã sững lại, lập tức nhìn về phía xa xa, thân thể run rẩy","bridge":true,"khoang":"@c1325"}],"tuViMoc":[],"nhanMach":[{"ten":"Vọng Nguyệt","tag":"khac","quanHe":"Cự thú mà lão cưỡi, cùng lao tới cổ mộ","gap":"@c1325"}],"tuiDo":{}},"nguon":["@c1325"]},{"id":"vong-nguyet","name":"Vọng Nguyệt","gioiTinh":"khac","tabs":{"kinhLich":[{"mucCt":"vua","text":"Khi cổ mộ mở ra, sững lại, run rẩy, trong mắt hung ác lộ sợ hãi và kích động, gầm thét kinh thiên. Theo lệnh lão già mặt âm dương lao thẳng tới hướng cổ mộ.","anchor":"thân thể run rẩy, trong đôi mắt hung ác lộ ra vẻ sợ hãi và kích động, cũng mở miệng phát ra một tiếng gầm thét kinh thiên","bridge":true,"khoang":"@c1325"},{"importance":"bridge","mucCt":"gon","chuong":"@c1345","text":"Mang Âm Dương lão nhân trên lưng, nhận Vũ Đông Thiện và Cực Hiền Thiên chui vào cơ thể, cả ba bị hút vào sương mù cổ mộ.","anchor":"có một mãnh thú thân thể khổng lồ như một tu chân tinh - Vọng Nguyệt"},{"mucCt":"vua","text":"Đang dùng sức phá tấm lưới cấm chế phía bắc cung điện, ký hiệu phong ấn trên mi tâm loé kịch liệt. Bị Vương Lâm xé tấm lưới tạo cuồng phong đẩy lùi rồi thu vào khe không gian biến mất.","anchor":"trên mi tâm của Vọng Nguyệt hiển nhiên là ký hiệu phong ấn, lúc này lại càng loé lên kịch liệt","bridge":true,"khoang":"@c1386"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1325","@c1345","@c1386"],"trangThai":"song","cn":"望月"},{"id":"ly-thien-mai","name":"Lý Thiến Mai","gioiTinh":"nu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1325","text":"Được Lam Mộng đạo tôn dùng lam quang bao phủ đưa rời Đại Đế tinh khi cổ mộ mở.","anchor":"nhìn lướt qua Lý Thiến Mai bên cạnh, thầm than, tay áo vung lên, lam quang bao phủ hai phụ tử"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Thiên tài tu luyện truyền kỳ Vân Hải: 5 tuổi khởi tu, 7 tuổi Trúc Cơ, hơn 1200 năm đạt Toái Niết hậu kỳ","chuong":"@c1090"},{"text":"Bất chấp quân lệnh đào ngũ chiến trường Yêu Tông, phi tinh trảm nguyệt xuyên tinh vực đến đại hội Vô Cực Tông tìm Vương Lâm","chuong":"@c1163"},{"text":"Đánh tan Triệu Long và cảnh cáo Lữ Anh Kiệt khi phóng thẳng tới khu vực Quy Nguyên Tông tại đại hội phân tông","chuong":"@c1172"},{"text":"Bị sư tôn Phá Thiên Tông đoạn tuyệt sư đồ, cô độc rời tông môn phóng đi trong tinh không","chuong":"@c1200"},{"text":"Ẩn thân mười năm bên tượng đá Vương Lâm trên đại lục hoang dã, lần lượt hy sinh máu tươi và tinh huyết chăm sóc tượng đá đến kiệt quệ","chuong":"@c1214"},{"text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"}]},"nguon":["@c1325"],"vaiTro":"Nữ tu sĩ truyền kỳ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ tình cảm của Vương Lâm","tinhCach":"Thiên phú tu luyện phi phàm, tốc độ đột phá cảnh giới hiếm có; ham hỏi đạo, trọng bản tâm, chủ động tìm người luận đạo; nặng tình kiên định, dám bất chấp sư mệnh và quân lệnh vì lời hứa; kiên nghị cô độc, một mình gánh chịu hậu quả không hối tiếc","blurb":"Lý Thiến Mai (bí danh Lý Oánh Chi) là nữ tu sĩ tóc xanh lam truyền kỳ của Phá Thiên Tông thuộc Vân Hải tinh vực cấp chín, khởi tu từ năm tuổi và sau hơn 1200 năm đạt Toái Niết hậu kỳ. Trên hành trình hỏi đạo, nàng kết giao và dần sinh tình với Vương Lâm, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp quân lệnh đào ngũ, phi tinh trảm nguyệt xuyên tinh vực đến đại hội Vô Cực Tông tìm hắn, vì đó mà bị sư tôn Phá Thiên Tông đoạn tuyệt sư đồ. Nàng ẩn thân suốt mười năm bên tượng đá Vương Lâm trên đại lục hoang dã, hy sinh máu tươi và tinh huyết chăm sóc tượng đá đến kiệt qu"},{"id":"nghiet-tuoc-doi-thu-ba","name":"Nghiệt Tước đời thứ ba","gioiTinh":"khong-ro","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nghiệt Tước đời thứ ba của Chu Tước tộc, trộm chí bảo của lão tổ đời đầu rồi trốn đi lập thành Hỏa Tước tộc.","vaiTro":"Kẻ phản bội Chu Tước tộc, sáng lập Hỏa Tước tộc","tinhCach":"Phản bội, mưu tính riêng","tabs":{"diem":[{"text":"Trộm chí bảo của lão tổ Chu Tước đời đầu rồi trốn đi lập thành Hỏa Tước tộc","chuong":"@c1325"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1325","tieuDe":"Được nhắc tới: trộm chí bảo lập Hỏa Tước tộc","text":"Lão tổ đời đầu tiết lộ Nghiệt Tước đời thứ ba trộm chí bảo rồi trốn đi lập thành Hỏa Tước tộc. Lão tổ bị phong ấn không thể thanh lý môn hộ.","anchor":"Nghiệt tước đời thứ ba trộm chí bảo của ta rồi trốn đi, lập thành Hỏa Tước tộc"},{"importance":"bridge","mucCt":"gon","chuong":"@c1326","tieuDe":"Bị tiết lộ là kẻ giả mạo tộc nhân","text":"Được Chu Tước đời đầu nhắc tới: là kẻ do người khác tạo ra, giả mạo tộc nhân lừa gạt lão tổ đời đầu khiến lão bị nhốt trong Thiên phương giới, dùng sưu hồn kiểm tra cũng không phát hiện sơ hở.","anchor":"cuối cùng mới biết là hắn được người ta tạo ra"},{"importance":"bridge","mucCt":"gon","chuong":"@c1328","tieuDe":"","text":"Được Chu Tước đời đầu cảnh báo Vương Lâm chi tiết: có thiên tư đệ nhất, tính cách gian trá, bị đánh trọng thương nhưng còn đường lui, nghi có thân phận khác ở Thái Cổ Tinh Thần, có thể đang bế quan thánh địa Hỏa Tước tộc, tay có chí bảo Chu Tước tộc.","anchor":"tính cách gian trá dị thường, năm đó vẫn còn lưu lại đường lui"}],"tuViMoc":[],"nhanMach":[{"ten":"Điên Lạc đại đế","tag":"doi-thu","quanHe":"Lão tổ đời đầu, bị Nghiệt Tước trộm chí bảo phản bội","gap":"@c1325"}],"tuiDo":{}},"nguon":["@c1325","@c1326","@c1328"],"aliases":["Chu Tước đời thứ ba"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","aliases":["Uyển Nhi"],"trangThai":"khong-ro","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1327","tieuDe":"Tình trạng được Chu Tước đời đầu phân tích","text":"Được Vương Lâm lấy quan tài ra cho Chu Tước đời đầu tiên xem. Lão xác nhận thọ nguyên đã tuyệt, Nguyên Anh bị thương nặng đã tử vong, hồn phách tan nát. Quan tài kỳ dị giữ linh hồn tạm không tiêu tán. Tại quê nhà Chu Tước đời đầu có ba người có thể dung hợp hồn phách cứu sống nàng, nhưng đều hạng cao quý khó nhờ. Là chấp niệm lớn nhất của Vương Lâm, ảnh hưởng trực tiếp tới quyết định từ chối đề xuất.","anchor":"nữ tử này chính là chấp niệm của ngươi"},{"importance":"bridge","mucCt":"gon","chuong":"@c1328","tieuDe":"","text":"Được Vương Lâm nhắc tới khi tuyên thệ trước thiên địa rằng sẽ chỉ dựa vào sức bản thân để cứu nàng sống lại.","anchor":"Làm cho Uyển Nhi sống lại cũng không thể trông cậy vào người khác"},{"chuong":"@c1334","importance":"normal","mucCt":"vua","tieuDe":"Vương Lâm liên hệ tới Uyển Nhi","text":"Được Vương Lâm nhắc tới cuối chương khi liên hệ cảm xúc: nếu muội muội kia là Uyển Nhi thì hắn sẽ lựa chọn ra sao. Thể hiện vị trí quan trọng trong tâm hồn Vương Lâm.","anchor":"muội muội kia là uyển Nhi thì ta. sẽ lựa chọn ra sao"},{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Là đối tượng cốt lõi của đề nghị Chưởng Tôn hồi sinh bằng Trường sinh ấn, Vương Lâm đấu tranh nội tâm kịch liệt vì nàng nhưng cuối cùng chọn tự mình tái sinh thay vì trở thành nô bộc.","anchor":"Uyển Nhi. Bình Nhi. Các người đừng trách ta."},{"chuong":"@c1342","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm gọi Uyển Nhi, hắn thì thào hứa sẽ cứu sống nàng, cả nhà ẩn cư sơn thôn dạy Bình Nhi khắc tượng gỗ.","anchor":"ta có thể làm cho nàng sống lại. Đến lúc đó, chúng ta sẽ cùng với Bình Nhi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Bị trưởng lão Song Tu Môn truy sát để cướp Thiên Ly đan, được Vương Lâm cứu giúp rồi đồng hành bốn năm tại Tu Ma Hải, khắc gần hai vạn ngọc giản đan phương","chuong":"@c0123"},{"text":"Ba lần Kết Anh thất bại, tuổi thọ cạn kiệt, dung nhan tang thương — sống nhờ lộ thủy hạt châu nghịch thiên nhưng không quá mười năm","chuong":"@c0302"},{"text":"Thân xác hóa xương khô, kim đan nứt vỡ; Vương Lâm dùng bức tranh Sinh Tử Luân Hồi đưa nguyên anh vào luân hồi chuyển sinh thành bé gái Chu Như","chuong":"@c0313"},{"text":"Sau chín mươi năm im lặng, thức tỉnh trong thân thể Chu Như nhưng từ chối cắn nuốt hồn phách đứa trẻ, tự đẩy nguyên anh ra để cứu Chu Như","chuong":"@c0381"},{"text":"Nguyên anh được Vương Lâm đưa ra trước Lôi Tiên điện xin cứu, bị chẩn đoán tử vong nhưng còn tia hy vọng Thất Tịch Thuật","chuong":"@c0827"},{"text":"Vận mệnh bị kẻ bí ẩn đánh cắp khỏi mặt trời thứ chín, Vương Lâm phát thề nhất định thu hồi","chuong":"@c1541"}]},"nguon":["@c1327","@c1328","@c1334","@c1341","@c1342"],"cn":"李慕婉","gioiTinh":"nu","vaiTro":"Nhân vật nữ chính — người yêu Vương Lâm, thiên tài luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp; kiên cường chịu đựng trước suy kiệt kéo dài và cái chết cận kề; nặng tình với Vương Lâm dù biết duyên phận mong manh; giàu lòng trắc ẩn và tự hy sinh — từ chối cắn nuốt hồn phách Chu Như dù phải đánh đổi cơ hội tái sinh","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ có thiên phú luyện đan và trận pháp hiếm thấy, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu, hai người đồng hành bốn năm tại Tu Ma Hải và khắc sâu tình cảm trước khi chia cách. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến tuổi thọ cạn kiệt; dù Vương Lâm tìm mọi cách điều trị, thân xác nàng vẫn hóa xương khô, nguyên anh được dùng bức tranh Sinh Tử Luân Hồi đưa vào chuyển sinh thành bé gái Chu Như tại Hạnh Hoa Thôn, nhưng sau chín mươi năm nàng thức tỉnh và tự đẩy nguyên anh ra khỏi thân thể Chu Như để cứu đứa trẻ. Nguyên anh được Vươn"},{"id":"tieu-lan","name":"Tiểu Lan","cn":"小兰","aliases":["Nữ tử lụa trắng","muội muội Tư Mặc Tử"],"gioiTinh":"nu","trangThai":"tu-vong","theLuc":[],"blurb":"Tiểu Lan là muội muội của Tư Mặc Tử (Tư Mã Mặc), sinh thời là phàm nhân tại một thôn trang. Ngày lên kiệu hoa xuất giá, thôn trang bị mã phỉ thiêu rụi tàn sát; nàng bị vũ nhục rồi tự vẫn bằng dải lụa trắng treo cổ để giữ trinh tiết. Sau khi chết, hồn phách nàng ẩn trong dải lụa trắng vấy vết máu hoa mai — pháp bảo của Tư Mặc Tử — và có thể được triệu hồi từ đám sương đỏ, phóng sức mạnh tuế nguyệt tham chiến.","vaiTro":"Muội muội của Tư Mặc Tử — nữ tử bí ẩn ẩn trong pháp bảo dải lụa trắng","tinhCach":"Ôn nhu; kiên trinh; quyến luyến","tabs":{"diem":[{"text":"Được Tư Mặc Tử triệu hồi từ đám sương đỏ hóa bởi dải lụa trắng, phóng sức mạnh tuế nguyệt bao vây Cổ Ma Hồn","chuong":"@c1332"},{"text":"Trong ký ức hư ảo, mặc áo cưới đội khăn đỏ lên kiệu hoa, lo lắng vì ca ca Tư Mã Mặc chưa trở về","chuong":"@c1333"},{"text":"Thôn trang bị mã phỉ thiêu rụi tàn sát, bị vũ nhục rồi tự vẫn bằng dải lụa trắng treo cổ để giữ trinh tiết","chuong":"@c1334"}],"kinhLich":[{"mucCt":"vua","text":"Được Tư Mặc Tử triệu hồi từ đám sương đỏ hóa bởi dải lụa trắng, phóng sức mạnh tuế nguyệt bao vây Cổ Ma Hồn. Bên trong Thiên Hoàng Lô, đứng yên cạnh Tư Mặc Tử với ánh mắt ôn nhu. Cuối cùng lên tiếng u uất van xin đưa muội về nhà, khiến Tư Mặc Tử dừng tay không kích hoạt bộ xương thú chưởng ấn Chưởng Tôn.","anchor":"Tư Mã. đưa muội về nhà. được không.","bridge":true,"khoang":"@c1332"},{"mucCt":"vua","text":"Trong ký ức hư ảo, Tiểu Lan mặc áo cưới đội khăn đỏ lên kiệu hoa, lo lắng vì ca ca Tư Mã Mặc chưa trở về. Mười một đại hán cưỡi ngựa xông vào thôn trang, lửa cháy ngập trời đúng ngày cưới.","anchor":"Thiếu nữ mặc áo cưới, đội khăn đỏ, trong lúc bước lên kiệu hoa ngẩng đầu nhìn qua góc khăn về phía xa xa","bridge":true,"khoang":"@c1333"},{"chuong":"@c1334","importance":"major","mucCt":"gon","tieuDe":"Tự vẫn giữ trinh khi thôn bị tàn sát","text":"Thôn trang bị mã phỉ thiêu rụi tàn sát, Tiểu Lan bị vũ nhục rồi tự vẫn bằng dải lụa trắng treo cổ để giữ trinh tiết. Được Tư Mã Mặc chôn trên núi cao nơi có hoa lan tím.","anchor":"Ca ca. ca ca, huynh mau tỉnh lại. huynh nhìn xem, nơi đó có một nhành lan tím"}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"nhanMach":[{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"Người triệu hồi nàng, bị nàng gọi là Tư Mã, xưng muội","ghiChu":"Quan hệ thân mật, van xin được đưa về nhà"},{"ten":"Tư Mặc Tử","tag":"ho-hang","quanHe":"Ca ca","ghiChu":"Mồ côi cha mẹ, ca ca nuôi lớn"},{"ten":"Hổ Tử","tag":"the-thiep","quanHe":"Phu quân","ghiChu":"Thành hôn ngày thôn trang bị lửa thiêu"},{"ten":"Hồ Tử","tag":"khac","quanHe":"Hôn phu dự kiến","ghiChu":"Chết trong thảm họa mã phỉ"}]},"nguon":["@c1332","@c1333","@c1334"],"canhGioiCaoNhat":"Phàm nhân"},{"id":"chuong-ton","name":"Chưởng Tôn","cn":"掌尊","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1332","importance":"bridge","mucCt":"gon","text":"Được Tư Mặc Tử nhắc đến: dẫn lời Chưởng Tôn rằng hư hỏa tu sĩ đều đáng chết, và bộ xương thú chưởng ấn của Chưởng Tôn ban tặng cho Tư Mặc Tử được lấy ra.","anchor":"Bộ xương thú này là năm đó hắn được Chưởng Tôn ban tặng, chưởng ấn trên đó cũng là của chưởng tôn"},{"chuong":"@c1334","importance":"normal","mucCt":"vua","tieuDe":"Chiêu mộ Tư Mã Mặc tại Thất Thải Giới","text":"Trong ký ức Tư Mặc Tử: giáng xuống Thất Thải Giới mang Tư Mã Mặc đi sau khi hắn bị đóng Thất Thải Đinh. Dụ bằng lời hứa cho muội muội ngưng hóa thành hình, theo cạnh vĩnh hằng, nếu tăng tu vi có thể sống lại. Ban cho tên Tư Mặc Tử.","anchor":"Đi cùng lão phu. từ nay ngươi không còn là tu sĩ Tư Mã Mặc của giới nội nữa, mà là người của chưởng tôn ta, ban cho tên là Tư Mặc Tử"},{"chuong":"@c1338","importance":"normal","mucCt":"ky","tieuDe":"Thi triển Mò Trăng Đáy Giếng, bị Vương Lâm lừa bằng Cổ Ma Hồn","text":"Ngồi trong ngọn lửa bảy màu tại thánh địa Hỏa Tước tộc, nhận ra Vương Lâm, cảm nhận khí tức Thanh Lâm, Thanh Thủy, Tư Mã Mặc trên người hắn. Không ngăn Vương Lâm cứu Hứa Lập Quốc và Lưu Kim Bưu. Thi triển đại thần thông Mò Trăng Đáy Giếng — biến tinh không thành mặt nước hình giếng, phản chiếu rồi mò hồn Vương Lâm lên, bóp nát. Lộ diện là nam tử trung niên anh tuấn, tiên phong đạo cốt, sắc mặt tái nhợt, mặc áo giáp màu xám cổ quái gắn liền thân thể. Xác nhận bị trọng thương chưa lành, nói Thiên Nghịch trên người Vương Lâm là hy vọng bình phục hoàn toàn. Phát hiện thứ mò được chỉ là Cổ Ma Hồn, thừa nhận đã xem thường Vương Lâm.","anchor":"Đúng là bổn tôn đã xem thường ngươi"},{"importance":"normal","mucCt":"ky","chuong":"@c1339","tieuDe":"Thi triển Tứ Đại Giai Không Thuật đối kháng nguyên linh Chu Tước","text":"Kinh hãi khi nguyên linh Chu Tước chân chính giáng thế, hóa ngọn lửa bảy màu thành hình Chu Tước đối kháng nhưng vừa chạm vào liền tan vỡ, phun máu. Thi triển Tứ Đại Giai Không Thuật triệu xuất bốn tầng nguyên tố Địa Thủy Hỏa Phong xếp chồng lao lên đối kháng, tu vi phát huy vượt xa Thủy Đạo Tử và Tư Mặc Tử. Sau bốn nhịp thở va chạm, bốn tầng lần lượt tan vỡ, cả hai đều bị thương. Phun máu ngấm vào mặt đất thao túng nó lao lên phá nát cơn lốc xoáy nơi nguyên linh Chu Tước xuất hiện. Bước từng bước tới Vương Lâm định giết, vung chưởng ấn lớn như mặt trời xuyên thấu vạn cổ mộc linh. Kinh hãi nhận ra Vương Lâm đang thi triển Phần Giới Cổ Tán.","anchor":"Đáng chết, lão già kia không ngờ đã truyền cho ngươi thuật này!"},{"chuong":"@c1340","importance":"normal","mucCt":"ky","tieuDe":"Xé áo giáp chí bảo đối kháng — bị Cổ Thần đánh trọng thương","text":"Xé tấm áo giáp thái cổ chí bảo (lấy từ sư tôn) khỏi thân biến thành bàn tay khổng lồ che trời, xuyên thấu hỏa khí Phần Giới Cổ Tán đánh lên chiếc ô. Tiếp tục truy kích Vương Lâm bằng nhiều chưởng ấn liên tiếp xuyên qua tu chân tinh. Bị Thuật bảo mệnh bát tinh Cổ Thần phản kích, Cổ Thần hư ảo tung quyền đánh trúng, thương thế hàng vạn năm điều dưỡng bùng phát, hoàn toàn trọng thương. Cuối cùng yếu ớt dụ dỗ Vương Lâm quy phục bằng lời hứa hồi sinh vợ con.","anchor":"Áo giáp này là lão phu lấy được từ sư tôn, là một thái cổ chí bảo"},{"chuong":"@c1341","importance":"normal","mucCt":"ky","tieuDe":"Dụ dỗ Vương Lâm bằng Trường sinh ấn","text":"Dù trọng thương thanh âm suy yếu, trực tiếp dùng điểm yếu lớn nhất đạo tâm Vương Lâm để dụ dỗ. Hứa cầu sư tôn — người cùng tề danh Viễn Cổ Tiên Tôn thời Thái Cổ — tìm sinh linh giới, giết hàng vạn người lấy hồn phách hóa Trường sinh ấn hồi sinh cả Lý Mộ Uyển và Vương Bình. Đề nghị ban ngoại hiệu Lâm Thương Tử, địa vị vượt Tư Mặc Tử, Thanh Thủy, Thanh Lâm. Thậm chí đề nghị cho tái sinh thê tử trước rồi hãy đồng ý. Cuối cùng bị Vương Lâm kiên định từ chối.","anchor":"Chỉ cần ngươi đồng ý, trở thành người của lão phu, lão phu sẽ có thể giúp ngươi làm chuyện đó!"},{"chuong":"@c1342","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm phân tích nghi ngờ danh tính: nam tử trung niên thừa nhận là Chưởng Tôn nhưng không xuất Thái Sơ Lực, khí chất không giống kiêu hùng vạn năm.","anchor":"Thanh Lâm từng nói, bổn nguyên mà Chưởng tôn tu luyện là Thái sơ lực! Nhưng người này từ đầu đến cuối không hề xuất ra một thần thông nào có liên quan đến Thái Sơ Lực"},{"importance":"normal","mucCt":"ky","chuong":"@c1378","tieuDe":"Triệu chưởng ấn che tinh vực, hé lộ Thái Cổ Ngũ Tôn","text":"Xuất hiện dưới chưởng ấn hư ảo khổng lồ che lấp toàn bộ tinh vực, toàn thân bị áo bào đen bao phủ, hình dạng mơ hồ. Cảnh báo Diệu Âm và Cửu Thiên Ma Tôn rằng đại chiến sắp bắt đầu, khuyên không nên vào cổ mộ, nhưng khi Diệu Âm hỏi liệu chắc chắn có chuyện ngoài ý muốn thì thừa nhận vẫn chưa chắc chắn. Thương thế đã khôi phục hơn phân nửa. Cuối cùng để hai người vào. Sau đó than nhẹ, hé lộ: trong Thái Cổ Ngũ Tôn có Đại Hoang cảnh giới Không Huyền, Chu Tọa, Viễn Cổ Tiên Tôn — ba người chiếm ba phần sức mạnh Thái Cổ Tinh Thần, tất cả đều đã vào cổ mộ, khiến hắn rất lo lắng.","anchor":"Hai người trong Thái cổ Ngũ Tôn, Đại Hoang cảnh giới Không Huyền, còn có Chu Tọa, Viễn cổ Tiên Tôn"},{"chuong":"@c1382","importance":"normal","mucCt":"vua","tieuDe":"Đối đầu Vương Lâm qua khe, vung chưởng thái sơ lực","text":"Lơ lửng bên ngoài khe cổ mộ dưới chưởng ấn khổng lồ, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, xin Vương Lâm thả người. Khi khe bị ép co lại, thu chưởng ấn dung nhập tay phải, vung một chưởng thái sơ lực xuyên khe đánh vào thần thức Vương Lâm, gây chấn động cổ mộ.","anchor":"lão phu là Chưởng Tôn của Thái cổ Tinh Thần"},{"mucCt":"vua","text":"Chưởng ấn tan vỡ không chút sức kháng cự, tiếng rống từ khe xuyên vào tâm thần khiến phun máu, hai chân nổ tung chỉ còn xương trắng, hắc bào rách hơn nửa. Trong hoảng sợ nhanh chóng bỏ trốn mất tung tích. Đây là lần thứ hai bị tiếng rống đẩy lui, lần đầu ở giới nội bị đẩy ngàn vạn dặm.","anchor":"như chó trong nhà có tang, trong sự hoảng sợ đang nhanh chóng bỏ trốn","bridge":true,"khoang":"@c1383"}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối đầu qua khe cổ mộ","ghiChu":"Vương Lâm ép khe đóng, Chưởng Tôn vung chưởng thái sơ lực phản kích"}],"diem":[{"text":"Tự xưng Chưởng Tôn Thái Cổ Tinh Thần, triệu chưởng ấn hư ảo khổng lồ che lấp toàn bộ tinh vực, hé lộ Thái Cổ Ngũ Tôn","chuong":"@c1378"},{"text":"Dùng thần thông Thiên Địa Thái Sơ phong ấn giết chết Chiến Tinh Dã đoạt chiến hồn, tiết lộ Thiên Đạo Kế","chuong":"@c1134"},{"text":"Luyện 108 cây Thất Thải Thần Không Đinh từ thiên thạch thần bí, liên thủ người Viễn Cổ Tiên Vực đánh trọng thương Chủ nhân Phong Giới","chuong":"@c1206"},{"text":"Hiện thân tách huyết mạch tiên nhân khỏi Vương Lâm, bị Xích Hồn Tử phá phong ấn và kinh hãi gọi người điên là Chủ trước khi bị đánh tan biến mất","chuong":"@c1492"},{"text":"Bổn tôn lần đầu bước vào giới nội, bị mũi tên xuyên thấu phải dùng tam mệnh thuật bỏ trốn","chuong":"@c1561"},{"text":"Bái kiến sư tôn đạo nhân bảy màu, lộ giao kèo với chủ nhân bí ẩn và bẩm báo thất bại","chuong":"@c1573"}]},"nguon":["@c1332","@c1334","@c1338","@c1339","@c1340","@c1341","@c1342","@c1378","@c1382","@c1383"],"aliases":["Người mặc áo đen (Thái Cổ Tinh Thần)"],"vaiTro":"Lão tổ tông Nguyệt Tộc bước thứ ba — Chưởng Tôn Thái Cổ Tinh Thần, kẻ thù chính của Vương Lâm","tinhCach":"Mưu tính thâm sâu, bày bố Thiên Đạo Kế xuyên suốt vạn năm; tàn nhẫn quyết đoán, phong ấn giết Chiến Tinh Dã đoạt chiến hồn không chút do dự; giỏi dùng lợi ích mua chuộc người khác ra tay; ngoài mạnh trong yếu, hoảng loạn sợ hãi trước tồn tại bậc cao hơn","blurb":"Chưởng Tôn là lão tổ tông Nguyệt Tộc bước thứ ba, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, cha của Thu Dao và lão tổ Phù Văn tộc, sở hữu hai luồng bản nguyên đại thành nhập đạo, một tồn tại uy thế bậc cao khiến Phù Tộc phải trốn vào Phong Giới để tránh bị khống chế. Từng luyện 108 cây Thất Thải Thần Không Đinh chuyên giết tu sĩ bước thứ ba, liên thủ với người Viễn Cổ Tiên Vực đánh trọng thương Chủ nhân Phong Giới gần tử vong, bày mưu Thiên Đạo Kế xuyên suốt nhiều đời và phát lệnh tàn sát Phong Giới tuân ý chỉ Viễn Cổ Tiên Vực. Trong nhiều lần đối đầu Vương Lâm, liên tiếp bị đánh lui và trọng thươ"},{"id":"ho-tu","name":"Hổ Tử","aliases":["Hồ Tử"],"gioiTinh":"nam","trangThai":"tu-vong","theLuc":[],"blurb":"Bạn thuở nhỏ của Tư Mã Mặc và Tiểu Lan trong ký ức hư ảo, chăm sóc hai anh em mồ côi, sau thành hôn với Tiểu Lan.","vaiTro":"Nhân vật trong mộng cảnh/ký ức gốc của Tư Mặc Tử","tinhCach":"Quan tâm chăm sóc; trọng tình nghĩa","tabs":{"diem":[{"text":"Chăm sóc anh em Tư Mã Mặc và Tiểu Lan từ nhỏ, thành hôn với Tiểu Lan","chuong":"@c1333"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1333","tieuDe":"Thành hôn với Tiểu Lan","text":"Trong ký ức hư ảo, Hổ Tử quan tâm chăm sóc hai anh em mồ côi, hôn trộm Tiểu Lan, rồi thành hôn với nàng.","anchor":"Hổ Tử mấy năm nay rất quan tâm chăm sóc chúng ta"},{"chuong":"@c1334","importance":"normal","mucCt":"gon","tieuDe":"Tử vong trong thảm kịch thôn trang","text":"Thi thể nằm bên cạnh kiệu hoa trong thôn bị mã phỉ tàn sát.","anchor":"Ca ca. ca ca, huynh mau tỉnh lại. huynh nhìn xem, nơi đó có một nhành lan tím"}],"tuViMoc":[],"nhanMach":[{"ten":"Tiểu Lan","tag":"the-thiep","quanHe":"Thê tử","ghiChu":"Thành hôn ngày thôn trang bị lửa thiêu"},{"ten":"Tư Mặc Tử","tag":"ban-be","quanHe":"Bạn thuở nhỏ","ghiChu":"Ca ca của Tiểu Lan"},{"ten":"Tiểu Lan","tag":"khac","quanHe":"Hôn thê dự kiến","ghiChu":"Cả hai đều chết trong thảm họa mã phỉ"},{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"Đồng hương","ghiChu":"Cùng thôn trang"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1333","@c1334"],"canhGioiCaoNhat":"Phàm nhân","cn":"虎子"},{"id":"hong-hong","name":"Hồng Hồng","gioiTinh":"nu","trangThai":"tu-vong","theLuc":[],"blurb":"Thiếu nữ trong thôn trang mà Tư Mã Mặc thầm thích, đã có người trong lòng nên không lấy hắn.","vaiTro":"Nhân vật phụ trong mộng cảnh/ký ức Tư Mặc Tử","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Người Tư Mã Mặc thầm thích nhưng đã có người trong lòng","chuong":"@c1333"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1333","tieuDe":"Được nhắc trong mộng cảnh","text":"Tiểu Lan nói Hồng Hồng tỷ đã có người trong lòng, Tư Mã Mặc biết mình không có cơ hội.","anchor":"Hổ Tử mấy năm nay rất quan tâm chăm sóc chúng ta"},{"chuong":"@c1334","importance":"normal","mucCt":"gon","tieuDe":"Tử vong trong thảm kịch thôn trang","text":"Thi thể bị lột trần nằm cạnh Hồ Tử sau cuộc tàn sát của mã phỉ.","anchor":"Ca ca. ca ca, huynh mau tỉnh lại. huynh nhìn xem, nơi đó có một nhành lan tím"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"Người thầm thích nàng","ghiChu":"Trong ký ức hư ảo"},{"ten":"Hồ Tử","tag":"ho-hang","quanHe":"Em trai","ghiChu":"Cả hai chết trong thảm họa mã phỉ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1333","@c1334"],"canhGioiCaoNhat":"Phàm nhân","aliases":["Hồng Hồng tỷ"],"cn":"红红"},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","tabs":{"kinhLich":[{"chuong":"@c1335","importance":"major","mucCt":"ky","tieuDe":"Giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc","text":"Ẩn náu cùng Hứa Lập Quốc trên tinh cầu hoang dã vùng đất Điên Lạc, bị Hỏa Tước tộc tìm thấy và bắt sau ác chiến. Giả dạng Chu Tước đời thứ sáu đang bế quan chữa thương, toát khí thế nhất đại tông sư, mắng Hỏa Tước tộc đánh lén. Vượt qua mọi kiểm tra của lão tổ Hỏa Tước tộc: rút máu tươi, nuốt tiên huyết, Sưu Hồn Thuật kiểm ký ức — tất cả đều bị lừa. Bị cuốn đi về tổng bộ Hỏa Tước tộc, đạo thuật cực kỳ cao minh.","anchor":"Đạo thuật của Lưu Kim Bưu này quả nhiên cao minh, ngay cả lão tổ của Hỏa Tước tộc cũng bị lừa"},{"chuong":"@c1337","importance":"normal","mucCt":"ky","tieuDe":"Bị đưa vào thánh địa Hỏa Tước tộc gặp chủ nhân bí ẩn","text":"Bị lão tổ Hỏa Tước tộc mang về thánh địa trên Hỏa Tước tinh, đóng giả Chu Tước đời thứ sáu. Thấy lão tổ bước thứ ba quỳ gối gọi chủ nhân thì hoàn toàn thức tỉnh, hết dám diễn vai. Bị chủ nhân bí ẩn trong ngọn lửa bảy màu nhận ra không phải Chu Tước đời thứ sáu, bị sợi tơ cuốn vào cơ thể rút máu và sức sống. Trong lúc nguy cấp phun tinh khí giải phóng Hứa Lập Quốc.","anchor":"da đầu Lưu Kim Bưu tê rần, mắt hắn lộ ra vẻ rung động"},{"chuong":"@c1338","importance":"bridge","mucCt":"gon","text":"Bị vô số sợi tơ quấn quanh trong thánh địa, được Vương Lâm cứu bằng bàn tay lửa kết hợp lôi đình đưa vào không gian trữ vật.","anchor":"đem Lưu kim Bưu đang giãy giụa giữa vô số những xúc tu, đưa vào bên trong không gian trữ vật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dùng ngọc giản chứa khí tức Toái Niết phá tan hộ sơn đại trận Thiên Cương Tông để tống tiền","chuong":"@c1158"},{"text":"Lừa gạt Quy Nguyên Tông bằng thực lực giả Toái Niết, bị Vương Lâm truy kích và mất sạch bảo vật ngọc bội cùng ngọc giản","chuong":"@c1198"},{"text":"Bị Hứa Lập Quốc tra tấn đến tiều tụy, tự thú đạo lừa đảo đã ăn mòn ký ức và nguyên thần của chính mình","chuong":"@c1302"},{"text":"Giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc, bị đưa vào thánh địa rồi được Vương Lâm cứu thoát","chuong":"@c1335"},{"text":"Bị Vương Lâm tước tự do, đánh bắn đi và bắt làm nô bộc ngàn năm","chuong":"@c1474"},{"text":"Thuật lừa đảo của lão được Vương Lâm học hỏi và sử dụng để tự lừa gạt bản thân trong Mộng Đạo suốt bảy mươi năm","chuong":"@c1519"}]},"nguon":["@c1335","@c1337","@c1338"],"trangThai":"song","cn":"刘金宝","gioiTinh":"nam","vaiTro":"Kẻ lừa đảo kỳ cựu chuyên tống tiền phân tông yếu, sau trở thành tốt thí và nô bộc của Vương Lâm","tinhCach":"Xảo quyệt, mỗi ngàn năm đổi tên một lần để tránh bị truy cứu; Tính toán kỹ lưỡng, điều tra tiểu sử nạn nhân trước khi hành động; Giả mạo thực lực, dùng ngọc giản khí tức Toái Niết che giấu tu vi thật chỉ Âm Hư; Đạo lừa đảo ăn sâu đến mức tự lừa gạt bản thân, ký ức và nguyên thần đều bị ảnh hưởng","blurb":"Lưu Kim Bưu, đạo hiệu Kim Bưu Tử, là tên lừa đảo lão luyện chuyên đổi tên mỗi kỳ đại hội ngàn năm, nhắm vào các phân tông suy yếu sắp giải tán để tống tiền bằng ngọc giản phát khí tức giả Toái Niết dù tu vi thực chỉ ở tầng Âm Hư. Sau khi lừa gạt Quy Nguyên Tông, lão bị Vương Lâm truy kích, mất sạch bảo vật, rồi sa vào tay Hứa Lập Quốc bị tra tấn đến tiều tụy và tự thú đạo lừa đảo đã ăn mòn cả ký ức lẫn nguyên thần. Về sau lão bị buộc giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc, rơi vào hiểm cảnh trong thánh địa và được Vương Lâm cứu thoát, cuối cùng bị tước tự do bắt làm nô bộc ngàn "},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","tabs":{"kinhLich":[{"chuong":"@c1335","importance":"normal","mucCt":"vua","tieuDe":"Ẩn náu cùng Lưu Kim Bưu tại Điên Lạc","text":"Linh hồn thủ hộ, ẩn náu cùng Lưu Kim Bưu ở chỗ sâu nhất trên tinh cầu hoang dã trong vùng đất Điên Lạc. Bị Hỏa Tước tộc lùng sục.","anchor":"Lưu Kim Bưu cùng với linh hồn thủ hộ Hứa Lập Quốc đang ẩn náu ở chỗ sâu nhất trên tinh cầu hoang dã"},{"mucCt":"vua","text":"Ẩn trong tinh khí của Lưu Kim Bưu, khi nguy cấp liền xuất hiện biến hóa thành thanh đại kiếm tạo cơn lốc kiếm, tuyên bố thông đạo đã mở. Hồn bay phách tán, tâm thần kịch chấn, trong lòng gào thét oán Vương Lâm đã sắp đặt mọi chuyện.","anchor":"Chủ nhân, thông đạo đã mở!","bridge":true,"khoang":"@c1337"},{"chuong":"@c1338","importance":"bridge","mucCt":"vua","text":"Hoảng sợ gào thét cầu cứu Vương Lâm khi Lưu Kim Bưu bị xúc tu quấn, được Vương Lâm dùng lôi đình và lửa chín màu cuốn đưa vào không gian trữ vật.","anchor":"vội vàng gọi Vương Lâm tới"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc và ép luyện thành Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan","chuong":"@c0112"},{"text":"Cản đòn bảo vệ thân thể Vương Lâm trước người khổng lồ băng tuyết, kiệt sức suýt tan rã","chuong":"@c0338"},{"text":"Phản chủ bẻ kiếm chém đứt cánh tay trái Cự Ma lão tổ rồi quay về theo Vương Lâm","chuong":"@c0373"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm","chuong":"@c0596"},{"text":"Bị giam trong lốc xoáy lửa suốt ba năm, liên tục kháng cự khiến thực lực tăng mạnh","chuong":"@c1018"},{"text":"Được thả ra tại Thiểm Lôi Tộc, thu phục gần trăm tu sĩ và sống kiểu đế vương trước khi bị truy sát rồi Vương Lâm thu hồi","chuong":"@c1256"}]},"nguon":["@c1335","@c1337","@c1338"],"trangThai":"song","cn":"许立国","gioiTinh":"nam","vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm hồn, kiếm linh đời thứ nhất của Vũ tiên kiếm","tinhCach":"Kiêu ngạo hay lải nhải, thường xuyên đòi đảo ngược thân phận chủ tớ; thực dụng biết tự bảo toàn, dao động giữa phản chủ và lập công tùy tình thế; si mê nữ sắc, dễ mất bình tĩnh trước mỹ nhân; bản tính nhát gan nhưng khi bị dồn ép có thể liều mạng","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc và ép luyện nguyên thần thành Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan. Từ đó hắn trở thành ma đầu duy nhất được Vương Lâm giữ lại, lần lượt ẩn trong đám du hồn, nhập tiên kiếm làm kiếm hồn, rồi được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ mà trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Dù miệng liên tục đòi tự do và nhiều lần dao động ý phản chủ, Hứa Lập Quốc vẫn theo Vương Lâm xông pha vô số trận chiến — từng bị giam luyện trong lốc xoáy lửa ba năm khiến thực lực "},{"id":"lao-to-hoa-tuoc-toc","name":"Lão tổ Hỏa Tước tộc","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Lão tổ Hỏa Tước tộc là cường giả bước thứ ba giới ngoại, tu luyện ẩn cư trong biển lửa tím nơi thánh địa chủ tinh Hỏa Tước. Ông từng rời thánh địa truy tìm nguồn gốc huyết mạch Chu Tước tại Điên Lạc, bắt Lưu Kim Bưu đưa về kiểm chứng nhưng bị lừa nhận giả Chu Tước, sau đó còn bị trọng thương khi cánh cửa thánh địa sụp đổ. Trong cuộc đại chiến phá Phong Giới Đại Trận, ông dẫn đầu giới ngoại xông trận, hợp chiến Hồng Sam Tử cùng bốn tu sĩ bước thứ ba khác, và là người đầu tiên thoát khỏi vòng cầm chân nhưng bị Khai Thiên Phủ chẻ đôi tử trận.","vaiTro":"Lão tổ Hỏa Tước tộc — cao thủ bước thứ ba giới ngoại, trưởng bối tối cao của Hỏa Tước tộc","tinhCach":"Uy nghiêm và nghiêm khắc với tộc nhân; cẩn trọng đa nghi khi kiểm chứng huyết mạch Chu Tước; sát phạt quyết đoán trên chiến trường; trung thành tuyệt đối với tộc ấn và sứ mệnh Hỏa Tước tộc","tabs":{"diem":[{"text":"Tu luyện trong biển lửa tím thánh địa chủ tinh Hỏa Tước, trách phạt tộc trưởng vì tự ti, thể hiện uy nghiêm trưởng bối","chuong":"@c1304"},{"text":"Truy tìm huyết mạch Chu Tước tại Điên Lạc, bắt Lưu Kim Bưu và kiểm tra nhiều lần nhưng bị lừa nhận giả Chu Tước","chuong":"@c1335"},{"text":"Thi triển Súc Địa Thành Thốn mang Lưu Kim Bưu về thánh địa, quỳ gối trước cánh cửa hư ảo gọi chủ","chuong":"@c1337"},{"text":"Bị mảnh vỡ cánh cửa thánh địa sụp đổ đâm trúng, phun máu trọng thương","chuong":"@c1340"},{"text":"Dẫn đầu giới ngoại xông vào khe Phong Giới Đại Trận, phóng tộc ấn Hỏa Tước Tộc hóa hỏa điểu đen","chuong":"@c1425"},{"text":"Tử trận khi bị Khai Thiên Phủ chẻ đôi — là người đầu tiên thoát vòng cầm chân Hồng Sam Tử, toàn thân bao phủ ngọn lửa đen","chuong":"@c1431"}],"kinhLich":[{"chuong":"@c1335","importance":"normal","mucCt":"ky","tieuDe":"Bắt Lưu Kim Bưu, bị lừa nhận giả Chu Tước","text":"Đứng ngoài vùng đất Điên Lạc chờ tộc nhân đưa Lưu Kim Bưu ra. Kiểm tra nhiều lần: ép rút máu tươi, nuốt tiên huyết khiến hỏa điểu sau lưng nuốt hình ảnh Chu Tước nhỏ bị trọng thương và biến hóa ngày càng giống Chu Tước. Thi triển Sưu Hồn Thuật đặt tay lên thiên linh đối phương quét ký ức, xác nhận đối phương là Chu Tước đời thứ sáu. Cuốn Lưu Kim Bưu bay về tổng bộ Hỏa Tước tộc.","anchor":"tất cả mọi thứ trong trời đất đều là giả tạo, chỉ có Sưu Hồn Thuật này mới là chân thực nhất"},{"mucCt":"vua","text":"Thi triển Súc Địa Thành Thốn mang Lưu Kim Bưu về thánh địa Hỏa Tước tinh. Quỳ gối trước cánh cửa hư ảo gọi chủ nhân, dâng Lưu Kim Bưu đóng giả Chu Tước đời thứ sáu. Được chủ nhân ban ngọn lửa bảy màu bằng nắm tay dung nhập mi tâm làm phần thưởng, cung kính rút lui.","anchor":"lão tổ này ở trong tinh không vặn vẹo, một bước phóng tới, trong mắt lộ ra vẻ vui mừng điên cuồng","bridge":true,"khoang":"@c1337"},{"mucCt":"gon","text":"Đang khoanh chân ngồi ngoài cửa thánh địa, bị mảnh vỡ từ cánh cửa sụp đổ đâm trúng, phun máu trọng thương.","anchor":"lão tổ của Hỏa Tước tộc đang khoanh chân ngồi, mở mạnh hai mắt, lộ ra vẻ kinh ngạc","bridge":true,"khoang":"@c1340"}],"tuViMoc":[],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"khac","quanHe":"Tưởng là Chu Tước đời thứ sáu, thực ra bị lừa","ghiChu":"Bắt được và kiểm tra, xác nhận sai thân phận @c1335"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1335","@c1337","@c1340"]},{"id":"chung-dai-hong","name":"Chung Đại Hồng","tabs":{"kinhLich":[{"chuong":"@c1335","importance":"minor","mucCt":"gon","text":"Vương Lâm nhờ Lão Chu Tước chiếu cố, đang ở vùng đất Điên Lạc.","anchor":"trong vùng đất Điên Lạc vãn bối còn có một thuộc hạ, người này tên là Chung Đại Hồng"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ nhân","ghiChu":"Thuộc hạ của Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Chứng kiến Vương Lâm phế tứ đại trưởng lão Thiên Lôi Tông, lập tức chuyển từ hoảng sợ sang cuồng nhiệt sùng bái, dùng kỹ thuật nịnh hót để bảo toàn tính mạng và xin làm tôi tớ","chuong":"@c1255"},{"text":"Được Vương Lâm ban đan dược và một thanh phi kiếm, nhờ đó chiến lực ngang Hóa Thần trung kỳ","chuong":"@c1256"},{"text":"Dẫn đường tại Lôi Tinh Điện, giới thiệu quy củ và ba cửa đông/nam/tây cho Vương Lâm","chuong":"@c1259"},{"text":"Dò được tin đan dược có giá trị cao tại tu chân tinh và giao dịch con rối, nhưng bị thương dẫn họa về cho chủ","chuong":"@c1285"},{"text":"Được Vương Lâm chỉ định làm người đại diện, nắm quyền chỉ huy hơn ngàn tu sĩ trong lúc chủ rời đi","chuong":"@c1297"},{"text":"Ỷ thế Vương Lâm, kiêu ngạo cáo oai qua lại giữa Ám Hạt Tộc và Vân Độn tộc, ép tu sĩ hai tộc chữa thương và dâng lễ vật","chuong":"@c1301"}]},"nguon":["@c1335"],"trangThai":"song","vaiTro":"Tu sĩ Hóa Thần Thiên Lôi Tông, tôi tớ cuồng tín của Vương Lâm","tinhCach":"Cuồng nhiệt sùng bái cường giả, chuyển hoảng sợ thành phục tùng cực nhanh; nịnh hót khéo léo, thức thời tự bảo toàn; ỷ thế chủ nhân mà kiêu ngạo cáo oai với kẻ yếu","blurb":"Chung Đại Hồng là tu sĩ Hóa Thần sơ kỳ thuộc Thiên Lôi Tông, tướng mạo gầy gò xấu xí. Sau khi chứng kiến Vương Lâm phế tứ đại trưởng lão, hắn lập tức quy phục, dâng hết pháp bảo xin làm tôi tớ và được ban đan dược cùng phi kiếm, chiến lực nhờ đó tăng ngang Hóa Thần trung kỳ. Từ đó hắn dẫn đường tại Lôi Tinh Điện, dò tin tức, tận lực hầu hạ chủ nhân, thậm chí được Vương Lâm ủy quyền chỉ huy hơn ngàn tu sĩ, đồng thời ỷ vào uy danh chủ mà cáo oai qua lại giữa Ám Hạt Tộc và Vân Độn tộc.","gioiTinh":"nam"},{"id":"vien-co-tien-ton","name":"Viễn Cổ Tiên Tôn","cn":"","aliases":["Viễn Cổ Tiên Hoàng"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1336","text":"Được Lão Chu Tước nhắc đến: năm xưa học trộm Phần Giới Cổ Tán, ở quê hương dùng thuật mở ô tám lần hủy diệt vạn người một giới, lần thứ chín không dám mở.","anchor":"Viễn Cổ tiên tôn năm đó đã học trộm mà thành"},{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1378","text":"Được nhắc là một trong Thái Cổ Ngũ Tôn, đã tiến vào cổ mộ, chiếm một phần sức mạnh Thái Cổ Tinh Thần.","anchor":"Hai người trong Thái cổ Ngũ Tôn, Đại Hoang cảnh giới Không Huyền, còn có Chu Tọa, Viễn cổ Tiên Tôn"}],"diem":[{"text":"Chủ thượng của tứ đại chiến tướng, trong đó có Chu Tước lão tổ","chuong":"@c1311"},{"text":"Từng bảo vệ lão tổ Chu Tước đời đầu khi vượt qua nghiệp kiếp","chuong":"@c1317"},{"text":"Học trộm Phần Giới Cổ Tán, tại quê hương dùng thuật mở ô tám lần gây hủy diệt","chuong":"@c1336"},{"text":"Một trong Thái Cổ Ngũ Tôn, đã tiến vào cổ mộ chiếm một phần sức mạnh Thái Cổ Tinh Thần","chuong":"@c1378"}]},"nguon":["@c1336","@c1378"],"gioiTinh":"nam","vaiTro":"Chủ thượng viễn cổ — một trong Thái Cổ Ngũ Tôn, thống lĩnh tứ đại chiến tướng","blurb":"Viễn cổ tiên tôn là một trong Thái Cổ Ngũ Tôn, chủ thượng của tứ đại chiến tướng trong đó có Chu Tước lão tổ. Từng bảo vệ lão tổ Chu Tước đời đầu khi vượt qua nghiệp kiếp, và đã tiến vào cổ mộ chiếm một phần sức mạnh Thái Cổ Tinh Thần. Năm xưa từng học trộm Phần Giới Cổ Tán, tại quê hương dùng thuật này mở ô tám lần gây hủy diệt."},{"id":"than-anh-bi-an-ngon-lua-bay-mau","name":"Thân ảnh bí ẩn trong ngọn lửa bảy màu","cn":"","aliases":["Chủ nhân Hỏa Tước tộc","Tam đại nghiệt tước"],"gioiTinh":"nam","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (mạnh hơn bước thứ ba)","trangThai":"song","blurb":"Thân ảnh bí ẩn ngồi sâu trong ngọn lửa bảy màu tại thánh địa Hỏa Tước tộc, toàn thân phủ khôi giáp, sau lưng hiện hình Chu Tước bóng ảnh. Thực lực vượt trên bước thứ ba, từng bị Chu Tước đời đầu cùng tu sĩ thần bí đánh trọng thương, phải bế quan trị thương vài ngàn năm, song vẫn âm thầm thao túng cục diện Thái Cổ Tinh Thần từ hậu trường.","vaiTro":"Kẻ bí ẩn thao túng hậu trường Thái Cổ — chủ nhân Hỏa Tước tộc, Tam đại nghiệt tước","tinhCach":"Quyền uy tuyệt đối, sai khiến lão tổ bước thứ ba làm nô bộc; nhẫn nại bố cục, bế quan trị thương hàng ngàn năm vẫn duy trì thao túng","tabs":{"diem":[{"text":"Lộ diện tại thánh địa Hỏa Tước tộc: ngồi khoanh chân trong ngọn lửa bảy màu, toàn thân như mặc khôi giáp, sau lưng hiện Chu Tước bóng ảnh","chuong":"@c1337"}],"kinhLich":[{"chuong":"@c1337","importance":"major","mucCt":"ky","tieuDe":"Lộ diện trong thánh địa Hỏa Tước tộc","text":"Ngồi khoanh chân sâu trong ngọn lửa bảy màu tại thánh địa, toàn thân như mặc khôi giáp, sau lưng có Chu Tước bảy màu lấp lánh. Nhận ra Lưu Kim Bưu không phải Chu Tước đời thứ sáu, dùng sợi tơ rút máu và sức sống của hắn. Khen Hứa Lập Quốc thông minh khi mở thông đạo. Xung quanh là mạng lưới sợi tơ giống mạng nhện, vô số đốm sáng theo thông đạo bay về ngọn lửa trung tâm bị hấp thụ.","anchor":"thân ảnh này toàn thân giống như mặc khôi giáp, sau lưng còn có một con Chu Tước bảy màu lấp lánh"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão tổ Hỏa Tước tộc","tag":"khac","quanHe":"Nô bộc phục tùng","ghiChu":"Lão tổ bước thứ ba quỳ gối gọi chủ nhân"},{"ten":"Lưu Kim Bưu","tag":"khac","quanHe":"Nạn nhân bị rút sức sống","ghiChu":"Nhận ra không phải Chu Tước đời thứ sáu, dùng sợi tơ rút máu"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù — mục tiêu bị tấn công","ghiChu":"Vương Lâm lên kế hoạch tấn công lúc đang trị thương"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1337"]},{"id":"thien-van-tu","name":"Thiên Vận Tử","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1337","importance":"bridge","mucCt":"gon","text":"Hồn phách đang bị Vương Lâm tìm kiếm trong Hô Phong Hoán Vũ giới để dung nhập vào thể xác và tinh thần.","anchor":"tâm thần dung nhập vào trong Hô Phong Hoán Vũ giới tìm kiếm hồn phách của Thiên Vận Tử"},{"mucCt":"vua","text":"Tiết lộ Vương Lâm trước khi tới thánh địa Hỏa Tước tộc đã dung hợp hồn Thiên Vân Tử, triển khai kế hoạch điên cuồng giống trận chiến năm xưa với Thủy Đạo Tử.","anchor":"Trước khi hắn tới đây đã dung hợp với hồn của Thiên Vân Tử, triển khai một kế hoạch điên cuồng","bridge":true,"khoang":"@c1338"},{"importance":"bridge","mucCt":"gon","chuong":"@c1345","text":"Được Vương Lâm phân thần thức dung nhập vào trước đó để tính toán hướng đi, mơ hồ chỉ dẫn hướng có ích lợi vô cùng.","anchor":"hắn trước khi bỏ chạy đã phân thần thức ra dung nhập vào Thiên Vận Tử, mơ hồ tính ra là nên chạy theo hướng này"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Cưỡi tảng đá như sao băng qua Chu Tước tinh, cứu Vương Lâm khỏi cảm ngộ thiên đạo luân hồi suýt lạc vào nguy hiểm","chuong":"@c0241"},{"text":"Tổ chức đại thọ vạn năm trên Thiên Vận Tinh, giảng đạo phân tu đạo làm ba bước và nhận Vương Lâm làm đệ tử chân chính, mở tâm thần cho tự chọn thần thông","chuong":"@c0472"},{"text":"Bố cục hàng trăm năm cho kế hoạch Đông Hải Yêu Linh, sử dụng lạc ấn đặt trên Vương Lâm làm then chốt tính toán","chuong":"@c0552"},{"text":"Lần lượt mở hai đạo phong ấn mi tâm, giải phóng tu vi Thiên Nhân nhất suy rồi nhị suy để quyết chiến với Vương Lâm","chuong":"@c1012"},{"text":"Linh hồn bị Vương Lâm thu vào Phong Tiên Ấn, nhiều lần bị dung hợp để tính toán thiên cơ và thi triển chiến hồn","chuong":"@c1197"},{"text":"Tái xuất tại Triệu Hà tinh vực tuyên bố đại kế bắt đầu, ẩn thân khiến Vương Lâm đạt Không Linh trung kỳ vẫn cực kỳ kiêng kỵ","chuong":"@c1531"}]},"nguon":["@c1337","@c1338","@c1345","@c1346","@c1362"],"cn":"天运子","gioiTinh":"nam","aliases":["Thiên Vân Tử"],"vaiTro":"Chưởng môn Thiên Vận Tông — sư tôn của Vương Lâm, thành viên Liên Minh Trưởng Lão Đoàn","tinhCach":"Toan tính sâu xa, bố cục hàng trăm năm và suy tính thiên cơ bằng la bàn đen trắng; uy nghi điềm tĩnh khi giảng đạo và chủ trì đại sự, thản nhiên trước biến cố; cứng rắn quyết liệt trước cường địch, sẵn sàng tự phá phong ấn đánh đổi tất cả; che giấu dã tâm dưới vẻ hòa ái với đệ tử, bản chất là kẻ lợi","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông kiêm thành viên Liên Minh Trưởng Lão Đoàn, đại cường giả tu vi thực tế vượt Hóa Thần với ba đạo phong ấn phong tỏa cảnh giới Thiên Nhân, sở hữu huyết tinh sát khí cực mạnh và thần thông bảy màu độc đáo. Ông từng cứu Vương Lâm khỏi cảm ngộ thiên đạo luân hồi, tổ chức đại thọ vạn năm giảng đạo ba bước, nhận Vương Lâm làm đệ tử chân chính và mở tâm thần cho tự chọn thần thông, nhưng đồng thời ngầm bố cục lên Vương Lâm qua lạc ấn và kế hoạch Đông Hải Yêu Linh kéo dài hàng trăm năm. Tới các mốc sau cùng, Thiên Vận Tử lần lượt mở hai đạo phong ấn giải phóng "},{"id":"vuong-binh","name":"Vương Bình","cn":"王平","aliases":["Bình Nhi"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Chưởng Tôn hứa có thể hồi sinh cả con trai duy nhất của Vương Lâm, Vương Lâm cuối chương xin Bình Nhi đừng trách.","anchor":"ngay cả đứa con trai độc nhất của ngươi cũng có thể hồi sinh"},{"chuong":"@c1342","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc tới trong lời thì thào nhớ nhà, muốn dạy nó khắc tượng gỗ kế thừa kỹ thuật phụ thân.","anchor":"Ta còn muốn dạy Bình Nhi khắc tượng gỗ, đem kỹ thuật của phụ thân truyền cho nó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Thành hình trong màn sương đen dưới dạng oán ảnh do Liễu Mi luyện hóa trăm năm, cắn hút máu Vương Lâm nhưng được hắn nhận làm huyết mạch ruột thịt","chuong":"@c0636"},{"text":"Nhiều lần khẩn cầu phụ thân cho tu đạo nhưng đều bị cấm; Vương Lâm muốn hắn sống trọn kiếp phàm nhân thay vì bước vào tu chân giới","chuong":"@c0646"},{"text":"Từ thủ lĩnh Thiên Hành phái trở thành quân chủ Thiên Hành đế quốc, đạt đến chí tôn trong thế giới phàm nhân","chuong":"@c0652"},{"text":"Cuối đời tha thứ mọi sự, tiếp tục khắc tượng phụ thân và thừa nhận nếu có kiếp sau chỉ muốn cùng Vương Lâm sống bên nhau","chuong":"@c0654"},{"text":"Bị Lôi Đạo Tử dùng thần thông nhìn thấu thân phận oán anh, tự xâu chuỗi chân tướng rồi tan thành hồn tức, nhập vào Thiên Nghịch Châu","chuong":"@c0659"},{"text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"}]},"nguon":["@c1341","@c1342"],"vaiTro":"Con trai duy nhất của Vương Lâm — oán anh được sống trọn một đời phàm nhân","tinhCach":"hiếu thuận sâu sắc, nhiều lần khẩn cầu tu đạo dù bị cha cấm; trầm ổn trước hiểm nguy, không hoảng loạn khi đối diện thần thông của Lôi Đạo Tử; biết tha thứ và trân trọng tình phụ tử đến tận cuối đời","blurb":"Vương Bình vốn là oán anh do Liễu Mi luyện hóa trăm năm trong màn sương đen trên Nhiễm Vân Tinh, sau được Vương Lâm nhận là huyết mạch ruột thịt và đưa về thôn Lạc Nguyệt nuôi dưỡng như con phàm. Hắn sống trọn một đời người bên phụ thân — uống đan dược, học điêu khắc, du ngoạn sơn xuyên, gây dựng Thiên Hành đế quốc — rồi cuối đời bị Lôi Đạo Tử nhìn thấu thân phận oán anh mà tan thành hồn tức, từ đó tồn tại bên trong Thiên Nghịch Châu và trở thành nỗi day dứt không nguôi trong tâm thần Vương Lâm suốt nhiều năm về sau."},{"id":"tu-do-nam","name":"Tư Đồ Nam","cn":"司徒南","gioiTinh":"nam","tabs":{"kinhLich":[{"mucCt":"ky","text":"Được Vương Lâm hồi tưởng như ân nhân lớn nhất: bỏ qua khả năng lấy Thiên Nghịch, theo hắn mấy trăm năm từ nhỏ dạy tu đạo, như sư phụ sư huynh.","anchor":"Cả đời Vương Lâm ta, không quỳ trước trời đất, chỉ kính Tư Đồ!","bridge":true,"khoang":"@c1341"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Tiết lộ danh tính cường giả lục cấp Chu Tước Quốc, tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu của Vương Lâm sau khi bị truy sát thân hủy","chuong":"@c0047"},{"text":"Được lửa Chu Tước đánh thức, đoạt xá thành công thân xác đồng tử áo đỏ, nuốt tứ tổ Tiên Di Tộc đạt Vấn Đỉnh Kỳ","chuong":"@c0401"},{"text":"Tu vi đạt Tịnh Niết sơ kỳ, dùng thần thức quét ngang chấn động Thủy Linh tinh, hội ngộ Vương Lâm","chuong":"@c0932"},{"text":"Bái Thanh Lâm làm sư phụ tại Vũ Tiên Giới với điều kiện không bị hạn chế tự do","chuong":"@c1050"},{"text":"Được Thanh Lâm trợ giúp phá Không Môn, chính thức đột phá bước thứ ba, tử chiến bảo vệ Chu Tước Tinh","chuong":"@c1520"},{"text":"Dẫn mấy ngàn tu sĩ theo Vương Lâm xuất chinh tinh không, bảo vệ lực lượng giới nội trong đại chiến","chuong":"@c1556"}]},"nguon":["@c1341"],"vaiTro":"Thế lực ẩn — cường giả lục cấp Chu Tước Quốc, huynh trưởng và ân nhân lớn nhất của Vương Lâm","tinhCach":"Kiêu ngạo bất kính, hành xử ngang tàng không kiêng nể; tàn độc quyết đoán, chủ trương diệt địch tận gốc; trọng tình nghĩa với Vương Lâm, sẵn sàng xả thân tương trợ; thận trọng toan tính lâu dài nhưng dễ mất kiên nhẫn","blurb":"Tư Đồ Nam vốn là đệ nhất cao thủ lục cấp tu chân quốc Chu Tước, bị kẻ địch từ thất cấp tu chân quốc truy sát đến thân hủy, chỉ còn tinh hoa Nguyên Anh ẩn náu trong Thiên Nghịch Châu của Vương Lâm suốt hàng trăm năm, dẫn dắt hắn từ thuở nhỏ. Sau khi được lửa Chu Tước đánh thức, ông đoạt xá thành công thân xác đồng tử áo đỏ, nuốt tứ tổ Tiên Di Tộc đạt Vấn Đỉnh Kỳ rồi tu luyện tới Tịnh Niết sơ kỳ, gây họa khắp tinh vực và bị Loan Phượng tinh truy nã, nhưng luôn quay về bên Vương Lâm trong những lúc nguy cấp nhất. Tại Vũ Tiên Giới, ông được Thanh Lâm thu nhận làm đệ tử với điều kiện không bị hạn c"},{"id":"thanh-thuy","name":"Thanh Thủy","cn":"青水","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhớ lại như sư huynh mặt lạnh lòng ấm, thừa nhận Vương Lâm là truyền nhân sư tôn Bạch Phàm, bất chấp tất cả bảo vệ, thê tử bị giết do âm mưu giới ngoại khiến hắn phát điên.","anchor":"Hắn là sư đệ của bổn quân, người khác không được làm tổn thương hắn"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lai lịch thái tử Thanh Thủy Quốc, phi thăng Tiên giới rồi trở thành sát tinh Lôi Giới, sau tỉnh ngộ mà tự phong ấn tu vi","chuong":"@c0746"},{"text":"Dùng Cực Cảnh đồ diệt đại bộ phận tu sĩ Sát Vực Giới, giết Thần Ma Tử","chuong":"@c0894"},{"text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá Không Môn, đột phá Không Niết Sơ Kỳ","chuong":"@c1467"},{"text":"Sát lục đại thành, ôm hồn phách thê tử hóa ấn ký đặt tại trái tim, tặng Vương Lâm sát lục kiếm rồi điên cuồng sát phạt tiến vào Triệu Hà","chuong":"@c1468"},{"text":"Hóa thân thành Vương Lâm trấn thủ đài chiến, bị Hư Thần Thiên Tôn trọng thương gần chết","chuong":"@c1516"},{"text":"Được Vương Lâm xua độc tố cứu chữa khỏi cận tử, xác nhận nữ nhi còn sống và khuyên nàng đuổi theo Vương Lâm","chuong":"@c1562"}]},"nguon":["@c1341"],"vaiTro":"Tiên quân Cực Cảnh — sư huynh đồng môn Bạch Phàm, bảo hộ và truyền thừa cho Vương Lâm","tinhCach":"trọng tình nghĩa đồng môn, nguyện xả thân bảo hộ truyền nhân; sát phạt quyết liệt, không nương tay với kẻ địch; thận trọng đa nghi, không dễ tin người; biết tự tỉnh sau sát nghiệp, từng tự phong ấn vì hối hận","blurb":"Thanh Thủy Tiên Quân vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới, sau khi cố quốc bị diệt vong đã bảy ngày đẫm máu báo thù rồi phi thăng lên Tiên giới, trở thành sát tinh khét tiếng tại Lôi Giới; về sau tỉnh ngộ trước sát nghiệp mà tự phong ấn tu vi. Với tư cách sư huynh cùng sư môn Bạch Phàm, ông nhiều lần hiện thân bảo hộ Vương Lâm, truyền thừa các tiên thuật Hoán Vũ, Tát Đậu Thành Binh, U Minh Dẫn Lộ cùng quy tắc, giao chiến Huyết Thần Tử và Huyền Bảo thượng nhân, dùng Cực Cảnh đồ diệt Sát Vực Giới. Sau biến cố trong cõi hư vô phong ấn tự mở và tu vi khôi phục, ông đột phá K"},{"id":"chu-dat","name":"Chu Dật","cn":"朱逸","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhớ lại: cả đời si tình Thanh Sương, đã cho Vương Lâm cơ hội sinh tử giúp tránh kiếp nạn.","anchor":"Cả đời Chu Dật ta chỉ muốn làm một việc, đó là cùng với Thanh Sương gắn bó mãi mãi."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lộ diện tại đáy động tầng 2 với tư cách đại trưởng lão Thi Âm Tông, tiết lộ lai lịch đệ tử Ngũ Hành Tông từ Chu Tước tinh, mang theo nữ thi tiên nhân Đình Nhi","chuong":"@c0288"},{"text":"Thiêu đốt Nguyên Thần cứu Đình Nhi, đột phá Vấn Đỉnh kỳ nhờ hạt châu đỏ ngay trước khi thân thể cháy tàn, giao phó Vũ Chi Tiên Kiếm và di nguyện cho Vương Lâm rồi Nguyên Thần nhập kiếm thành Kiếm Tiêu Chi Hồn","chuong":"@c0293"},{"text":"Bị phong ấn hàng trăm năm trong Luyện Tiên Hóa Ma đại trận, linh thể chỉ còn tàn dư nhưng vẫn không khuất phục, cuối cùng được giải cứu","chuong":"@c0594"},{"text":"Hóa kiếm quang đánh thẳng vào Hư Không Tử dẫn phát thương thế cũ của đối phương, bản thân linh thể hao tổn nghiêm trọng","chuong":"@c0991"},{"text":"Nhìn thấy Thanh Sương thì thần sắc nhu hòa không rời mắt, nhưng bị nàng phủ nhận và quên lãng; vẫn lặng lẽ thủ hộ băng sơn Thanh Sương với thần sắc chua xót bi thương","chuong":"@c1046"},{"text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"}]},"nguon":["@c1341"],"vaiTro":"Phụ — si tình kiếm tu, Kiếm Tiêu Chi Hồn của Vũ Chi Tiên Kiếm, ân nhân giao phó di sản cho Vương Lâm","tinhCach":"Si tình đến cùng cực, nhiều lần thiêu đốt Nguyên Thần vì Đình Nhi và lặng lẽ thủ hộ Thanh Sương dù bị phủ nhận quên lãng; trọng nghĩa khí, tận lực trợ chiến và bảo hộ Vương Lâm xuyên suốt không tính toán; kiên nghị bất khuất, chịu phong ấn hàng trăm năm trong Luyện Tiên Hóa Ma đại trận vẫn không khu","blurb":"Chu Dật vốn là đệ tử tư chất xuất sắc của Ngũ Hành Tông trên Chu Tước tinh, về sau trở thành đại trưởng lão Thi Âm Tông, suốt đời mang theo nữ thi tiên nhân Đình Nhi bên mình. Vì cứu Đình Nhi, y nhiều lần thiêu đốt Nguyên Thần, đột phá Vấn Đỉnh kỳ ngay trước lúc thân thể cháy tàn rồi giao phó Vũ Chi Tiên Kiếm cùng di nguyện cho Vương Lâm; Nguyên Thần nhập kiếm trở thành Kiếm Tiêu Chi Hồn, y tiếp tục đồng hành trợ chiến xuyên suốt hành trình Vương Lâm — từ Triều Tịch vực, qua Yêu Linh chi địa đến Vũ Tiên Giới — chịu đựng cả bi kịch bị Thanh Sương phủ nhận và quên lãng mà vẫn lặng lẽ thủ hộ."},{"id":"chu-tuoc-doi-thu-hai","name":"Chu Tước đời thứ hai","cn":"","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhớ lại: tiếng cười sang sảng, bắt rồng lấy máu, nhiều lần trợ giúp, truyền Phần Giới Cổ Tán trái ý Chu Tước đời đầu, giao mai rùa Cổ Hồn Cấm.","anchor":"Tiểu tử kia, không được quên, lần sau gặp lại phải đưa tới cho lão phu Chu Tước đời thứ bảy"},{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1378","text":"Được nhắc có chút giao tình với Đại Hoang Thượng Nhân, nhưng giao tình so với lợi ích chẳng là gì.","anchor":"Hắn cùng với Chu Tước đời thứ hai mặc dù cũng có chút giao tình"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Ngồi câu bên hồ, câu lên Viêm long và cho Vương Lâm uống máu rồng","chuong":"@c1310"},{"text":"Kiểm tra thiên linh Vương Lâm, phát hiện năm đạo bổn nguyên khác nhau, xác nhận tiểu bối Chu Tước đời thứ sáu","chuong":"@c1311"},{"text":"Công khai bao che Vương Lâm trước các đại năng, gọi hắn là tiểu bối nhà mình","chuong":"@c1313"},{"text":"Nghiêm túc chủ trì thí luyện thiếu đế, hô dâng hương khiến ba cây hương Thiên, Địa, Nhân hiện ra","chuong":"@c1314"},{"text":"Vi phạm quy định thí luyện truyền âm thúc Vương Lâm đốt hương, bị hắn từ chối","chuong":"@c1316"},{"text":"Liều mạng lấy toàn bộ viêm huyết tinh hoa trên đỉnh đầu Viêm long truyền vào Địa Phương hương, trợ Vương Lâm thức tỉnh Chu Tước lần bốn","chuong":"@c1321"}]},"nguon":["@c1341","@c1378"],"vaiTro":"Tiền bối Chu Tước đời thứ hai — chủ trì thí luyện thiếu đế, che chở Vương Lâm","tinhCach":"Tinh tường, nhìn thấu căn cơ và bổn nguyên người khác; che chở tiểu bối cùng tộc một cách công khai và quyết đoán; dám vi phạm quy định thí luyện để cứu viện khi biến cố xảy ra; tính tình hào sảng, cười sang sảng giữa nguy nan","blurb":"Chu Tước đời thứ hai là một lão giả thường ngồi câu bên hồ trên Đại Đế tinh, có thể câu lên và áp chế Viêm long, lấy máu rồng mời khách uống. Lão kiểm tra thiên linh Vương Lâm, xác nhận hắn là tiểu bối Chu Tước đời thứ sáu mang năm đạo bổn nguyên khác nhau, sau đó công khai bao che hắn trước các đại năng và đưa hắn vào thí luyện thiếu đế. Khi thí luyện sinh biến nghiêm trọng, lão nhiều lần vi phạm quy định để cứu viện, thậm chí liều mạng lấy toàn bộ viêm huyết tinh hoa của Viêm long truyền vào cây hương nhằm trợ Vương Lâm thức tỉnh Chu Tước lần bốn."},{"id":"lao-thanh-hoang","name":"Lão Thánh Hoàng","cn":"","aliases":["Chu Tước đời thứ năm"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhớ lại: dù ngọn đèn cạn dầu vẫn vì Vương Lâm trị thương, giao phó Chu Tước Thánh Tông.","anchor":"Cả đời Lỗ Vân lão phu toàn bộ hiến tặng cho Chu Tước thánh tông"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1341"]},{"id":"ngo-dao-khai","name":"Lão tổ Luyện Hồn Tông","cn":"","aliases":["Đại trưởng lão Luyện Hồn Phong"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1341","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhớ lại: lúc chết hiền từ mỉm cười, truyền chí bảo Luyện Hồn Tông và giao hương hỏa cho Vương Lâm trên Chu Tước tinh.","anchor":"Từ nay về sau, Luyện Hồn Tông sẽ giao cho ngươi."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Ngồi trấn giữ đại điện trên đỉnh Luyện Hồn Phong, dùng uy áp Nguyên Anh kiểm tra Vương Lâm","chuong":"@c0356"},{"text":"Ba lần dùng Vạn Hồn Phiên chiến Kim sắc Hồn Phiên, lần thứ 3 huyết tế liều mình nhưng bị Vương Lâm điểm hôn mê, mất Vạn Hồn Phiên và Tử Mộc Phiên Linh","chuong":"@c0360"},{"text":"Lúc chết hiền từ mỉm cười, truyền chí bảo Luyện Hồn Tông và giao hương hỏa cho Vương Lâm","chuong":"@c1341"}]},"nguon":["@c1341"],"vaiTro":"Nhân vật phụ — đại trưởng lão Luyện Hồn Tông, thủ hộ Luyện Hồn Phong","tinhCach":"Lạnh lùng, uy áp; kiên trì liều mình chiến đấu dù đối mặt nguy hiểm; hiền từ, trọng nghĩa truyền thừa","blurb":"Đại trưởng lão Luyện Hồn Phong là lão nhân áo xanh tu vi Nguyên Anh hậu kỳ trấn giữ Luyện Hồn Phong, thần thức mạnh mẽ, chỉ còn thiếu lĩnh ngộ ý cảnh là đột phá Hóa Thần. Ông ba lần dùng Vạn Hồn Phiên liều mình chiến đấu với Kim sắc Hồn Phiên, cuối cùng bị Vương Lâm điểm hôn mê và mất Vạn Hồn Phiên cùng Tử Mộc Phiên Linh. Trước lúc chết ông hiền từ mỉm cười, truyền lại chí bảo Luyện Hồn Tông và giao phó hương hỏa cho Vương Lâm."},{"id":"thanh-lam","name":"Thanh Lâm","cn":"青鸾","gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1342","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ lại lời từng nói rằng bổn nguyên Chưởng Tôn tu luyện là Thái Sơ Lực.","anchor":"Thanh Lâm từng nói, bổn nguyên mà Chưởng tôn tu luyện là Thái sơ lực"}],"diem":[{"text":"Lộ thân phận Tiên Đế, đệ nhất cường giả Tiên giới và phụ thân Thanh Sương qua ngọc giản","chuong":"@c0595"},{"text":"Thi triển Định Thân Thuật và lập Cửu Ấn Trận áp chế thánh tổ Phù Tộc trong động phủ Tiên Đế","chuong":"@c0968"},{"text":"Hiện thân trong Thức Hải truyền thụ Quy tắc thân thể cho Vương Lâm, đánh tan tay phải Cổ Ma và chuyển giao khống chế Thức Hải","chuong":"@c1047"},{"text":"Thức tỉnh trong trận pháp hồi sinh, khai sinh Tân Vũ Giới, ôn hòa an ủi các đệ tử","chuong":"@c1050"},{"text":"Thi triển viễn cổ tiên thuật gọi ánh sáng viễn cổ giết tu sĩ giới ngoại, lãnh đạo giới nội đánh trận","chuong":"@c1453"},{"text":"Xuất nguyên thần mênh mông nhấn vào bánh xe khi tu sĩ giới nội kiệt sức trong quyết chiến","chuong":"@c1565"}]},"nguon":["@c1342"],"vaiTro":"Tiên Đế — đệ nhất cường giả Tiên giới, phụ thân Thanh Sương, ân sư Vương Nguy và Hồ Quyên","tinhCach":"Ôn hòa, che chở đệ tử và người thân; mưu tính sâu xa với bố cục vượt thời gian khiến Cổ Ma kiêng dè; lạnh lùng quyết đoán khi đối đầu kẻ địch; trọng ân nghĩa, từng cứu người kết duyên","blurb":"Thanh Lâm là Tiên Đế, đệ nhất cường giả Tiên giới, phụ thân Thanh Sương, phu quân Hoa Phi, ân sư của Vương Nguy cùng Hồ Quyên và có đại ân với Lữ Vân Đạo. Sau khi Tiên giới vỡ nát, thân thể ông tồn tại trong khe không gian rồi bị Cổ Ma Tháp Già nhập thể; hiện thân của ông trong Thức Hải đã truyền thụ Quy tắc thân thể và chuyển giao khống chế Thức Hải cho Vương Lâm, sau đó thức tỉnh trong trận pháp hồi sinh và khai sinh Tân Vũ Giới. Ông bế quan chữa thương mấy trăm năm tại Vũ Tiên Giới, từng ngăn cản Thác Sâm, thi triển viễn cổ tiên thuật bảo vệ giới nội, và được tiết lộ là một trong hai người "},{"id":"nu-tu-than-bi-van-hai","name":"Nữ tử thần bí (Vân Hải Tinh vực)","gioiTinh":"nu","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Nữ tử thần bí ở cái khe tầng thứ chín Vân Hải Tinh vực, từng đưa cho Vương Lâm ngọc giản chứa cấm chế siêu việt không thuộc giới này, nhờ hắn tìm một vùng đất.","vaiTro":"Nhân vật bí ẩn từng giao ngọc giản cho Vương Lâm","tinhCach":"Thần bí; chủ động nhờ vả nhưng chưa rõ mục đích","tabs":{"diem":[{"text":"Đưa ngọc giản chứa cấm chế siêu việt cho Vương Lâm, có thể tránh Phong Giới Đại Trận quay về giới nội","chuong":"@c1342"}],"kinhLich":[{"chuong":"@c1342","importance":"normal","mucCt":"gon","tieuDe":"Được Vương Lâm nhớ tới","text":"Từng đưa cho Vương Lâm ngọc giản ở cái khe tầng chín Vân Hải Tinh vực, nhờ tìm một vùng đất, nói mở ở giới ngoại có thể tránh Phong Giới Đại Trận quay về.","anchor":"cũng nói là ở giới ngoại mở ngọc giản này ra, có thể tránh Phong giới đại trận mà quay trở về bên trong cái khe"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Giao ngọc giản nhờ tìm vùng đất","ghiChu":"Chưa rõ bạn thù"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1342"]},{"id":"ke-than-bi-ban-tay-khe-nut","name":"Kẻ thần bí (bàn tay từ khe nứt)","gioiTinh":"khong-ro","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Kẻ thần bí chưa rõ danh tính, xuất hiện khi bầu trời chấn động nứt ra khe nứt khổng lồ. Một bàn tay to lớn mang uy áp vô biên vươn ra từ khe nứt ấy chộp lấy Vương Lâm.","vaiTro":"Nhân vật bí ẩn — kẻ vô danh vươn tay từ khe nứt bắt Vương Lâm","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Khiến bầu trời chấn động, mở khe nứt khổng lồ và vươn bàn tay mang uy áp vô biên chộp lấy Vương Lâm","chuong":"@c1342"}],"kinhLich":[{"chuong":"@c1342","importance":"major","mucCt":"gon","tieuDe":"Bàn tay khổng lồ chộp Vương Lâm","text":"Bầu trời chấn động, khe nứt khổng lồ quét ngang, uy áp vô biên giáng xuống, bàn tay to vươn ra từ khe nứt chộp lấy Vương Lâm đang sắp dung nhập trời đất.","anchor":"Ở bên trong cái khe còn có một bàn tay to, mạnh mẽ vươn ra, chộp lấy Vương Lâm đang sắp sửa dung nhập vào trong trời đất"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chộp bắt","ghiChu":"Vương Lâm đang thổ nạp trên tu chân tinh bỏ hoang"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1342"]},{"id":"dai-han-phung-thien-lang-toc","name":"Đại hán Phụng Thiên lang tộc","cn":"","aliases":["Chu Cẩn"],"gioiTinh":"nam","theLuc":[{"ten":"Phụng Thiên lang tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Chu Cẩn là tu sĩ Không Niết sơ kỳ bước thứ ba thuộc Phụng Thiên lang tộc — một trong tứ đại Thái Cổ hung tộc dưới trướng Chưởng Tôn. Thân cao ba trượng, mi tâm mang ấn ký đầu sói xanh, hắn nhận lệnh phục kích Vương Lâm nhưng liên tiếp thất bại: trúng độc từ móng tay Đại Hoang thượng nhân, bị cuốn vào sương mù cổ mộ, rồi cuối cùng bị Vương Lâm cùng Linh Động áp chế hoàn toàn và luyện hóa trong Thiên Hoàng Lô. Dù thoát ra được nhờ nhân cơ hội uy áp Cổ Thần khiến phong ấn lơi lỏng, đạo tâm hắn đã tan nát và phải quỳ phục.","vaiTro":"Đại hán Phụng Thiên lang tộc — tu sĩ bước thứ ba truy sát Vương Lâm theo lệnh Chưởng Tôn","tinhCach":"Hung hãn, cuồng bạo khi giao chiến; tham lam, muốn chiếm đoạt Cổ Tức Diệp; tuân lệnh Chưởng Tôn nhưng thiếu bản lĩnh khi gặp áp chế cường giả","tabs":{"diem":[{"text":"Từ khe nứt hư không phục kích Vương Lâm bằng bàn tay khổng lồ, bị móng tay Đại Hoang thượng nhân xuyên thấu trúng độc","chuong":"@c1343"},{"text":"Dẫn sáu tu chân tinh truy đuổi Vương Lâm, bị cơn lốc tu chân tinh nổ tung nuốt trọn nhưng nhờ Thanh Lang thoát nạn","chuong":"@c1344"},{"text":"Bị hút vào sâu trong sương mù cổ mộ, mi tâm xuất hiện ký hiệu con số một bốn","chuong":"@c1346"},{"text":"Tuyên bố giết Vương Lâm để nâng đài cao lên bậc sáu, tham lam mười tám Cổ Tức Diệp, bị Vương Lâm và Linh Động áp chế hoàn toàn","chuong":"@c1372"},{"text":"Bị luyện hóa trong Thiên Hoàng Lô, chín giọt độc dịch vây quanh, Cổ Tức Diệp phong ấn, hoàn toàn bất lực","chuong":"@c1373"},{"text":"Thoát Thiên Hoàng Lô nhờ uy áp Cổ Thần khiến phong ấn lơi lỏng, nhưng đạo tâm tan nát và quỳ phục","chuong":"@c1379"}],"kinhLich":[{"chuong":"@c1343","importance":"normal","mucCt":"ky","tieuDe":"Phục kích Vương Lâm, bị phản kích trúng độc","text":"Từ khe nứt hư không phục kích Vương Lâm bằng bàn tay khổng lồ, bị móng tay Đại Hoang thượng nhân xuyên thấu cánh tay tan thành bụi và trúng độc giảm chiến lực ba thành. Dùng lực xung kích xé hư không tạo hố đen truy đuổi nhưng bị Cổ Tức Diệp phong ấn, phải mở hố đen thứ hai mới thoát ra. Nữ tử Phong Diệt tộc (thị nữ Diệu Âm đạo tôn) đột ngột tới giúp, đặt điều kiện lấy đồ vật trên người Vương Lâm đổi lục phẩm đạo linh. Đồng ý điều kiện, điên cuồng truy đuổi Vương Lâm về phía bộ lạc phân tông.","anchor":"Dưới trướng của Chưởng tôn có tứ đại Thái cổ hung tộc, Phụng Thiên lang tộc là một trong số đó"},{"mucCt":"vua","text":"Dẫn sáu tu chân tinh truy đuổi Vương Lâm, bị cơn lốc tu chân tinh nổ tung nuốt trọn nhưng nhờ Thanh Lang lao ra mà thoát. Hư hỏa thiêu đốt trong cơ thể phải toàn lực áp chế, tạo cơ hội cho Vương Lâm dùng huyết kiếm xuyên mi tâm thiếu nữ Phong Diệt tộc. Chấn động trước tâm cơ thâm trầm của Vương Lâm, trong lòng nổi lên sợ hãi sâu sắc. Sau khi thiếu nữ sống lại, xé tinh không mở khe tiếp tục truy đuổi về hướng cổ mộ.","anchor":"Rõ ràng là tu sĩ có hư hỏa mà vẫn luôn ẩn nhẫn, đợi cho tới vừa rồi mới đột nhiên thôi động tâm tình của ta","bridge":true,"khoang":"@c1344"},{"mucCt":"ky","text":"Xé không xuất hiện trong tinh không, nữ tử trên vai vẫn chưa chết nhưng ẩn đi khó phát hiện. Đại hán do dự rồi tấn công Vương Lâm bằng Bát phương cực lang đạo — tám hư ảnh sói khổng lồ lao tới. Vương Lâm hóa lưu tinh né tránh, cơn lốc sương mù ập tới đánh tan tám con sói rồi cuốn tới đại hán. Tu vi vốn Không Niết sơ kỳ nên không suy yếu thêm, mi tâm xuất hiện ấn ký, nhưng nữ tử trên vai phát ra tiếng kêu thảm thiết.","anchor":"Tu vi hắn vốn là Không Niết sơ kỳ, không thể suy yếu nữa, trên mi tâm đột nhiên xuất hiện ấn ký","bridge":true,"khoang":"@c1345"},{"chuong":"@c1346","importance":"bridge","mucCt":"gon","text":"Bị hút vào sâu trong sương mù cổ mộ, mi tâm có ký hiệu con số một bốn.","anchor":"Con số trên mi tâm của đại hán kia là một bốn","bridge":true,"khoang":"@c1346–@c1346"},{"mucCt":"vua","text":"Cảm ứng đài mộ cấp năm mới xuất hiện, sắc mặt âm trầm. Bước vào mảnh bản đồ thứ năm, tay cầm một mảnh Cổ Tức Diệp đoạt được từ người khác (một trong hai phiến, phiến kia bị Linh Động Thượng Nhân cướp). Nhận biết giá trị Cổ Tức Diệp nhờ quan sát khi truy sát Vương Lâm, nhắm tới dấu hiệu hình lá trên bản đồ thứ năm.","anchor":"nếu không phải khi đuổi giết tiểu tu kia thấy được sự cường đại của phiến lá này có thể so với sự quỷ dị của Phong diệt tộc","bridge":true,"khoang":"@c1368"},{"mucCt":"vua","text":"Đứng trên đài cao bậc năm xuyên sương mù, còn ba ngày nữa tới nơi. Muốn lấy chín chiếc lá phối hợp thần thông bản tộc để khóa Phụng Thiên Lang Đạo vĩnh viễn bên người, trở thành kẻ Không Niết Sơ Kỳ mạnh nhất.","anchor":"Nếu ta có thể lấy được chín chiếc lá loại này, phối hợp với thần thông của tộc ta, có thể làm cho Phụng Thiên Lang Đạo vĩnh viễn ở lại bên người","bridge":true,"khoang":"@c1370"},{"chuong":"@c1372","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm và Linh Động áp chế hoàn toàn","text":"Tuyên bố giết Vương Lâm sẽ nâng đài cao lên bậc sáu, đồng thời tham lam mười tám Cổ Tức Diệp. Dùng Cổ Tức Diệp dán ngực khóa tâm tình phòng hư hỏa, triệu hoán Phụng Thiên Lang ngàn trượng đánh lôi đồ. Vỗ vào Thiên Hoàng Lô nhưng bị lực phản chấn cường đại phun máu. Triệu sói đỏ mấy ngàn trượng từ khe hắc ám chống trả Linh Động. Thi triển thần thông Quần Lang Bái Nguyệt hóa mười vạn sói triệu mặt trăng đỏ nhưng bị Thiên Hoàng Lô bao phủ thiên địa chặn đứng. Bị chín giọt nước đen khống chế, không dám cử động.","anchor":"giết ngươi, đài cao của lão phu sẽ trở thành bậc sáu"},{"importance":"normal","mucCt":"ky","chuong":"@c1373","tieuDe":"Bị luyện hóa trong Thiên Hoàng Lô","text":"Bị chín giọt độc dịch vây quanh, Cổ Tức Diệp phong ấn hơn nửa phương hướng, hoàn toàn bất lực. Kinh ngạc khi nghe Linh Động cao thủ bước thứ ba gọi Vương Lâm là Chủ nhân. Bị Vương Lâm thu vào Thiên Hoàng Lô để luyện hóa thành Cổ Nô, có Linh Động trông coi bên trong.","anchor":"Cao thủ bước thứ ba này là những người hung mạnh nhất trong tinh không này, số lượng cực kỳ ít ỏi"},{"chuong":"@c1379","importance":"normal","mucCt":"ky","tieuDe":"Thoát Thiên Hoàng Lô nhưng đạo tâm tan nát, quỳ phục","text":"Uy áp Cổ Thần khiến chín giọt độc dịch và hai mươi lá Cổ Tức Diệp bao quanh lơi lỏng, Chu Cẩn nhân cơ hội phá ra khỏi Thiên Hoàng Lô. Nhận ra khí tức là sức mạnh Vương Lâm mượn từ chiếc ghế, thân là lão tổ Phụng Thiên Lang Tộc, hắn kiên quyết chống cự vì sợ khuất phục sẽ để lại ám ảnh trong đạo tâm. Gào thét chống lại, máu tươi tràn khóe miệng, hai chân run rẩy. Nhưng khi mười tám tinh điểm đột ngột dừng xoay, uy áp bộc phát gấp trăm lần, đạo tâm tan nát, phun máu quỳ xuống khuất phục hoàn toàn.","anchor":"Phịch một tiếng, đại hán Phụng Thiên Lang Tộc quỳ xuống, giống như Linh Động, trong lúc run rẩy, không dám ngẩng đầu một chút nào"}],"tuViMoc":[{"chuong":"@c1343","canhGioi":"Không Niết sơ kỳ (bước thứ ba)","text":"Tu vi tại thời điểm xuất hiện.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu truy sát","ghiChu":"Truy sát theo lệnh Chưởng Tôn."},{"ten":"Chưởng Tôn","tag":"cap-tren","quanHe":"Chủ tướng, kẻ ra lệnh truy sát","ghiChu":"Phụng Thiên lang tộc là một trong tứ đại hung tộc dưới trướng."},{"ten":"Thiếu nữ Phong Diệt tộc","tag":"dong-hanh","quanHe":"Người dẫn đường, chỉ phương hướng","ghiChu":"Thị nữ Diệu Âm đạo tôn, ngồi trên vai đại hán, dùng la bàn định vị Vương Lâm."},{"ten":"Nữ tử Phong Diệt tộc","tag":"dong-hanh","quanHe":"Người dẫn đường / đối tác","ghiChu":"Thị nữ Diệu Âm đạo tôn ngồi trên vai hắn, cầm la bàn chỉ phương hướng truy sát."},{"ten":"Diệu Âm đạo tôn","tag":"dong-minh","quanHe":"Bên thưởng công","ghiChu":"Hứa thưởng lục phẩm đạo linh thông qua thị nữ nếu bắt được Vương Lâm."},{"ten":"Diệu Âm đạo tôn","tag":"khac","quanHe":"Chủ nhân của nữ tử đồng hành","ghiChu":"Hứa thưởng lục phẩm đạo linh nếu bắt được Vương Lâm"},{"ten":"Nữ tử Phong Diệt tộc","tag":"dong-minh","quanHe":"Đồng hành truy sát","ghiChu":"Thị nữ Diệu Âm đạo tôn, ngồi trên vai, cầm la bàn truy tung Vương Lâm, đề nghị thỏa thuận chia đồ vật đổi lục phẩm đạo linh"},{"ten":"Tư Mặc Tử","tag":"dong-minh","quanHe":"Đồng liêu","ghiChu":"Bực bội vì Tư Mặc Tử đã giao chiến với Vương Lâm nhưng không chia sẻ thông tin"},{"ten":"Vân Lạc","tag":"dong-minh","quanHe":"Đồng liêu","ghiChu":"Bực bội vì Vân Lạc sau khi trở về liền bế quan, không cung cấp thông tin"},{"ten":"Nữ tử áo đỏ Phong Diệt tộc","tag":"dong-minh","quanHe":"Đồng minh tạm thời","ghiChu":"Nữ tử tới giúp truy sát, đặt điều kiện đổi đồ vật Vương Lâm lấy lục phẩm đạo linh."},{"ten":"Diệu Âm đạo tôn","tag":"cap-tren","quanHe":"Bề trên gián tiếp","ghiChu":"Không dám đắc tội nữ tử vì nàng là thị nữ Diệu Âm đạo tôn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1343","@c1344","@c1345","@c1346","@c1368","@c1370","@c1372","@c1373","@c1379"]},{"id":"thieu-nu-phong-diet-toc","name":"Thiếu nữ Phong Diệt tộc","cn":"","aliases":["Nữ tử Phong Diệt Tộc","Nữ tử trên vai đại hán Phụng Thiên Lang tộc","Nữ tử Phong Diệt tộc chỉ còn có một mạng","Thị nữ Diệu Âm đạo tôn"],"gioiTinh":"nu","theLuc":[{"ten":"Phong Diệt tộc","trangThai":"gan-bo"},{"ten":"Diệu Âm đạo tôn (thị nữ)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân đệ tam suy","trangThai":"mat-tich","blurb":"Thiếu nữ áo đỏ tu vi Thiên Nhân đệ tam suy, mi tâm mang ấn ký Phong Diệt tộc, là thị nữ của Diệu Âm đạo tôn — một trong Thái Cổ ngũ tôn. Ngồi trên vai đại hán Phụng Thiên Lang tộc cầm la bàn truy sát Vương Lâm, nhưng bị sương mù cổ mộ giết chết hai lần, chỉ còn mạng cuối cùng nhờ năng lực tái sinh của tộc mình. Cuối cùng bị Vương Lâm bắt làm thí nghiệm xóa dấu ấn con số, bị sương mù nuốt mất và mất tích.","vaiTro":"Thị nữ Diệu Âm đạo tôn — thiếu nữ Phong Diệt tộc truy sát Vương Lâm","tinhCach":"Quyến rũ, tự tin khi chiếm thế thượng phong; sợ hãi, thận trọng khi đối mặt kẻ mạnh hơn","tabs":{"diem":[{"text":"Ngồi trên vai đại hán Phụng Thiên Lang tộc, triệu hồi đại thần thông phong ấn truy đuổi Vương Lâm","chuong":"@c1344"},{"text":"Bị sương mù cổ mộ giết chết lần thứ hai, xương cốt tái sinh nhờ năng lực Phong Diệt tộc, chỉ còn mạng cuối cùng","chuong":"@c1346"},{"text":"Dùng hào quang ấn ký mi tâm bảo vệ đài cao, chống lại tu sĩ bốn phía vây công","chuong":"@c1349"},{"text":"Là người duy nhất biết Vương Lâm là tu sĩ hư hỏa, sắc mặt tái nhợt sợ hãi muốn tìm người giúp đỡ","chuong":"@c1350"},{"text":"Nhận ra bà lão áo lục là người Phong Huyễn Tộc, sợ hãi nộp pháp bảo cho Vương Lâm","chuong":"@c1353"},{"text":"Bị Vương Lâm lấy ra làm thí nghiệm xóa dấu ấn con số, bị sương mù nuốt mất, mất tích","chuong":"@c1373"}],"kinhLich":[{"mucCt":"ky","text":"Ngồi trên vai đại hán Phụng Thiên Lang tộc truy đuổi Vương Lâm. Bắt đầu triệu hồi đại thần thông phong ấn của Phong Diệt tộc để phong ấn đường lui Vương Lâm, nhưng bị huyết kiếm giấu sẵn trong tu chân tinh xuyên thẳng mi tâm, chết một lần. Nhờ đặc tính mệnh ba hồn của Phong Diệt tộc mà hồi sinh, vết thương khép lại nhưng để sẹo vĩnh viễn, lần đầu đời suýt chết thật. Dùng la bàn xác định vị trí Vương Lâm ở phía Đông Bắc cách 173 vạn 4532 dặm, chính là hướng cổ mộ, cảnh giác lộ tuyến có thể là bẫy của Vương Lâm.","anchor":"nếu không phải Phong diệt tộc ta có mệnh ba hồn thì vừa rồi. ta đã chết rồi","bridge":true,"khoang":"@c1344"},{"importance":"bridge","mucCt":"gon","chuong":"@c1345","text":"Vẫn chưa chết nhưng ẩn thân trên vai đại hán Phụng Thiên Lang tộc, khi sương mù cổ mộ cuốn tới đại hán, nữ tử phát ra tiếng kêu thảm thiết.","anchor":"nhưng quỷ dị là ngồi trên đó nhưng ẩn đi, rất khó phát hiện"},{"chuong":"@c1346","importance":"normal","mucCt":"vua","tieuDe":"Chết lần hai rồi tái sinh, chỉ còn mạng cuối","text":"Bị sương mù cổ mộ giết chết lần thứ hai, xương cốt không tiêu, ánh sáng xám tản ra rồi máu thịt tái sinh nhờ năng lực ba mạng Phong Diệt tộc. Mi tâm hình thành ký hiệu con số hai, sau đó bị lực hút cuốn vào sâu trong sương mù.","anchor":"Phong diệt tộc có ba mạng, bây giờ đã chết mất hai"},{"importance":"bridge","mucCt":"gon","chuong":"@c1348","text":"Xuất hiện trong cổ mộ, mặc áo đỏ núp sau đài cao trôi nổi, đã bị tách khỏi đại hán Phụng Thiên Lang tộc.","anchor":"một thiếu nữ toàn thân mặc áo đỏ ánh mắt lộ ra vẻ sợ hãi, chính là nữ tử của Phong Diệt tộc chỉ còn có một mạng"},{"importance":"bridge","mucCt":"vua","chuong":"@c1349","tieuDe":"Bảo vệ đài cao bằng hào quang mi tâm","text":"Ngồi khoanh chân trên đài cao, mi tâm lóe hào quang bao phủ toàn bộ đài cao, tu sĩ bốn phía vây công cũng không phá được.","anchor":"mi tâm lóe lên hào quang, một đạo hào quang nhẹ nhàng bao phủ toàn bộ đài cao"},{"chuong":"@c1350","importance":"normal","mucCt":"gon","tieuDe":"Lo sợ Vương Lâm, muốn tìm người giúp","text":"Sắc mặt tái nhợt sợ hãi Vương Lâm, muốn tìm người giúp đỡ. Là người duy nhất biết Vương Lâm là tu sĩ hư hỏa.","anchor":"Ngoài nữ tử Phong Diệt Tộc ra, tất cả mọi người ở đây đều không biết"},{"chuong":"@c1351","importance":"bridge","mucCt":"gon","text":"Không dám rời đài cao, thấy Vương Lâm phát uy thì tâm thần chấn động, sắc mặt tái nhợt, không dám cử động.","anchor":"Thiếu nữ Phong Diệt Tộc ở đằng xa tâm thần chấn động"},{"importance":"bridge","mucCt":"gon","chuong":"@c1352","tieuDe":"Vào vùng phong ấn cùng nhóm","text":"Vẫn đứng trên đài cao, trong mắt lộ vẻ vui mừng nhưng vụt tắt khi nhớ tới sự đáng sợ của Vương Lâm.","anchor":"Thiếu nữ của Phong Diệt Tộc vẫn chưa rời khỏi đài cao, trong mắt lộ vẻ vui mừng"},{"chuong":"@c1353","importance":"bridge","tieuDe":"Nhận ra Phong Huyễn Tộc, nộp bảo","text":"Nhận ra bà lão áo lục là người Phong Huyễn Tộc, kinh ngạc, sợ hãi nộp pháp bảo cho Vương Lâm.","mucCt":"gon","anchor":"Ánh mắt của nữ tử Phong diệt tộc sững lại, lộ vẻ kinh ngạc"},{"importance":"normal","mucCt":"gon","chuong":"@c1373","tieuDe":"Bị xóa dấu ấn, sương mù nuốt mất","text":"Bị Vương Lâm lấy ra làm thí nghiệm xóa dấu ấn con số, lần đầu dùng Cổ Thần lực không thành, lần sau dung hợp tam tộc lực xóa thành công. Mất dấu ấn, bị sương mù cổ mộ sôi trào tấn công và nuốt mất, biến mất trước mặt Vương Lâm.","anchor":"thiếu nữ này đã bị sương mù bao phủ, biến mất ở phía trước Vương Lâm"}],"tuViMoc":[{"chuong":"@c1343","canhGioi":"Thiên Nhân đệ tam suy","text":"Tu vi tại thời điểm xuất hiện.","importance":"minor"}],"nhanMach":[{"ten":"Diệu Âm đạo tôn","tag":"cap-tren","quanHe":"Chủ nhân","ghiChu":"Là thị nữ của Diệu Âm đạo tôn, Thái Cổ ngũ tôn."},{"ten":"Đại hán Phụng Thiên lang tộc","tag":"dong-hanh","quanHe":"Cộng sự truy sát","ghiChu":"Ngồi trên vai đại hán, dẫn đường cho hắn truy kích Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu truy sát","ghiChu":"Muốn lấy tất cả đồ vật trên người Vương Lâm."},{"ten":"Diệu Âm đạo tôn","tag":"su-mon","quanHe":"Chủ nhân","ghiChu":"Là thị nữ của Diệu Âm đạo tôn"},{"ten":"Đại hán Phụng Thiên lang tộc","tag":"dong-minh","quanHe":"Đồng hành","ghiChu":"Ngồi trên vai đại hán, cùng truy đuổi Vương Lâm"},{"ten":"Tư Mã Mặc","tag":"khac","quanHe":"Người liên quan","ghiChu":"Nhắc đến Tư Mặc Tử đã giao chiến với Vương Lâm nhưng không báo lại pháp thuật."},{"ten":"Vân Lạc","tag":"khac","quanHe":"Người liên quan","ghiChu":"Nhắc Vân Lạc đại ti sau khi trở về liền lập tức bế quan."}],"tuiDo":{"phapBao":[{"ten":"La bàn","moTa":"Dùng để định vị chính xác vị trí Vương Lâm, chỉ phương hướng và khoảng cách cụ thể.","nguon":"@c1343"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1343","@c1344","@c1345","@c1346","@c1348","@c1349","@c1350","@c1351","@c1352","@c1353","@c1373"]},{"id":"am-duong-lao-nhan","name":"Âm Dương lão nhân","cn":"阴阳老人","tabs":{"kinhLich":[{"mucCt":"vua","text":"Cưỡi trên lưng mãnh thú Vọng Nguyệt, Âm Dương lão nhân nhìn ra quy tắc sương mù. Lão đẩy Vũ Đông Thiện và Cực Hiền Thiên từ mi tâm mình chui vào cơ thể Vọng Nguyệt, ra lệnh cả ba tiến vào cổ mộ. Ba thực thể đều xuất hiện số hiệu trên mi tâm và bị hút vào sương mù. Lão lui về tu chân tinh xa ngồi tịnh tọa, sắc mặt tái nhợt.","anchor":"Vũ Đông Thiện, Cực Hiền Thiên, Vọng Nguyệt thú, ba người tiến vào trong cổ mộ","bridge":true,"khoang":"@c1345"}],"diem":[{"text":"Cảnh giới Nguyên Anh hậu kỳ, ngang hàng Đằng Hóa Nguyên, giữ vị trí đệ nhất thủy tổ Hợp Hoan Tông","chuong":"@c0213"},{"text":"Họp cùng ba Nguyên Anh tu sĩ trong tông bàn đối sách trước 'ma tu' nghi ở cảnh giới Hóa Thần đang tàn sát Đằng gia","chuong":"@c0213"},{"text":"Bị ép mở hộ sơn đại trận và đầu hàng Vương Lâm, cung kính gọi đối phương là 'Tiền bối', chỉ nơi Đằng gia ẩn náu","chuong":"@c0213"},{"text":"Cưỡi mãnh thú Vọng Nguyệt, nhìn ra quy tắc sương mù và đẩy Vũ Đông Thiện cùng Cực vào trước","chuong":"@c1345"}]},"nguon":["@c1345"],"vaiTro":"Thủy tổ Hợp Hoan Tông — tu sĩ Nguyên Anh hậu kỳ","tinhCach":"Thận trọng khi đối mặt kẻ mạnh hơn; thực dụng, ưu tiên bảo toàn tông môn hơn giữ nghĩa với đồng minh; cung kính hạ mình trước cường giả","blurb":"Đệ nhất thủy tổ của Hợp Hoan Tông, cảnh giới Nguyên Anh hậu kỳ. Khi Vương Lâm tấn công Hợp Hoan Tông để truy sát Đằng gia, lão chủ trì hộ sơn đại trận nhưng bị ép phải đầu hàng mở trận sau khi hàng nghìn đệ tử hộ trận bị giết, cuối cùng cung kính chỉ nơi Đằng gia ẩn náu. Về sau xuất hiện cưỡi mãnh thú Vọng Nguyệt, nhìn ra quy tắc sương mù và đẩy đồng hành vào trước."},{"id":"vu-dong-thien","name":"Vũ Đông Thiện","gioiTinh":"nam","theLuc":[{"ten":"Âm Dương lão nhân (thuộc hạ)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Võ Đông Thiện là cường giả bí ẩn được nữ nhân váy lam mời ra từ đám mây đen để thách đấu Viêm Lôi Tử, từng giao chiến kinh thiên động địa giữa tinh không. Sau trận chiến, hắn cắn răng lao vào cơ thể Vọng Nguyệt, nhiều lần triền đấu Nhất Mộc Tử và bị thương nặng nhưng vẫn góp sức diệt Cực Hiền Thiên. Về sau hắn được Âm Dương lão nhân phái vào cổ mộ cùng Cực Hiền Thiên và Vọng Nguyệt, đứng trên đầu Vọng Nguyệt cảnh giác quan sát chờ phá cấm chế.","vaiTro":"Cường giả bí ẩn phía Liên Minh Tu Chân, đối thủ Viêm Lôi Tử","tinhCach":"Cuồng ngạo, chủ động thách đấu cường giả; quyết liệt tranh đoạt cơ duyên; lâm nguy vẫn chống đỡ dai dẳng","tabs":{"diem":[{"text":"Được nữ nhân váy lam mời ra, cuồng ngạo thách đấu Viêm Lôi Tử giữa tinh không","chuong":"@c0865"},{"text":"Cắn răng lao vào miệng Vọng Nguyệt, truy đuổi và triền đấu Nhất Mộc Tử trong thông đạo bên trong thân thể Vọng Nguyệt","chuong":"@c0878"},{"text":"Bị Cực Hiền Thiên đánh lõm ngực, tu vi giảm thảm hại, nhưng vẫn góp phần tiêu diệt Cực Hiền Thiên","chuong":"@c0880"},{"text":"Nhớ sách cổ Liên Minh Tu Chân ghi về Vọng Nguyệt, nhắm đoạt Nguyệt Hoa bên trong","chuong":"@c0882"},{"text":"Được Âm Dương lão nhân đẩy vào cơ thể Vọng Nguyệt, cùng đồng bạn tiến vào cổ mộ trong sương mù","chuong":"@c1345"},{"text":"Đứng trên đầu Vọng Nguyệt cùng đồng bạn cảnh giác quan sát, chờ Vọng Nguyệt phá cấm chế","chuong":"@c1386"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1345","tieuDe":"Được phái vào cổ mộ","text":"Bị Âm Dương lão nhân đẩy từ mi tâm vào cơ thể Vọng Nguyệt, cùng Cực Hiền Thiên và Vọng Nguyệt tiến vào sương mù cổ mộ.","anchor":"Vũ Đông Thiện, Cực Hiền Thiên, Vọng Nguyệt thú, ba người tiến vào trong cổ mộ"},{"mucCt":"vua","text":"Đứng trên đầu Vọng Nguyệt cùng đồng bạn, cảnh giác quan sát bốn phía chờ Vọng Nguyệt phá cấm chế. Bị cuồng phong của Vương Lâm cuốn, phun máu tươi, bị thu vào không gian trữ vật.","anchor":"trong tiếng kêu thảm thiết phuc ra máu tươi","bridge":true,"khoang":"@c1386"}],"tuViMoc":[],"nhanMach":[{"ten":"Âm Dương lão nhân","tag":"cap-tren","quanHe":"Chủ nhân, phái hắn vào cổ mộ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1345","@c1386"],"cn":"武东善","aliases":["Vũ Đông Thiện"]},{"id":"cuc-hien-thien","name":"Cực Hiền Thiên","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1345","text":"Bị Âm Dương lão nhân đẩy từ mi tâm vào cơ thể Vọng Nguyệt, cùng tiến vào sương mù cổ mộ.","anchor":"Vũ Đông Thiện, Cực Hiền Thiên, Vọng Nguyệt thú, ba người tiến vào trong cổ mộ"}],"diem":[{"text":"Ẩn trong khe nứt tinh không, bị Viêm Lôi Tử điểm chỉ ép lộ diện","chuong":"@c0863"},{"text":"Bại trận trước Viêm Lôi Tử, mất toàn bộ 13 tầng Lam ý","chuong":"@c0864"},{"text":"Tự bạo bốn tầng Lam ý, bị thuật định thân và Vọng Nguyệt nuốt chửng","chuong":"@c0865"},{"text":"Lộ bản chất Cổ Thần Khôi Lỗi — dung hợp nhất tinh Cổ Thần khi bị phun ra từ mắt Vọng Nguyệt","chuong":"@c0879"},{"text":"Bị tiêu diệt hoàn toàn, mất lực lượng truyền thừa","chuong":"@c0880"},{"text":"Bị Âm Dương lão nhân đẩy từ mi tâm vào cơ thể Vọng Nguyệt, cùng tiến vào sương mù cổ mộ","chuong":"@c1345"}]},"nguon":["@c1345"],"vaiTro":"Tứ Tôn của Tu Chân Liên Minh — Cổ Thần Khôi Lỗi dung hợp nhất tinh Cổ Thần","tinhCach":"Ẩn nhẫn chờ thời; quyết liệt cầu sinh; hung hãn trong giao chiến","blurb":"Cực Hiền Thiên, tức Hiền Tôn, là một trong Tứ Tôn của Tu Chân Liên Minh, tu vi Toái Niết trung kỳ nhưng không đủ tư cách vào Trưởng Lão Đoàn. Bản chất thực là Cổ Thần Khôi Lỗi dung hợp nhất tinh Cổ Thần, hắn ẩn trong khe nứt tinh không cho đến khi bị Viêm Lôi Tử ép lộ diện, trải qua nhiều trận bại rồi bị Vọng Nguyệt nuốt chửng, cuối cùng bị tiêu diệt và mất toàn bộ lực lượng truyền thừa."},{"id":"dai-hoang-thuong-nhan","name":"Đại Hoang thượng nhân","cn":"大荒上人","gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền","trangThai":"song","blurb":"Đại Hoang thượng nhân là cường giả cảnh Không Huyền, lão giả mặc da thú trú trên một tu chân tinh khô héo. Không có phân thân sẵn và không dám suy yếu tu vi bản thể, hắn đoạt xá tu sĩ khác để phân hồn tiến vào cổ mộ, gây ra hàng loạt cuộc tranh đoạt tàn khốc — giải ấn Tam Tiên biến biển hương hỏa thành biển độc, đoạt xá thành công Diệu Âm Đạo Tôn. Phân hồn cuối cùng bị hủy diệt khi tham lam lao tới đài mộ cấp chín, còn bổn tôn bị nhốt lại trong cổ mộ sau khi Địa Phù bị Vương Lâm thu đoạt.","vaiTro":"Cường giả Không Huyền — kẻ đoạt xá tàn độc trong cổ mộ","tinhCach":"Tàn nhẫn bất chấp, sẵn sàng hy sinh người khác để đạt mục đích; mưu mô thâm trầm, tính toán nhiều bước nhưng hay bị phản đòn; tham lam không kiềm chế, lao vào nguy hiểm vì lợi ích trước mắt","tabs":{"diem":[{"text":"Bắt tu sĩ bên ngoài sương mù để đoạt xá, dùng phân hồn xâm nhập cổ mộ do không có phân thân và không dám suy yếu bản thể","chuong":"@c1345"},{"text":"Giải ấn Tam Tiên, biến biển hương hỏa thành biển độc, đồng thời bổn tôn phun máu khiến toàn bộ tu chân tinh chết theo","chuong":"@c1365"},{"text":"Đoạt xá thành công Diệu Âm Đạo Tôn, hắc khí chui vào thất khiếu chiếm đoạt thân xác","chuong":"@c1366"},{"text":"Phân hồn bị hủy diệt khi tham lam lao tới đài mộ cấp chín, bị cánh tay khổng lồ đánh tan","chuong":"@c1377"},{"text":"Bổn tôn bị nhốt lại trong cổ mộ sau khi Địa Phù bị Vương Lâm thu đoạt, không còn đường thoát","chuong":"@c1386"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1345","tieuDe":"Đoạt xá tu sĩ để vào cổ mộ","text":"Không có phân thân và không dám suy yếu tu vi bản thể, Đại Hoang thượng nhân bắt tu sĩ bên ngoài sương mù ném vào thử. Bảy người chết, người thứ tám — lão già sắc mặt vàng vọt — sống sót với ấn ký trên mi tâm. Lão lập tức phóng một đám nguyên thần nhảy vào mi tâm lão già đó, đoạt xá thành công, theo thân xác bị hút vào cổ mộ. Bản thể tái nhợt rời đi.","anchor":"một đám nguyên thần từ trong cơ thể hắn lao thẳng tới lão già sắp bị hút vào trong sương mù, nhảy thẳng vào mi tâm hắn, trực tiếp đoạt xá"},{"mucCt":"ky","text":"Phân hồn giao chiến với Diệu Âm trong vùng phong ấn thứ hai, tranh đoạt tứ phẩm đạo linh. Đe dọa bổn tôn sẽ lập tức tới Âm Hải quyết chiến với bổn tôn Diệu Âm. Bị Diệu Âm khinh miệt, tuyên bố phân hồn không phải đối thủ, chê Đại Hoang tính cổ quái, trong Thái Cổ Tinh Thần ngoài Lão Điểu không có đạo hữu, không ai giúp.","anchor":"Diệu Âm, hôm nay ngươi dám đoạt đạo linh của lão phu, bổn tôn của lão phu sẽ lập tức tới Âm Hải, quyết chiến với bổn tôn của ngươi","bridge":true,"khoang":"@c1363"},{"mucCt":"ky","text":"Đến vùng đất phong ấn trước tiên, phá giải cấm chế lấy tứ phẩm mộc đạo linh nhưng bị Diệu Âm đánh lén cướp mất. Giao chiến bất lợi vì thân thể mượn không thể ngưng luyện hương hỏa lực. Nhận ra Vương Lâm bất phàm, muốn liên thủ. Giả vờ chấp nhận kế li gián của Diệu Âm, lấy hương hỏa thề nhận đạo linh rời đi, nhưng lập tức quay lại tập kích Diệu Âm bằng bàn tay đen khổng lồ chứa tinh phong độc khí. Tuyên bố thề vô dụng, gọi Vương Lâm là hậu bối của lão điểu (Cổ Thần Đồ Ti) — bạn chí cốt cả đời, muốn lấy thân thể Diệu Âm dung nhập hồn mình. Năm móng tay đánh vỡ thuẫn sương tím đâm trúng trước ngực Diệu Âm.","anchor":"lão điểu là bạn chí cốt cả đời này của lão phu","bridge":true,"khoang":"@c1364"},{"chuong":"@c1365","importance":"major","mucCt":"ky","tieuDe":"Giải ấn Tam Tiên, biến biển hương hỏa thành biển độc, mưu đoạt xá","text":"Phun máu do thệ phù bị phá, bổn tôn ở tinh cầu hoang dã phun máu khiến toàn tinh cầu chết. Phân hồn tung ngũ độc từ năm ngón tay bàn tay khổng lồ, phun độc khí biến dung nhan thành bổn tôn — khuôn mặt đầy sẹo, ba cây châm xuyên môi. Giải ấn Đại Hoang Tam Tiên phong ấn bốn vạn năm, ba châm hóa hắc quang cắm vào mi tâm Diệu Âm. Phóng cái lưỡi tím đen quỷ dị biến toàn bộ biển hương hỏa Diệu Âm thành biển độc. Thân thể phân hồn bị biển tím đánh tan chỉ còn phân hồn, nhân lúc Diệu Âm trọng thương lao tới cưỡng bức đoạt xá muốn nhập vào cơ thể Diệu Âm.","anchor":"phân hồn của Đại Hoang Thượng Nhân đã mất đi thân thể kia vội vàng lao tới, muốn nhập vào trong cơ thể của Diệu âm đ*o Tôn, c**ng b*c đoạt xá."},{"chuong":"@c1366","importance":"normal","mucCt":"vua","tieuDe":"Đoạt xá thành công Diệu Âm","text":"Phân hồn lao tới thân thể Diệu Âm, hóa hắc khí chui vào thất khiếu triển khai đoạt xá tàn nhẫn. Khi cánh tay khổng lồ đánh trúng Diệu Âm, mượn cơ hội áp chế nguyên thần đối phương, đoạt xá thành công. Cùng thân thể bị bàn tay khổng lồ hút vào biển sương mù, không thể thoát ra.","anchor":"thân thể liền bị hút vào bàn tay không lồ kia, không thể thoát ra"},{"mucCt":"vua","text":"Ngồi trong lòng bàn tay khổng lồ với thân xác Diệu Âm Đạo Tôn đã đoạt xá, tướng mạo dần biến thành dữ tợn của bổn tôn. Định dùng hắc khí kịch độc công kích bàn tay nhưng bị Vương Lâm ngăn lại. Khi bị ném bay như lưu tinh nhưng tốc độ chậm hơn Vương Lâm. Nội tâm bộc lộ ba lần bày sát cơ đều bị Vương Lâm hóa giải, vốn định thừa lúc suy yếu đầu độc chết nhưng Vương Lâm nhìn ra manh mối mượn lực đào tẩu. Buông ấn ký đã chuẩn bị sẵn rồi biến mất trong sương mù.","anchor":"vốn ta định thừa dịp hắn suy yếu mà đầu độc chết nhưng hắn lại nhìn ra manh mối, mượn lức đào tẩu","bridge":true,"khoang":"@c1367"},{"chuong":"@c1375","importance":"normal","mucCt":"vua","tieuDe":"Đài mộ lên cấp năm, gia nhập truy sát","text":"Tranh đoạt dấu ấn từ tu sĩ chết, đài mộ nhanh chóng lên cấp năm. Cảm ứng được các đài mộ khác, phát hiện đài mộ cấp tám, dùng cách riêng tăng tốc đuổi theo Vương Lâm.","anchor":"nhanh chóng trở thành một đài mộ cấp năm!"},{"chuong":"@c1377","importance":"normal","mucCt":"ky","tieuDe":"Tử vong — thân thể và phân hồn đều bị hủy","text":"Mắt lộ vẻ tham lam lao tới đài mộ cấp chín để tranh đoạt. Ở gần cánh tay khổng lồ nhất, không kịp né, bị cánh tay vỗ trực tiếp — thân thể (Diệu Âm Đạo Tôn bước thứ ba) tan nát hoàn toàn. Phân hồn bay ra định bỏ chạy nhưng bị dư lực thổi tan thành mây khói — tử vong hoàn toàn.","anchor":"Đại Hoang Thượng Nhân kêu lên thảm thiết, phân hồn ở bên trong bay ra, đang muốn bỏ chạy, nhưng dư lực từ trên cánh tay này đánh ra giống như cuồng phong quét qua, trực tiếp thổi nát phân hồn tan thành mây khói"},{"mucCt":"vua","text":"Bổn tôn trú trên tu chân tinh khô héo, sắc mặt tái nhợt do phân hồn bị tan vỡ. Phát hiện khe cổ mộ không còn hạn chế tu vi, trực tiếp nhảy vào cổ mộ trước Diệu Âm và Cửu Thiên Ma Tôn.","anchor":"Hắn cả đời tu đạo chỉ vì mình, sẵn sàng phá bỏ lời thề","bridge":true,"khoang":"@c1378"},{"mucCt":"vua","text":"Bổn tôn ở bản đồ thứ bảy cố bắt thần thức Vương Lâm nhưng bị ý chí cổ mộ phản chấn đẩy lui. Dưới tiếng rống, phun máu, thân thể tan vỡ, nguyên thần sống sót, hoảng sợ rút lui.","anchor":"Đại Hoang Thượng Nhân này thân thể đạp đạp lui về phía sau, sắc mặt lập tức đại biến","bridge":true,"khoang":"@c1382"},{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Phát hiện Địa Phù xuất hiện trong cổ mộ nhưng bị Vương Lâm thu mất, cuối cùng bị nhốt lại trong cổ mộ.","anchor":"cổ mộ đã bị Vương Lâm hoàn toàn khoá kín, những người này sẽ bị nhốt ở đây trong một thời gian dài"}],"tuViMoc":[],"nhanMach":[{"ten":"Diệu Âm Đạo Tôn","tag":"doi-thu","quanHe":"Đối thủ tranh đoạt tứ phẩm đạo linh trong cổ mộ","gap":"@c1363"},{"ten":"Cổ Thần Đồ Ti","tag":"ban-be","quanHe":"Người duy nhất có quan hệ tốt với Đại Hoang trong Thái Cổ Tinh Thần, nhưng không rời Điên Lạc","gap":"@c1363"},{"ten":"Chu Tước đời thứ hai","tag":"khac","quanHe":"Có chút giao tình nhưng sẵn sàng bỏ qua vì lợi ích"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ cạnh tranh trong cổ mộ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1345","@c1363","@c1364","@c1365","@c1366","@c1367","@c1375","@c1377","@c1378","@c1382","@c1386"],"aliases":["Đại Hoang Lão Độc","Đại Hoang"]},{"id":"lao-gia-sac-mat-vang-vot","name":"Lão già sắc mặt vàng vọt","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Tu sĩ bị Đại Hoang thượng nhân bắt ném vào sương mù, là người thứ tám sống sót. Bị Đại Hoang thượng nhân phóng nguyên thần đoạt xá, thân xác biến mất trong sương mù.","vaiTro":"Tu sĩ bị đoạt xá, vật hy sinh của Đại Hoang thượng nhân","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Sống sót khi bị ném vào sương mù cổ mộ, nhưng lập tức bị Đại Hoang thượng nhân đoạt xá.","chuong":"@c1345"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1345","text":"Bị Đại Hoang thượng nhân bắt ném vào sương mù, là người thứ tám sống sót với ấn ký trên mi tâm, lập tức bị đoạt xá.","anchor":"Tu sĩ này là một lão già sắc mặt vàng vọt, giống như bị bệnh nặng lâu ngày vậy"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1345"]},{"id":"van-si-trung-nien","name":"Văn sĩ trung niên","cn":"","aliases":["Tam tỷ","Thánh nữ Thiên Đạo Môn","Nam tử cầm ô","Văn sĩ trung niên cầm ô"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Văn sĩ trung niên cầm ô là nhân vật bí ẩn mang nhiều bí danh — Tam tỷ, Thánh nữ Thiên Đạo Môn — với diện mạo mỹ miều ẩn chứa nữ tính, giọng nói giống nữ tử, có chín pho tượng kỳ dị hộ thân. Xuất hiện từ sương mù vùng cổ mộ nhờ Vương Lâm giúp đỡ nhưng bị phớt lờ, bản thể không thể tiến vào khe cổ mộ. Trong ảo cảnh đại chiến cổ xưa, nhân vật này tay cầm ô giương ánh sáng bảy màu đối kháng đạo cổ thuật, cuối cùng hóa đá trên đài cao và đã tu vong.","vaiTro":"Tu sĩ bí ẩn — ẩn chứa nữ tính, liên quan đến Thiên Đạo Môn và đại chiến cổ xưa","tinhCach":"Bí ẩn khó lường; khẩn thiết khi cầu cứu; kiên cường đối kháng cường địch","tabs":{"diem":[{"text":"Xuất hiện từ sương mù vùng cổ mộ nhờ Vương Lâm giúp đỡ nhưng bị phớt lờ; nhận định Vương Lâm là Cổ Thần","chuong":"@c1347"},{"text":"Hiện diện trong ảo cảnh đại chiến cổ xưa: tay cầm ô đã mở, yên lặng xuyên qua chiến trường","chuong":"@c1379"},{"text":"Giương ô triển khai ánh sáng bảy màu đối kháng đạo cổ thuật, cuối cùng hóa đá trên đài cao","chuong":"@c1380"}],"kinhLich":[{"mucCt":"ky","text":"Nhờ Vương Lâm giúp đỡ nhưng bị phớt lờ, bản thể không thể vào khe cổ mộ. Nhận định Vương Lâm là Cổ Thần đã diệt phân thân thất muội, trên thân vẫn có dấu vết Tĩnh trung lao nguyệt do lão hắc bào thi triển. Kích hoạt chín pho tượng tạo phân thân nữ tử áo trắng cho vào cổ mộ. Tiết lộ cấu trúc nhóm chị em: đại tỷ và bát muội mất tích nhiều năm, nhị tỷ đã có đồng minh, tứ muội Hồ Mị Tử hợp tác Thác Sâm, ngũ muội đoạt xá được Lam Mộng đạo tôn giúp. Lo bị cô lập, tính hợp tác với Vương Lâm. Bị Hồ Mị Tử giễu cợt là xử nữ, từng bị Tiên Tôn bắt nuôi làm lô đỉnh.","anchor":"Đại tỷ, bát muội mất tích nhiều năm, nhị tỷ đã tìm được người hợp tác, ngay cả lão tứ cũng bất chấp tất cả hợp tác với tên mãng phu Thác Sâm","bridge":true,"khoang":"@c1347"},{"chuong":"@c1379","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện trong ảo cảnh đại chiến cổ xưa","text":"Trong ảo cảnh nghịch chuyển thời gian mà Vương Lâm nhìn thấy, một văn sĩ trung niên cầm ô đã mở, yên lặng xuyên qua vô số tu sĩ đang xông lên phía trước, nhìn người ngồi trên ghế, giơ tay trái chỉ về phía trước. Thi thể hóa đá của hắn chính là tu sĩ đặc biệt cầm ô đối diện chiếc ghế trên đài.","anchor":"Ở dưới chiếc ô là một văn sĩ trung niên, yên lặng xuyên qua vô số tu sĩ đang xông lên phía trước"},{"chuong":"@c1380","importance":"major","mucCt":"vua","tieuDe":"Đối kháng Đạo Cổ, hóa đá trên đài cao","text":"Đứng đối diện đài cao, giương ô triển khai ánh sáng bảy màu đối kháng đạo cổ thuật. Bị khí tức đầu lâu cuốn tới mất sức sống, hóa thành đá cùng cái ô. Được tu sĩ bảy màu xác nhận là đệ tử đầu tiên trong ba đệ tử.","anchor":"Cả đời ta thu nhận ba đệ tử… ngươi là người đầu tiên"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cầu cứu nhưng bị phớt lờ","ghiChu":"@c1346"},{"ten":"Hồ Mị Tử","tag":"ho-hang","quanHe":"Tứ muội trong nhóm chị em","ghiChu":"Giễu cợt tam tỷ, mỗi người theo phe riêng"},{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Tứ muội hợp tác với Thác Sâm, tam tỷ coi hắn là mãng phu","ghiChu":""},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Muốn hợp tác với Cổ Thần (Vương Lâm) nhưng chưa thành","ghiChu":"Vương Lâm phớt lờ"},{"ten":"Tu sĩ bảy màu","tag":"su-mon","quanHe":"Sư phụ, tự xưng thu nhận ba đệ tử, nam tử cầm ô là người đầu tiên","ghiChu":""},{"ten":"Lý Quảng","tag":"dong-hanh","quanHe":"Đồng hành cùng chiến tuyến, Lý Quảng đứng sau bắn cung hỗ trợ","ghiChu":""},{"ten":"Đạo Cổ Diệp Mịch","tag":"doi-thu","quanHe":"Đối thủ, dùng ánh sáng bảy màu đối kháng đạo cổ thuật của Diệp Mịch","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Chín pho tượng kỳ dị","moTa":"Chín pho tượng không tóc, biểu cảm khác nhau, vờn quanh thân phát ánh sáng vàng nhạt để hộ thân trong sương mù","nguon":"@c1346"}]}},"nguon":["@c1346","@c1347","@c1379","@c1380"]},{"id":"lao-gia-hac-bao","name":"Lão già hắc bào (trong đại điện)","cn":"","aliases":["Người mặc hắc bào (kẻ thao túng trong cung điện)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Kẻ cực kỳ bí ẩn ẩn thân trong cung điện giữa tinh không Thái Cổ Tinh Thần. Dùng thuật Tĩnh Trung Lao Nguyệt thao túng tâm trí Vương Lâm từ xa qua giếng nước và ba ngọn nến.","vaiTro":"Kẻ thao túng bí ẩn trong cung điện ẩn giấu ở Thái Cổ Tinh Thần","tinhCach":"Bình thản trước thất bại; mưu mô sâu xa","tabs":{"diem":[{"text":"Dùng thuật Tĩnh Trung Lao Nguyệt thao túng tâm trí Vương Lâm từ xa, kế hoạch chỉ thiếu một chút là thành công","chuong":"@c1346"}],"kinhLich":[{"chuong":"@c1347","importance":"normal","mucCt":"ky","tieuDe":"Bị lam quang ngăn giết Vương Lâm, nhượng bộ","text":"Chuẩn bị giết Vương Lâm qua mặt nước giếng, bị lam quang bùng lên ngăn cản. Nhắc ước định năm xưa, nói đối phương là một trong Thái Cổ ngũ tôn, hỏi có muốn lấy lại thân thể vợ con. Người trong lam quang nói còn có một phụ thân, đồng ý nhượng bộ chỉ một lần. Lão xoay người đi sâu vào đại điện.","anchor":"Đừng quên ngươi là một trong thái Cổ ngũ tôn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu thao túng","ghiChu":"@c1346"}],"tuiDo":{}},"nguon":["@c1346","@c1347"]},{"id":"thac-sam","name":"Thác Sâm","cn":"拓森","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1347","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Thân ảnh khổng lồ bước trong sương mù, hai mắt đỏ bừng rít gào điên cuồng, trên mi tâm có Hồ Mị Tử (tứ muội) ký sinh.","anchor":"Ngươi không cần phải gọi, bổn thần cũng tự mình đến! Con bà ngươi, câm miệng cho ta!"},{"mucCt":"vua","text":"Thân ảnh cao mười trượng, bước đi trong dòng khí gào thét xé nát thân thể ở tầng sâu nhất cổ mộ. Mang theo nữ tử áo hồng trên đài mộ ngàn trượng, bị nàng trêu chọc, gầm mắng nàng là mụ yêu quái nhưng vẫn tiếp tục mang theo.","anchor":"Câm miệng cho bổn thần. Mụ yêu quái ngươi quá mức phiền phức","bridge":true,"khoang":"@c1368"},{"chuong":"@c1374","importance":"normal","mucCt":"vua","tieuDe":"Chật vật ở khu vực bản đồ thứ chín","text":"Đang ở khu vực bản đồ thứ chín, gặp khó khăn trong không gian loạn lưu dày đặc. Chửi rủa Đạo Cổ Diệp Mịch vì truyền thừa quá gian nan, tự xưng là tộc nhân của Diệp Mịch.","anchor":"Đạo Cổ Diệp Mịch, bổn thần chính là tộc nhân của ngươi, truyền thừa này ngươi không truyền cho ta thì truyền cho ai"},{"mucCt":"vua","text":"Đang tiến trong tấm bản đồ thứ chín, cánh tay khổng lồ xuất hiện từ biển sương mù lao tới. Không bị đụng trực tiếp nhưng dư lực khiến lảo đảo phun máu, lộ vẻ sợ hãi hiếm thấy.","anchor":"Thác Sâm ngẩng đầu, trong mắt lộ ra một vẻ sợ hãi hiếm thấy, nhìn chằm chằm cánh tay khổng lồ kia đang nhanh chóng đi xa","bridge":true,"khoang":"@c1377"},{"chuong":"@c1380","importance":"normal","mucCt":"vua","tieuDe":"Phá lưới cổ mộ, bị Vương Lâm đánh bật","text":"Theo cảm ứng tìm đến cung điện cổ mộ, tám tinh điểm trên mi tâm xoay tròn, điên cuồng đấm phá tấm lưới hư ảo. Gầm thét rằng truyền thừa nên thuộc về mình, chê Đồ Ti ngăn cản. Sắp phá lưới tiến vào thì bị Vương Lâm ném thân thể Cổ Thần hóa đá mang lực phản chấn đánh trúng đầu, phun máu bị cuốn bay.","anchor":"Đạo Cổ đáng chết, truyền thừa này nên thuộc về bổn thần"},{"mucCt":"ky","text":"Phá cấm chế bên ngoài cung điện, bị thi thể Cổ Thần khổng lồ đâm trúng, xương cốt tay phải vỡ nát. Nhìn thấy Vương Lâm đang đoạt đạo cổ truyền thừa lẽ ra thuộc về mình, phát điên lồng lộn. Đấm vỡ ba lá cổ Tức Diệp, chống lại hợp lực của Linh Động và Chu Cẩn (hai Không Niết Sơ Kỳ). Phát tiếng rống Cổ Thần hóa cuồng phong đánh bại cả hai, hủy diệt tu sĩ và tám ngọn núi thi thể. Đang chuẩn bị xông vào thì bị thần thức Vương Lâm dung hợp ý chí cổ mộ chấn nhiếp, im bặt hoảng sợ.","anchor":"Ngươi đã cướp mất ký ức truyền thừa của ta, lúc này lại còn muốn cướp đi Đạo cổ truyền thừa","bridge":true,"khoang":"@c1381"},{"mucCt":"ky","text":"Dưới tiếng rống, phun máu, hơn nửa thân thể tan nát lộ xương trắng. Chương xác nhận đây là sự tan vỡ thân thể của bát tinh Cổ Thần, cho thấy Thác Sâm đạt bát tinh Cổ Thần.","anchor":"Thác Sâm dưới tiếng rống này phun ra máu tươi, thân thể lảo đảo, hai tay đỡ lấy toàn thân","bridge":true,"khoang":"@c1382"},{"mucCt":"ky","text":"Bị tiếng rống chấn động, thân thể máu thịt lẫn lộn lộ xương trắng, đang cấp tốc hồi phục bên trong tấm lưới hư ảo. Lộ thông tin tu vi hiện tại đạt bát tinh Cổ Thần nhờ chiếm thân thể Đồ Ti (vương tộc bát tinh Cổ Thần tồn tại từ vạn cổ) sau khi thoát nguy ở Chu Tước Tinh. Tinh điểm đã nhiều lần bị vỡ rồi khôi phục, Vương Lâm nhận xét không còn bằng năm đó.","anchor":"Tu vi của hắn từ sau khi thoát nguy ở Chu Tước Tinh, liền ch**m l** th*n th* của Đồ Ti","bridge":true,"khoang":"@c1383"},{"chuong":"@c1384","importance":"normal","mucCt":"ky","tieuDe":"Thừa nhận Vương Lâm, trận chiến định mệnh truyền thừa","text":"Hồi phục tám phần sức mạnh trên thân thể bát tinh đỉnh phong Đồ Ti. Lần đầu tiên bỏ xưng bổn thần, đổi sang ta khi nói với Vương Lâm, thừa nhận hắn là Cổ Thần thực sự. Tuyên bố trận chiến định mệnh tiếp nối trận ở Phong Giới Đại Trận. Biến thân cao ngàn trượng, dùng chín mươi chín quyền dung hợp thành một — đạo dĩ lực phá thiên. Chủ động đánh bật nữ tử phong tình, mắng nàng là đồ chơi của Tiên Tôn, phong kín tấm lưới hư ảo cách ly nàng khỏi trận chiến. Triệu pháp khí vương tộc Diệt Thần Mâu phóng tới Vương Lâm.","anchor":"Ngươi vẫn thật sự tưởng rằng bổn thần là hạng người l* m*ng hay sao"},{"chuong":"@c1385","importance":"normal","mucCt":"vua","tieuDe":"Diệt Thần Mâu bị chẻ đôi, bị xuyên thấu ngực","text":"Sử dụng Diệt Thần Mâu tấn công Vương Lâm nhưng bị một chỉ ma đạo cản lại. Huyết kiếm Vương Lâm chẻ đôi Diệt Thần Mâu rồi xuyên thấu ngực, phun máu lùi mấy trăm trượng, quỳ trên mặt đất.","anchor":"trực tiếp xuyên thấu, máu tươi b*n r* ra bốn phía, loé lên ở phía sau lưng Thác Sâm!"},{"chuong":"@c1386","importance":"major","mucCt":"ky","tieuDe":"Nhận truyền thừa Đồ Ti — hoang mang bản ngã","text":"Quỳ trên mặt đất nhận truyền thừa Đồ Ti từ Vương Lâm, lần đầu trong đời nói hai chữ đa tạ. Sau khi Vương Lâm rời đi, quỳ một mình trong cung điện đổ nát, trầm tư hoang mang về bản ngã — tự hỏi mình rốt cuộc là Thác Sâm hay Đồ Ti, vì chỉ là tia ma niệm từ phân thân thuật thất bại. Cuối cùng quyết tâm đặt ký ức truyền thừa lên mi tâm để hấp thu.","anchor":"Đồ Ti … … từ ngày ta sinh ra, ra đã biết mình chỉ là một tia ma niệm"}],"tuViMoc":[{"chuong":"@c1382","canhGioi":"Bát tinh Cổ Thần","text":"Chương xác nhận Thác Sâm là bát tinh Cổ Thần qua miêu tả sự tan vỡ thân thể bát tinh Cổ Thần.","importance":"major"}],"nhanMach":[{"ten":"Nữ tử áo hồng","tag":"khac","quanHe":"Bạn đồng hành trong cổ mộ, nàng gọi hắn là ca ca","ghiChu":"Quan hệ kỳ lạ, nàng trêu chọc hắn, hắn mắng nhưng vẫn mang theo @c1368"}],"tuiDo":{},"diem":[{"text":"Lộ diện là kẻ đứng đầu huyết hải bị phong ấn mấy vạn năm trong Cổ Thần Chi Địa, thực chất là ma vật do oán niệm Cổ Thần Đồ Ti ngưng tụ","chuong":"@c0163"},{"text":"Trao Hỗn Nguyên khu thú quyển và cực phẩm linh thạch cho Vương Lâm, dùng bảo vật làm mồi nhử để mưu cầu phá phong ấn","chuong":"@c0170"},{"text":"Phá phong ấn, hóa huyết hải thành huyết long vạn trượng xông vào hư vô, thi triển tuế nguyệt quy tắc tàn sát tu sĩ dưới Toái Niết","chuong":"@c1060"},{"text":"Thức tỉnh với thân thể to bằng mấy tu chân tinh cùng tám tinh điểm, triệu hồi Diệt Thần Mâu tàn sát và quét ngang Liên Minh tinh vực truy tìm Vương Lâm","chuong":"@c1065"},{"text":"Đại chiến Vương Lâm và Nguyệt Tộc, bị chém mất ngón trỏ, cho nổ tinh điểm phá vây ba cao thủ bước thứ ba","chuong":"@c1239"},{"text":"Lần đầu bỏ xưng bổn thần, quỳ nhận truyền thừa Đồ Ti từ Vương Lâm và nói hai chữ đa tạ, sau đó rơi vào hoang mang bản ngã","chuong":"@c1386"}]},"nguon":["@c1347","@c1368","@c1374","@c1377","@c1380","@c1381","@c1382","@c1383","@c1375","@c1384","@c1385","@c1386"],"canhGioiCaoNhat":"Bát tinh Cổ Thần (chiếm thân Đồ Ti)","vaiTro":"Phản diện trọng yếu — Cổ Ma Đồ Ti, ma vật chủ huyết hải bị phong ấn trong Cổ Thần Chi Địa","tinhCach":"Xảo trá, dùng cực phẩm linh thạch và Hỗn Nguyên khu thú quyển làm mồi nhử để mưu cầu phá phong ấn; tàn nhẫn, khinh miệt chúng sinh như kiến và tàn sát hàng loạt tu sĩ không chớp mắt; cuồng ngạo đỉnh thiên, coi mọi thế lực đều không đáng kể; chấp niệm sâu nặng, liên tục khắc tên Vương Lâm và thề truy","blurb":"Thác Sâm là nam tử tóc đỏ như máu, kẻ đứng đầu huyết hải, thực chất là ma vật do oán niệm của Cổ Thần Đồ Ti chết ngưng tụ — tức Cổ Ma Đồ Ti — bị phong ấn mấy vạn năm trên thạch chùy giữa Cổ Thần Chi Địa. Hắn dùng bảo vật dụ dỗ Vương Lâm phá phong ấn, thừa kế lực lượng truyền thừa bát tinh của Cổ Thần Đồ Ti, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ, phá phong ấn bay khỏi Chu Tước Tinh quét ngang Liên Minh tinh vực, truy tìm Vương Lâm xuyên suốt nhiều tinh vực. Cuối cùng trong cổ mộ, sau trận chiến định mệnh với Vương Lâm, Thác Sâm lần đầu bỏ xưng bổn thần"},{"id":"ho-mi-tu","name":"Hồ Mị Tử","cn":"","aliases":["Tứ muội","Lão tứ"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tứ muội trong nhóm chị em bí ẩn, thanh âm tràn đầy ma lực hấp dẫn. Bất chấp tất cả hợp tác với Thác Sâm, ký sinh trên mi tâm hắn.","vaiTro":"Tứ muội trong nhóm chị em, đồng minh của Thác Sâm","tinhCach":"Phóng đãng; ác độc; thích giễu cợt; bị thu hút bởi sự điên cuồng","tabs":{"diem":[{"text":"Thanh âm ma âm tràn đầy hấp dẫn, ký sinh trên mi tâm Thác Sâm, thích sự điên cuồng của hắn","chuong":"@c1347"},{"text":"Giễu cợt tam tỷ từng là thánh nữ Thiên Đạo Môn, bị Tiên Tôn bắt nuôi làm lô đỉnh","chuong":"@c1347"}],"kinhLich":[{"mucCt":"ky","text":"Thanh âm ma âm tràn đầy hấp dẫn từ mi tâm Thác Sâm truyền ra. Tự xưng nhân gia, thích Thác Sâm điên cuồng, chê Tiên Tôn vô dụng. Giễu cợt tam tỷ từng là thánh nữ Thiên Đạo Môn, vẫn là xử nữ, năm đó bị Tiên Tôn bắt nuôi dưỡng nhiều năm trở thành lô đỉnh tuyệt hảo nhưng lão không có phúc hưởng thụ.","anchor":"Nhân gia không nói không được, ngươi càng điên cuồng, nhân gia lại càng thích ngươi","bridge":true,"khoang":"@c1347"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"dong-minh","quanHe":"Hợp tác, ký sinh trên mi tâm Thác Sâm","ghiChu":"Thích sự điên cuồng của hắn"},{"ten":"Văn sĩ trung niên","tag":"ho-hang","quanHe":"Tam tỷ trong nhóm chị em","ghiChu":"Giễu cợt tam tỷ"}],"tuiDo":{}},"nguon":["@c1347"]},{"id":"nam-tu-trung-nien-dao-bao","name":"Nam tử trung niên đạo bào (kẻ đánh lén)","cn":"","aliases":["Nam tử trung niên (tu sĩ đánh lén)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Thiên Nhân đệ tam suy","trangThai":"tu-vong","blurb":"Tu sĩ trong khe cổ mộ, đánh lén Vương Lâm khi vừa bị truyền tống vào nhưng bị Quang Ảnh thuẫn phản kích bị thương.","vaiTro":"Tu sĩ đánh lén trong khe cổ mộ","tinhCach":"Ranh mãnh; nhát gan khi gặp kẻ mạnh","tabs":{"diem":[{"text":"Chuyên liên thủ với nhóm hơn mười tu sĩ giết người đoạt bảo trong khe cổ mộ","chuong":"@c1347"}],"kinhLich":[{"chuong":"@c1347","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Đánh lén Vương Lâm vừa bị truyền tống vào khe cổ mộ, bị Quang Ảnh thuẫn khúc xạ phản kích, khóe miệng chảy máu hoảng sợ lui lại.","anchor":"Sắc mặt hắn tái nhợt, khóe miệng còn có máu tươi tràn ra, ánh mắt nhìn về phía Vương Lâm, lộ ra vẻ hoảng sợ"},{"mucCt":"gon","text":"Đánh lén Vương Lâm thất bại, thần thông bị phản xạ ngược, dùng Huyết Độn thuật bỏ chạy nhưng bị Dịch Thiên Ấn xuyên thấu thân thể nghiền nát mà chết.","anchor":"tu sĩ trung niên kia bị chưởng ấn xuyên thấu thân thể, tan vỡ mà chết","bridge":true,"khoang":"@c1348"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1347","@c1348"]},{"id":"nu-tu-ao-trang","name":"Nữ tử áo trắng","aliases":["Nữ tử áo trắng tóc dài","Nữ tử tóc dài bạch y","Nữ tử tóc dài quá lưng","Tiên phi","bạch y nữ tử"],"trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Nữ tử tóc đen dài dung nhan tuyệt trần, lạnh lùng như băng, hình dáng cực kỳ giống văn sĩ trung niên bên ngoài khe. Khi ánh mắt chạm ánh mắt Vương Lâm, cổ mộ phát sinh kinh biến — bầu trời ầm ầm, sương mù cuộn cuồng, cái khe bên ngoài Thái Cổ Tinh Thần đóng chặt hoàn toàn.","anchor":"Hình dáng của nữ tử này so với văn sĩ trung niên mà hắn nhìn thấy lúc ở bên ngoài cái khe cực kỳ giống nhau","bridge":true,"khoang":"@c1348"},{"mucCt":"vua","text":"Yên lặng đứng trên đài cao nhìn chân trời xa, ai tới gần đều bị trúng hắc khí, hai mắt chảy máu đen, kêu thảm thiết mà chết. Không cần động tay.","anchor":"hễ có tu sĩ nào tiến gần đài cao, chưa kịp bước vào liền lập tức kêu lên thảm thiết, hai mắt chảy ra máu đen","bridge":true,"khoang":"@c1349"},{"chuong":"@c1351","importance":"bridge","mucCt":"vua","text":"Bình tĩnh đứng trên đài cao, không thi triển thần thông, mãnh thú tới gần tự phát hắc khí thất khiếu chảy máu rồi lùi lại. Không tranh đoạt mãnh thú, cuối cùng tỏ vẻ tán thưởng gật đầu về phía Vương Lâm.","anchor":"nữ tử áo trắng kia trong mắt lộ vẻ tán thưởng, hướng về v gật đầu tỏ ý"},{"importance":"bridge","mucCt":"gon","chuong":"@c1352","text":"Luôn giữ vẻ bình tĩnh nhưng khoảnh khắc Vương Lâm lộ thân phận tu sĩ hư hỏa thì ánh mắt cũng lộ khiếp sợ, có tia sáng kỳ dị lóe lên.","anchor":"Ngay cả nữ tử áo trắng thủy chung vẫn bình tĩnh kia trong khoảnh khắc này ánh mắt cũng lộ ra vẻ khiếp sợ"},{"chuong":"@c1353","importance":"normal","tieuDe":"Rời vùng phong ấn, hẹn gặp lại Vương Lâm","text":"Không dâng pháp bảo, nở nụ cười nhìn Vương Lâm thật sâu, tự bay lên từ đài cao chui qua khe hở trên bầu trời rời khỏi vùng phong ấn. Để lại lời trong phong ấn có kỳ bảo, nhường cho Vương Lâm, và hẹn sẽ còn gặp lại.","mucCt":"vua","anchor":"Nếu ngươi cảm thấy hứng thú thì ta sẽ rời đi"},{"mucCt":"vua","text":"Đứng trên đài mộ năm ngàn trượng tại nơi sâu trong cổ mộ dưới bầu trời đen tối. Cảm ứng được đài mộ cấp năm mới xuất hiện, tự nhận định có lẽ là Diệu Âm rồi tiếp tục lao đi.","anchor":"Là người nào vậy… có lẽ là Diệu Âm…","bridge":true,"khoang":"@c1368"},{"chuong":"@c1374","importance":"normal","mucCt":"gon","tieuDe":"Dùng bí thuật hấp thu ký hiệu trong cổ mộ","text":"Ở khu vực bản đồ thứ tám trên bầu trời biển sương mù, đài mộ sắp đạt cấp bảy, dùng bí thuật hấp thu ký hiệu rải rác trong cổ mộ để thăng cấp.","anchor":"ta bởi vì có bí thuật nên mới có thể hấp thu những ký hiệu rải rác trong vùng đất cổ mộ này"},{"chuong":"@c1375","importance":"normal","mucCt":"vua","tieuDe":"Chuyển hướng truy sát chủ đài mộ cấp tám","text":"Đài mộ cấp bảy ở bản đồ thứ tám, cảm nhận đài mộ cấp tám, thần sắc âm trầm rồi chuyển hướng truy sát. Xuất hiện bên phải khi Vương Lâm thi triển Phần Giới Cổ Tán, nhìn thấy rõ Vương Lâm thì sửng sốt.","anchor":"ngay khi nhìn thấy rõ Vương Lâm, cũng hiện lên một vẻ sửng sốt"},{"mucCt":"vua","text":"Bị biển lửa Phần Giới Cổ Tán bức lui. Ra tay quyết đoán thi triển Thiên môn tam đạo Nhật Nguyệt Tinh — Tinh môn mở ra, tạo cánh cửa khổng lồ chặn đạo thuật Cách Sơn Chi Tiên của Cửu Thiên Ma Tôn, cứu Vương Lâm. Cánh cửa tan biến, sắc mặt tái nhợt bị chấn lùi trăm trượng. Đáp lạnh lùng khi bị hỏi lý do, nhíu mày nhìn theo hướng Vương Lâm biến mất rồi cất bước theo sau.","anchor":"Bổn cung làm việc mà lại cần phải giải thích với ngươi sao? Ngươi là có tư cách gì?","bridge":true,"khoang":"@c1376"},{"mucCt":"vua","text":"Khi đài mộ cấp chín xuất hiện, trong trầm mặc lui về phía sau bỏ qua tranh đoạt. Nhờ ở xa nhất nên chỉ bị dư lực cánh tay khổng lồ thổi phun máu, thoát chết.","anchor":"Duy chỉ có nữ tử áo trắng kia trong lúc trầm mặc lui về phía sau, giống như bỏ qua việc tranh đoạt","bridge":true,"khoang":"@c1377"},{"chuong":"@c1382","importance":"normal","mucCt":"vua","tieuDe":"Lùi về bản đồ thứ nhất, bị thần thức Vương Lâm dừng lại trên người","text":"Đang lùi về bản đồ thứ nhất định rời cổ mộ vì linh cảm không ổn. Bị thần thức Vương Lâm dừng lại trên người một lúc, sợ hãi xấu hổ, toát mồ hôi. Sau khi thần thức rời đi, ánh mắt phức tạp nhìn theo.","anchor":"nàng mơ hồ có cảm giác không ổn, dường như nếu lúc này không rời khỏi nàng sẽ vĩnh viễn phải ở lại chỗ này"},{"chuong":"@c1383","importance":"normal","mucCt":"vua","tieuDe":"Thoát khỏi cổ mộ nhờ Vương Lâm","text":"Bên trong cổ mộ bị tiếng rống trọng thương, gần tuyệt vọng khi khe sắp đóng. Được Vương Lâm dùng thần thức tạm dừng khe, lao ra ngoài thoát thân. Nhận ra thần thức quen thuộc của Vương Lâm, vẻ phức tạp xen xấu hổ, xoay người nhìn lại cổ mộ rồi rời đi.","anchor":"đôi mắt nhìn thoáng qua cổ mộ phía sau, mơ hồ nàng có thể cảm nhận được thần thức của Vương Lâm"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Ánh mắt chạm nhau gây kinh biến toàn cổ mộ"}],"tuViMoc":[],"diem":[{"text":"Bước ra từ đại điện Tiên phủ, chỉ một ánh mắt đã khiến nhóm Vương Lâm trọng thương tâm thần","chuong":"@c0946"},{"text":"Dùng kỳ hương, rừng hoa, trâm cài tóc, Táng hoa và quang đoàn bổn nguyên lực áp chế Vương Lâm, sau đó tự xưng Hoa Phi Hàm Yên — một trong tiên đế bát phi","chuong":"@c0949"},{"text":"Bị Vương Lâm phân tích chỉ là hình chiếu phân thân tu vi thiên nhân tam suy, không phải thực thể","chuong":"@c1249"},{"text":"Hồn phách và hương hỏa bị Vương Lâm đoạt sau khi ấn ký hình chữ 'xuyên' kích hoạt ký ức bị phong ấn","chuong":"@c1251"},{"text":"Trong cổ mộ dùng bí thuật hấp thu ký hiệu, nâng đài mộ lên cấp bảy rồi chuyển hướng truy sát chủ đài mộ cấp tám","chuong":"@c1375"},{"text":"Thoát khỏi cổ mộ nhờ Vương Lâm dùng thần thức cứu giúp khi khe hở sắp đóng","chuong":"@c1383"}]},"nguon":["@c1348","@c1349","@c1350","@c1351","@c1352","@c1353","@c1368","@c1374","@c1375","@c1376","@c1377","@c1382","@c1383"],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","vaiTro":"Hoa Phi Hàm Yên — một trong tiên đế bát phi, người khảo nghiệm Tiên phủ","tinhCach":"Uy áp tuyệt đối, chỉ bằng ánh mắt đã khiến đối thủ trọng thương tâm thần; hành sự lạnh lùng bình tĩnh, đứng yên không thi triển thần thông mà vạn vật tới gần tự diệt; kiên trì truy đuổi, theo dấu từng lần dịch chuyển của đối thủ để chặn đường; quyết đoán khi tiến lui, biết bỏ tranh đoạt lúc bất lợi ","blurb":"Nữ tử áo trắng dung mạo tuyệt trần bước ra từ đại điện Tiên phủ, dùng kỳ hương, rừng hoa và Táng hoa áp chế Vương Lâm rồi tự xưng Hoa Phi Hàm Yên — một trong tiên đế bát phi, có liên hệ mật thiết với Tiên Đế Thanh Lâm và bí mật về Thu Dao. Thân phận thực chất chỉ là hình chiếu phân thân tu vi thiên nhân tam suy; hồn phách và hương hỏa cuối cùng bị Vương Lâm đoạt. Về sau, một nữ tử dung nhan tuyệt trần hình dáng cực giống nàng xuất hiện trong cổ mộ, sở hữu đài mộ và bí thuật hấp thu ký hiệu, trải qua nhiều lần giao phong rồi được Vương Lâm cứu thoát khỏi cổ mộ."},{"id":"tu-si-trung-nien-ao-vai","name":"Tu sĩ trung niên áo vải (kiếm khách bầu rượu)","cn":"","aliases":["Tu sĩ trung niên cầm bầu rượu","Tu sĩ trung niên tay trái cầm bầu rượu"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Kiếm khách phóng khoáng tay trái cầm bầu rượu, tay phải cầm trường kiếm bảy thước. Vừa uống rượu vừa ngâm thơ vừa giết người, máu rơi thành hình hoa mai trên đài cao.","vaiTro":"Một trong năm cao thủ đáng chú ý trên đài cao trong sương mù","tinhCach":"Tiêu sái phóng khoáng; coi chuyện giết người nhẹ như uống rượu ngâm thơ","tabs":{"diem":[{"text":"Kiếm pháp cực cao, mỗi kiếm đâm xuyên mi tâm kẻ địch, máu tươi rơi thành hình hoa mai trên đài cao","chuong":"@c1349"},{"text":"Vừa uống rượu vừa ngâm câu Hiệp Khách Hành của Lý Bạch, phong cách tiêu sái hiệp khách","chuong":"@c1349"}],"kinhLich":[{"mucCt":"ky","text":"Tay trái cầm bầu rượu, tay phải cầm trường kiếm bảy thước, vừa uống rượu vừa ngâm câu Hiệp Khách Hành của Lý Bạch. Tùy ý vung kiếm đâm xuyên mi tâm kẻ địch, máu tươi rơi xuống đài cao thành hình hoa mai. Phong cách tiêu sái phóng khoáng, kiếm pháp cực cao, được Vương Lâm chú ý.","anchor":"mũi kiếm kia đã đâm vào mi tâm một người đang lao tới","bridge":true,"khoang":"@c1349"},{"chuong":"@c1351","importance":"bridge","mucCt":"vua","text":"Tay trái cầm bầu rượu, tay phải cầm kiếm chiến đấu với mãnh thú. Khi sắp thi triển thần thông thì Vương Lâm xông tới giết hơn phân nửa trong khoảng trăm con mãnh thú quanh hắn, rồi nhận ra manh mối về sức sống mãnh thú.","anchor":"Tu sĩ trung niên kia nhướng mày, nói thầm vài câu nhưng đột nhiên ánh mắt sững lại"},{"importance":"normal","mucCt":"vua","chuong":"@c1352","tieuDe":"Mỉa mai Vương Lâm, lao vào chiến mãnh thú","text":"Lắc đầu uống rượu, mỉa mai Vương Lâm tham lam ngu xuẩn, hỏi mỉa hắn tưởng mình là cao thủ bước thứ ba sao, rồi lao xuống đám mãnh thú. Sau đó chứng kiến hư hỏa, kinh hoàng.","anchor":"Tu sĩ trung niên tay trái cầm bầu rượu, lắc đầu uống rượu xong"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[{"ten":"Trường kiếm bảy thước","trangThai":"dang-co","moTa":"Binh khí chủ lực, kiếm pháp tinh diệu đâm mi tâm kẻ địch","nguon":"@c1349"},{"ten":"Bầu rượu","trangThai":"dang-co","moTa":"Tay trái luôn cầm khi chiến đấu, vừa uống vừa giết người","nguon":"@c1349"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1349","@c1351","@c1352"]},{"id":"nam-tu-ao-tim","name":"Nam tử áo tím","cn":"","aliases":["Nam tử áo tím (hư ảnh cá ngàn trượng)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nam tử sắc mặt âm trầm tràn ngập khí âm hàn, có thể triệu hồi con cá dữ dài ngàn trượng từ trong tay áo nuốt chửng kẻ địch.","vaiTro":"Một trong năm cao thủ đáng chú ý trên đài cao trong sương mù","tinhCach":"Âm trầm lạnh lùng","tabs":{"diem":[{"text":"Triệu hồi con cá dữ dài ngàn trượng mang theo tinh phong cắn nuốt kẻ địch","chuong":"@c1349"},{"text":"Phía sau có hư ảnh con cá ngàn trượng","chuong":"@c1350"}],"kinhLich":[{"mucCt":"vua","text":"Sắc mặt âm trầm tràn ngập khí âm hàn, triệu hồi con cá dữ dài ngàn trượng từ trong tay áo nuốt chửng tất cả tu sĩ lại gần. Được Vương Lâm chú ý.","anchor":"ở phía sau liền có một con cá dữ tợn dài ngàn trượng chạy ra, mang theo tinh phong cắn nuốt","bridge":true,"khoang":"@c1349"},{"chuong":"@c1350","importance":"normal","mucCt":"gon","tieuDe":"Quan sát Vương Lâm trên đài cao","text":"Ngồi đả tọa trên đài cao, nhận xét Vương Lâm chiến đấu không lộ nhiều thần thông, không nhìn ra manh mối.","anchor":"Người này vừa rồi chiến đấu không lộ nhiều thần thông nên nhìn không ra chút manh mối nào"},{"mucCt":"vua","text":"Mắt lóe sát khí, dọa nếu Vương Lâm chọc giận thì biến khỏi nhóm tự lo sống chết, không biến thì hắn cho thi thể biến. Sau khi Vương Lâm lộ tu sĩ hư hỏa, kinh hoàng lui về sau.","anchor":"Nam tử áo tím sau lưng có con cá hung ác biến ảo trong mắt lóe lên sát khí","bridge":true,"khoang":"@c1352"},{"chuong":"@c1353","importance":"bridge","tieuDe":"Dâng hồ lô cho Vương Lâm","text":"Sắc mặt tái nhợt, dâng bảo vật hình hồ lô đoạt từ đài cao trong cổ mộ cho Vương Lâm, trong lòng hối hận.","mucCt":"vua","anchor":"trực tiếp xuất ra một bảo vật hình hồ lô đoạt được trên một đài cao trong cổ mộ"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát","ghiChu":"Nhận xét không nhìn ra manh mối thần thông"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1349","@c1350","@c1352","@c1353"]},{"id":"nam-tu-gay-ao-den","name":"Nam tử gầy áo đen (nhắm mắt)","cn":"","aliases":["Tu sĩ mặc hắc y (mắt nhắm)","Tu sĩ áo đen gầy đét (nhắm hai mắt)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nam tử gầy như bộ xương, thân hình cực cao, thủy chung nhắm mắt. Tốc độ siêu phàm đến mức Vương Lâm cũng không nhìn rõ tung tích, giết người bằng cách kéo nguyên thần ra khỏi thân thể.","vaiTro":"Một trong năm cao thủ đáng chú ý trên đài cao trong sương mù","tinhCach":"Bí ẩn, thủy chung nhắm mắt","tabs":{"diem":[{"text":"Tốc độ siêu phàm đến mức Vương Lâm cũng không nhìn rõ tung tích","chuong":"@c1349"},{"text":"Giết người bằng cách kéo nguyên thần ra khỏi thân thể, thi thể rơi vào sương mù","chuong":"@c1349"}],"kinhLich":[{"mucCt":"vua","text":"Gầy như bộ xương, thủy chung nhắm mắt, thân ảnh cực nhanh kể cả Vương Lâm cũng không nhìn rõ tung tích. Giết người bằng cách kéo nguyên thần ra, thân thể rơi vào sương mù.","anchor":"ngay cả Vương Lâm cũng không nhìn rõ tung tích","bridge":true,"khoang":"@c1349"},{"mucCt":"vua","text":"Lạnh lùng dọa nếu Vương Lâm giết hơn một con mãnh thú thì hôm nay phải chết tại chỗ. Sau khi Vương Lâm lộ thân phận tu sĩ hư hỏa, kinh hoàng lui về sau.","anchor":"Nếu giết hơn một con, hôm nay ngươi sẽ phải chết ở chỗ này!","bridge":true,"khoang":"@c1352"},{"chuong":"@c1353","importance":"bridge","tieuDe":"Dâng phi kiếm đen cho Vương Lâm","text":"Dâng thanh phi kiếm đen tràn ngập khí tức Cổ Ma cho Vương Lâm, trên mi tâm có phong ấn kỳ dị — nếu mở mắt sẽ bùng phát lực lượng phong ấn.","mucCt":"vua","anchor":"trên mi tâm của người này có một luồng lực lượng kì dị, dường như là một phong ấn vậy"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1349","@c1352","@c1353"]},{"id":"lao-gia-thien-nhan-tu-suy","name":"Lão già Thiên Nhân Đệ Tứ Suy","cn":"","aliases":["Lão già Thiên Nhân Tứ Suy"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Thiên Nhân Đệ Tứ Suy","trangThai":"song","blurb":"Tu sĩ cao nhất tu vi trong nhóm xông vào đài cao Vương Lâm. Dùng chín con hắc long hộ thân và túm tu sĩ khác làm khiên chắn để sống sót, bị quát cút thì hoảng sợ rời đi.","vaiTro":"Tu sĩ xông vào đài cao Vương Lâm, bị đuổi","tinhCach":"Xảo quyệt; sẵn sàng hy sinh đồng đội để bảo mạng","tabs":{"diem":[{"text":"Túm tu sĩ khác làm khiên chắn kiếm khí Vương Lâm để sống sót","chuong":"@c1349"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1349","text":"Dùng chín con hắc long hộ thân và túm tu sĩ khác làm khiên chắn kiếm khí Vương Lâm, sống sót, bị quát cút thì hoảng sợ rời đi.","anchor":"hai tay bấn quyết, toàn thân lập tức tràn ngập chín con hắc long"},{"chuong":"@c1350","importance":"normal","mucCt":"gon","tieuDe":"Cướp đài thành công, mang ơn Vương Lâm","text":"Cướp đoạt đài cao thành công, cúi đầu sợ hãi, coi việc Vương Lâm không giết mình là một ân tình.","anchor":"Hắn vừa rồi không giết ta, thật ra đã cho ta một ân tình"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1349","@c1350"]},{"id":"nu-tu-trung-nien-mat-canh-tay","name":"Nữ tử trung niên (mất cánh tay)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tu sĩ trung niên tốc độ cực nhanh, né được một phần kiếm khí của Vương Lâm nhưng bị mất cánh tay phải.","vaiTro":"Tu sĩ xông vào đài cao Vương Lâm, sống sót nhưng mất cánh tay","tinhCach":"Nhanh nhẹn; cố chấp","tabs":{"diem":[{"text":"Né được một phần kiếm khí Vương Lâm nhờ tốc độ nhanh nhưng mất cánh tay phải","chuong":"@c1349"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1349","text":"Xông vào đài cao Vương Lâm, né kiếm khí nhưng mất cánh tay phải, bị quát cút thì rời đi.","anchor":"vai phải của nữ tử này bị đánh thành một đám thịt nát"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1349"]},{"id":"tu-si-beo-map-vien-ngoai","name":"Tu sĩ béo mập viên ngoại (bàn tính)","cn":"","aliases":["Tu sĩ béo cầm bàn tính","Tu sĩ béo mập mặc như viên ngoại","Tu sĩ mập mạp viên ngoại"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ thân thể mập mạp như quả bóng thịt, khuôn mặt hiền lành, mặc áo giáp viên ngoại đội mũ dẹt, tay cầm bàn tính nhỏ. Thi triển cấm chế phong ấn nhiều tu sĩ, là một trong những người cướp đoạt đài cao thành công.","vaiTro":"Tu sĩ tham gia tranh đoạt đài cao trong vùng cổ mộ","tinhCach":"Hiền lành bề ngoài nhưng thủ đoạn tàn nhẫn; quan sát tinh tế, nhận ra ma công thôn phệ huyết vụ","tabs":{"diem":[{"text":"Thân hình mập mạp như viên ngoại, tay cầm bàn tính, thi triển cấm chế phong ấn hàng loạt tu sĩ","chuong":"@c1350"},{"text":"Thân thể mập mạp như quả bóng thịt, khuôn mặt hiền lành, tay cầm bàn tính nhỏ, mặc áo giáp viên ngoại đội mũ dẹt","chuong":"@c1350"}],"kinhLich":[{"chuong":"@c1350","importance":"normal","mucCt":"vua","tieuDe":"Cướp đài cao, nhận xét Vương Lâm","text":"Thi triển cấm chế phong ấn tu sĩ xung quanh rơi xuống biển sương mù, cướp đài cao thành công. Nhận xét Vương Lâm thôn phệ huyết vụ, cho rằng ma công loại này gần đây ở Thái Cổ Tinh Thần xuất hiện không ít.","anchor":"ma công cỡ này những năm gần đây ở Thái Cổ Tinh Thần xuất hiện không ít"},{"mucCt":"vua","text":"Vung bàn tính cười tủm tỉm đe dọa Vương Lâm không được giết hơn mười con mãnh thú. Sau khi Vương Lâm lộ thân phận tu sĩ hư hỏa, mặt cắt không còn máu.","anchor":"Đạo hữu tóc bạc kia, mãnh thú nơi này ngươi không thể giết hơn mười con","bridge":true,"khoang":"@c1352"},{"chuong":"@c1353","importance":"bridge","tieuDe":"Dâng mảnh lân giáp cho Vương Lâm","text":"Sợ hãi dâng mảnh lân giáp lấy từ bình đài cổ mộ cho Vương Lâm để xin tha lỗi vì trước đó đã đe dọa luyện hồn.","mucCt":"vua","anchor":"tiểu đạo đúng là có nói như vậy, xin đạo hữu thứ lỗi cho"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ tiềm tàng trên đài cao","ghiChu":"Ngầm quan sát và đánh giá thần thông của Vương Lâm"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát","ghiChu":"Nhận xét thần thông thôn phệ huyết vụ của Vương Lâm"}],"tuiDo":{"phapBao":[{"ten":"Bàn tính nhỏ","moTa":"Tay cầm bàn tính nhỏ vung vẩy phát tiếng lách cách, chưa rõ công năng","nguon":"@c1350"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1350","@c1352","@c1353"]},{"id":"lao-ba-ao-luc","name":"Lão bà áo lục","cn":"","aliases":["Lão bà mặc lục bào mặt đầy mụn","Bà lão áo lục (Phong Huyễn Tộc)","Lão bà mặt mụn nhọt"],"gioiTinh":"nu","theLuc":[{"ten":"Phong Huyễn Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Lão bà mặc áo lục, mặt đầy mụn nhọt, có thần thông khiến người khác mê mang. Chiếm đài cao mà không cần chiến đấu, có kiến thức về cổ mộ từ sách cổ.","vaiTro":"Tu sĩ chiếm đài cao, có kiến thức về vùng đất cổ mộ","tinhCach":"Am hiểu cổ tịch; chủ động kêu gọi hợp tác; bí ẩn đáng ngờ","tabs":{"diem":[{"text":"Chiếm đài cao mà không cần đánh — hơn mười người tự lùi đi nhờ thần thông mê mang","chuong":"@c1350"},{"text":"Đọc sách cổ biết rõ nơi đây là ngoại vi vùng đất cổ mộ, kêu gọi hợp tác vượt khảo nghiệm","chuong":"@c1350"},{"text":"Mặt đầy mụn nhọt, có thần thông mê mang khiến hơn mười tu sĩ tự rời đài mà không cần đánh","chuong":"@c1350"},{"text":"Đọc sách cổ, biết rõ nơi đây là ngoại vi vùng đất cổ mộ","chuong":"@c1350"}],"kinhLich":[{"chuong":"@c1350","importance":"normal","mucCt":"vua","tieuDe":"Chiếm đài không đánh, tiết lộ bí mật cổ mộ","text":"Chiếm đài cao mà không cần đánh, hơn mười tu sĩ tự lùi đi khi bà tới gần. Sau khi đài cao chìm vào sương mù, kêu gọi hợp tác, tiết lộ nơi đây là ngoại vi vùng đất cổ mộ cần vượt khảo nghiệm mới được vào. Tiếng nói kích động đàn mãnh thú gầm rống xông ra tấn công.","anchor":"Chúng ta hiện giờ đang ở ngoại vi của vùng đất cổ mộ, sau khi vượt qua khảo nghiệm thì mới được tiến vào"},{"mucCt":"vua","text":"Lên tiếng dọa nếu Vương Lâm còn tham lam thì lão bà sẽ tự tay giết dù tu vi cao đến đâu. Sau khi Vương Lâm lộ tu sĩ hư hỏa, kinh hoàng lui về sau.","anchor":"nếu quá mức tham lam, ngay cả lão bà cũng nhìn có chút không vừa mắt","bridge":true,"khoang":"@c1352"},{"text":"Giao chiến với Vương Lâm, va chạm nguyên lực mấy mươi lần, phun máu tươi. Bị ép sử dụng Phong Huyễn Thuật — phun sương mù đỏ nhạt tạo ảo giác người chí thân. Bị Tuế Nguyệt nhất chỉ phá tan thần thông, ấn ký trên mi tâm hiện ra hình bóng lưng một nữ tử. Hư hỏa bùng phát thiêu đốt, bị Vương Lâm biến hư hỏa thành cấm chế trên người. Lộ thân phận thuộc Phong Huyễn Tộc (tam đại kỳ tộc). Dâng pháp bảo xin tha mạng.","mucCt":"ky","anchor":"Người này không ngờ lại là người của một trong tam đại kỳ tộc – Phong huyễn tộc","bridge":true,"khoang":"@c1353"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm uy hiếp, đánh bại, đặt cấm chế hư hỏa"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1350","@c1352","@c1353"]},{"id":"tu-si-hung-ac","name":"Tu sĩ hung ác (cướp đài thành công)","cn":"","aliases":["Tu sĩ hung ác (cướp đài thành công)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong những tu sĩ cướp đoạt đài cao thành công, nhìn Vương Lâm với vẻ không lành, đoán thần thông của hắn liên quan đến âm thanh.","vaiTro":"Tu sĩ tranh đoạt đài cao trong vùng cổ mộ","tinhCach":"Hung ác, hay quan sát đánh giá đối thủ","tabs":{"diem":[{"text":"Đoán thần thông của Vương Lâm liên quan đến âm thanh","chuong":"@c1350"},{"text":"Cướp đài cao thành công, nhìn Vương Lâm với vẻ không lành","chuong":"@c1350"}],"kinhLich":[{"chuong":"@c1350","importance":"normal","mucCt":"gon","tieuDe":"Cướp đài, đoán thần thông Vương Lâm","text":"Cướp đài cao thành công, nhìn Vương Lâm với vẻ không lành, đoán thần thông của hắn liên quan đến âm thanh.","anchor":"xem ra thần thông của người này có liên quan đến âm thanh"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng cảnh giác","ghiChu":"Đoán thần thông Vương Lâm liên quan âm thanh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1350"]},{"id":"ke-phat-tieng-noi-chin-dai-cao","name":"Kẻ phát tiếng nói uy áp (chủ chín đài cao)","gioiTinh":"nam","trangThai":"song","vaiTro":"Kẻ thần bí chưa lộ diện, sở hữu chín đài cao khổng lồ, ra lệnh kiêu ngạo tại vùng cổ mộ","tinhCach":"uy áp; kiêu ngạo","blurb":"Kẻ chưa lộ danh tính, giọng nói âm trầm tràn ngập uy áp. Xuất hiện cùng chín đài cao khổng lồ từ chân trời lao tới vùng đất cổ mộ, ra lệnh mọi người dâng pháp bảo đoạt được rồi đợi xử lý.","tabs":{"diem":[{"text":"Chưa lộ diện, chỉ phát giọng nói uy áp âm trầm, chỉ huy chín đài cao khổng lồ lao vào vùng phong ấn cổ mộ.","chuong":"@c1353"}],"kinhLich":[{"chuong":"@c1353","importance":"normal","tieuDe":"Xuất hiện tại vùng cổ mộ với chín đài cao","text":"Chín đài cao khổng lồ từ chân trời ầm ầm lao tới vùng đất cổ mộ. Giọng nói âm trầm tràn ngập uy áp ra lệnh mọi người dâng pháp bảo đoạt từ cổ mộ rồi đợi xử lý.","mucCt":"gon","anchor":"các người dâng ra pháp bảo đoạt được từ cổ mộ, sau đó đợi quyết định của ta"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1353"]},{"id":"tu-ma-mac","name":"Tư Mã Mặc","cn":"司马默","aliases":["Tư Mặc Tử"],"tabs":{"kinhLich":[]},"nguon":["@c1343"]},{"id":"van-si-trung-nien-chin-tuong","name":"Văn sĩ trung niên (chín pho tượng)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Văn sĩ diện mạo mỹ miều ẩn chứa nữ tính, có chín pho tượng kỳ dị không tóc vờn quanh hộ thân, xuất hiện ở chỗ sâu nhất sương mù vùng cổ mộ xin Vương Lâm giúp đỡ.","vaiTro":"Tu sĩ bí ẩn trong vùng sương mù cổ mộ Thái Cổ Tinh Thần","tinhCach":[{"text":"Hoảng sợ, cầu cứu người lạ khi gặp nguy"}],"tabs":{"diem":[{"text":"Diện mạo mỹ miều ẩn chứa nữ tính, giọng nói giống nữ tử, có chín pho tượng kỳ dị không tóc phát ánh sáng vàng nhạt vờn quanh hộ thân.","chuong":"@c1346"}],"kinhLich":[{"chuong":"@c1346","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện trong sương mù, xin Vương Lâm giúp đỡ","text":"Xuất hiện từ sương mù ở chỗ sâu nhất gần khe vùng cổ mộ, sắc mặt tái nhợt, bên ngoài thân có chín pho tượng kỳ dị vờn quanh. Mi tâm cũng có ký hiệu con số. Nhìn thấy Vương Lâm thì kinh ngạc, dùng giọng giống nữ tử xin giúp đỡ nhưng bị phớt lờ.","anchor":"Một thanh âm rất dễ nghe giống như của một nữ tử từ trong miệng văn sĩ kia truyền ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Gặp trong sương mù cổ mộ, xin giúp đỡ nhưng bị phớt lờ","ghiChu":"@c1346"}],"tuiDo":{"phapBao":[{"ten":"Chín pho tượng kỳ dị","moTa":"Chín pho tượng không tóc, biểu cảm khác nhau, vờn quanh thân phát ánh sáng vàng nhạt, hộ thân xuyên sương mù","nguon":"@c1346"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1346"]},{"id":"ke-hac-bao-cung-dien","name":"Kẻ hắc bào (cung điện ẩn giấu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Kẻ bí ẩn mặc hắc bào ẩn thân trong cung điện giữa tinh không Thái Cổ Tinh Thần, dùng thuật Tĩnh Trung Lao Nguyệt thao túng tâm trí Vương Lâm từ xa, kế hoạch thất bại khi Vương Lâm bước vào sương mù cổ mộ.","vaiTro":"Kẻ thao túng bí ẩn, ẩn thân trong cung điện không ai tìm được giữa tinh không Thái Cổ Tinh Thần","tinhCach":[{"text":"Bình tĩnh, mưu mô thâm sâu, không hoảng loạn khi kế hoạch thất bại"}],"tabs":{"diem":[{"text":"Dùng thuật Tĩnh Trung Lao Nguyệt thao túng tâm trí Vương Lâm từ xa — gieo ý tưởng, che giấu nghi ngờ — thông qua giếng nước và ba ngọn nến phong ấn thân ảnh.","chuong":"@c1346"},{"text":"Ẩn thân trong cung điện trôi nổi giữa tinh không vô biên mà không ai tìm được, giọng già nua khàn khàn.","chuong":"@c1346"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu thao túng bằng thuật Tĩnh Trung Lao Nguyệt, kế hoạch thất bại","ghiChu":"@c1346"}],"tuiDo":{"phapBao":[{"ten":"Giếng nước + ba ngọn nến","moTa":"Giếng mặt nước trong suốt như gương kết hợp ba ngọn nến, bộ phận cốt lõi của thuật Tĩnh Trung Lao Nguyệt, phản chiếu và phong ấn thân ảnh mục tiêu để thao túng","nguon":"@c1346"}],"danDuoc":[],"congPhap":[{"ten":"Tĩnh Trung Lao Nguyệt","moTa":"Thuật thao túng tâm trí từ xa: dùng giếng nước tĩnh + ba ngọn nến tạo thân ảnh mục tiêu rồi phong ấn, gieo ý tưởng và che giấu nghi ngờ trong tâm trí đối phương","nguon":"@c1346"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1346"]},{"id":"nguoi-hac-bao-ben-gieng","name":"Người hắc bào bên giếng","cn":"","aliases":["Kẻ thao túng Vương Lâm"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nhân vật bí ẩn toàn thân hắc bào ẩn trong cung điện giữa Thái Cổ Tinh Thần, dùng thuật Tĩnh trung lao nguyệt thao túng tâm trí Vương Lâm từ xa qua giếng nước và ba ngọn nến.","vaiTro":"Kẻ thao túng bí ẩn, đứng sau mọi quyết định điên cuồng của Vương Lâm ở Thái Cổ Tinh Thần","tinhCach":[{"text":"Bình tĩnh trước thất bại, giọng già nua khàn khàn, không lộ tướng mạo"}],"tabs":{"diem":[{"text":"Dùng thuật Tĩnh trung lao nguyệt phong ấn thân ảnh Vương Lâm trong giếng nước bằng ba ngọn nến, thao túng tâm trí hắn suốt thời gian ở Thái Cổ Tinh Thần","chuong":"@c1346"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu thao túng","ghiChu":"Phong ấn thân ảnh Vương Lâm trong giếng nước, thao túng tâm trí hắn từ khi tới Thái Cổ Tinh Thần"}],"tuiDo":{"phapBao":[{"ten":"Giếng nước trong cung điện","moTa":"Giếng trên mặt đất cung điện, mặt nước trong suốt như gương, phản chiếu ba ngọn nến và thân ảnh mục tiêu bị phong ấn","nguon":"@c1346"},{"ten":"Ba ngọn nến","moTa":"Ba ngọn nến phản chiếu trong giếng, vờn quanh thân ảnh mục tiêu tạo hiệu ứng phong ấn thao túng","nguon":"@c1346"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1346"]},{"id":"van-si-trung-nien-nu-tinh","name":"Văn sĩ trung niên (diện mạo nữ tính)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nam tử trung niên diện mạo mỹ miều ẩn chứa nữ tính, sắc mặt tái nhợt, xung quanh có chín pho tượng kỳ dị không tóc phát ánh sáng vàng nhạt. Xuất hiện tại cửa khe vào vùng đất cổ mộ.","vaiTro":"Tu sĩ bí ẩn tại cửa khe cổ mộ","tinhCach":[{"text":"Chủ động cầu cứu, giọng nói giống nữ tử"}],"tabs":{"diem":[{"text":"Diện mạo mỹ miều ẩn chứa nữ tính, có chín pho tượng kỳ dị không tóc vờn quanh thân thể phát ánh sáng vàng nhạt","chuong":"@c1346"}],"kinhLich":[{"chuong":"@c1346","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện tại cửa khe cổ mộ xin giúp đỡ","text":"Bước ra từ sương mù tại cửa khe vào vùng đất cổ mộ, sắc mặt tái nhợt, mi tâm có ký hiệu con số. Xung quanh có chín pho tượng kỳ dị phát ánh sáng vàng nhạt. Cất giọng giống nữ tử xin Vương Lâm giúp đỡ nhưng không được đáp.","anchor":"bộ dạng cũng cực kỳ mỹ miều, mơ hồ có ẩn chứa nữ tính"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người gặp tại cửa khe","ghiChu":"Xin Vương Lâm giúp đỡ nhưng bị phớt lờ"}],"tuiDo":{"phapBao":[{"ten":"Chín pho tượng kỳ dị","moTa":"Chín pho tượng không tóc, biểu cảm khác nhau (giận/vui/buồn), vờn quanh thân thể phát ánh sáng vàng nhạt, giúp vượt qua sương mù","nguon":"@c1346"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1346"]},{"id":"van-si-trung-nien-cuu-tuong","name":"Văn sĩ trung niên (chín pho tượng)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Văn sĩ dung mạo mỹ miều ẩn chứa nữ tính, sắc mặt tái nhợt, xuất hiện từ sương mù gần khe vào cổ mộ với chín pho tượng kỳ dị hộ thân.","vaiTro":"Tu sĩ bí ẩn trong sương mù cổ mộ, xin Vương Lâm giúp đỡ nhưng bị phớt lờ.","tinhCach":[{"text":"Giọng nói dễ nghe giống nữ tử, chủ động cầu cứu người lạ."}],"tabs":{"diem":[{"text":"Dung mạo mỹ miều ẩn chứa nữ tính, thanh âm giống nữ tử. Có chín pho tượng không tóc vờn quanh thân phát ánh sáng vàng nhạt.","chuong":"@c1346"}],"kinhLich":[{"chuong":"@c1346","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện từ sương mù xin Vương Lâm cứu giúp","text":"Xuất hiện từ sương mù tại chỗ sâu nhất gần khe vào cổ mộ, sắc mặt tái nhợt. Bên ngoài thân thể có chín pho tượng kỳ dị không tóc với vẻ mặt khác nhau vờn quanh phát ánh sáng vàng nhạt, mi tâm cũng có ký hiệu con số. Cất tiếng xin Vương Lâm giúp đỡ nhưng bị phớt lờ.","anchor":"Một thanh âm rất dễ nghe giống như của một nữ tử từ trong miệng văn sĩ kia truyền ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người xin cứu giúp","ghiChu":"Gặp gần khe vào cổ mộ, xin giúp nhưng bị phớt lờ."}],"tuiDo":{"phapBao":[{"ten":"Chín pho tượng kỳ dị","moTa":"Chín pho tượng không tóc, vẻ mặt khác nhau (tức giận/vui/buồn), vờn quanh thân thể phát ánh sáng vàng nhạt, giúp hộ thân xuyên sương mù cổ mộ.","nguon":"@c1346"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1346"]},{"id":"ke-hac-bao-cung-dien-bi-mat","name":"Kẻ hắc bào bí ẩn (cung điện ẩn giấu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Kẻ toàn thân mặc hắc bào không lộ tướng mạo, ẩn trong cung điện bí mật trôi nổi trong Thái Cổ Tinh Thần, dùng thuật Tĩnh trung lao nguyệt thao túng Vương Lâm.","vaiTro":"Kẻ bí ẩn giám sát và khống chế Vương Lâm từ xa thông qua giếng nước và ba ngọn nến trong cung điện ẩn giấu.","tinhCach":[{"text":"Bình tĩnh trước biến cố, thanh âm già nua khàn khàn, tự xưng lão phu."}],"tabs":{"diem":[{"text":"Dùng thuật Tĩnh trung lao nguyệt thao túng Vương Lâm qua giếng nước phản chiếu thân ảnh bị ba ngọn nến vờn quanh như phong ấn. Kế hoạch bị cổ mộ mở ra nhiễu loạn.","chuong":"@c1346"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu thao túng","ghiChu":"Dùng thuật Tĩnh trung lao nguyệt khống chế Vương Lâm từ xa, kế hoạch bị cổ mộ phá vỡ."}],"tuiDo":{"phapBao":[{"ten":"Giếng nước + ba ngọn nến","moTa":"Giếng mặt nước trong suốt phản chiếu ba ngọn nến và thân ảnh mục tiêu, ba nến vờn quanh thân ảnh như phong ấn — phương tiện thi triển thuật Tĩnh trung lao nguyệt.","nguon":"@c1346"}],"danDuoc":[],"congPhap":[{"ten":"Tĩnh Trung Lao Nguyệt","moTa":"Thuật thao túng tâm trí mục tiêu từ xa, cần giếng nước và ba ngọn nến làm môi giới. Bị nhiễu loạn khi mục tiêu vào vùng cổ mộ có sương mù đặc thù.","nguon":"@c1346"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1346"]},{"id":"linh-dong-thuong-nhan","name":"Linh Động Thượng Nhân","cn":"灵动上人","aliases":["Cổ Nô Tử","Linh Động"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Lão tổ của Linh Động tộc tại Thái Cổ Tinh Thần, tu sĩ tóc đỏ như máu từng dẫn đầu chín tu sĩ trong chỗ phong ấn trên lưng Cổ Thần. Sau khi bước vào bước thứ ba, bị Vương Lâm đánh bại, nhốt vào Thiên Hoàng Lô luyện nô, ký ức bị cải biến hoàn toàn khiến nhận Vương Lâm là chủ nhân, đổi tên Cổ Nô Tử. Từ đó trở thành chiến lực bước thứ ba dưới trướng Vương Lâm, lĩnh ngộ đạo thuật Dung để củng cố cảnh giới, nhiều lần được triệu hoán từ Thiên Hoàng Lô xông trận tác chiến.","vaiTro":"Cường giả Thái Cổ Tinh Thần, bị Vương Lâm luyện nô thu phục, đổi tên Cổ Nô Tử","tinhCach":"Kiêu ngạo khinh thường kẻ yếu; tàn nhẫn sẵn sàng hy sinh thuộc hạ; đạo tâm kiên định trải mấy vạn năm tu hành; trung thành tuyệt đối sau khi bị luyện hóa","tabs":{"diem":[{"text":"Đứng trên đài cao trong phong ấn trên lưng Cổ Thần, khinh thường đám tu sĩ yếu, sai thuộc hạ đi phá phong ấn thay mình","chuong":"@c1354"},{"text":"Bị Vương Lâm đánh bại trọng thương, bị nhốt vào Thiên Hoàng Lô luyện hóa, ký ức bị xâm nhập và cải biến, thu phục hoàn toàn, được ban tên Cổ Nô Tử","chuong":"@c1361"},{"text":"Lĩnh ngộ hoàn toàn đạo thuật Dung mà Vương Lâm ban cho, củng cố chân chính bước thứ ba","chuong":"@c1371"},{"text":"Được triệu hoán từ Thiên Hoàng Lô, bộc phát khí tức bước thứ ba, uy áp vượt xa lão tổ La Thiên","chuong":"@c1403"},{"text":"Tung tử hải phá tan phân thân Chu Đức, tự xưng nô bộc của chủ nhân trước chư tu","chuong":"@c1417"},{"text":"Tự giới thiệu thân phận lão tổ Linh Động tộc tại Thái Cổ Tinh Thần, tộc chỉ có một vạn tộc nhân","chuong":"@c1407"}],"kinhLich":[{"mucCt":"ky","text":"Đứng trên đài cao trong chỗ phong ấn trên lưng Cổ Thần, khinh thường đám tu sĩ yếu. Sai một tu sĩ đi phá phong ấn sương mù đỏ, tu sĩ đó bị nuốt chửng chết. Tự mình tiến tới chụp sương mù nhưng bị ma ảnh bên trong phản kích, phải lùi hơn mười trượng. Nhận định cấm chế ít nhất lục phẩm. Tiếp nhận Hứa Phúc xưng thần nhưng cắt ngang khi Hứa Phúc toan tố cáo bí mật về Vương Lâm.","anchor":"Ngay cả mộ thai bậc hai cũng không đoạt được mà cũng có lòng tham đoạt bảo vật nơi này","bridge":true,"khoang":"@c1354"},{"mucCt":"vua","text":"Bị Tiêu Tĩnh thuyết phục để hắn thử phá cấm chế trước, sau đó không do dự dùng hương hỏa lực phóng chưởng ấn vào sương đỏ trợ lực. Sương đỏ bùng nổ thành cơn lốc hủy diệt, sắc mặt đại biến, hoảng sợ bỏ chạy qua khe nứt.","anchor":"Linh Động kia sắc mặt đại biến, cơn lốc này ẩn chứa một sức mạnh đáng sợ","bridge":true,"khoang":"@c1355"},{"chuong":"@c1356","importance":"normal","mucCt":"ky","tieuDe":"Hiện thân đoạt cơ duyên","text":"Sau khi bước vào bước thứ ba, Linh Động Thượng Nhân hiện thân từ đài cao hai ngàn trượng, thừa nhận đã để Tiêu Tĩnh và Vương Lâm phá cấm chế thay mình. Hắn dùng bọt khí nhốt Vương Lâm và định giữ đối phương làm vật tế cho đạo linh tự nhiên. Vì tin rằng mình là kẻ đứng sau toàn bộ kế hoạch, Linh Động tiến vào thông đạo nhưng lập tức gặp cấm chế còn sót lại và phát ra tiếng kêu thảm thiết, khiến kết cục của hắn chưa rõ.","anchor":"Đúng là bọ ngựa bắt ve, chim sẻ ở phía sau"},{"importance":"normal","mucCt":"ky","chuong":"@c1357","tieuDe":"Bị Vương Lâm đánh bại nhốt trong sương mù","text":"Bị cấm chế trong thông đạo đánh trọng thương nguyên thần, bị huyết kiếm xuyên tay phải, bị lôi đình bổn nguyên phá nát pho tượng phòng thủ. Phản kích bằng Sơn Hải Đồ với chiêu Hải Khiếu triệu sóng biển cao trăm trượng và chiêu Sơn Lâm triệu ngọn núi, nhưng biển bị hư hỏa bốc hơi, núi bị lôi hỏa giao hòa phá nát. Bị Vương Lâm kích hoạt hư hỏa bên trong cơ thể đốt cháy từ bên trong, đau đớn cực độ. Trong tuyệt vọng mở Linh Động Đại Ma Giới dùng hương hỏa triệu hồi Thủy Động Ma Thần, đồng thời dùng Cổ Tức Diệp triệt tiêu Cổ Tức Diệp của Vương Lâm. Thủy Động Ma Thần bị Cổ Thần hư ảnh một quyền phá nát, bản thân bị lực tàn dư đánh văng trở lại sương mù. Sương đỏ khép lại nhốt cùng tứ phẩm đạo linh, nửa thân thể còn lộ ngoài bị Vương Lâm dùng Định khống chế. Mấy vạn năm chưa từng rơi vào nguy cơ sinh tử như vậy.","anchor":"Loại nguy cơ sinh tử này, Linh Động Thượng nhân đã mấy vạn năm qua chưa từng gặp phải"},{"chuong":"@c1358","importance":"major","mucCt":"vua","tieuDe":"Bị Vương Lâm kết liễu và luyện hóa trong Thiên Hoàng Lô","text":"Bị Vương Lâm thi triển Định Thân Thuật trong lúc trọng thương cực điểm, bị sương đỏ nuốt vào bên trong, bị cấm chế và đạo linh tấn công, tiếng gào dần suy yếu rồi tiêu tan. Cổ Tức Diệp bị Vương Lâm thu hồi, bị nhốt trong Thiên Hoàng Lô luyện hóa.","anchor":"tiếng rít gào không ngừng suy yếu đi, hồi lâu sau dần dần tiêu tan"},{"mucCt":"vua","text":"Giao chiến gian nan với tứ phẩm đạo linh bên trong sương mù Thiên Hoàng Lô, bại trận nằm thân thể máu thịt lẫn lộn, nguyên thần co rút trong cơ thể trị thương giả chết. Bị Vương Lâm tuyên bố sẽ luyện thành Cô Nô bước thứ ba, bắt đầu chịu quá trình luyện nô tàn khốc.","anchor":"nguyên thần đang co rút bên trong cơ thể, đang nhanh chóng trị thương","bridge":true,"khoang":"@c1359"},{"chuong":"@c1360","importance":"normal","mucCt":"ky","tieuDe":"Bị luyện nô trong Thiên Hoàng Lô, ký ức bị xâm nhập","text":"Tỉnh lại trong Thiên Hoàng Lô, tuyên bố đạo tâm kiên định mấy vạn năm không thể bị luyện hóa, triệu hồi pho tượng Ma Thần kháng cự. Sau tám nhát búa Cổ Thần liên hoàn, pho tượng vỡ, bị búa xuyên thiên linh, phun máu mê man. Bị Vương Lâm thi triển Mộng Đạo, rơi vào mộng cảnh lộ ký ức cả đời. Ký ức cho thấy hắn không phải người Linh Động Tộc, được sư phụ tên Vương Lâm dẫn vào tộc từ nhỏ, sau được lão già áo đen tên thật cũng là Vương Lâm trao tộc ấn trước khi chết. Từng bị ba người truy kích trong tinh không Thái Cổ Tinh Thần suýt chết.","anchor":"Muốn luyện hóa lão phu tuyệt đối không thể!"},{"chuong":"@c1361","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm thu phục, ban tên Cổ Nô Tử","text":"Hồi ức lộ ra: cả đời tu đạo nhiều lần gặp nguy sinh tử đều được người tự xưng Vương Lâm cứu mạng. Cuối đời bị Thiên Nhân Đệ Ngũ Suy, toàn thân rữa nát sắp chết, khi nhắm mắt rơi vào thiên địa mơ hồ gặp Vương Lâm đề nghị làm nô bộc đổi lấy đắc đạo, bị đặt tên Cổ Nô Tử. Trong Thiên Hoàng Lô, tám Cổ Thần dung hợp thành Cổ Thần thứ chín chém lưỡi búa thứ mười khắc ấn ký hình tròn trên mi tâm. Mất hết thần thái, bị lốc hồn phách cuốn đi.","anchor":"Thiên Nhân Đệ Ngũ Suy… Đệ Ngũ Suy… Linh Động ta cả đời tu đạo, chẳng lẽ lại dừng ở chỗ này"},{"chuong":"@c1365","importance":"normal","mucCt":"vua","tieuDe":"Phục kích Diệu Âm từ Thiên Hoàng Lô","text":"Ẩn bên trong Thiên Hoàng Lô chờ sẵn, khi lò hướng về Diệu Âm thì lao ra cùng pho tượng Ma Thần, tung sức mạnh hủy diệt đánh trúng. Điểm mạnh mi tâm Diệu Âm đẩy ba cây châm Tam Tiên sâu thêm một tấc, khiến độc tố bộc phát toàn diện.","anchor":"tay phải của Linh Động điểm mạnh lên mi tâm của Diệu Âm, khiến cho ba cây châm trên trán hắn đâm sâu vào một tấc"},{"mucCt":"vua","text":"Vừa trở thành Cổ Nô Tử chưa lâu, cần ôn dưỡng, chỉ ra tay được một kích duy nhất. Đánh xong bị phản chấn phun máu, pho tượng sụp đổ, bị Vương Lâm thu vào Thiên Hoàng Lô. Hắn đã bước nửa bước vào bước thứ ba, chỉ còn thiếu hương hỏa để hoàn thành.","anchor":"Cổ Nô Tử của hắn lại đã bước nửa bước vào bước thứ ba, chỉ còn thiếu hương hỏa","bridge":true,"khoang":"@c1366"},{"importance":"bridge","mucCt":"gon","chuong":"@c1368","text":"Được đại hán Phụng Thiên Lang tộc nhắc tới: đã cướp đi một trong hai phiến Cổ Tức Diệp, không rõ đã đi đâu.","anchor":"Đáng tiếc là một phiến lại bị Linh Động Thượng Nhân cướp đi"},{"mucCt":"vua","text":"Đang khoanh chân dưới đáy biển tím trong Thiên Hoàng Lô luyện hóa hồn phách hương hỏa Diệu Âm Đạo Tôn, phía sau có pho tượng Ma Thần Linh Động tộc phát hào quang, một số hồn phách đã bị cải biến hiến hương hỏa cho hắn hấp thụ. Khi Vương Lâm gọi, quỳ gọi chủ nhân, nhận lạc ấn đạo thuật Dung vào mi tâm để nhanh chóng cảm ngộ tiến bước thứ ba.","anchor":"Cổ Nô Linh Động tham kiến chủ nhân, không biết chủ nhân có việc gì cần Cổ Nô làm","bridge":true,"khoang":"@c1370"},{"chuong":"@c1371","importance":"normal","mucCt":"ky","tieuDe":"Đột phá bước thứ ba nhờ đạo thuật Dung","text":"Lĩnh ngộ hoàn toàn đạo thuật Dung mà Vương Lâm ban cho chỉ trong mấy canh giờ. Thi triển bên trong biển của Thiên Hoàng Lô, dung hợp bốn phần hồn phách hương hỏa không chủ nhân. Đột phá thành cao thủ bước thứ ba thực sự, hương hỏa hiện hình bên ngoài cơ thể như dải lụa hư ảo.","anchor":"rốt cuộc cũng đã tiến được nửa bước mấu chốt, trở thành một cao thủ bước thứ ba thực sự"},{"chuong":"@c1372","importance":"normal","mucCt":"ky","tieuDe":"Lộ rõ đã tiến vào bước thứ ba","text":"Ẩn trong Thiên Hoàng Lô, xông ra khóe miệng dính máu, bước trên sóng tím, bên ngoài thân thể có hương hỏa vô tận vờn quanh và tiếng nam mô vang vọng. Triệu hoán pho tượng trên biển tím, song chưởng tấn công Chu Cẩn, phối hợp với Vương Lâm kiềm chế đại hán. Chu Cẩn nội tâm xác nhận Linh Động đã tiến vào bước thứ ba thành công, hồi tưởng khi Linh Động là thiên nhân đệ ngũ suy thì hắn chỉ là tiểu bối.","anchor":"Linh Động kia khi là thiên nhân đệ ngũ suy thì ta vẫn chỉ là một tiểu bối"},{"mucCt":"vua","text":"Quỳ trước Vương Lâm gọi Chủ nhân, hỏi giết hay luyện hóa Chu Cẩn. Bước từ hương hỏa giới vào độc hải giới, khoanh chân ngồi giữa không trung hỗ trợ luyện hóa Chu Cẩn bên trong Thiên Hoàng Lô.","anchor":"Chủ nhân muốn giết hay muốn luyện hóa hắn","bridge":true,"khoang":"@c1373"},{"chuong":"@c1379","importance":"normal","mucCt":"ky","tieuDe":"Bị uy áp Cổ Thần bức ra, quỳ phục hoàn toàn","text":"Đang toàn lực áp chế Chu Cẩn bên trong Thiên Hoàng Lô trên mi tâm Vương Lâm. Khi uy áp Cổ Thần từ chiếc ghế bùng phát, sắc mặt đại biến, hoảng sợ, bị bức ra khỏi Thiên Hoàng Lô, ra khỏi tinh điểm, ra khỏi thân Vương Lâm. Lập tức quỳ trên đài, run rẩy không dám ngẩng đầu, khuất phục hoàn toàn.","anchor":"Linh Động Thượng Nhân từ bên trong hiện ra, sau khi vội vàng xuất hiện lập tức hướng về phía Vương Lâm, quỳ trên đài"},{"chuong":"@c1380","importance":"normal","mucCt":"vua","tieuDe":"Hỗ trợ phong ấn ghế, bị lực phản chấn đánh bật","text":"Không do dự tuân lệnh Vương Lâm, đứng bên trái truyền hương hỏa lực phong ấn ghế chia sẻ lực phản chấn. Nhịp thở 16, tay trái tan nát, bị hất bay khỏi đài, triệu hồi pho tượng ma thần đen hỗ trợ. Nhịp thở 17, ma thần sụp đổ, bị đánh bay xuống mặt đất phun máu.","anchor":"pho tượng màu đen khổng lồ ầm ầm biến ảo ra phía sau thân thể"},{"mucCt":"vua","text":"Cắn răng không quản thương thế, triển khai tử hải hương hỏa chứa vô số hồn phách tấn công Thác Sâm. Bị tiếng rống Cổ Thần đánh bại, tử hải tan vỡ, phun máu, mất sức chiến đấu.","anchor":"Linh Động lại phun máu tươi tử hải ở trước người tan vỡ thân thể lảo đảo không còn sức để tiếp tục chiến đấu","bridge":true,"khoang":"@c1381"}],"tuViMoc":[{"chuong":"@c1354","canhGioi":"Nửa bước bước thứ ba","text":"Đã bước nửa bước vào bước thứ ba nhưng thiếu hương hỏa lớn nên không đột phá thành công.","importance":"major"},{"chuong":"@c1356","canhGioi":"Bước thứ ba","text":"Linh Động Thượng Nhân đã bước vào bước thứ ba trước khi hiện thân tranh đoạt cơ duyên trong vùng đất phong ấn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ tranh đoạt đạo linh trong phong ấn","ghiChu":"@c1354"},{"ten":"Hứa Phúc","tag":"khac","quanHe":"Hứa Phúc chủ động xưng thần, xin phối hợp phá cấm chế","ghiChu":"@c1354"},{"ten":"Tiêu Tĩnh","tag":"doi-thu","quanHe":"Đối thủ bị Linh Động lợi dụng để mở đường qua cấm chế.","ghiChu":"Linh Động biết Tiêu Tĩnh có dã tâm nhưng vẫn để hắn phá cấm chế thay mình."},{"ten":"Sư phụ Linh Động","tag":"su-mon","quanHe":"Sư phụ (trong ký ức), tên Vương Lâm, dẫn hắn vào Linh Động Tộc tu đạo","ghiChu":"@c1360"},{"ten":"Lão già áo đen trao tộc ấn","tag":"su-mon","quanHe":"Trưởng bối Linh Động Tộc, tên thật Vương Lâm, trao tộc ấn cho hắn trước khi chết","ghiChu":"@c1360"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân","ghiChu":"Cả đời nhiều lần được Vương Lâm cứu mạng qua thuật Mộng Đạo, cuối cùng bị thu phục làm nô bộc, bị ban tên Cổ Nô Tử"},{"ten":"Ba người truy kích Linh Động","tag":"doi-thu","quanHe":"Kẻ truy kích trong tinh không Thái Cổ Tinh Thần","ghiChu":"Ký ức, thân phận không rõ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1354","@c1355","@c1356","@c1357","@c1358","@c1359","@c1360","@c1361","@c1363","@c1365","@c1366","@c1368","@c1370","@c1371","@c1372","@c1373","@c1379","@c1380","@c1381"]},{"id":"tieu-tinh","name":"Tiêu Tĩnh","cn":"萧静","aliases":["Văn sĩ trung niên","mưu hồ"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên nhân đệ tam suy","trangThai":"tu-vong","blurb":"Văn sĩ trung niên tay cầm quạt lông chim, chỉ tu vi thiên nhân đệ tam suy nhưng được đứng trong hàng ngũ chín tu sĩ cường giả. Tâm cơ thâm trầm, đa mưu túc trí, am hiểu thuật cấm chế, nhận ra Cổ Hồn cấm.","vaiTro":"Mưu sĩ thâm trầm trong hàng ngũ chín tu sĩ trên đài cao","tinhCach":"Tâm cơ thâm trầm; bình tĩnh; đa mưu túc trí; ẩn nhẫn quan sát","tabs":{"diem":[{"text":"Tu vi chỉ thiên nhân đệ tam suy nhưng đứng ngang hàng các cường giả đệ tứ, đệ ngũ suy, cho thấy bản lĩnh phi thường","chuong":"@c1354"},{"text":"Nhận ra cấm chế là Cổ Hồn cấm, tự nhận chỉ nắm hai phần phá giải, khóe miệng lộ nụ cười trào phúng khi Hứa Phúc xung phong","chuong":"@c1354"},{"text":"Giả vờ phá cấm chế sương đỏ, thực chất dụ Linh Động Thượng Nhân kích hoạt sương đỏ bùng nổ để đuổi tất cả tu sĩ, mưu đồ độc chiếm đạo linh — mưu kế bọ ngựa rình ve sầu","chuong":"@c1355"},{"text":"Sở hữu thuật thế thân bằng thi thể, trúng cấm chế bổ sung mà thân thể thối rữa vỡ vụn nhưng bản thể không chết","chuong":"@c1355"},{"text":"Được gọi là Mưu hồ trong Thái Cổ Tinh Thần nhờ tâm cơ và thủ đoạn giảo hoạt.","chuong":"@c1356"},{"text":"Có thể giả chết đến mức nguyên thần cũng mang trạng thái giống như đã tan vỡ.","chuong":"@c1356"},{"text":"Tổ hợp các cấm chế đơn độc để kích động sương đỏ, loại bỏ phần lớn những người tranh đoạt.","chuong":"@c1356"}],"kinhLich":[{"chuong":"@c1354","importance":"normal","mucCt":"vua","tieuDe":"Nhận diện Cổ Hồn cấm trên lưng Cổ Thần","text":"Đứng trong hàng ngũ chín tu sĩ trên đài cao, nhận ra cấm chế sương mù đỏ là Cổ Hồn cấm, tự nhận chỉ nắm hai phần phá giải. Lộ nụ cười trào phúng khi Hứa Phúc xung phong, bị Vương Lâm đánh giá là người tâm cơ thâm trầm.","anchor":"Tiên mỗ về thuật cấm chế thì chỉ là người đi sau"},{"chuong":"@c1355","importance":"normal","mucCt":"ky","tieuDe":"Lộ mưu kế bọ ngựa rình ve sầu, độc chiếm đạo linh","text":"Giả vờ tình nguyện phá cấm chế sương đỏ trước Linh Động Thượng Nhân, bấm quyết khiến sương tan một phần nhưng thực chất giấu thủ đoạn. Gọi Linh Động trợ lực bằng hương hỏa lực, khiến sương đỏ bùng nổ thành cơn lốc hủy diệt đuổi tất cả tu sĩ ra khỏi vùng phong ấn. Bản thân giả chết trong sương đỏ, đợi mọi người rời đi rồi hiện thân. Dùng chín ngọc giản phát u quang xếp hình tròn khiến Cổ Hồn cấm và Tuế Nguyệt cấm ngừng vận hành trong hai mươi nhịp thở, xé khe hở trên sương đỏ. Khi bước vào khe hở thì trúng cấm chế bổ sung không lường trước, thân thể thối rữa vỡ vụn — nhưng đó chỉ là thi thể thế thân. Sau một nén nhang, bản thể phục hồi từ thây nát, xác nhận không ai lẻn vào, rồi tiếp tục tiến về phía sương đỏ.","anchor":"Linh Động Thượng Nhân sao có thể có được bảo vật mà Tiêu Tĩnh ta đã để ý"},{"chuong":"@c1356","importance":"normal","mucCt":"vua","tieuDe":"Vong mạng trong cấm","text":"Tiêu Tĩnh dùng thuật giả chết và cấm chế để loại bỏ hơn nửa số tu sĩ, xua đuổi những người còn lại rồi phá hủy các khe tiến vào vùng đất phong ấn. Khi tự mình tiến sâu vào sương đỏ, hắn bị Sinh Tử cấm khiến khuôn mặt cùng nguyên thần mang nụ cười quỷ dị không thể khống chế và chết hoàn toàn. Vương Lâm sau đó hóa thi thể hắn thành tro để đề phòng thuật giả chết.","anchor":"trên mặt hắn vẫn thủy chung mang theo nụ cười quỷ dị kia, nhìn lên trên bầu trời"}],"tuViMoc":[{"chuong":"@c1354","canhGioi":"Thiên nhân đệ tam suy","text":"Tu vi thiên nhân đệ tam suy nhưng đứng trong hàng ngũ chín cường giả.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị Vương Lâm quan sát và đánh giá cao tâm cơ","ghiChu":"@c1354"},{"ten":"Linh Động Thượng Nhân","tag":"khac","quanHe":"Cùng thuộc hàng ngũ chín tu sĩ trên đài cao","ghiChu":"@c1354"},{"ten":"Linh Động Thượng Nhân","tag":"doi-thu","quanHe":"Lợi dụng hương hỏa lực của Linh Động để kích hoạt sương đỏ bùng nổ, coi Linh Động là con cờ","ghiChu":"@c1355"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ nhìn thấu và lợi dụng ngược mưu kế của Tiêu Tĩnh.","ghiChu":"Sau khi Tiêu Tĩnh chết vì Sinh Tử cấm, Vương Lâm hóa thi thể hắn thành tro."}],"tuiDo":{"phapBao":[{"ten":"Quạt lông chim","moTa":"Cầm trên tay, chưa sử dụng","nguon":"@c1354"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1354","@c1355","@c1356"]},{"id":"lao-gia-thanh-bao","name":"Lão già thanh bào","cn":"","aliases":["Cao tiền bối"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Tu sĩ tự xưng nghiên cứu thuật cấm chế gần ngàn năm, sáng tạo Vạn cấm phá quyết. Xung phong phá cấm chế sương mù đỏ trên lưng Cổ Thần nhưng bị nuốt chửng, chết.","vaiTro":"Tu sĩ tự phụ thuật cấm chế, xung phong phá phong ấn và bị giết","tinhCach":"Tự phụ; nóng vội xung phong; quá tin vào bản thân","tabs":{"diem":[{"text":"Tự xưng nghiên cứu thuật cấm chế gần ngàn năm, sáng tạo Vạn cấm phá quyết nhưng vẫn thất bại trước Cổ Hồn cấm và bị giết","chuong":"@c1354"}],"kinhLich":[{"mucCt":"vua","text":"Phủ nhận cấm chế là Cổ Hồn cấm, thi triển ký hiệu cấm chế khổng lồ Vạn cấm phá quyết lao vào sương mù đỏ, ban đầu áp chế được cuồng phong nhưng cuối cùng bị sương mù nuốt luôn cả ký hiệu lẫn người, chết thê thảm.","anchor":"thuật cấm chế là bổn nguyên của trận pháp. Lão phu nghiên cứu đã gần ngàn năm","bridge":true,"khoang":"@c1354"}],"tuViMoc":[],"nhanMach":[{"ten":"Linh Động Thượng Nhân","tag":"khac","quanHe":"Cùng thuộc hàng ngũ chín tu sĩ, xung phong trước mặt Linh Động","ghiChu":"@c1354"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1354"]},{"id":"hua-phuc","name":"Hứa Phúc","cn":"","aliases":["Tu sĩ to béo họ Hứa"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Tu sĩ to béo mặc áo viên ngoại, trước cùng phe Vương Lâm, sau chủ động phản bội, xưng thần với Linh Động Thượng Nhân. Tuyên bố bảy phần nắm chắc phá cấm chế, toan tố cáo bí mật về Vương Lâm nhưng bị cắt lời.","vaiTro":"Tu sĩ phản bội Vương Lâm, am hiểu thuật cấm chế","tinhCach":"Phản phúc; xảo quyệt; tự phụ bản lĩnh cấm chế; tham lam","tabs":{"diem":[{"text":"Phản bội Vương Lâm, chủ động bước ra xưng thần với Linh Động Thượng Nhân và toan tố cáo bí mật về Vương Lâm","chuong":"@c1354"},{"text":"Dùng bàn tính biến thành đoàn xoáy cấm chế, tuyên bố bảy phần nắm chắc phá phong ấn","chuong":"@c1354"}],"kinhLich":[{"mucCt":"ky","text":"Bật cười khi lão già thanh bào chết, chủ động bước ra trước mặt Vương Lâm xưng danh với Linh Động Thượng Nhân. Tuyên bố bảy phần nắm chắc phá cấm chế nếu được phối hợp. Toan tố cáo bí mật Vương Lâm nhưng bị Linh Động cắt lời. Liếc lạnh Vương Lâm rồi dùng bàn tính biến thành đoàn xoáy cấm chế, đi về phía sương mù đỏ.","anchor":"Vãn bối còn có một chuyện bí mật muốn nói cho tiền bối biết, hắn là hư…","bridge":true,"khoang":"@c1354"},{"mucCt":"gon","text":"Dùng pháp bảo bàn tính phá cấm chế sương đỏ, hạt châu xếp thành bàn cờ tàn cuộc nhưng bị sương đỏ nuốt, pháp bảo bị hủy, liên hệ nguyên thần bị cắt đứt, bản thân bị lôi vào sương đỏ tử vong.","anchor":"pháp bảo đã bị hủy. Pháp bảo này cùng với nguyên thần đã bị cắt đứt liên hệ","bridge":true,"khoang":"@c1355"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Trước cùng phe, sau phản bội, toan tố cáo bí mật về Vương Lâm","ghiChu":"@c1354"},{"ten":"Linh Động Thượng Nhân","tag":"khac","quanHe":"Chủ động xưng thần, xin phối hợp phá cấm chế","ghiChu":"@c1354"}],"tuiDo":{"phapBao":[{"ten":"Bàn tính","moTa":"Bàn tính phát ra tiếng lách cách, vỡ tung ra, con tính bay ra hóa thành đoàn xoáy cấm chế khổng lồ dùng phá phong ấn sương mù đỏ","nguon":"@c1354"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1354","@c1355"]},{"id":"tu-si-bi-sai-pha-phong-an","name":"Tu sĩ bị sai phá phong ấn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Một trong năm tu sĩ từng cướp đoạt đài cao, bị Linh Động Thượng Nhân chỉ định đi phá phong ấn sương mù đỏ, bị nuốt chửng và chết.","vaiTro":"Tu sĩ bị sai đi phá phong ấn, chết làm vật thí nghiệm","tinhCach":"Do dự nhưng không dám từ chối cường giả","tabs":{"diem":[{"text":"Bị Linh Động Thượng Nhân chỉ định đi phá phong ấn sương mù đỏ, do dự nhưng không dám từ chối, lao vào và bị sương mù nuốt chửng","chuong":"@c1354"}],"kinhLich":[{"chuong":"@c1354","importance":"normal","mucCt":"gon","tieuDe":"Bị sương mù nuốt chửng, chết","text":"Bị Linh Động Thượng Nhân chỉ định đi phá phong ấn sương mù đỏ, do dự nhưng không dám từ chối, lao vào và bị sương mù nuốt chửng, chết thê thảm.","anchor":"không có chút khả năng né tránh, chỉ một tiếng kêu thảm thiết kinh thiên vang lên"}],"tuViMoc":[],"nhanMach":[{"ten":"Linh Động Thượng Nhân","tag":"cap-tren","quanHe":"Bị sai đi phá phong ấn","ghiChu":"@c1354"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1354"]},{"id":"su-phu-linh-dong","name":"Sư phụ Linh Động","cn":"","aliases":["thanh niên mơ hồ tên Vương Lâm"],"gioiTinh":"nam","theLuc":[{"ten":"Linh Động Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thanh niên mơ hồ xuất hiện trong ký ức Linh Động Thượng Nhân, tự xưng tên Vương Lâm, dẫn thiếu niên Linh Động vào Linh Động Tộc tu đạo.","vaiTro":"Sư phụ của Linh Động Thượng Nhân (trong ký ức)","tinhCach":"Không rõ, chỉ hiện diện thoáng qua trong mộng cảnh","tabs":{"diem":[{"text":"Tự xưng tên Vương Lâm, dẫn thiếu niên Linh Động vào Linh Động Tộc, bảo thiếu niên ghi nhớ tên mình","chuong":"@c1360"},{"text":"Tự xưng tên Vương Lâm, dẫn Linh Động vào Linh Động Tộc, trùng tên với nhân vật chính — ẩn ý chưa rõ","chuong":"@c1360"}],"kinhLich":[{"chuong":"@c1360","importance":"normal","mucCt":"vua","tieuDe":"Dẫn thiếu niên Linh Động vào tộc","text":"Trong ký ức Linh Động, là thanh niên mơ hồ nói sẽ dẫn thiếu niên vào Linh Động Tộc tu đạo, bảo thiếu niên ghi nhớ tên mình là Vương Lâm.","anchor":"Hãy nhớ kĩ tên ta, tên ta là Vương Lâm!"}],"tuViMoc":[],"nhanMach":[{"ten":"Linh Động Thượng Nhân","tag":"su-mon","quanHe":"Đệ tử, dẫn vào Linh Động Tộc tu đạo","ghiChu":"@c1360"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1360"]},{"id":"lao-gia-ao-den-trao-toc-an","name":"Lão già áo đen trao tộc ấn","cn":"","aliases":["lão già áo đen tên thật Vương Lâm"],"gioiTinh":"nam","theLuc":[{"ten":"Linh Động Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Lão già áo đen bị trọng thương nặng, nguyên thần sắp tan vỡ, tên thật là Vương Lâm. Trước khi chết trao tộc ấn Linh Động Tộc cho Linh Động Thượng Nhân dù hắn không phải người trong tộc.","vaiTro":"Người giữ tộc ấn Linh Động Tộc, trưởng bối trong ký ức Linh Động","tinhCach":"Trọng tình nghĩa, sẵn lòng trao tộc ấn cho ngoại nhân trung thành","tabs":{"diem":[{"text":"Tên thật là Vương Lâm, trước khi chết trao tộc ấn Linh Động Tộc cho Linh Động dù hắn là ngoại nhân","chuong":"@c1360"},{"text":"Tên thật cũng là Vương Lâm, trao tộc ấn cho ngoại nhân Linh Động vì lòng trung thành — trùng tên sư phụ Linh Động và nhân vật chính","chuong":"@c1360"},{"text":"Trước khi chết tiết lộ tên thật là Vương Lâm và trao tộc ấn Linh Động Tộc cho Linh Động dù hắn không phải người trong tộc — trùng tên với nhân vật chính và sư phụ Linh Động","chuong":"@c1360"}],"kinhLich":[{"chuong":"@c1360","importance":"normal","mucCt":"vua","tieuDe":"Trao tộc ấn trước khi chết","text":"Bị trọng thương nặng, nguyên thần sắp tan vỡ. Trao tộc ấn Linh Động Tộc cho Linh Động vì hắn trung thành và thiên tư tuyệt vời dù là ngoại nhân. Tiết lộ tên thật là Vương Lâm.","anchor":"Tên thật của vi sư ngươi cũng biết rồi, đó là… Vương Lâm!"}],"tuViMoc":[],"nhanMach":[{"ten":"Linh Động Thượng Nhân","tag":"su-mon","quanHe":"Đệ tử / người được trao tộc ấn","ghiChu":"@c1360"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1360"]},{"id":"ba-nguoi-truy-kich-linh-dong","name":"Ba người truy kích Linh Động","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Ba người không rõ thân phận, trong ký ức Linh Động từng truy kích gắt gao hắn trong tinh không Thái Cổ Tinh Thần khiến hắn tuyệt vọng suýt chết.","vaiTro":"Kẻ truy kích Linh Động Thượng Nhân (trong ký ức)","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Truy kích gắt gao Linh Động trong tinh không Thái Cổ Tinh Thần, khiến hắn tuyệt vọng","chuong":"@c1360"}],"kinhLich":[{"chuong":"@c1360","importance":"normal","mucCt":"gon","tieuDe":"Truy kích Linh Động trong Thái Cổ Tinh Thần","text":"Ba người truy kích gắt gao Linh Động trong tinh không Thái Cổ Tinh Thần, khiến hắn tuyệt vọng suýt chết.","anchor":"Chẳng lẽ Linh Động ta hôm nay lại chết ở chỗ này!"},{"chuong":"@c1361","importance":"bridge","mucCt":"gon","text":"Đuổi tới gần Linh Động Thượng Nhân, thần thông hóa ba con ác long lao tới, bị bàn tay hư ảo của Vương Lâm đánh phun máu lùi lại.","anchor":"ba con ác long rít gào lao tới cắn nuốt"}],"tuViMoc":[],"nhanMach":[{"ten":"Linh Động Thượng Nhân","tag":"doi-thu","quanHe":"Mục tiêu truy kích","ghiChu":"@c1360"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1360","@c1361"]},{"id":"tham-lang","name":"Tham Lang","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1367","text":"Được nhắc tên: từng lấy được Cổ Tức Diệp và pho tượng khiến ngân y nữ tử hoảng sợ tại khu rừng gần vị trí hiện tại của Vương Lâm.","anchor":"Tham Lang đã lấy được pho tượng khiến ngân y nữ tử hoảng sợ thét lên chói tai"},{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Được nhắc: vị trí Vương Lâm xuất hiện ngoài biên giới La Thiên chính là chỗ Tham Lang bị cuốn vào năm xưa.","anchor":"ở chỗ Tham Lang bị cuốn vào năm đó"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Tu vi từng đạt Âm Hư chi cảnh, chỉ kém Dương Thật, nhưng do trọng thương mà rớt về Vấn Đỉnh kỳ đại viên mãn","chuong":"@c0571"},{"text":"Rời Chu Tước Tinh tránh Tư Đồ Nam, tới Đại La Kiếm Tông tìm Kiếm Tôn rồi hóa thành đạo kiếm khí bảo mệnh cho đệ tử cuối cùng của Kiếm Tông","chuong":"@c0491"},{"text":"Khống chế Vương thú gián tiếp điều khiển bầy Văn thú hơn vạn con vây khốn Đại La Kiếm Tông, giao chiến với Vương Lâm bằng Phệ Tử tam thức và Sơn Hà Đồ","chuong":"@c0604"},{"text":"Tham bảo vào Vân Hà Tinh đào Kim Viêm quáng mạch và chạm Nguyệt Hoa, bị Vọng Nguyệt nuốt vào giam bảy mươi năm, cuối cùng nhân biến động phóng ra trong tình trạng thân thể vỡ nát","chuong":"@c0674"},{"text":"Phục hồi tu vi tới Toái Niết trung kỳ nhờ dâng pháp bảo cho Điên Lạc đại đế, trở thành đại cung phụng nổi danh cả một tinh vực","chuong":"@c1295"},{"text":"Bị Vương Lâm dùng Định Thân Thuật khóa cứng, đoạt pho tượng và tra xét ký ức, để lộ tọa độ dòng xoáy gần hàng rào giới nội La Thiên Tinh Vực","chuong":"@c1302"}]},"nguon":["@c1362","@c1367","@c1386"],"trangThai":"khong-ro","cn":"贪狼","gioiTinh":"nam","vaiTro":"Lão tu sĩ lưu lạc — cường giả trọng thương từ Đại La Kiếm Tông, khắc tinh duyên nợ với Vương Lâm","tinhCach":"Tàn bạo cưỡng ép, khống chế Văn thú bằng cực hình thay vì thuần phục; tham bảo liều thân, dám đào Kim Viêm quáng mạch và chạm Nguyệt Hoa dẫn tới bị nuốt vào Vân Hà Tinh; thận trọng biết thời, chủ động rời Chu Tước Tinh tránh Tư Đồ Nam khi thân mang trọng thương; kiên nhẫn bền bỉ, bảy mươi năm chật v","blurb":"Tham Lang là tiền bối đồng lứa với sư tôn của Thần Long và Vương Lâm, tu vi từng đạt Âm Hư chi cảnh nhưng vì trọng thương mà rớt còn Vấn Đỉnh kỳ đại viên mãn, phải rời Chu Tước Tinh tới Đại La Kiếm Tông rồi lưu lạc qua La Thiên Tinh Vực. Hắn trải qua hàng loạt kiếp nạn — vây khốn Đại La Kiếm Tông bằng bầy Văn thú, bị cường giả bắt trước mặt các lão quái, mắc kẹt bảy mươi năm trong bụng Vọng Nguyệt rồi thoát ra trong tình trạng thân vỡ nát và bị Vương Lâm đoạt sạch bảo vật. Tính tới mốc mới nhất, hắn đã phục hồi tu vi tới Toái Niết trung kỳ nhờ dâng pháp bảo cho Điên Lạc đại đế, trở thành đại c"},{"id":"thanh-long-thanh-hoang","name":"Thanh Long Thánh Hoàng","tabs":{"kinhLich":[],"diem":[{"text":"Thần niệm được giấu trong Thanh quang thuẫn, dung hòa với khí tức Cổ, là đầu mối duy nhất về sự mất tích","chuong":"@c0923"},{"text":"Thoát khỏi phong ấn của Tiên Đế Thanh Lâm trong lòng núi tại Vũ chi Tiên giới, tiết lộ bí mật máu thiên đạo và triệu hoán Thanh Long phun thiên hỏa hủy ngọn núi","chuong":"@c1044"},{"text":"Chỉnh hợp Tứ Thánh Tông thành một tông duy nhất, xưng thánh tôn, thu thái cổ thánh khí của các tông","chuong":"@c1054"},{"text":"Bế quan một tháng bị tám sợi xích sắt đen khoá chặt trấn áp nội hoạ, xuất quan hạ lệnh thu phục Côn Hư","chuong":"@c1141"},{"text":"Một mình tiến vào tinh vực Thi Âm Tông, giết và trọng thương nhiều trưởng lão, đánh bại tông chủ Đệ Nhất Vương","chuong":"@c1147"},{"text":"Tái xuất cùng Tứ Thánh Tông tử chiến tại Chu Tước Tinh, tu vi đạt thiên nhân ngũ suy, thân thể chấn động khi cảm nhận khí tức Phong Tôn","chuong":"@c1520"}]},"nguon":["@c1362"],"vaiTro":"Thánh Hoàng hùng mạnh nhất Tứ Thánh Tông, sau chỉnh hợp bốn tông xưng thánh tôn","tinhCach":"Năm xưa hào sảng phóng khoáng; nay âm trầm tâm cơ sâu do ảnh hưởng máu thiên đạo; giỏi bày mưu giăng bẫy; quyết đoán cứng rắn trong việc chỉnh hợp và thu phục các thế lực","blurb":"Thanh Long Thánh Hoàng là Thánh Hoàng hùng mạnh nhất của Tứ Thánh Tông, vừa nhậm chức liền đi điều tra nguyên nhân Tiên giới sụp đổ rồi bị Tiên Đế Thanh Lâm phong ấn trong lòng núi tại Vũ chi Tiên giới, chỉ kịp để lại thần niệm cầu cứu trong Thanh quang thuẫn. Sau khi được đoàn của Vương Lâm giải cứu, ông trở về chỉnh hợp Tứ Thánh Tông thành một tông duy nhất và xưng thánh tôn, tính tình đổi khác do ảnh hưởng của máu thiên đạo, bế quan trấn áp nội hoạ rồi ra tay thu phục các thế lực, một mình đánh bại Thi Âm Tông. Vài thập niên sau tái xuất cùng Tứ Thánh Tông trở thành lực lượng hùng mạnh tham"},{"id":"nguoi-dao-bao-bay-mau","name":"Người mặc đạo bào bảy màu","cn":"","aliases":["Người mặc đạo bào bảy màu"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (vượt xa tầm hiểu biết hiện tại)","trangThai":"khong-ro","blurb":"Thân ảnh mơ hồ xuất hiện trong cảnh Lưu Nguyệt nghịch chuyển nguồn gốc đạo linh, đạo bào bảy màu, ngón trỏ phải đeo nhẫn xanh biếc. Vung tay dung hợp chín mặt trời hỗn mang thành đan dược để nuôi dưỡng thiên đạo. Hình tượng trùng với pho tượng Vương Lâm lấy từ Tham Lang, Vương Lâm suy đoán có thể là Viễn Cổ Tiên Hoàng nhưng chưa xác nhận.","vaiTro":"Nhân vật bí ẩn luyện đan dược nuôi thiên đạo, nghi là Viễn Cổ Tiên Hoàng","tinhCach":"Không rõ, chỉ xuất hiện qua thân ảnh trong quá khứ","tabs":{"diem":[{"text":"Dung hợp chín mặt trời hỗn mang thành đan dược để nuôi dưỡng thiên đạo, quyền năng vượt xa mọi tầng tu sĩ đã biết.","chuong":"@c1362"},{"text":"Hình tượng trùng pho tượng Vương Lâm lấy từ Tham Lang nhưng khác ở chiếc nhẫn xanh biếc trên ngón trỏ phải.","chuong":"@c1362"}],"kinhLich":[{"chuong":"@c1380","importance":"normal","mucCt":"vua","tieuDe":"Gỡ cung Lý Quảng, bị Diệp Mịch uy hiếp bỏ chạy","text":"Sau trận chiến tới cung điện, đứng trước nam tử cầm ô đã hóa đá. Gỡ cung kinh thiên từ tay Lý Quảng, hứa đưa cung về tông môn Lý Quảng. Khi nghe tiếng Diệp Mịch nói 'Cổ Đạo không có tiên', biết Diệp Mịch chưa chết, sắc mặt đại biến, phun máu biến mất.","anchor":"Ngươi vẫn chưa chết"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Vương Lâm phát hiện hình tượng qua Lưu Nguyệt nghịch chuyển","ghiChu":"Suy đoán là Viễn Cổ Tiên Hoàng nhưng chưa xác nhận"},{"ten":"Tham Lang","tag":"khac","quanHe":"Pho tượng trùng hình tượng nhân vật này vốn do Tham Lang lấy từ cổ mộ","ghiChu":""},{"ten":"Nam tử cầm ô","tag":"su-mon","quanHe":"Đệ tử đầu tiên trong ba đệ tử","ghiChu":""},{"ten":"Lý Quảng","tag":"su-mon","quanHe":"Gỡ cung từ tay Lý Quảng, hứa đưa về tông môn","ghiChu":""},{"ten":"Đạo Cổ Diệp Mịch","tag":"doi-thu","quanHe":"Nghe Diệp Mịch chưa chết liền phun máu biến mất","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Chiếc nhẫn xanh biếc","trangThai":"dang-co","moTa":"Đeo trên ngón trỏ tay phải, pho tượng không có chi tiết này.","nguon":"@c1362"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1362","@c1380"]},{"id":"van-thu","name":"Văn Thú","tabs":{"kinhLich":[{"mucCt":"vua","text":"Dẫn đầu bởi Hồng Vương, mười vạn Văn Thú hấp thụ dòng sông máu trên mặt đất, thân thể to gấp đôi, toát huyết quang, sức chiến đấu tăng mạnh. Diệt sạch vạn mãnh thú hình người, tổn thất gần vạn con, số sống sót cắn nuốt mãnh thú tăng trưởng thêm.","anchor":"Văn Thú này cực kỳ trung thành, đối với Vương Lâm mà nói có cảm giác giống như phụ thân","bridge":true,"khoang":"@c1363"},{"chuong":"@c1365","importance":"minor","mucCt":"gon","tieuDe":"Bị thu vào tay áo","text":"Bị Vương Lâm thu vào tay áo khi thần thông Diệu Âm bùng nổ.","anchor":"gần một trăm tu sĩ trên mặt đất lúc này cũng không cách nào né tránh, dưới tiếng gào thét của biển này, cả đám kêu lên thảm thiết, thân thể ầm ầm tan vỡ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Đột phá lên trung phẩm linh cấp (ngang Nguyên Anh hậu kỳ đại viên mãn) sau khi dung hợp Cực Quang Hỏa Tuyến","chuong":"@c0266"},{"text":"Được xác nhận là thú đến từ tinh không, hung tính vượt xa yêu thú tu chân giới, sống bằng cắn nuốt vạn vật","chuong":"@c0479"},{"text":"Lột xác thành công sau trăm năm tế luyện bằng nguyên tinh, khí tức đạt ngang Tịnh Niết","chuong":"@c1153"},{"text":"Hạ sát bốn Văn Thú lam, chiến thắng Văn Thú Vương tím và tiến hóa thành tân Văn Thú Vương thống lĩnh Phong Tiên Giới","chuong":"@c1169"},{"text":"Máu hóa vàng, hiện hình bóng Văn Vương vạn trượng, hút máu Văn Vương khổng lồ trong khe nứt trung tâm Phong giới","chuong":"@c1178"},{"text":"Thống lĩnh hơn vạn Văn Thú thu vào không gian trữ vật, theo Vương Lâm rời Phong Tiên Giới","chuong":"@c1180"}]},"nguon":["@c1363","@c1365"],"trangThai":"song","tinhCach":"Trung thành tuyệt đối với chủ nhân, sống chết không rời; hung mãnh hiếu chiến, sống bằng cắn nuốt hút máu vạn vật; nặng tình đồng tộc, liều mình cứu bầy dù mang trọng thương; cảnh giác nhạy bén, phản ứng cực nhanh trước nguy hiểm","cn":"蚊兽","gioiTinh":"nam","vaiTro":"Linh thú tọa kỵ trung thành nhất của Vương Lâm — Văn Thú Vương đến từ tinh không","blurb":"Văn Thú — thường được gọi là con muỗi khổng lồ — là hung thú đến từ tinh không với bản tính hung tàn vượt xa yêu thú tu chân giới, trở thành linh thú tọa kỵ trung thành nhất của Vương Lâm từ thuở hắn còn Ngưng Khí. Sau khi dung hợp Cực Quang Hỏa Tuyến đột phá lên trung phẩm linh cấp, nó trải qua trăm năm tế luyện bằng nguyên tinh để lột xác đạt khí tức ngang Tịnh Niết, rồi tại Phong Tiên Giới khuất phục gần nghìn đồng tộc, hạ sát Văn Thú lam, chiến thắng Văn Thú Vương tím và tiến hóa thành tân Văn Thú Vương thống lĩnh hơn vạn Văn Thú. Trong trận đối đầu Văn Vương khổng lồ tại trung tâm Phong T"},{"id":"chu-cong","name":"Chu Công","cn":"","aliases":["lão già đài cao bậc hai"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Lão già lãnh đạo nhóm hơn 30 tu sĩ trong cổ mộ, sở hữu đài cao bậc hai. Bị Vương Lâm uy hiếp giao đài cao, sau đó bị cánh tay vạn trượng từ sương mù chộp mất cùng toàn bộ nhóm.","vaiTro":"Tu sĩ bị Vương Lâm đoạt đài cao, sau bị cánh tay bí ẩn nuốt chửng","tinhCach":"Cẩn trọng, biết thời thế; phân tích tình hình rõ ràng trước khi nhượng bộ","tabs":{"diem":[{"text":"Sở hữu đài cao bậc hai trong cổ mộ, lãnh đạo hơn 30 tu sĩ; bị Vương Lâm uy hiếp bằng mười vạn Văn Thú buộc phải giao đài cao","chuong":"@c1363"},{"text":"Bị cánh tay vạn trượng khí tức Cổ Thần từ sương mù chộp mất cùng toàn bộ nhóm, tử vong","chuong":"@c1363"}],"kinhLich":[{"mucCt":"vua","text":"Lãnh đạo hơn 30 tu sĩ đang tử chiến với mãnh thú hình người, được Vương Lâm dùng Văn Thú giải cứu nhưng bị uy hiếp giao đài cao bậc hai. Cân nhắc rồi chấp nhận, nhảy sang đài khác. Ngay sau đó bị cánh tay vạn trượng khí tức Cổ Thần từ sương mù chộp mất cùng toàn bộ nhóm.","anchor":"Người này có đài cao bậc ba, tu vi sao có thể yếu được","bridge":true,"khoang":"@c1363"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm uy hiếp đoạt đài cao bậc hai","gap":"@c1363"}],"tuiDo":{"phapBao":[{"ten":"Đài cao bậc hai","trangThai":"mat","moTa":"Có 312 ấn ký, bị Vương Lâm rút hết ấn ký, đài tan vỡ","nguon":"@c1363"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1363"]},{"id":"tu-si-trung-nien-nhom-chu-cong","name":"Tu sĩ trung niên (nhóm Chu Công)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Tu sĩ trung niên trong nhóm Chu Công, không cam lòng bị đoạt đài cao, định phản bác nhưng bị cánh tay khổng lồ chộp mất.","vaiTro":"Tu sĩ phụ trong nhóm Chu Công, bị cánh tay bí ẩn nuốt","tinhCach":"Nóng nảy, không cam lòng nhượng bộ","tabs":{"diem":[{"text":"Định phản kháng Vương Lâm nhưng bị cánh tay vạn trượng xuất hiện chộp mất cùng cả nhóm","chuong":"@c1363"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1363","tieuDe":"Bị cánh tay vạn trượng nuốt","text":"Định phản bác việc giao đài cao cho Vương Lâm nhưng bị cánh tay khổng lồ từ sương mù chộp mất cùng cả nhóm.","anchor":"Chu Công, mãnh thú cổ quái này tuy nhiều, nhưng nếu ta toàn lực phản kháng, không chừng cũng có thể xông ra!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1363"]},{"id":"nu-tu-phong-diet-toc","name":"Nữ tử Phong Diệt Tộc","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Phong Diệt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử thuộc Phong Diệt Tộc, có bí ẩn hai lần bất tử. Bị Vương Lâm âm thầm cài ấn ký trên cơ thể để theo dõi. Đang tham chiến trong vùng phong ấn thứ hai, sát khí đậm.","vaiTro":"Nữ tử bí ẩn thuộc Phong Diệt Tộc, mục tiêu truy tìm của Vương Lâm","tinhCach":"Sát khí nặng, thiện chiến","tabs":{"diem":[{"text":"Sở hữu bí ẩn hai lần bất tử khiến Vương Lâm quyết tâm truy tìm","chuong":"@c1363"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1363","tieuDe":"Tham chiến vùng phong ấn thứ hai","text":"Đang chiến đấu trong vùng phong ấn thứ hai, sát khí đậm, bên cạnh gần mười người bị tử thương; bị Vương Lâm cài ấn ký trên cơ thể theo dõi vị trí.","anchor":"còn nữ tử Phong Diệt Tộc kia, ở trên cơ thể cô ta đã âm thầm để lại một ấn ký"},{"mucCt":"vua","text":"Kêu cứu Diệu Âm khi Vương Lâm xông tới, cố thi triển ấn ký Phong Diệt Tộc trên mi tâm nhưng chưa kịp hoàn thành. Bị Vương Lâm dùng song chỉ điểm lên trán đặt cấm chế phong kín toàn thân, thu vào không gian trữ vật.","anchor":"song chỉ của Vương Lâm điểm lên trên trán của thiếu nữ này","bridge":true,"khoang":"@c1364"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm cài ấn ký theo dõi, mục tiêu truy tìm bí ẩn hai lần bất tử","gap":"@c1363"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1363","@c1364","@c1374"]},{"id":"do-ti","name":"Đồ Ti","nguon":["@c1364","@c1383","@c1385","@c1386"],"tabs":{"kinhLich":[{"chuong":"@c1383","importance":"bridge","mucCt":"gon","tieuDe":"Nhắc thân thể bị Thác Sâm chiếm","text":"Được nhắc: thân thể Đồ Ti là vương tộc bát tinh Cổ Thần tồn tại từ vạn cổ, đã bị Thác Sâm chiếm.","anchor":"Thân thể của Đồ Ti là vương tộc bát tinh Cổ Thần đã tồn tại từ vạn cổ"},{"chuong":"@c1385","importance":"bridge","mucCt":"gon","text":"Hư ảnh Đồ Ti ở sau lưng Vương Lâm tan vỡ dưới luồng đại lực truyền thừa; Vương Lâm tuyên bố không còn là truyền thừa của Đồ Ti, chủ động rút ký ức truyền thừa Đồ Ti ra khỏi hồn phách.","anchor":"ký ức truyền thừa của Đồ Ti lấy được ở vùng đất Cổ Thần năm đó bị Vương Lâm chậm rãi lấy ra từ trong hồn phách!"},{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Được nhắc lại: truyền thừa của hắn chỉ đạt đỉnh bát tinh Cổ Thần, theo Vương Lâm hơn ngàn năm nay được trả về cho Thác Sâm.","anchor":"Ngươi thật sự đã vì phân thân thất bại mà chết"}],"nhanMach":[{"ten":"Đại Hoang Thượng Nhân","tag":"ban-be","quanHe":"Bạn chí cốt cả đời (theo lời Đại Hoang)","ghiChu":"Đại Hoang gọi Đồ Ti là lão điểu, nói là bạn chí cốt"}],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Phân thân xuất hiện sau khi Vương Lâm vượt ba trăm trượng cuối trong mười ba năm thử luyện, công nhận Vương Lâm là người lĩnh ngộ và truyền lại ký ức cùng truyền thừa Cổ Thần vương tộc","chuong":"@c0160"},{"text":"Được La Trần xác nhận đã chết; La Trần nhận ra Diệt Thần Mâu và xác nhận truyền thừa của Vương Lâm đến từ Đồ Ti","chuong":"@c0882"},{"text":"Thân thể khổng lồ tồn tại bên trong khe không gian, từng có biểu hiện ngón tay khẽ động và đôi mắt mở ra","chuong":"@c1064"},{"text":"Năm xưa tự mình luyện chế Tam Xoa Kích có thần thông thôn phệ vạn vật và tế luyện ra Cổ Thần Đỉnh, để lại Mặc Lưu Phân Thần Thuật chưa triệt để hoàn thành","chuong":"@c1123"},{"text":"Thân thể vương tộc bát tinh Cổ Thần tồn tại từ vạn cổ, đã bị Thác Sâm chiếm đoạt","chuong":"@c1383"},{"text":"Hư ảnh Đồ Ti tan vỡ khi Vương Lâm vượt qua giới hạn bát tinh; Vương Lâm tuyên bố truyền thừa của Đồ Ti hơn ngàn năm nay được trả về, không còn là truyền thừa giả của lão","chuong":"@c1385"}]},"trangThai":"khong-ro","cn":"屠戾","gioiTinh":"nam","aliases":["Đồ Ti"],"vaiTro":"Cổ thần chủ Cấm Sơn — nguồn truyền thừa Cổ Thần vương tộc của Vương Lâm","tinhCach":"Thận trọng, chọn lọc kỹ càng người kế thừa; kiêu hãnh mang khí phách đặc trưng của Cổ Thần; đơn độc khai phá, tự lực cánh sinh","blurb":"Đồ Ti là Cổ thần vương tộc bát tinh đến từ Thái Cổ Tinh Thần — nơi không tồn tại Phong giới trận — và là người đơn độc mở ra không gian Cổ Thần Chi Địa, lấy Cấm Sơn làm nơi đặt truyền thừa. Sau mười ba năm thử luyện, phân thân của lão công nhận Vương Lâm là người lĩnh ngộ, truyền lại ký ức và truyền thừa Cổ Thần mang tính vương tộc, dù phần ký ức ấy chưa trọn vẹn và còn bị phong ấn. Bản thân Đồ Ti đã được La Trần xác nhận là đã chết, thân thể khổng lồ tồn tại bên trong khe không gian và sau đó bị Thác Sâm chiếm đoạt; di sản của lão — từ ký ức, Cổ Thần Đỉnh, Tam Xoa Kích đến Mặc Lưu Phân Thần T"},{"id":"cuu-thien-ma-ton","name":"Cửu Thiên ma tôn","cn":"九天魔尊","aliases":["Cửu Thiên"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (Thái Cổ Ngũ Tôn)","trangThai":"song","blurb":"Cửu Thiên Ma Tôn là đại năng ma đạo từng nổi tiếng vì dám lẻn vào Điên Lạc Địa, song trọng thương rút lui và lập thề không quay lại. Về sau, hắn hoạt động trong cổ mộ nhiều tầng bản đồ, ngồi trên đài mộ cấp bảy và thi triển đạo thuật truy sát đối thủ, nhưng liên tục bị Vương Lâm áp chế — phân thân tử vong, bổn tôn hoảng sợ, cuối cùng bị nhốt lại trong cổ mộ.","vaiTro":"Đại năng ma đạo — từng thám hiểm Điên Lạc Địa, sau hoạt động trong cổ mộ","tinhCach":"tự phụ thực lực, dám đơn độc xâm nhập hiểm địa; biết tiến biết lui, thề không tái phạm khi trọng thương; mưu mô toan tính, sẵn sàng kết thỏa thuận vì lợi ích","tabs":{"diem":[{"text":"Từng âm thầm lẻn vào Điên Lạc Địa, trọng thương rút lui và thề không vào lại","chuong":"@c1284"},{"text":"Ngồi trên đài mộ sáu ngàn trượng trong mảnh bản đồ thứ sáu, nơi có trận pháp đầu lâu","chuong":"@c1368"},{"text":"Đạt đài mộ cấp bảy ở bản đồ thứ tám, tự tin muốn thi đua khi cảm nhận đối thủ cùng cấp","chuong":"@c1374"},{"text":"Phân thân bị áp chế tu vi, thi triển đạo thuật Cách Sơn Chi Tiên nhưng bị biển lửa bức lui, sau đó toàn bộ phân thân tử vong khi đối đầu Vương Lâm","chuong":"@c1377"},{"text":"Thỏa thuận với Diệu Âm sau khi trọng thương, vẻ tang thương xuất hiện từ chín vùng trời vặn vẹo","chuong":"@c1378"},{"text":"Bổn tôn và phân thân đều bị thần thức Vương Lâm uy hiếp, cuối cùng bị nhốt trong cổ mộ","chuong":"@c1386"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi trên đài mộ sáu ngàn trượng trong mảnh bản đồ thứ sáu, đài mộ có đám đầu lâu chất đống tạo thành trận pháp. Cảm ứng được đài mộ cấp năm mới xuất hiện, thì thào nói đây là cái thứ sáu. Được xác nhận là một trong Thái Cổ Ngũ Tôn, năm đó bị đánh trọng thương ở vùng đất Điên Lạc.","anchor":"Người này chính là một trong Thái Cổ Ngũ Tôn, năm đó ở vùng đất Điên Lạc đã bị đánh trọng thương","bridge":true,"khoang":"@c1368"},{"chuong":"@c1374","importance":"normal","mucCt":"vua","tieuDe":"Cảm nhận đối thủ đạt cấp bảy, muốn thi đua","text":"Đang ở khu vực bản đồ thứ tám ngồi trên đài mộ cấp bảy, cảm nhận được có người khác cũng đạt cấp bảy. Tự tin đài mộ mình sẽ nhanh đạt cấp tám, quyết tâm thi đua tốc độ.","anchor":"cấp bảy… lão phu còn chưa coi vào đâu. Rất nhanh đài mộ của lão phu sẽ trở thành cấp tám."},{"chuong":"@c1375","importance":"normal","mucCt":"ky","tieuDe":"Chấn kinh trước đài mộ cấp tám, chuyển hướng truy sát","text":"Đang ở bản đồ thứ tám với đài mộ cấp bảy, cảm nhận được đài mộ cấp tám xuất hiện. Kinh hoảng vì đối phương chưa tới một ngày đã từ cấp năm lên cấp tám. Chuyển hướng quay lại quyết tâm giết chủ nhân đài mộ cấp tám, cướp đài mộ và bí mật tăng cấp, nhắm mục tiêu đoạt địa phủ Đạo Cổ Diệp Mịch. Truy đuổi vào bản đồ thứ bảy, xuất hiện bên trái khi Vương Lâm phản công bằng Phần Giới Cổ Tán.","anchor":"Lão phu muốn xem người này là đạo hữu nào!"},{"mucCt":"vua","text":"Phân thân bị áp chế tu vi, bị biển lửa Phần Giới Cổ Tán bức lui. Thi triển đạo thuật Cách Sơn Chi Tiên định giết Vương Lâm xuyên không gian nhưng bị bạch y nữ tử (Tiên phi) mở Tinh môn chặn lại, phun máu tươi lùi mấy trăm trượng. Hỏi tại sao Tiên phi cản trở, bị đáp lạnh lùng. Nở cười quay người đuổi theo Vương Lâm vào bản đồ thứ tám, cuối chương thu đài mộ lao về trung tâm cơn lốc.","anchor":"Chỉ cần ta có thể nhìn thấy thân ảnh của ngươi một lần thì dù ngươi có cách xa bao nhiêu thì bổn tôn của ta cũng có thể vượt qua mà tới giết ngươi","bridge":true,"khoang":"@c1376"},{"chuong":"@c1377","importance":"normal","mucCt":"ky","tieuDe":"Trọng thương, toàn bộ phân thân tử vong","text":"Cùng nữ tử áo hồng lao vào vòng xoáy Cổ Yêu tấn công Vương Lâm, kinh ngạc khi thấy Vương Lâm tự chế tạo ký hiệu. Nhận ra thân ảnh Cổ Yêu đang ngủ say bên trong vòng xoáy. Khi đài mộ cấp chín xuất hiện thì bỏ mọi thứ lao tới tranh đoạt. Bị cánh tay khổng lồ đánh trúng, dung nhan từ lão già biến thành trung niên rồi thiếu niên, tất cả phân thân trong cổ mộ tan vỡ tử vong để đổi lấy đường sống cho bản thể, phun máu trọng thương lùi lại.","anchor":"Cửu Thiên Ma Tôn đã biến thành thiếu niên thân thể tiêu tan một cách quỷ dị, để mặc cho cánh tay kia đi qua"},{"mucCt":"vua","text":"Xuất hiện từ chín vùng trời vặn vẹo, vẻ tang thương, sắc mặt hơi đen. Thỏa thuận với Diệu Âm: hắn giúp ngăn Đại Hoang, giao vật lấy được cho Diệu Âm, đổi lại đòi Vương Lâm. Nhận xét thương thế người áo đen đã khôi phục hơn phân nửa, rồi bước vào khe cổ mộ.","anchor":"Đại Hoang muốn ngăn cản ngươi, bổn tôn sẽ giúp ngươi ngăn lão độc, những vật mà bổn tôn lấy được có thể giao cho ngươi, nhưng tiểu tử kia là của ta","bridge":true,"khoang":"@c1378"},{"mucCt":"vua","text":"Phân thân ở bản đồ thứ chín bị thần thức Vương Lâm quét qua, hoảng sợ cực độ. Bổn tôn ở bản đồ thứ tư cũng bị thần thức lướt qua. Dưới tiếng rống, phân thân trực tiếp tan vỡ; bổn tôn phun máu, thân thể tan vỡ, nguyên thần sống sót nhờ thần thông bảo mệnh, lấy thân thể dự phòng rút lui.","anchor":"Phân thân của Cửu Thiên Ma Tôn kia trực tiếp tan vỡ, không có bất cứ tư cách phản kháng","bridge":true,"khoang":"@c1382"},{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Phát hiện Địa Phù xuất hiện trong cổ mộ nhưng bị Vương Lâm thu mất, cuối cùng bị nhốt lại trong cổ mộ.","anchor":"cổ mộ đã bị Vương Lâm hoàn toàn khoá kín, những người này sẽ bị nhốt ở đây trong một thời gian dài"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1368","@c1374","@c1375","@c1376","@c1377","@c1378","@c1382","@c1386"]},{"id":"nu-tu-ao-hong-ban-dong-hanh-thac-sam","name":"Nữ tử áo hồng (bạn đồng hành Thác Sâm)","aliases":["nữ tử phong tình","bát phi"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử áo hồng dung mạo mị hoặc, thường ngồi trên đài mộ ngàn trượng của Thác Sâm tại tầng sâu nhất cổ mộ, gọi hắn là ca ca và dùng lời lẽ phóng đãng trêu chọc. Nàng đặt cấm chế thao túng Thác Sâm, chủ động truy sát chủ đài mộ cấp tám, tranh đoạt đài mộ cấp chín, nhưng cuối cùng bị thần thức khổng lồ của Vương Lâm chấn nhiếp mà hoảng sợ.","vaiTro":"Bạn đồng hành bí ẩn của Thác Sâm — nữ tu phóng đãng trong cổ mộ","tinhCach":"Phóng đãng, quyến rũ; sát phạt quyết đoán; mưu tính tranh đoạt","tabs":{"diem":[{"text":"Ngồi trên đài mộ ngàn trượng của Thác Sâm, dùng lời lẽ phóng đãng trêu chọc hắn","chuong":"@c1368"},{"text":"Bỏ mặc Thác Sâm, chủ động truy sát chủ nhân đài mộ cấp tám với sát khí đằng đằng","chuong":"@c1375"},{"text":"Tiếng cười duyên chứa đạo thuật, tiến từ bản đồ thứ chín vào bản đồ thứ tám","chuong":"@c1376"},{"text":"Cùng Cửu Thiên Ma Tôn tấn công Vương Lâm và tranh đoạt đài mộ cấp chín","chuong":"@c1377"},{"text":"Bị thần thức Vương Lâm chấn nhiếp, hoảng sợ khi phát hiện cấm chế thao túng Thác Sâm bị lơi lỏng","chuong":"@c1381"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi trên đài mộ ngàn trượng của Thác Sâm tại tầng sâu nhất cổ mộ, trêu chọc Thác Sâm bằng lời lẽ phóng đãng, nói rằng tiểu muội tiến sâu vào cổ mộ hay không đều dựa vào ca ca.","anchor":"Người ta lại thích vẻ thô lỗ này của ca ca","bridge":true,"khoang":"@c1368"},{"chuong":"@c1375","importance":"normal","mucCt":"vua","tieuDe":"Bỏ mặc Thác Sâm, truy sát chủ đài mộ cấp tám","text":"Ở bản đồ thứ chín phía sau Thác Sâm, đứng dậy đầy sát khí, tuyên bố phải trừ khử chủ nhân đài mộ cấp tám hoặc chiếm phương pháp tăng cấp, đổi hướng bay về phía sau, hoàn toàn không để ý Thác Sâm.","anchor":"Người này nhất định phải trừ khử, phương pháp có thể tăng cấp nhanh như vậy nếu ta không chiếm được, quyết không để người khác có được!"},{"mucCt":"vua","text":"Từ bản đồ thứ chín tiến vào bản đồ thứ tám trên đài mộ rộng bảy ngàn trượng. Tiếng cười duyên chứa đạo thuật mê hoặc khiến Vương Lâm tâm thần chấn động huyễn hóa ra mỹ nhân nhưng thất bại. Kinh ngạc vì Vương Lâm tỉnh quá nhanh, nhận ra hắn rồi nhắc tới Thác Sâm, tiến vào cơn lốc phóng về phía Vương Lâm.","anchor":"Hóa ra lại là ngươi. Đáng tiếc đã có Thác Sâm, nếu không ta cũng không nỡ đả thương ngươi đó","bridge":true,"khoang":"@c1376"},{"mucCt":"vua","text":"Cùng Cửu Thiên Ma Tôn lao vào vòng xoáy tấn công Vương Lâm, khi đài mộ cấp chín xuất hiện cũng lao tới tranh đoạt. Phun ra sợi tơ đen cuốn quanh thân để né cánh tay khổng lồ nhưng vẫn bị đầu ngón tay chạm phải, phun máu bị thương lùi lại.","anchor":"bị nữ tử này túm lấy, cuốn quanh thân thể, lập tức sợi tơ này vờn quanh thân thể của nàng","bridge":true,"khoang":"@c1377"},{"chuong":"@c1381","importance":"normal","mucCt":"vua","tieuDe":"Bị thần thức Vương Lâm chấn nhiếp, hoảng sợ","text":"Phát hiện cấm chế thao túng Thác Sâm bị lơi lỏng, đang tiến về phía trước thì bị thần thức khổng lồ lướt qua, chấn động tâm thần. Hoảng sợ tự hỏi phải chăng Đạo cổ Diệp Mịch chưa bị Tiên Tôn giết.","anchor":"Đây là thần thức của ai vậy! Chẳng lẽ Đạo cổ Diệp Mịch kia vẫn chưa bị Tiên Tôn g**t ch*t"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"khac","quanHe":"Gọi hắn là ca ca, được hắn mang theo trong cổ mộ","ghiChu":"@c1368"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1368","@c1374","@c1375","@c1376","@c1377","@c1381"]},{"id":"dao-co-diep-mich","name":"Đạo Cổ Diệp Mịch","cn":"道古叶幂","aliases":["Cổ Diệp Mịch","Diệp Mịch"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Cửu tinh Cổ Thần / Cửu tinh Cổ Yêu / Cửu tinh Cổ Ma","trangThai":"khong-ro","blurb":"Đạo Cổ Diệp Mịch là chủ nhân cổ mộ, một đại năng thượng cổ đạt Cửu tinh Cổ Thần / Cổ Yêu / Cổ Ma, tu vi đủ khiến các tiên tôn e dè dù không nằm trong hàng ngũ tiên tôn. Ông nắm giữ tam phủ Thiên Địa Nhân của Đạo Cổ, dung hợp cả thần thuật, yêu thuật và ma thuật, đồng thời để lại hệ thống truyền thừa thí luyện gồm đài mộ nhiều cấp và cánh cửa luân hồi. Trước khi chết, ba ngàn giọt máu của ông hóa thành ba tộc, trong đó chín giọt là tâm huyết, và ông không có con trai nối dõi.","vaiTro":"Chủ nhân cổ mộ — đại năng thượng cổ ngoài nhóm tiên tôn, nắm tam phủ Đạo Cổ","tinhCach":"Bí ẩn, mưu lược sâu xa (thiết kế hệ thống truyền thừa thí luyện nhiều cấp); uy nghiêm, có thanh danh hiển hách tại đại tôn cổ quốc","tabs":{"diem":[{"text":"Để lại hệ thống truyền thừa thí luyện trong cổ mộ: mở đài mộ cấp năm sẽ mở cánh cửa luân hồi, trở thành người thí luyện truyền thừa","chuong":"@c1368"},{"text":"Nắm giữ tam phủ Thiên Địa Nhân của Đạo Cổ, tiết lộ qua thanh âm uy nghiêm truyền vào tâm thần Vương Lâm","chuong":"@c1373"},{"text":"Dung hợp đạo cổ thuật: tuần tự thi triển thần thuật, yêu thuật và ma thuật trong trận chiến đài cao năm xưa","chuong":"@c1380"},{"text":"Mắt trái bị Lý Quảng bắn rơi, phong ấn tại tầng 19 hố sâu Phù Văn tộc","chuong":"@c1479"},{"text":"Có thanh danh hiển hách tại đại tôn cổ quốc; từng tìm đến động phủ Thất Đạo Tông, chỉ trích Thất Thải Đạo Tôn","chuong":"@c1545"},{"text":"Không có con trai; trước khi chết ba ngàn giọt máu hóa thành ba tộc, trong đó chín giọt là tâm huyết","chuong":"@c1578"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1368","tieuDe":"Thông điệp truyền thừa trong cổ mộ được Vương Lâm nhận","text":"Để lại thông điệp trong đài mộ cấp năm: mở cấp năm thì mở cánh cửa luân hồi, trở thành người thí luyện truyền thừa; nếu không phải tộc của hắn mà đạt cấp chín thì có thể lấy địa phủ mà rời đi. Vương Lâm nhận thông điệp này, nhớ lại lần đầu nghe tên Diệp Mịch từ Chu Tước đời đầu — Diệp Mịch tuy không nằm trong nhóm tiên tôn nhưng tu vi đủ khiến tiên tôn e dè.","anchor":"Năm đó Đạo Cổ Diệp Mịch cho dù không nằm trong nhóm tiên tôn nhưng tu vi cũng đủ khiến các tiên tôn khác phải e dè"},{"importance":"normal","mucCt":"gon","chuong":"@c1373","tieuDe":"Thông điệp về Nhân Hỏa Kiếm","text":"Thanh âm uy nghiêm truyền vào tâm thần Vương Lâm khi hấp thụ đài cao, tiết lộ Đạo Cổ có tam phủ Thiên Địa Nhân, Nhân phủ chứa Nhân Hỏa Kiếm — thanh kiếm tàn ác nhất thiên hạ, theo Đạo Cổ chém giết cả đời, vì chém giết mà thành ma nên bị ba đạo phong ấn.","anchor":"Nhân phủ có Nhân Hỏa Kiếm, kiếm này theo bổn đạo chém giết cả đời, là một thanh kiếm tàn ác nhất trong thiên hạ"},{"chuong":"@c1380","importance":"major","mucCt":"vua","tieuDe":"Trận chiến đài cao — dung hợp đạo cổ thuật","text":"Trong cảnh tượng hư ảo trận chiến năm xưa, tuần tự thi triển Thần chấn Binh Tu Liệt Vị, Yêu thuật Phong Hỏa Thành Sơn, Ma đạo Sinh Tử Nghịch Động và Đạo cổ thuật, giết sạch đại quân mấy vạn tu sĩ. Bị Lý Quảng bắn mất mắt trái chứa ký ức nửa đời. Sau trận chiến vẫn chưa chết, nói 'Cổ Đạo không có tiên' khiến tu sĩ bảy màu phun máu bỏ chạy.","anchor":"Đạo sĩ Lý Quảng bắn rơi mắt trái của ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nhận truyền thừa thí luyện trong cổ mộ của Diệp Mịch","ghiChu":"@c1368"},{"ten":"Lý Quảng","tag":"doi-thu","quanHe":"Đạo sĩ bắn mũi tên ghim mắt trái của Diệp Mịch","ghiChu":"Trước khi hóa đá nói đã hoàn thành lời hứa"},{"ten":"Nam tử cầm ô","tag":"doi-thu","quanHe":"Đối thủ đứng đối diện đài cao, dùng ánh sáng bảy màu đối kháng đạo cổ thuật","ghiChu":"Bị khí tức đầu lâu hóa thành đá"},{"ten":"Tu sĩ bảy màu","tag":"doi-thu","quanHe":"Xuất hiện sau trận chiến, nghe Diệp Mịch nói Cổ Đạo không có tiên liền phun máu bỏ chạy","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1368","@c1373","@c1380"]},{"id":"phong-chi-man","name":"Phong Chỉ Mạn","cn":"封止蔓","aliases":["Thiếu nữ Phong Diệt tộc"],"gioiTinh":"nu","theLuc":[{"ten":"Phong Diệt tộc","trangThai":"da-roi"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thiếu nữ xinh đẹp thuộc Phong Diệt tộc, là thị nữ của Diệu Âm đạo tôn. Bị Vương Lâm bắt giữ, thẩm vấn và soát hồn, bị rút tộc ấn khỏi mi tâm.","vaiTro":"Tù nhân của Vương Lâm, nguồn thông tin bí mật Phong Diệt tộc","tinhCach":["Sợ hãi bối rối khi bị bắt","Ban đầu cố đe dọa bằng danh nghĩa Diệu Âm nhưng nhanh chóng mất hy vọng"],"tabs":{"diem":[{"text":"Thị nữ Diệu Âm đạo tôn, thuộc Phong Diệt tộc, mang tộc ấn và tam mệnh thuật","chuong":"@c1371"},{"text":"Bị Vương Lâm soát hồn rút tộc ấn, mất tư cách tộc nhân Phong Diệt tộc","chuong":"@c1371"}],"kinhLich":[{"chuong":"@c1371","importance":"normal","mucCt":"ky","tieuDe":"Bị thẩm vấn, soát hồn, rút tộc ấn","text":"Bị Vương Lâm lôi ra khỏi không gian trữ vật thẩm vấn. Đe dọa bằng danh nghĩa Diệu Âm đạo tôn nhưng bị cho xem ngọc giản cảnh phân thân Diệu Âm bị diệt, mất hy vọng. Khai ra bí mật Phong Diệt tộc: tộc nhân không huyết thống, cướp trẻ con tế tổ, sống sót được tộc ấn và ba mạng. Bị soát hồn đọc toàn bộ ký ức, rút tộc ấn từ mi tâm, thu vào không gian trữ vật.","anchor":"Tộc nhân của Phong Diệt tộc ta có ba mạng…"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người bắt giữ, thẩm vấn soát hồn và rút tộc ấn","ghiChu":"@c1371"},{"ten":"Diệu Âm Đạo Tôn","tag":"cap-tren","quanHe":"Chủ nhân (thị nữ của Diệu Âm)","ghiChu":"@c1371"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Tộc ấn Phong Diệt tộc","trangThai":"mat","moTa":"Bị Vương Lâm rút ra khỏi mi tâm, không còn thuộc Phong Diệt tộc","nguon":"@c1371"}]}},"nguon":["@c1371"]},{"id":"dai-han-tren-dai-cao","name":"Đại hán trên đài cao","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đại hán bí ẩn xuất hiện trên cái đài cao năm ngàn trượng trên bầu trời khu rừng trong cổ mộ. Ngẩn ra khi thấy Vương Lâm, cho thấy quen biết nhưng không ngờ gặp ở đây.","vaiTro":"Nhân vật bí ẩn xuất hiện cuối chương, danh tính chưa rõ","tinhCach":["Ngạc nhiên khi gặp Vương Lâm"],"tabs":{"diem":[{"text":"Xuất hiện bí ẩn trên đài cao năm ngàn trượng, biết Vương Lâm nhưng không ngờ gặp ở đây","chuong":"@c1371"}],"kinhLich":[{"chuong":"@c1371","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện trên đài cao năm ngàn trượng","text":"Xuất hiện trên cái đài cao năm ngàn trượng hiện ra trên bầu trời khu rừng. Ngẩn ra vì không ngờ ở chỗ này lại có thể nhìn thấy Vương Lâm.","anchor":"giống như là không ngờ tới ở chỗ này lại có thể nhìn thấy Vương Lâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Biết Vương Lâm, ngạc nhiên khi gặp ở cổ mộ","ghiChu":"@c1371"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1371"]},{"id":"dieu-tich-tuyet","name":"Diêu Tích Tuyết","cn":"刁惜雪","gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1371","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Vương Lâm nhìn Phong Chỉ Mạn liên tưởng đến nàng: cùng bối rối sợ hãi nhưng trong mắt Diêu Tích Tuyết có quật cường và oán hận.","anchor":"cũng bối rối như vậy, cũng sợ hãi như vậy, nhưng khác ở chỗ trong mắt của gương mặt kia có một vẻ quật cường cùng oán hận"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Theo lệnh phụ thân đến Đông Hải Yêu Linh quan sát Vương Lâm, trao Huyết Hồn đan nhờ hắn bài trừ phong ấn cấm chế bí mật","chuong":"@c0519"},{"text":"Bị Vương Lâm phong ấn giữa sinh tử tại động phủ, thu vào túi trữ vật và ép khai phương pháp Huyết Hồn đan cùng bí mật Thanh Lâm Tiên lệnh","chuong":"@c0523"},{"text":"Sinh tử trở thành con tin then chốt trong dương mưu của Vương Lâm đối phó Huyết Tổ","chuong":"@c0717"},{"text":"Được Huyết Tổ bóp vỡ quả cầu cấm chế, hoàn tất hồi sinh nhờ Huyết Hồn đan và hiện thân ở vùng đất Yêu Linh","chuong":"@c0718"},{"text":"Chấp nhận truyền thừa Phong Yêu, đánh đổi linh hồn và thân thể bị hủy hoại đầy sẹo để báo thù Vương Lâm","chuong":"@c0939"},{"text":"Được Vương Lâm giải cứu, tách yêu khí Phong Yêu, tỉnh lại nhưng mất toàn bộ ký ức; được Huyết Tổ nhận lại, kết thúc nhân quả với Vương Lâm","chuong":"@c0974"}]},"nguon":["@c1371"],"vaiTro":"Con gái duy nhất của Huyết Tổ Diêu Tinh Hải — tu sĩ huyết hệ, con tin và kẻ thù của Vương Lâm","tinhCach":"Cương liệt, thà chết không khuất phục; kiêu ngạo nhờ thân phận huyết hệ; nhẫn nhịn có mục đích, kín miệng về ý đồ riêng; quật cường trước nghịch cảnh","blurb":"Diêu Tích Tuyết là nữ nhi duy nhất và thân nhân duy nhất của đại năng Huyết Tổ Diêu Tinh Hải, được phụ thân cử đến Đông Hải Yêu Linh quan sát Vương Lâm. Nàng từng trao Huyết Hồn đan nhờ Vương Lâm giải phong ấn cấm chế, song bị hắn phản bội phong ấn giữa sinh tử, giam trong túi trữ vật và ép khai hết bí mật, trở thành con tin trong dương mưu đối phó Huyết Tổ. Sau khi được Huyết Tổ cứu hồi sinh, nàng chấp nhận truyền thừa Phong Yêu đánh đổi linh hồn để báo thù, nhưng cuối cùng được chính Vương Lâm giải cứu tách yêu khí Phong Yêu, mất đi toàn bộ ký ức và được cha nhận lại, kết thúc nhân quả với V"},{"id":"thuy-dao-tu","name":"Thủy Đạo Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1373","tieuDe":"Bị Vương Lâm nhắc đến","text":"Vương Lâm tính toán nếu có hai cao thủ bước ba phò tá khi trở về giới nội, Thủy Đạo Tử sẽ hoảng sợ bỏ chạy.","anchor":"đại địch Thủy Đạo Tử năm đó nhìn thấy chắc chắn sẽ hồn bay phách tán"}],"diem":[{"text":"Tiết lộ quá khứ từng theo chủ nhân phong giới chinh chiến khắp thiên địa rồi phản bội đánh lén tôn sư, mưu bày Luân Hồi đại trận trong cung điện Thần Tông","chuong":"@c1193"},{"text":"Bị Thất Thải Thần Không Đinh găm hoàn toàn vào mi tâm hủy diệt, hy sinh toàn bộ môn phái để bỏ chạy bảo mạng","chuong":"@c1211"},{"text":"Cảm nhận Vương Lâm trở về, phát bảy đạo mệnh lệnh tổng động viên toàn Vân Hải tinh vực chống trả","chuong":"@c1414"},{"text":"Kích nổ chuông vàng Viễn cổ Tiên Vực bằng bí thuật do Chủ nhân phong giới truyền, mưu phá hủy toàn bộ Vân Hải tinh vực để đồng quy vu tận với Vương Lâm","chuong":"@c1419"},{"text":"Lật quân bài mệnh hồn cuối cùng nhưng thất bại, nguyên thần bị Vương Lâm đánh từng quyền phá hủy và diệt sát","chuong":"@c1421"},{"text":"Sau khi chết vẫn nhiều lần được Vương Lâm lấy làm mốc đối chiếu uy lực các cường giả khác như Điên Lạc đại đế, Thiên Vận Tử, Viêm Long","chuong":"@c1293"}]},"nguon":["@c1373"],"vaiTro":"Cao thủ Đệ Tam Bộ của Thần Tông — kẻ phản chủ truy sát Vương Lâm","tinhCach":"Tàn nhẫn quyết đoán, giết lầm không tha kẻ khả nghi; phản trắc mưu mô, từng đánh lén tôn sư để đoạt quyền; liều mạng bất chấp tổn thất khi quyết diệt mục tiêu; tham sống sợ chết, sẵn sàng hy sinh toàn môn phái để bảo toàn bản thân","blurb":"Thủy Đạo Tử là đồng tử tóc bạc tu vi Đệ Tam Bộ, nắm quyền cao nhất Thần Tông khi sư tôn Vương San vắng mặt, ngồi trấn tại cung điện trung tâm tinh vực cấp chín. Năm xưa y từng theo chủ nhân phong giới chinh chiến khắp thiên địa rồi phản bội đánh lén tôn sư, về sau điều tra truy sát Vương Lâm suốt nhiều năm. Trong trận quyết chiến cuối cùng, y lần lượt dùng hết mọi thủ đoạn từ pháp bảo chuông vàng Viễn cổ Tiên Vực đến quân bài mệnh hồn nhưng đều bị Vương Lâm hóa giải, cuối cùng nguyên thần bị đánh nát từng phần và bị diệt sát."},{"id":"co-yeu-lao-to-tong","name":"Cổ Yêu","cn":"古妖","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1377","importance":"normal","mucCt":"ky","tieuDe":"Thức tỉnh — phong ấn bị nghiền nát","text":"Đang ngủ say sâu trong vòng xoáy, thân ảnh bị Cửu Thiên Ma Tôn nhìn thấy. Cánh tay khổng lồ quét qua nghiền nát phong ấn trên Cổ Yêu. Cổ Yêu mở mắt thức tỉnh, mắt trái có tám tinh điểm xoay tròn. Ngửa mặt lên trời phát ra tiếng kêu dài, thân thể hóa mơ hồ trong suốt khiến cánh tay xuyên thấu qua, thoát được.","anchor":"cổ Yêu vừa mới thức tỉnh này ngửa mặt lên trời phát ra một tiếng kêu dài"},{"importance":"normal","mucCt":"vua","chuong":"@c1378","tieuDe":"Giải phong ấn, rít gào","text":"Cùng Cửu Thiên Ma Tôn đứng nhìn Vương Lâm bước vào khe, không dám tiến lên trước uy lực hai bàn tay khổng lồ. Sau khi bàn tay tiêu tan, được giải phong ấn, hai mắt lộ hồng quang, liếm môi, ngửa mặt lên trời rít gào.","anchor":"cổ Yêu được giải phong ấn xuất hiện kia hai mắt lộ ra một tia hồng quang"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lần đầu lộ diện, lập giao kèo với Vương Lâm và kể nguồn gốc chín tồn tại không hoàn chỉnh từ giới ngoại đến","chuong":"@c0555"},{"text":"Giáng ý chí cứu Vương Lâm, mượn máu ngưng hình đại chiến tán ma ba ngày","chuong":"@c0565"},{"text":"Đoạt cuốn tranh trong bình bạch ngọc, biến tiên khí thành yêu khí","chuong":"@c0963"},{"text":"Liên thủ đánh Cổ Ma Tháp Già, thi triển Yêu Linh Biến và tự bạo phân thân cản địch","chuong":"@c0999"},{"text":"Phong ấn bị Cửu Thiên Ma Tôn nghiền nát, thức tỉnh sau giấc ngủ dài","chuong":"@c1377"},{"text":"Bị Vương Lâm bắt sống khi hiện nguyên hình lục tinh, từ đó bị phong ấn trong không gian trữ vật","chuong":"@c1406"}]},"nguon":["@c1377","@c1378"],"vaiTro":"Cường giả viễn cổ ẩn trong Yêu Cổ — lão tổ tông Thiên Yêu quận, đồng minh giao kèo của Vương Lâm","tinhCach":"Hành sự qua giao kèo và điều kiện ràng buộc lợi ích, tính toán chặt chẽ; sẵn sàng hao tổn bản thể và tự bạo phân thân để chiến đấu, không né tránh khi cần đối đầu; can thiệp gián tiếp qua trung gian thay vì trực tiếp lộ diện; mỉa mai sắc bén và tự phụ về lai lịch cổ tộc","blurb":"Cổ Yêu là một trong chín tồn tại không hoàn chỉnh từ giới ngoại đến, trú ngụ trong Yêu Cổ với tư cách lão tổ tông của Thiên Yêu quận, thường được gọi là Bối La. Ông lập giao kèo với Vương Lâm từ sớm, nhiều lần giáng ý chí hoặc hiện bản thể cứu viện và tham chiến — từ đại chiến tán ma đến liên thủ đánh Cổ Ma Tháp Già trong Tiên phủ — đồng thời trở thành biến số then chốt trong nhiều bước ngoặt của Vương Lâm. Về sau phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, bị Vương Lâm bắt sống và ép giao nộp bí mật, hiện vẫn tồn tại dưới dạng cổ yêu bị phong ấn trong không gian trữ vật của Vương Lâ"},{"id":"dao-co-hoa-mich","name":"Đạo Cổ Hoa Mịch","cn":"","aliases":["Đạo cổ Diệp Mịch","Cổ Diệp Mịch"],"gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1378","tieuDe":"Di ngôn về Thiên Phủ và quá khứ bi thương","text":"Thanh âm tang thương truyền vào tâm thần Vương Lâm sau khi mộ đài cấp chín bị phá. Kể rằng Thiên Phủ là nơi phong ấn kẻ địch, cần đủ tu vi và cơ duyên lớn lao mới tiến vào. Cả đời chỉ có một cơ duyên, không hối tiếc. Bị đạo môn bao vây phong tỏa đường lui, đạo sĩ Lý Quảng bắn rơi mắt trái chứa ký ức nửa đời và nỗi nhớ quê hương. Lời cuối mơ hồ dặn dò truyền thừa: nếu có thể thành cổ.","anchor":"đạo sĩ Lý Quảng bắn rơi mắt trái của ta, trong mắt trái kia có chứa ký ức nửa đời của ta cùng với nổi nhớ quê hương"}],"nhanMach":[{"ten":"Lý Quảng","tag":"doi-thu","quanHe":"Đạo sĩ bắn rơi mắt trái của Hoa Mịch trong cuộc bao vây"}]},"nguon":["@c1378"]},{"id":"ly-quang","name":"Lý Quảng","cn":"","aliases":["đạo sĩ Lý Quảng","tu sĩ áo đen bắn cung"],"gioiTinh":"nam","canhGioiCaoNhat":"khong-ro","trangThai":"tu-vong","vaiTro":"Đạo sĩ áo đen bắn cung — người bắn rơi mắt trái Đạo Cổ Hoa Mịch / Diệp Mịch","tinhCach":"Quyết đoán, dứt khoát trong chiến đấu; thiện xạ phi phàm; oai hùng, bất khuất trước cường địch","blurb":"Lý Quảng là đạo sĩ áo đen từng tham gia cuộc bao vây của đạo môn đối với Đạo Cổ Hoa Mịch, nổi danh với phát cung bắn rơi mắt trái của Hoa Mịch. Về sau tại vùng đất cổ mộ, ông dùng cây cung lớn mang chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân xuyên qua mọi trở ngại, ghim trúng mắt trái đầu lâu Diệp Mịch rồi hóa đá tử vong, để lại ấn tượng oai hùng tuyệt đối trong ký ức Vương Lâm. Mũi tên năm ấy sau này được Vương Lâm thu phục làm bảo vật.","theLuc":[],"tabs":{"diem":[{"text":"Được nhắc trong di ngôn Hoa Mịch: là đạo sĩ bắn rơi mắt trái Hoa Mịch khi đạo môn bao vây","chuong":"@c1378"},{"text":"Dùng cây cung lớn chín đạo phong ấn bắn mũi tên xuyên mọi trở ngại, ghim mắt trái đầu lâu Diệp Mịch rồi hóa đá tử vong","chuong":"@c1380"},{"text":"Được Vương Lâm hồi tưởng về sự oai hùng tuyệt đối khi bắn cung trong vùng đất cổ mộ","chuong":"@c1436"},{"text":"Mũi tên năm xưa mang huyết mạch tiên nhân, khiến mắt trái Đạo Cổ Diệp Mịch tiêu tán thành tro","chuong":"@c1479"},{"text":"Mũi tên mà Lý Quảng bắn rơi mắt trái Đạo Cổ được Vương Lâm thu phục làm bảo vật","chuong":"@c1482"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1378","text":"Được nhắc trong di ngôn Hoa Mịch: đạo sĩ bắn rơi mắt trái Hoa Mịch khi đạo môn bao vây.","anchor":"đạo sĩ Lý Quảng bắn rơi mắt trái của ta"},{"chuong":"@c1380","importance":"major","mucCt":"vua","tieuDe":"Bắn mắt trái Diệp Mịch, hóa đá","text":"Dùng cây cung lớn chín đạo phong ấn bắn mũi tên xuyên qua mọi trở ngại, ghim mắt trái đầu lâu Diệp Mịch, mang con mắt đẫm máu bay vào hư vô. Sau đó bị khí tức đạo cổ cuốn tới hóa thành đá. Trước khi hóa đá nói câu duy nhất trong đời: hoàn thành lời hứa.","anchor":"Nhắm mắt kéo cung, buông tay trừng mắt"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Cổ Hoa Mịch","tag":"doi-thu","quanHe":"Bắn rơi mắt trái Hoa Mịch trong cuộc bao vây của đạo môn"},{"ten":"Đạo Cổ Diệp Mịch","tag":"doi-thu","quanHe":"Bắn mũi tên ghim mắt trái Diệp Mịch","ghiChu":""},{"ten":"Nam tử cầm ô","tag":"dong-hanh","quanHe":"Đứng sau nam tử cầm ô cùng chiến tuyến","ghiChu":""},{"ten":"Tu sĩ bảy màu","tag":"su-mon","quanHe":"Tu sĩ bảy màu thu nhận, gỡ cung hứa đưa về tông môn sau khi thiên đạo trưởng thành","ghiChu":"Đệ tử thứ mấy không rõ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1378","@c1380"]},{"id":"chu-toa","name":"Chu Tọa","cn":"","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","vaiTro":"Một trong Thái Cổ Ngũ Tôn, chiếm một phần sức mạnh Thái Cổ Tinh Thần","tinhCach":"Không rõ","blurb":"Một trong Thái Cổ Ngũ Tôn, được người áo đen nhắc cùng Đại Hoang và Viễn Cổ Tiên Tôn, chiếm một phần sức mạnh Thái Cổ Tinh Thần, đã tiến vào cổ mộ.","theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Một trong Thái Cổ Ngũ Tôn, chiếm một phần sức mạnh Thái Cổ Tinh Thần.","chuong":"@c1378"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1378","text":"Được nhắc là một trong Thái Cổ Ngũ Tôn, đã tiến vào cổ mộ.","anchor":"Hai người trong Thái cổ Ngũ Tôn, Đại Hoang cảnh giới Không Huyền, còn có Chu Tọa, Viễn cổ Tiên Tôn"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1378"]},{"id":"chu-can","name":"Dương Sâm","tabs":{"kinhLich":[{"chuong":"@c1380","importance":"normal","mucCt":"vua","tieuDe":"Bị điểm ấn Cổ Nô, hỗ trợ phong ấn ghế","text":"Bị Vương Lâm điểm ấn Cổ Nô lên mi tâm, giãy giụa nhưng phải tuân lệnh. Đứng bên phải truyền hương hỏa lực chia sẻ lực phản chấn. Cánh tay phải tan nát, triệu hồi hư ảnh huyết lang chia lực nhưng huyết lang cũng bị phá, bị cuốn bay lùi mấy trăm trượng.","anchor":"Huyết lang này rít gào, lướt qua Chu cẩn, thay thế thân thể hắn chia sẻ lực lượng"},{"mucCt":"vua","text":"Thi triển thần thông Quần Lang Bái Nguyệt: triệu hơn mười vạn sói hư ảo hóa lang yên dung nhập huyết nguyệt, huyết nguyệt đánh xuống Thác Sâm. Bị tiếng rống Cổ Thần phá hủy huyết nguyệt, ngực lõm, phun máu ngã xuống đất.","anchor":"Chu Cẩn mặt không còn chút máu trước ngực lõm xuống, cả người lảo đảo, phun ra máu tươi ầm một tiếng, ngã xuống mặt đất","bridge":true,"khoang":"@c1381"},{"chuong":"@c1384","importance":"minor","mucCt":"gon","text":"Trọng thương, chính mắt thấy sức mạnh Vương Lâm biến đổi trước sau khi vào cổ mộ, ảo tưởng cuối cùng bị chặt đứt, trầm mặc nhắm mắt trị thương.","anchor":"Chính mắt hắn nhìn thấy sức mạnh của Vương Lâm trước và sau khi tiến vào cổ mộ khác nhau, lúc này một tia ảo tưởng cuối cùng đã bị chặt đứt"},{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm thu vào Thiên Hoàng Lô cùng Linh Động.","anchor":"Linh Động và Chu Cẩn đang chấn động đằng xa lập tức bị Vương Lâm thu vào trong Thiên Hoàng Lô"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng có ảo tưởng vượt qua, nay thừa nhận khoảng cách","ghiChu":""}],"tuViMoc":[],"diem":[{"text":"Nhân hỗn loạn xông ra định giết Vương Lâm, bị Phượng Loan dùng Ngũ thải phượng xa can thiệp","chuong":"@c0119"},{"text":"Nghiêm khắc tra hỏi Vương Lâm về chiến công và tu vi tăng bất thường tại Thiên Điện","chuong":"@c0122"},{"text":"Bị Vương Lâm điểm ấn Cổ Nô lên mi tâm, buộc phải tuân lệnh phục vụ","chuong":"@c1380"},{"text":"Thi triển thần thông Quần Lang Bái Nguyệt, triệu hơn mười vạn sói hư ảo hóa lang yên dung nhập huyết nguyệt","chuong":"@c1381"},{"text":"Tự xưng thân phận lão tổ Phụng Thiên Lang tộc tại Thái Cổ Tinh Thần, đại tộc tồn tại từ thời thái cổ","chuong":"@c1407"},{"text":"Hóa thành huyết lang chiến đấu bảo vệ Vương Lâm, bị hút vào U Minh Thú rồi được thu hồi vào tinh điểm Cổ Thần","chuong":"@c1410"}]},"nguon":["@c1380","@c1381","@c1384","@c1386"],"trangThai":"song","cn":"朱谨","gioiTinh":"nam","aliases":["Đại hán Phụng Thiên Lang tộc"],"canhGioiCaoNhat":"Không rõ","vaiTro":"Nhân vật phụ — lão tổ Phụng Thiên Lang tộc, Cổ Nô dưới trướng Vương Lâm","tinhCach":"Hiếu chiến, dám xông ra hạ sát đối thủ trong hỗn loạn; nghiêm khắc, đa nghi khi tra hỏi chiến công bất thường; khuất phục trước cường quyền sau khi bị điểm ấn Cổ Nô","blurb":"Dương Sâm, bí danh Chu Cẩn, là tu sĩ Nguyên Anh sơ kỳ dáng trung niên văn sĩ, tự xưng lão tổ Phụng Thiên Lang tộc — đại tộc tồn tại từ thời thái cổ tại Thái Cổ Tinh Thần. Vốn thuộc phe Phượng Loan trong Chiến Thần Điện tại Hỏa Phần quốc, từng thù địch Vương Lâm, về sau bị điểm ấn Cổ Nô khuất phục, buộc phải phục vụ dưới trướng Vương Lâm và được thu trong Thiên Hoàng Lô để triệu xuất khi cần."},{"id":"phan-y-nu-tu","name":"Phấn y nữ tử","aliases":["Tứ phi","nữ tử phong tình","bát phi"],"nguon":["@c1382","@c1374"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1382","importance":"normal","mucCt":"vua","tieuDe":"Thân thể nổ tung, dải lụa Viễn Cổ Tiên Tôn bị hủy","text":"Dưới tiếng rống, dải lụa do Viễn Cổ Tiên Tôn ban tặng bị tan vỡ, thân thể nổ tung. Nguyên thần miễn cưỡng sống sót sau vài lần tan vỡ.","anchor":"nữ tử phong tình trong tiếng kêu thảm thiết thân thể trực tiếp nổ tung, nguyên thần bay ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Bị hỏa long nuốt khi chưa kịp vào đại điện, nhưng sống sót nhiều tháng nhờ ấn ký bông tuyết và pháp bảo hộ thân của Đại sư tỷ","chuong":"@c0992"},{"text":"Phủ nhận mình là Côn Hư Thánh nữ, xác nhận Thánh nữ là Đại sư tỷ của nàng","chuong":"@c0993"},{"text":"Ấn ký bông tuyết trên trán tự kích hoạt bảo vệ nàng khi Bối La định bắt, trong lúc tầng sáu sụp đổ","chuong":"@c0999"},{"text":"Liều thân dùng pháp bảo bông tuyết kéo Thiên Cầm thoát khỏi hắc long, bản thân phun máu chịu thương","chuong":"@c1000"},{"text":"Dải lụa do Viễn Cổ Tiên Tôn ban tặng bị hủy, thân thể nổ tung, chỉ nguyên thần miễn cưỡng sống sót","chuong":"@c1382"},{"text":"Cùng Mộc Băng Mi và Tây Tử Phượng tới nơi Vương Lâm bảo vệ, ngồi chờ đợi trong tinh không","chuong":"@c1573"}]},"vaiTro":"Sư muội của Côn Hư Thánh nữ — nữ tu áo phấn sống sót qua nhiều tử địa","tinhCach":"kiên cường, sống sót nhiều tháng trong bụng hỏa long nhờ ấn ký và pháp bảo hộ thân; vị tha, liều thân phun máu cứu Thiên Cầm thoát khỏi hắc long; gắn bó sư môn, luôn mang theo pháp bảo và ấn ký do Đại sư tỷ ban tặng","blurb":"Nữ tu mặc áo phấn hồng, sư muội của Côn Hư Thánh nữ (Đại sư tỷ). Nàng bị hỏa long nuốt khi chưa kịp vào đại điện nhưng sống sót nhiều tháng nhờ ấn ký bông tuyết và pháp bảo hộ thân của sư tỷ, sau đó nhiều lần liều mình cứu người trong các biến cố sụp tầng và hắc long. Dải lụa do Viễn Cổ Tiên Tôn ban tặng bị hủy khiến thân thể nổ tung, chỉ nguyên thần miễn cưỡng còn sống; về sau nàng cùng Mộc Băng Mi và Tây Tử Phượng tới nơi Vương Lâm bảo vệ, ngồi chờ đợi trong tinh không."},{"id":"nu-tu-phong-tinh","name":"Nữ tử phong tình","cn":"","aliases":["Tiên phi","Viễn cổ bát phi"],"gioiTinh":"Nữ","theLuc":[{"ten":"Viễn cổ bát phi","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong viễn cổ bát phi, nữ tử phong tình có liên hệ với Tiên Tôn. Bị Thác Sâm đánh bật và phong ấn khi muốn xen vào trận chiến truyền thừa.","vaiTro":"Viễn cổ bát phi, từng phục vụ Tiên Tôn","tinhCach":[{"text":"Phong tình, quyến rũ; khi bị phản bội lập tức trở nên dữ tợn","chuong":"@c1384"}],"tabs":{"diem":[{"text":"Một trong viễn cổ bát phi, bị Thác Sâm mắng là đồ chơi của Tiên Tôn, đánh bật và phong ấn trong tấm lưới hư ảo","chuong":"@c1384"}],"kinhLich":[{"chuong":"@c1384","importance":"normal","mucCt":"vua","tieuDe":"Bị Thác Sâm đánh bật, phong kín ngoài tấm lưới","text":"Ngưng tụ lại thân thể, dựa cảm ứng Thác Sâm tìm tới cung điện truyền thừa muốn xen vào trợ chiến. Bị chính Thác Sâm đánh phun máu lùi lại, bị mắng là đồ chơi của Tiên Tôn, bị phong kín ngoài tấm lưới hư ảo không thể tiến vào.","anchor":"Thác Sâm, ngươi dám làm phản bổn phi sao!"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Bị Thác Sâm đánh bật và phong ấn, bị mắng là đồ chơi của Tiên Tôn","ghiChu":""},{"ten":"Tiên Tôn","tag":"khac","quanHe":"Bị Thác Sâm gọi là đồ chơi của Tiên Tôn","ghiChu":"Chưa rõ quan hệ cụ thể"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1384"]},{"id":"linh-dong","name":"Linh Động","cn":"","aliases":[],"gioiTinh":"Nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Linh Động là tu sĩ từng có mặt trong cổ mộ Đạo Cổ, bị trọng thương do dư ba trận chiến giữa Vương Lâm và Thác Sâm nhưng vẫn giữ thần sắc bình tĩnh tự trị thương. Sau đó bị Vương Lâm thu vào Thiên Hoàng Lô cùng Chu Cẩn, rồi tham gia nghênh chiến Tiên Phi áo đỏ và theo Nam Vân Tử rút về sửa chữa Phong Giới Đại Trận.","vaiTro":"Tu sĩ phụ trợ — đồng hành cùng Vương Lâm trong cổ mộ Đạo Cổ","tinhCach":"Bình tĩnh khi bị trọng thương; phục tùng, không phản kháng khi bị thu phục","tabs":{"diem":[{"text":"Trọng thương sau trận chiến, lùi ra xa khoanh chân trị thương với thần sắc bình tĩnh","chuong":"@c1384"},{"text":"Bị Vương Lâm thu vào Thiên Hoàng Lô cùng Chu Cẩn","chuong":"@c1386"},{"text":"Cùng Nam Vân Tử và Chu Cẩn nghênh chiến Tiên Phi áo đỏ","chuong":"@c1429"},{"text":"Theo Nam Vân Tử rút về sửa chữa Phong Giới Đại Trận","chuong":"@c1434"}],"kinhLich":[{"chuong":"@c1384","importance":"minor","mucCt":"gon","text":"Trọng thương sau trận trước, lùi ra xa khoanh chân trị thương, thần sắc bình tĩnh.","anchor":"Chính mắt hắn nhìn thấy sức mạnh của Vương Lâm trước và sau khi tiến vào cổ mộ khác nhau, lúc này một tia ảo tưởng cuối cùng đã bị chặt đứt"},{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm thu vào Thiên Hoàng Lô cùng Chu Cẩn.","anchor":"Linh Động và Chu Cẩn đang chấn động đằng xa lập tức bị Vương Lâm thu vào trong Thiên Hoàng Lô"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng có mặt trong cổ mộ, chứng kiến trận chiến","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1384","@c1386"]},{"id":"diep-mich","name":"Diệp Mịch","cn":"","aliases":["Đạo Cổ"],"gioiTinh":"Nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Diệp Mịch, được gọi là Đạo Cổ, là chủ nhân cổ mộ truyền thừa mà Vương Lâm tiếp nhận. Năm xưa từng hóa thân thể khổng lồ chém giết trong vùng đất cổ mộ, nhưng bị Lý Quảng bắn rơi mắt trái khiến khí tức truyền thừa không hoàn chỉnh, ảnh hưởng trực tiếp tới Vương Lâm khi hấp thu. Di vật của ông bao gồm lầu các địa phủ chứa ba thần hồn, và khí tức Đạo Cổ mang đặc tính biến đổi giữa Cổ Thần, Cổ Ma, Cổ Yêu.","vaiTro":"Đạo Cổ — chủ nhân cổ mộ truyền thừa, người để lại di sản cho Vương Lâm","tinhCach":[],"tabs":{"diem":[{"text":"Từng hóa thân thể khổng lồ chém giết trong vùng đất cổ mộ, bị Lý Quảng bắn rơi mắt trái khiến khí tức truyền thừa không hoàn chỉnh","chuong":"@c1481"},{"text":"Để lại lầu các địa phủ chứa ba thần hồn bên trong, được Vương Lâm cân nhắc sử dụng","chuong":"@c1482"},{"text":"Khí tức Đạo Cổ biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu bùng lên từ chín quan tài trên tấm bia đá khổng lồ","chuong":"@c1576"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lý Quảng","tag":"doi-thu","quanHe":"Mắt trái bị Lý Quảng bắn rơi","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người kế thừa cổ mộ truyền thừa","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1384"]},{"id":"lo-phu-tu","name":"Lỗ Phu Tử","cn":"鲁夫子","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Người đầu tiên cảm nhận khí thế Vương Lâm khi hắn xuất hiện tại La Thiên, bừng tỉnh từ nhập định.","anchor":"Lỗ Phu Tử, là người đầu tiên cảm nhận được rõ rang! Từ trong nhập định…. bừng tỉnh!"}],"diem":[{"text":"Hoảng sợ trốn chạy khi Thác Sâm xuất hiện, rút vào tinh không không dám giao chiến","chuong":"@c1147"},{"text":"Bừng tỉnh từ nhập định khi cảm nhận khí thế Vương Lâm quét ngang La Thiên tinh vực","chuong":"@c1386"},{"text":"Đấu văn ba hiệp với Vương Lâm, luyện thành La Thiên Thụ được vạn tu sĩ tung hô","chuong":"@c1401"},{"text":"Thừa nhận bại trận, hòa giải với Vương Lâm và tiết lộ chiến tranh giới ngoại sắp tới","chuong":"@c1407"},{"text":"Dẫn đầu tu sĩ La Thiên chi viện giới nội, phối hợp các cường giả giáp công thế lực xâm nhập","chuong":"@c1434"},{"text":"Chọn ở lại Côn Hư tử chiến, bị trọng thương trong trận phản công và được Long Bàn Tử cứu rút lui","chuong":"@c1520"}]},"nguon":["@c1386"],"vaiTro":"Cường giả mạnh nhất La Thiên tinh vực — tu vi Không Niết Sơ Kỳ bước thứ ba","tinhCach":"Thận trọng, tránh đối đầu trực diện khi chưa nắm chắc phần thắng; biết tiến biết lui, chấp nhận bại trận trước kẻ mạnh hơn; trọng nhân quả và ân nghĩa cũ; sẵn sàng xả thân tử chiến khi đại cuộc lâm nguy","blurb":"Lỗ Phu Tử là cường giả được vạn tu sĩ La Thiên tôn sùng, tu vi Không Niết Sơ Kỳ bước thứ ba, lâu nay ẩn mình chữa thương trong tinh trận tây bắc La Thiên. Từng hoảng sợ trốn chạy khi Thác Sâm xuất hiện, về sau đối đầu Vương Lâm qua ba hiệp đấu văn, luyện thành La Thiên Thụ rồi thừa nhận bại trận, hòa giải và tiết lộ mối đe dọa chiến tranh giới ngoại. Sau đó dẫn đầu tu sĩ La Thiên chi viện giới nội, chọn ở lại Côn Hư tử chiến thay vì rút lui, bị trọng thương trong trận phản công và được cứu rút vào Chu Tước tinh."},{"id":"la-tran","name":"La Trần","cn":"罗尘","aliases":[],"gioiTinh":"nam","trangThai":"song","vaiTro":"Người có ân với Vương Lâm, đang ở bên trong cơ thể Vọng Nguyệt","tinhCach":"Chưa rõ","blurb":"Nhân vật có ân với Vương Lâm, hẳn vẫn đang ở trong cơ thể Vọng Nguyệt. Vương Lâm thuỷ chung nhớ ân này.","tabs":{"diem":[{"text":"Có ân với Vương Lâm, Vương Lâm thuỷ chung không quên","chuong":"@c1386"}],"kinhLich":[{"chuong":"@c1386","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc tới: có ân với hắn, hẳn vẫn ở trong cơ thể Vọng Nguyệt.","anchor":"La Trần đối với Vương Lâm có ân, việc này Vương Lâm thuỷ chung vẫn còn nhớ"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Vương Lâm nhớ ân La Trần"},{"ten":"Vọng Nguyệt","tag":"khac","quanHe":"Đang ở bên trong cơ thể Vọng Nguyệt"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1386"]}]};
